--#############################################################################
-- SOFTGUARD DESKTOP
-- updated : 2017-06-15 08:51:38.100 
--#############################################################################
CREATE FUNCTION [dbo].[Base36Encode](@a_number_to_convert [decimal](36, 0))
RETURNS [char](12) WITH EXECUTE AS CALLER
AS 
BEGIN

DECLARE @v_modulo INTEGER;  
DECLARE @v_temp_int decimal(38) = @a_number_to_convert;  
DECLARE @v_temp_val NVARCHAR(256) = '';  
DECLARE @v_temp_char NVARCHAR(1);    

--DECLARE @c_base36_digits NVARCHAR(36) = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz';
DECLARE @c_base36_digits NVARCHAR(36) = '0123456789abcdefghijklmnopqrstuvwxyz'; 
   
 IF ( @a_number_to_convert = 0 )
 BEGIN
   SET @v_temp_val = '0';  
 END    
        
 WHILE ( @v_temp_int <> 0 )
 BEGIN
   SET @v_modulo = @v_temp_int % 36;  
   SET @v_temp_char = substring( @c_base36_digits, @v_modulo + 1, 1 );  
   SET @v_temp_val = @v_temp_char + @v_temp_val;   
   SET @v_temp_int = floor(@v_temp_int / 36);  
   
 END
    
 RETURN @v_temp_val;  

END
GO
/****** Object:  UserDefinedFunction [dbo].[calcularTiempo]    Script Date: 4/21/2026 10:44:35 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

Create FUNCTION [dbo].[calcularTiempo]
(
    @Date1 Datetime,
    @Date2 Datetime,
    @TYPE VARCHAR(MAX)  -- Forma en la que se va a transformar
)                       -- 1: Formato String x horas x minutos x segundos
                        -- 2: Formato Number HH:MM:SS
 
RETURNS VARCHAR(MAX)
AS 
BEGIN
    DECLARE @temp VARCHAR(100)
    DECLARE @horas INT
    DECLARE @minutos INT
    DECLARE @tempMINUTOS INT
    DECLARE @segundos BIGINT
    
    SET @segundos = (
        SELECT
            datediff(SECOND,@Date1, @Date2) AS Segundos
    )
 
    SET @temp ='...'
 
    IF (@segundos < 3600) BEGIN
    
        SET @minutos =  FLOOR(@minutos / 60)
        SET @segundos = @minutos % 60
            --Según el tipo recibido lo formateo de una forma u otra
            IF @TYPE = 1
                SET @temp = '0 Horas ' + CONVERT(VARCHAR, @minutos) + ' Minutos ' + CONVERT(VARCHAR, @segundos) + ' Segundos'
            ELSE            
                SET @temp = '00:' + CONVERT(VARCHAR, @minutos) + ':' +  CONVERT(VARCHAR, @segundos)
    END ELSE 
BEGIN 
    SET @horas = FLOOR(@segundos / 3600)
    SET @tempMINUTOS = @segundos % 3600
    SET @minutos = FLOOR(@tempMINUTOS / 60) --MINUTOS FINALES
    SET @segundos = @tempMINUTOS % 60
        --Según el tipo recibido lo formateo de una forma u otra
        IF @TYPE = 1
            SET @temp = CONVERT(VARCHAR, @horas) + ' Horas ' + CONVERT(VARCHAR, @minutos) + ' Minutos ' + CONVERT(VARCHAR, @segundos) + ' Segundos'
        ELSE            
            SET @temp = CONVERT(VARCHAR, @horas) + ':' + CONVERT(VARCHAR, @minutos) + ':' + CONVERT(VARCHAR, @segundos) 
END 
    RETURN @temp
END
GO
/****** Object:  UserDefinedFunction [dbo].[fnCustomIndexName]    Script Date: 4/21/2026 10:44:35 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


Create FUNCTION [dbo].[fnCustomIndexName]
(    
	@base VARCHAR(Max) ,
	@dbName VARCHAR(Max) ,
	@Equality VARCHAR(Max) ,
	@Inequality VARCHAR(Max) ,
	@Included VARCHAR(Max)
)
RETURNS VARCHAR(Max)
AS
BEGIN    
	DECLARE @IndexName AS VARCHAR(Max) = ''
	Set @dbName = Replace(@dbName,@base,'')
	Set @dbName = Replace(@dbName,'[].[dbo].[','')
	Set @dbName = Replace(@dbName,']','')

	Set @Equality = Replace(@Equality,'[','')
	Set @Equality = Replace(@Equality,']','')

	Set @Inequality = Replace(@Inequality,'[','')
	Set @Inequality = Replace(@Inequality,']','')

	Declare @iFin Int=1,
			@iLen Int=0
	Declare @cCampo Varchar(100)=''
	Declare @cResult Varchar(Max)=''

	Set @Equality = Rtrim(@Equality)+','
	Set @iLen = Len(@Equality)

	WHILE CHARINDEX(',',@Equality) > 0
	BEGIN
		Set @iFin = CHARINDEX(',',@Equality)	
    
		Set @cCampo = Ltrim(SUBSTRING( @Equality, 1, @iFin-1 ))							   
	
		Set @cCampo = REPLACE(SUBSTRING(@cCampo, CHARINDEX('_', @cCampo), LEN(@cCampo)), '_', '')
	
		Set @cCampo = UPPER(LEFT(@cCampo,1))+LOWER(SUBSTRING(@cCampo,2,LEN(@cCampo))) 

		Set @cResult = @cResult + @cCampo
		Set @Equality = SUBSTRING( @Equality, @iFin+1, @iLen-@iFin )
	END
	Set @IndexName = Rtrim(@dbName) + '_' + Rtrim(@cResult)

	If Rtrim(@Inequality) != ''
	Begin
		Set @iFin=1
		Set @cCampo=''
		Set @cResult=''

		Set @Inequality = Rtrim(@Inequality)+','
		Set @iLen = Len(@Inequality)

		WHILE CHARINDEX(',',@Inequality) > 0
		BEGIN
			Set @iFin = CHARINDEX(',',@Inequality)	
    
			Set @cCampo = Ltrim(SUBSTRING( @Inequality, 1, @iFin-1 ))							   
	
			Set @cCampo = REPLACE(SUBSTRING(@cCampo, CHARINDEX('_', @cCampo), LEN(@cCampo)), '_', '')
	
			Set @cCampo = UPPER(LEFT(@cCampo,1))+LOWER(SUBSTRING(@cCampo,2,LEN(@cCampo))) 

			Set @cResult = @cResult + @cCampo
			Set @Inequality = SUBSTRING( @Inequality, @iFin+1, @iLen-@iFin )
		END
		
		Set @IndexName = @IndexName + Rtrim(@cResult)
	End

	If Rtrim(@Included) != ''
		Set @IndexName = @IndexName + 'IN'

	RETURN @IndexName

END
GO
/****** Object:  UserDefinedFunction [dbo].[GetDirectoryPath]    Script Date: 4/21/2026 10:44:35 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE FUNCTION [dbo].[GetDirectoryPath]
(
    @Path NVARCHAR(MAX)
)
RETURNS NVARCHAR(MAX)
AS
BEGIN
    DECLARE @FileName NVARCHAR(MAX)
    DECLARE @ReversedPath NVARCHAR(MAX)
    DECLARE @PathLength INT

    SET @ReversedPath = REVERSE(@Path)
    SELECT @PathLength = CHARINDEX('\', @ReversedPath)
    SELECT @FileName = LEFT(@Path, LEN(@Path) - @PathLength)
    RETURN @FileName
END
GO
/****** Object:  UserDefinedFunction [dbo].[GetExtension]    Script Date: 4/21/2026 10:44:35 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE FUNCTION [dbo].[GetExtension]
(
    @Path NVARCHAR(MAX)
)
RETURNS NVARCHAR(MAX)
AS
BEGIN
    DECLARE @FileName NVARCHAR(MAX)
    DECLARE @ReversedPath NVARCHAR(MAX)
    DECLARE @ExtLength INT

    SET @ReversedPath = REVERSE(@Path)
    SET @FileName = ''
    SELECT @ExtLength = CHARINDEX('.', @ReversedPath)
    IF (@ExtLength > 0) 
    BEGIN 
       SELECT @FileName = RIGHT(@Path, @ExtLength - 1)
    END
    RETURN @FileName
END
GO
/****** Object:  UserDefinedFunction [dbo].[GetFileName]    Script Date: 4/21/2026 10:44:35 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
