CREATE FUNCTION [dbo].[GetFileName](@Path [nvarchar](max))
RETURNS [nvarchar](max) WITH EXECUTE AS CALLER
AS 
BEGIN
    DECLARE @FileName NVARCHAR(MAX) = @Path
    DECLARE @ReversedPath NVARCHAR(MAX)
    
	SET @ReversedPath = REVERSE(@Path)
	Declare @iChar Int = CHARINDEX('\', @ReversedPath)
	IF @iChar > 0
		SELECT @FileName = RIGHT(@Path, @iChar-1)

    RETURN @FileName
END
GO
/****** Object:  UserDefinedFunction [dbo].[GetFileNameWithoutExtension]    Script Date: 4/21/2026 10:44:35 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE FUNCTION [dbo].[GetFileNameWithoutExtension]
(
    @Path NVARCHAR(MAX)
)
RETURNS NVARCHAR(MAX)
AS
BEGIN
    DECLARE @FileName NVARCHAR(MAX) = @Path
    DECLARE @ReversedPath NVARCHAR(MAX)
    DECLARE @ExtLength INT

    SET @ReversedPath = REVERSE(@Path)
    SELECT @ExtLength = CHARINDEX('.', @ReversedPath)

	Declare @iChar Int = CHARINDEX('\', @ReversedPath)
	IF @iChar > 0
		SELECT @FileName = RIGHT(@Path, @iChar-1)

    SELECT @FileName = LEFT(@FileName, LEN(@FileName) - @ExtLength)
    RETURN @FileName
END
GO
/****** Object:  UserDefinedFunction [dbo].[GetNumeric]    Script Date: 4/21/2026 10:44:35 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

Create   Function [dbo].[GetNumeric]
(@strAlphaNumeric VARCHAR(256))
RETURNS VARCHAR(256)
AS
BEGIN
DECLARE @intAlpha INT
SET @intAlpha = PATINDEX('%[^0-9]%', @strAlphaNumeric)
BEGIN
WHILE @intAlpha > 0
BEGIN
SET @strAlphaNumeric = STUFF(@strAlphaNumeric, @intAlpha, 1, '' )
SET @intAlpha = PATINDEX('%[^0-9]%', @strAlphaNumeric )
END
END
RETURN ISNULL(@strAlphaNumeric,0)
END
GO
/****** Object:  UserDefinedFunction [dbo].[GetSqlFilterForJson]    Script Date: 4/21/2026 10:44:35 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE FUNCTION [dbo].[GetSqlFilterForJson] (@filter nVarChar(2048), @objectType nVarChar(64))  
RETURNS nVarChar(4000) AS  
BEGIN 
     DECLARE @SqlFilter nVarChar(4000)
     SET @SqlFilter = ''
     
	 IF @filter != ''          
	 BEGIN        
	    DECLARE @FilterTable TABLE(element_id INT NOT NULL, parent_ID INT, Object_ID INT, NAME nVarChar(2000), StringValue nVarChar(MAX) NOT NULL, ValueType nVarChar(10) NOT null)
		INSERT INTO @FilterTable (element_id, parent_ID, Object_ID, NAME, StringValue, ValueType) 
		SELECT * FROM dbo.parseJSON(@filter) WHERE NAME IN ('property', 'value')		
	 
		DECLARE @FilterProperty nVarChar(32)
		DECLARE @FilterValue nVarChar(64)

		DECLARE @FilterIndex INT
		SET @FilterIndex = 1
		WHILE((SELECT COUNT(*) FROM @FilterTable WHERE parent_ID = @FilterIndex) != 0)
		BEGIN		
			--Read
			SELECT @FilterProperty = REPLACE(StringValue, '''', '''''') FROM @FilterTable WHERE parent_ID = @FilterIndex AND NAME = 'property'
			SELECT @FilterValue = RTRIM(LTRIM(REPLACE(StringValue, '''', ''''''))) FROM @FilterTable WHERE parent_ID = @FilterIndex AND NAME = 'value'																
						
			--Set Filters
			IF @FilterValue != ''
			BEGIN
				IF PATINDEX('%:LIKE', @FilterProperty) > 0				
					SET @SqlFilter = @SqlFilter + ' AND ' + REPLACE(@FilterProperty, ':LIKE', '') + ' LIKE ''%' + @FilterValue + '%'''     
				ELSE IF PATINDEX('%:IN', @FilterProperty) > 0
					SET @SqlFilter = @SqlFilter + ' AND ' + REPLACE(@FilterProperty, ':IN', '') + ' IN (SELECT RTRIM(LTRIM(strval)) FROM dbo.ParseArray(''' + @FilterValue + ''', '',''))'     				
				ELSE IF PATINDEX('%:NOT IN', @FilterProperty) > 0
					SET @SqlFilter = @SqlFilter + ' AND ' + REPLACE(@FilterProperty, ':NOT IN', '') + ' NOT IN (SELECT RTRIM(LTRIM(strval)) FROM dbo.ParseArray(''' + @FilterValue + ''', '',''))'     									
						
				ELSE IF @FilterProperty = 'Name'
					SET @SqlFilter = @SqlFilter + ' AND ' + @FilterProperty + ' LIKE ''%' + @FilterValue + '%'''     
				ELSE
					SET @SqlFilter = @SqlFilter + ' AND ' + @FilterProperty + ' = ''' + @FilterValue + ''''     				
			END
			ELSE	--2024-07-10 Pablo : Si un filter viene con un Property que se busca por valor vacio NUNCA lo consideraba. Ej: N'[{"property":"tel_ctelefono","value":""}]'
					SET @SqlFilter = @SqlFilter + ' AND ' + @FilterProperty + ' = ''' + @FilterValue + ''''     				
			--Next
			SET @FilterIndex = @FilterIndex + 1			
		END		
	 END
 
	 RETURN @SqlFilter
END
GO
/****** Object:  UserDefinedFunction [dbo].[GetSqlSortForJson]    Script Date: 4/21/2026 10:44:35 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE FUNCTION [dbo].[GetSqlSortForJson] (@sort nVarChar(512), @defaultSort nVarChar(256))  
RETURNS nVarChar(256) AS  
BEGIN 
            DECLARE @SqlSort AS nVarChar(256)            
 
            DECLARE @SortField nVarChar(64)
            DECLARE @SortDirection nVarChar(4)
                        
            IF @sort != ''          
            BEGIN        
               DECLARE @SortTable TABLE(element_id INT NOT NULL, parent_ID INT, Object_ID INT, NAME nVarChar(2000), StringValue nVarChar(MAX) NOT NULL, ValueType nVarChar(10) NOT null)
                        INSERT INTO @SortTable (element_id, parent_ID, Object_ID, NAME, StringValue, ValueType) SELECT * FROM dbo.parseJSON(@sort) WHERE NAME IN ('property', 'direction')                  
             
                        DECLARE @SortIndex INT
                        SET @SortIndex = 1
                        WHILE((SELECT COUNT(*) FROM @SortTable WHERE parent_ID = @SortIndex) != 0)
                        BEGIN                       
                                   --Read
                                   SELECT @SortField = REPLACE(StringValue, '''', '''''') FROM @SortTable WHERE parent_ID = @SortIndex AND NAME = 'property'
                                   SELECT @SortDirection = REPLACE(StringValue, '''', '''''') FROM @SortTable WHERE parent_ID = @SortIndex AND NAME = 'direction'                                          
                                   
                                   IF @SortDirection != 'ASC' AND @SortDirection != 'DESC'
                                     SET @SortDirection = 'ASC'
                                     
                                   --Set Sorts
                                   IF @SortIndex = 1
                                               SET @SqlSort = @SortField + ' ' + @SortDirection
                                   ELSE
                                               SET @SqlSort = @SqlSort + ', ' + @SortField + ' ' + @SortDirection
                                   
                                   --Next
                                   SET @SortIndex = @SortIndex + 1
                        END
                                                                       
            END 
            ELSE
            BEGIN
                        SET @SqlSort = @defaultSort
            END      
 
            RETURN @SqlSort
END
GO
/****** Object:  UserDefinedFunction [dbo].[ParseArray]    Script Date: 4/21/2026 10:44:35 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE Function [dbo].[ParseArray]( @Array	nVarChar(MAX),
				@separator nVarChar(4) )
Returns @strtable Table (strval	nVarChar(MAX))
As
Begin
	declare @separator_position int
	declare @array_value nVarChar(MAX) -- this holds each array value as it is returned
	
	set @array = @array + @separator
	
	while patindex('%' + @separator + '%' , @array) <> 0 
	begin 
	  set @separator_position =  patindex('%' + @separator + '%' , @array)
	  set @array_value = left(@array, @separator_position - 1)
	
	  Insert into @strtable values (@array_value)
	
	  set @array = stuff(@array, 1, @separator_position, '')
	End	
	Return
End
GO
/****** Object:  UserDefinedFunction [dbo].[parseJSON]    Script Date: 4/21/2026 10:44:35 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[parseJSON](@JSON [varchar](max))
RETURNS @hierarchy TABLE (
	[element_id] [int] IDENTITY(1,1),
	[parent_ID] [int] NULL,
	[Object_ID] [int] NULL,
	[NAME] [varchar](2000) NULL,
	[StringValue] [varchar](max),
	[ValueType] [varchar](10)
) WITH EXECUTE AS CALLER
AS 
BEGIN
  DECLARE
    @FirstObject INT, --the index of the first open bracket found in the JSON string
    @OpenDelimiter INT,--the index of the next open bracket found in the JSON string
    @NextOpenDelimiter INT,--the index of subsequent open bracket found in the JSON string
    @NextCloseDelimiter INT,--the index of subsequent close bracket found in the JSON string
    @Type NVARCHAR(10),--whether it denotes an object or an array
    @NextCloseDelimiterChar CHAR(1),--either a '}' or a ']'
    @Contents NVARCHAR(MAX), --the unparsed contents of the bracketed expression
    @Start INT, --index of the start of the token that you are parsing
    @end INT,--index of the end of the token that you are parsing
    @param INT,--the parameter at the end of the next Object/Array token
    @EndOfName INT,--the index of the start of the parameter at end of Object/Array token
    @token NVARCHAR(200),--either a string or object
    @value NVARCHAR(MAX), -- the value as a string
    @name NVARCHAR(200), --the name as a string
    @parent_ID INT,--the next parent ID to allocate
    @lenJSON INT,--the current length of the JSON String
    @characters NCHAR(36),--used to convert hex to decimal
    @result BIGINT,--the value of the hex symbol being parsed
    @index SMALLINT,--used for parsing the hex value
    @Escape INT --the index of the next escape character
   
 
  DECLARE @Strings TABLE /* in this temporary table we keep all strings, even the names of the elements, since they are 'escaped' in a different way, and may contain, unescaped, brackets denoting objects or lists. These are replaced in the JSON string by tokens representing the string */
    (
     String_ID INT IDENTITY(1, 1),
     StringValue NVARCHAR(MAX)
    )
  SELECT--initialise the characters to convert hex to ascii
    @characters='0123456789abcdefghijklmnopqrstuvwxyz',
  /* firstly we process all strings. This is done because [{} and ] aren't escaped in strings, which complicates an iterative parse. */
    @parent_ID=0;
  WHILE 1=1 --forever until there is nothing more to do
    BEGIN
      SELECT
        @start=PATINDEX('%[^a-zA-Z]["]%', @json);--next delimited string
      IF @start=0 BREAK --no more so drop through the WHILE loop
      IF SUBSTRING(@json, @start+1, 1)='"'
        BEGIN --Delimited Name
          SET @start=@Start+1;
          SET @end=PATINDEX('%[^\]["]%', RIGHT(@json, LEN(@json+'|')-@start));
        END
      IF @end=0 --no end delimiter to last string
        BREAK --no more
      SELECT @token=SUBSTRING(@json, @start+1, @end-1)
      --now put in the escaped control characters
      SELECT @token=REPLACE(@token, FROMString, TOString)
      FROM
        (SELECT
          '\"' AS FromString, '"' AS ToString
         UNION ALL SELECT '\\', '\'
         UNION ALL SELECT '\/', '/'
         UNION ALL SELECT '\b', CHAR(08)
         UNION ALL SELECT '\f', CHAR(12)
         UNION ALL SELECT '\n', CHAR(10)
         UNION ALL SELECT '\r', CHAR(13)
         UNION ALL SELECT '\t', CHAR(09)
        ) substitutions
      SELECT @result=0, @escape=1
  --Begin to take out any hex escape codes
      WHILE @escape>0
        BEGIN
          SELECT @index=0,
          --find the next hex escape sequence
          @escape=PATINDEX('%\x[0-9a-f][0-9a-f][0-9a-f][0-9a-f]%', @token)
          IF @escape>0 --if there is one
            BEGIN
              WHILE @index<4 --there are always four digits to a \x sequence  
                BEGIN
                  SELECT --determine its value
                    @result=@result+POWER(16, @index)
                    *(CHARINDEX(SUBSTRING(@token, @escape+2+3-@index, 1),
                                @characters)-1), @index=@index+1 ;
        
                END
                -- and replace the hex sequence by its unicode value
              SELECT @token=STUFF(@token, @escape, 6, NCHAR(@result))
            END
        END
      --now store the string away
      INSERT INTO @Strings (StringValue) SELECT @token
      -- and replace the string with a token
      SELECT @JSON=STUFF(@json, @start, @end+1,
                    '@string'+CONVERT(NVARCHAR(5), @@identity))
    END
  -- all strings are now removed. Now we find the first leaf. 
  WHILE 1=1  --forever until there is nothing more to do
  BEGIN
 
  SELECT @parent_ID=@parent_ID+1
  --find the first object or list by looking for the open bracket
  SELECT @FirstObject=PATINDEX('%[{[[]%', @json)--object or array
  IF @FirstObject = 0 BREAK
  IF (SUBSTRING(@json, @FirstObject, 1)='{')
    SELECT @NextCloseDelimiterChar='}', @type='object'
  ELSE
    SELECT @NextCloseDelimiterChar=']', @type='array'
  SELECT @OpenDelimiter=@firstObject
 
  WHILE 1=1 --find the innermost object or list...
    BEGIN
      SELECT
        @lenJSON=LEN(@JSON+'|')-1
  --find the matching close-delimiter proceeding after the open-delimiter
      SELECT
        @NextCloseDelimiter=CHARINDEX(@NextCloseDelimiterChar, @json,
                                      @OpenDelimiter+1)
  --is there an intervening open-delimiter of either type?
      SELECT @NextOpenDelimiter=PATINDEX('%[{[[]%',
             RIGHT(@json, @lenJSON-@OpenDelimiter))--object
      IF @NextOpenDelimiter=0 --then we are done.
        BREAK
      SELECT @NextOpenDelimiter=@NextOpenDelimiter+@OpenDelimiter
      IF @NextCloseDelimiter<@NextOpenDelimiter --we have found the next leaf
        BREAK
      --we prepare to walk the document further
      IF SUBSTRING(@json, @NextOpenDelimiter, 1)='{'
        SELECT @NextCloseDelimiterChar='}', @type='object'
      ELSE
        SELECT @NextCloseDelimiterChar=']', @type='array'
      SELECT @OpenDelimiter=@NextOpenDelimiter
    END
  /*and now we can parse out the list or name/value pairs. We first pull out the structure into the variable '@contents' and replace it in the JSON document with a token representing it.*/
  SELECT
    @contents=SUBSTRING(@json, @OpenDelimiter+1,
                        @NextCloseDelimiter-@OpenDelimiter-1)
  SELECT
    @JSON=STUFF(@json, @OpenDelimiter,
                @NextCloseDelimiter-@OpenDelimiter+1,
                '@'+@type+CONVERT(NVARCHAR(5), @parent_ID))
 /*and do each name/value pair, or just value, in the case of an ordered value list.  */           
  WHILE (PATINDEX('%[A-Za-z0-9@+.e]%', @contents))<>0
    BEGIN
      IF @Type='Object' /*it will be a 0-n list containing a string followed by a string, number,boolean, or null*/
        BEGIN
          SELECT
            @end=CHARINDEX(':', ' '+@contents) /*if there is anything, it will be a string-based name.*/
          SELECT  @start=PATINDEX('%[^A-Za-z@][@]%', ' '+@contents)--find out what the token is
          SELECT @token=SUBSTRING(' '+@contents, @start+1, @End-@Start-1),
            @endofname=PATINDEX('%[0-9]%', @token),--and find out the number so as to fish out the string
            @param=RIGHT(@token, LEN(@token)-@endofname+1)
          SELECT--separate the token from the contents of the structure (chop, chop0
            @token=LEFT(@token, @endofname-1),
            @Contents=RIGHT(' '+@contents, LEN(' '+@contents+'|')-@end-1)
          --now we get the string we have stored (names are stored as strings)
          SELECT  @name=stringvalue FROM @strings
            WHERE string_id=@param --fetch the name
        END
      ELSE --it is merely a value in an ordered list, without a name
        SELECT @Name=null 
      SELECT
        @end=CHARINDEX(',', @contents)-- a string-token, object-token, list-token, number,boolean, or null
      IF @end=0 --then we're at the end of the list
        SELECT @end=PATINDEX('%[A-Za-z0-9@+.e][^A-Za-z0-9@+.e]%', @Contents+' ')
          +1
      SELECT @start=PATINDEX('%[^A-Za-z0-9@+.e][A-Za-z0-9@+.e]%', ' '+@contents)
      SELECT --get the value and snip the contents
        @Value=RTRIM(SUBSTRING(@contents, @start, @End-@Start)),
        @Contents=RIGHT(@contents+' ', LEN(@contents+'|')-@end)
      IF SUBSTRING(@value, 1, 7)='@object'
        INSERT INTO @hierarchy
          (NAME, parent_ID, StringValue, Object_ID, ValueType)
          SELECT @name, @parent_ID, SUBSTRING(@value, 8, 5),
            SUBSTRING(@value, 8, 5), 'object'
      ELSE
        IF SUBSTRING(@value, 1, 6)='@array'
          INSERT INTO @hierarchy
            (NAME, parent_ID, StringValue, Object_ID, ValueType)
            SELECT @name, @parent_ID, SUBSTRING(@value, 7, 5),
              SUBSTRING(@value, 7, 5), 'array'
        ELSE
          IF SUBSTRING(@value, 1, 7)='@string' --it is a string
            INSERT INTO @hierarchy
              (NAME, parent_ID, StringValue, ValueType)
              SELECT @name, @parent_ID, stringvalue, 'string'
              FROM @strings
              WHERE string_id=SUBSTRING(@value, 8, 5)
          ELSE
            IF @value IN ('true', 'false')--a boolean!
              INSERT INTO @hierarchy
                (NAME, parent_ID, StringValue, ValueType)
                SELECT @name, @parent_ID, @value, 'boolean'
            ELSE
              IF @value='null' --it is a null
                INSERT INTO @hierarchy
                  (NAME, parent_ID, StringValue, ValueType)
                  SELECT @name, @parent_ID, @value, 'null'
              ELSE
                IF PATINDEX('%[^0-9]%', @value)>0 --a real number
                  INSERT INTO @hierarchy
                    (NAME, parent_ID, StringValue, ValueType)
                    SELECT @name, @parent_ID, @value, 'real'
                ELSE --it must be an INT
                  INSERT INTO @hierarchy
                    (NAME, parent_ID, StringValue, ValueType)
                    SELECT @name, @parent_ID, @value, 'int'
 
    END
  END
--and so lastly we put the root into the hierarchy.
INSERT INTO @hierarchy (NAME, parent_ID, StringValue, Object_ID, ValueType)
  SELECT '-', NULL, '', @parent_id-1, @type
--
   RETURN
END
GO
/****** Object:  UserDefinedFunction [dbo].[SplitDelimited]    Script Date: 4/21/2026 10:44:35 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO
CREATE FUNCTION [dbo].[SplitDelimited](@List [nvarchar](max), @SplitOn [nvarchar](1))
RETURNS @RtnValue TABLE (
	[Id] [int] IDENTITY(1,1),
	[Value] [nvarchar](max) COLLATE DATABASE_DEFAULT Null
) WITH EXECUTE AS CALLER
AS 
BEGIN
  While (Charindex(@SplitOn,@List)>0)
  Begin 
   Insert Into @RtnValue (value)
   Select 
    Value = ltrim(rtrim(Substring(@List,1,Charindex(@SplitOn,@List)-1))) 
   Set @List = Substring(@List,Charindex(@SplitOn,@List)+len(@SplitOn),len(@List))
  End 
  
  Insert Into @RtnValue (Value)
  Select Value = ltrim(rtrim(@List))

  Return
 END
GO
/****** Object:  UserDefinedFunction [dbo].[UrlDecodeUTF8]    Script Date: 4/21/2026 10:44:35 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE FUNCTION [dbo].[UrlDecodeUTF8](@URL VarChar(3072))
RETURNS VarChar(3072)
AS
BEGIN 

    DECLARE @Position INT,
        @Base CHAR(16),
        @Code INT,
        @Pattern CHAR(21)

    SELECT @URL = REPLACE(@URL, '%c3', '')

    SELECT  @Base = '0123456789abcdef',
        @Pattern = '%[%][0-9a-f][0-9a-f]%',
        @Position = PATINDEX(@Pattern, @URL)

    WHILE @Position > 0
        SELECT @Code = Cast(CONVERT(varbinary(4), '0x' + SUBSTRING(@URL, @Position + 1, 2), 1) As int),
            @URL = STUFF(@URL, @Position, 3, NCHAR(@Code + 64)),
            @Position = PATINDEX(@Pattern, @URL)

    RETURN REPLACE(@URL, '+', ' ')
END
GO
