/****** Object:  StoredProcedure [dbo].[AgregarTimelineAsignacionSearch]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[AgregarTimelineAsignacionSearch]
	--@calarma  VARCHAR (3),
	@estado int,
	@observacion NVARCHAR (MAX) = '',
	@rec_iid INT,
  @amh_amv_objectid INT,
	@amh_amv_objecttypeid INT
AS
BEGIN
  IF @estado != '' 
		BEGIN
			DECLARE @message NVARCHAR (MAX) = ''
			DECLARE @rec_iidcuenta INT ;

			select @rec_iidcuenta = rec_iidcuenta from _datos..p_recepcion where rec_iid = @rec_iid


			--elijo el mensaje segun la alarma
		/*	IF @calarma = 'V23'
				BEGIN
					SET @message = '%MOVIL CANCELADO%'
				END
			ELSE IF @calarma = 'V24'
				BEGIN
					SET @message = '%MOVIL COMPLETO%'
				END
			ELSE IF @calarma = 'V25'
				BEGIN
					SET @message = '%MOVIL EN CAMINO%'
				END
			ELSE IF @calarma = 'V26'
				BEGIN
					SET @message = '%MOVIL ARRIBADO%'
				END*/
			IF @estado = 1
				BEGIN
					SET @message = '%MOVIL ASIGNACION%'
				END
			ELSE IF @estado = 2
				BEGIN
					SET @message = '%MOVIL CANCELADO%'
				END
			ELSE IF @estado = 3
				BEGIN
					SET @message = '%MOVIL COMPLETO%'
				END
			ELSE IF @estado = 11
				BEGIN
					SET @message = '%MOVIL EN CAMINO%'
				END
			ELSE IF @estado = 12
				BEGIN
					SET @message = '%MOVIL ARRIBADO%'
				END
			
			DECLARE @datenow DateTime = GETDATE();
		  DECLARE @finalMessage NVARCHAR(max) = '['+@message+'] '+@observacion;

		  Insert into [_datos]..[EventosTimeline] ([etl_irecid],[etl_icuenta],[etl_tfechahora],[etl_caccion],[etl_cobservacion],[etl_cowner],[etl_ioperador],[etl_iaccioncode ])
										 						 values ( @rec_iid, @rec_iidcuenta, @datenow, '%AsignacionMovil%', @finalMessage, '%SISTEMA%', 0, 0 )





			Insert into [_datos]..[p_asignacionMovilHistorico] (amh_fechahora,amh_observacion,amh_rec_iid,amh_cue_iid, amh_amv_objectid, amh_amv_objecttypeid)
										 						 values ( @datenow,@finalMessage,@rec_iid, @rec_iidcuenta, @amh_amv_objectid, @amh_amv_objecttypeid )
										



		END
END


GO
/****** Object:  StoredProcedure [dbo].[CambioClavesNanoComm]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[CambioClavesNanoComm] AS
-- =============================================
-- Author:		Pablo Canonico
-- Create date: 15/02/2012
-- Description:	Actualiza la tabla de comandos con el cambio de clave para cuentas con NanoComm
-- =============================================

SET NOCOUNT ON

Declare @iParametro Int
Declare @idCta      Int
Declare @iReceptor  Int
Declare @cIMEI      nVarChar(20)
Declare @iCmd		Int
Declare @iPin		Int
Declare @cKey		As Char(8)

Set @iParametro = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='CLAVESNANOCOMM' )
If @iParametro = 1
	Begin	
		-- Aviso que la tarea esta funcionando	60min * 25hs = 1500
		Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'CambioClavesNanoComm', @Repetition = 1500
		--	
	
		Set @iCmd = (Select tcm_iid From _Tablas.dbo.t_comandos Where tcm_cinterno='CAMCLAnc')

		DECLARE ChangeKey_Cursor CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
		Select MC.cue_iid,MC.cue_cIMEI,RC.rec_iid From m_cuentas MC With (NOLOCK)
			Inner Join  _Tablas.Dbo.t_port_alias On MC.cue_clinea=tpa_cdealer
			Inner Join  _Tablas.Dbo.t_ip_con On ipc_icodigo=tpa_iportip
			Inner Join _Datos.dbo.m_receptores_cab RC ON ipc_ireceptor= rec_iid 
					And rec_ntcpip = 1 
					And rec_cdll = 'NANOCOMM'
			Where MC.cue_cIMEI > '' And MC.cue_cIMEI <> MC.cue_nCuenta 
			And Not MC.cue_ncuenta IN('0000','XXXX') And MC.cue_clinea Not In('_SG') 
				Order By MC.cue_iid

		OPEN ChangeKey_Cursor
		FETCH NEXT FROM ChangeKey_Cursor INTO @idCta, @cIMEI, @iReceptor
		WHILE @@FETCH_STATUS = 0
		BEGIN
			Set @iPin = ABS(CAST(NEWID() as binary(6)) % 10000) + 1
			Set @cKey = Right(Rtrim('111'+Cast(@iPin As Char(4))),4)
			--Si son iguales, regenero
			If Left(@cIMEI,4)=@cKey
				Begin
					Set @iPin = ABS(CAST(NEWID() as binary(6)) % 10000) + 1
					Set @cKey = Right(Rtrim('111'+Cast(@iPin As Char(4))),4)
		
				End 

			Insert Into p_comandos_ip (cmd_idCuenta,cmd_idReceptor,cmd_iComando,cmd_cValores,cmd_nEstado)
				Values (@idCta,@iReceptor,@iCmd,Left(@cIMEI,4)+'|'+@cKey,1)

		   FETCH NEXT FROM ChangeKey_Cursor INTO @idCta, @cIMEI, @iReceptor
		End

		CLOSE ChangeKey_Cursor
		DEALLOCATE ChangeKey_Cursor

   End
Else	-- Aviso que la tarea no cumple las condiciones para funcionar
	Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'CambioClavesNanoComm', @Repetition = 1500, @Date = null, @Status = 0   

GO
/****** Object:  StoredProcedure [dbo].[DBA_IndexDefrag]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[DBA_IndexDefrag]
      @minFragmentation     float           = 5.0          /* in percent, will not defrag if fragmentation less than specified */
    , @rebuildThreshold     float           = 30.0         /* in percent, greater than @rebuildThreshold will result in rebuild instead of reorg */
    , @executeSQL           bit             = 1            /* 1 = execute; 0 = print command only */
    , @database             varchar(128)    = Null         /* Option to specify a database name; null will return all */
    , @tableName            varchar(4000)   = Null		   /* Option to specify a table name ( databaseName.schema.tableName); null will return all */
    , @onlineRebuild        bit             = 1            /* 1 = online rebuild; 0 = offline rebuild; only in Enterprise */
    , @maxDopRestriction    tinyint         = Null         /* Option to restrict the number of processors for the operation; only in Enterprise */
    , @printCommands        bit             = 0            /* 1 = print commands; 0 = do not print commands */
    , @printFragmentation   bit             = 0            /* 1 = print fragmentation prior to defrag; 0 = do not print */
    , @defragDelay          char(8)         = '00:00:05'   /* time to wait between defrag commands */
    , @debugMode            bit             = 0            /* display some useful comments to help determine if/where issues occur */
As

Set NoCount On;
Set XACT_Abort On;
Set Quoted_Identifier On;

Begin
    If @debugMode = 1 RaisError('Starting up...', 0, 42) With NoWait;

    /* Declare variables */
    Declare   @objectID             int
            , @databaseID           int
            , @databaseName         nvarchar(128)
            , @indexID              int
            , @partitionCount       bigint
            , @schemaName           nvarchar(128)
            , @objectName           nvarchar(128)
            , @indexName            nvarchar(128)
            , @partitionNumber      smallint
            , @partitions           smallint
            , @fragmentation        float
            , @pageCount            int
            , @sqlCommand           nvarchar(4000)
            , @rebuildCommand       nvarchar(200)
            , @containsLOB          bit
            , @editionCheck         bit
            , @debugMessage         varchar(128)
            , @updateSQL            nvarchar(4000)
            , @partitionSQL         nvarchar(4000)
            , @partitionSQL_Param   nvarchar(1000)
            , @LOB_SQL              nvarchar(4000)
            , @LOB_SQL_Param        nvarchar(1000);

    /* Create temporary tables */
    Create Table #indexDefragList
    (
          databaseID        int
        , databaseName      nvarchar(128)
        , objectID          int
        , indexID           int
        , partitionNumber   smallint
        , fragmentation     float
        , page_count        int
        , defragStatus      bit
        , schemaName        nvarchar(128)   Null
        , objectName        nvarchar(128)   Null
        , indexName         nvarchar(128)   Null
    );

    Create Table #databaseList
    (
          databaseID        int
        , databaseName      varchar(128)
    );

    Create Table #processor 
    (
          [index]           int
        , Name              varchar(128)
        , Internal_Value    int
        , Character_Value   int
    );

    If @debugMode = 1 RaisError('Beginning validation...', 0, 42) With NoWait;

    /* Just a little validation... */
    If @minFragmentation Not Between 0.00 And 100.0
        Set @minFragmentation = 5.0;

    If @rebuildThreshold Not Between 0.00 And 100.0
        Set @rebuildThreshold = 30.0;

    If @defragDelay Not Like '00:[0-5][0-9]:[0-5][0-9]'
        Set @defragDelay = '00:00:05';

    /* Make sure we're not exceeding the number of processors we have available */
    Insert Into #processor
    Execute xp_msver 'ProcessorCount';

    If @maxDopRestriction Is Not Null And @maxDopRestriction > (Select Internal_Value From #processor)
        Select @maxDopRestriction = Internal_Value
        From #processor;

    /* Check out server version; 1804890536 = Enterprise, 610778273 = Enterprise Evaluation, -2117995310 = Developer */
    If (Select ServerProperty('EditionID')) In (1804890536, 610778273, -2117995310) 
        Set @editionCheck = 1 -- supports online rebuilds
    Else
        Set @editionCheck = 0; -- does not support online rebuilds

    If @debugMode = 1 RaisError('Retrieve a list of databases...', 0, 42) With NoWait;

    /* Retrieve the list of databases to investigate */
    Insert Into #databaseList
    Select database_id
        , name
    From sys.databases
    Where name = IsNull(@database, name)
        And database_id > 4 -- exclude system databases
        And [state] = 0; -- state must be ONLINE

    If @debugMode = 1 RaisError('Looping through list of databases and checking for fragmentation...', 0, 42) With NoWait;

    /* Loop through list of databases */
    While (Select Count(*) From #databaseList) > 0
    Begin

        Select Top 1 @databaseID = databaseID
        From #databaseList;

        Select @debugMessage = '  working on ' + DB_Name(@databaseID) + '...';

        If @debugMode = 1
            RaisError(@debugMessage, 0, 42) With NoWait;

       /* Determine which indexes to defrag using our user-defined parameters */
        Insert Into #indexDefragList
        Select
              database_id As databaseID
            , QuoteName(DB_Name(database_id)) As 'databaseName'
            , [object_id] As objectID
            , index_id As indexID
            , partition_number As partitionNumber
            , avg_fragmentation_in_percent As fragmentation
            , page_count 
            , 0 As 'defragStatus' /* 0 = unprocessed, 1 = processed */
            , Null As 'schemaName'
            , Null As 'objectName'
            , Null As 'indexName'
        From sys.dm_db_index_physical_stats (@databaseID, Object_Id(@tableName), Null , Null, N'Limited')
        Where avg_fragmentation_in_percent >= @minFragmentation 
            And index_id > 0 -- ignore heaps
            And page_count > 8 -- ignore objects with less than 1 extent
        Option (MaxDop 1);

        Delete From #databaseList
        Where databaseID = @databaseID;

    End
 
    Create Clustered Index CIX_temp_indexDefragList
        On #indexDefragList(databaseID, objectID, indexID, partitionNumber);

    Select @debugMessage = 'Looping through list... there''s ' + Cast(Count(*) As varchar(10)) + ' indexes to defrag!'
    From #indexDefragList;

    If @debugMode = 1 RaisError(@debugMessage, 0, 42) With NoWait;

    /* Begin loop for defragging */
    While (Select Count(*) From #indexDefragList Where defragStatus = 0) > 0
    Begin

        If @debugMode = 1 RaisError('  Picking an index to beat...', 0, 42) With NoWait;

        /* Grab the most fragmented index first to defrag */
        Select Top 1 
              @objectID         = objectID
            , @indexID          = indexID
            , @databaseID       = databaseID
            , @databaseName     = databaseName
            , @fragmentation    = fragmentation
            , @partitionNumber  = partitionNumber
            , @pageCount        = page_count
        From #indexDefragList
        Where defragStatus = 0
        Order By fragmentation Desc;

        If @debugMode = 1 RaisError('  Looking up index information...', 0, 42) With NoWait;

        /* Look up index information */
        Select @updateSQL = N'Update idl
            Set schemaName = QuoteName(s.name)
                , objectName = QuoteName(o.name)
                , indexName = QuoteName(i.name)
            From #indexDefragList As idl
            Inner Join ' + @databaseName + '.sys.objects As o
                On idl.objectID = o.object_id
            Inner Join ' + @databaseName + '.sys.indexes As i
                On o.object_id = i.object_id
            Inner Join ' + @databaseName + '.sys.schemas As s
                On o.schema_id = s.schema_id
            Where o.object_id = ' + Cast(@objectID As varchar(10)) + '
                And i.index_id = ' + Cast(@indexID As varchar(10)) + '
                And i.type > 0
                And idl.databaseID = ' + Cast(@databaseID As varchar(10));

        Execute sp_executeSQL @updateSQL;

        /* Grab object names */
        Select @objectName  = objectName
            , @schemaName   = schemaName
            , @indexName    = indexName
        From #indexDefragList
        Where objectID = @objectID
            And indexID = @indexID
            And databaseID = @databaseID;

        If @debugMode = 1 RaisError('  Determine if the index is partitioned...', 0, 42) With NoWait;

        /* Determine if the index is partitioned */
        Select @partitionSQL = 'Select @partitionCount_OUT = Count(*)
                                    From ' + @databaseName + '.sys.partitions
                                    Where object_id = ' + Cast(@objectID As varchar(10)) + '
                                        And index_id = ' + Cast(@indexID As varchar(10)) + ';'
            , @partitionSQL_Param = '@partitionCount_OUT int OutPut';

        Execute sp_executeSQL @partitionSQL, @partitionSQL_Param, @partitionCount_OUT = @partitionCount OutPut;

        If @debugMode = 1 RaisError('  Determine if the table contains LOBs to be handled...', 0, 42) With NoWait;
    
        /* Determine if the table contains LOBs */
        Select @LOB_SQL = ' Select Top 1 @containsLOB_OUT = column_id
                            From ' + @databaseName + '.sys.columns With (NoLock) 
                            Where [object_id] = ' + Cast(@objectID As varchar(10)) + '
                                And (system_type_id In (34, 35, 99)
                                        Or max_length = -1);'
                            /*  system_type_id --> 34 = image, 35 = text, 99 = ntext
                                max_length = -1 --> varbinary(max), varchar(max), nvarchar(max), xml */
                , @LOB_SQL_Param = '@containsLOB_OUT int OutPut';

        Execute sp_executeSQL @LOB_SQL, @LOB_SQL_Param, @containsLOB_OUT = @containsLOB OutPut;
        
        If @debugMode = 1 RaisError('  Building SQL statements...', 0, 42) With NoWait;

        /* If there's not a lot of fragmentation, or if we have a LOB, we should reorganize */
        If @fragmentation < @rebuildThreshold Or @containsLOB = 1 Or @partitionCount > 1
        Begin
        
            Set @sqlCommand = N'Alter Index ' + @indexName + N' On ' + @databaseName + N'.' 
                                + @schemaName + N'.' + @objectName + N' ReOrganize';

            /* If our index is partitioned, we should always reorganize */
            If @partitionCount > 1
                Set @sqlCommand = @sqlCommand + N' Partition = ' 
                                + Cast(@partitionNumber As nvarchar(10));

        End;

        /* If the index is heavily fragmented and doesn't contain any partitions or LOB's, rebuild it */
        If @fragmentation >= @rebuildThreshold And IsNull(@containsLOB, 0) != 1 And @partitionCount <= 1
        Begin

            /* Set online rebuild options; requires Enterprise Edition */
            If @onlineRebuild = 1 And @editionCheck = 1 
                Set @rebuildCommand = N' Rebuild With (Online = On';
            Else
                Set @rebuildCommand = N' Rebuild With (Online = Off';

            /* Set processor restriction options; requires Enterprise Edition */
            If @maxDopRestriction Is Not Null And @editionCheck = 1
                Set @rebuildCommand = @rebuildCommand + N', MaxDop = ' + Cast(@maxDopRestriction As varchar(2)) + N')';
            Else
                Set @rebuildCommand = @rebuildCommand + N')';
        
            Set @sqlCommand = N'Alter Index ' + @indexName + N' On ' + @databaseName + N'.'
                            + @schemaName + N'.' + @objectName + @rebuildCommand;

        End;

        /* Are we executing the SQL?  If so, do it */
        If @executeSQL = 1
        Begin

            If @debugMode = 1 RaisError('  Executing SQL statements...', 0, 42) With NoWait;

            /* Grab the time for logging purposes */
            Execute sp_executeSQL @sqlCommand;
            
            /* Just a little breather for the server */
            WaitFor Delay @defragDelay;

            /* Print if specified to do so */
            If @printCommands = 1
                Print N'Executed: ' + @sqlCommand;
        End
        Else
        /* Looks like we're not executing, just printing the commands */
        Begin
            If @debugMode = 1 RaisError('  Printing SQL statements...', 0, 42) With NoWait;
            
            If @printCommands = 1 Print IsNull(@sqlCommand, 'error!');
        End

        If @debugMode = 1 RaisError('  Updating our index defrag status...', 0, 42) With NoWait;

        /* Update our index defrag list so we know we've finished with that index */
        Update #indexDefragList
        Set defragStatus = 1,
		indexName=@indexName
        Where databaseID       = @databaseID
          And objectID         = @objectID
          And indexID          = @indexID
          And partitionNumber  = @partitionNumber;

    End

    /* Do we want to output our fragmentation results? */
    If @printFragmentation = 1
    Begin

        If @debugMode = 1 
		Begin
			RaisError('  Displaying fragmentation results...', 0, 42) With NoWait;

			Select databaseID
				, databaseName
				, objectID
				, objectName
				, indexID
				, indexName
				, fragmentation
				, page_count
			From #indexDefragList;
		End;
    End;

    /* When everything is said and done, make sure to get rid of temp table */
    Drop Table #indexDefragList;
    Drop Table #databaseList;
    Drop Table #processor;

    If @debugMode = 1 RaisError('DONE!!!', 0, 42) With NoWait;

    Set NoCount Off;
End


GO
