CREATE PROCEDURE [dbo].[SGSP_ControlEstadoPanel]
	@iIdCuenta [int]=0,
	@cCodAlarma [char](3)='',
	@iUsuario [int]=0,
	@iRecId [int]=0
AS
--Analizador de Eventos configurados para control de estado panel
--Autor : Pablo O. Canónico
--Fecha : 03/01/2018
--27-05-2024 : Pablo.DSS guarda usu_idkey en lugar de usu_icodigo. Se contiene desde aca (DSS-1020)

Set NoCount ON
BEGIN TRY
	Declare @cAlarmaEsperada Char(3),
		    @cAlarmaAGenerar Char(3)
	Declare @iUsuarioEsperado Int,
			@iMinutos Int

	Declare @tLimite Datetime,
		    @ahora Datetime = GetDate()

	Declare @message nVarChar(Max) = '',
			@StartDateTimeText VarChar(max) = ''

	Declare  @iExecute Int = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='TIMEREXECUTE' )
	If @iExecute = 0
	Begin	
		Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | [SGSP_ControlEstadoPanel] | TimerExecute configurado para NO ejecutar'
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

		Set NoExec On
	End
	
	--@iUsuario es usu_iCodigo y [mep_iUsuarioControl] guarda [usu_idKey]
	Select @iUsuario=[usu_idKey] From [_Datos].[dbo].[m_usuarios]  With (NOLOCK)
		Where [usu_iCodigo]=@iUsuario And [usu_iidcuenta]=@iIdCuenta

	--Query
	Select @cAlarmaEsperada=[mep_cAlarmaEsperada],@iUsuarioEsperado=[mep_iUsuarioEsperado],@iMinutos=[mep_iMinutos],@cAlarmaAGenerar=[mep_cAlarmaAGenerar],@tLimite = DATEADD(MINUTE,[mep_iMinutos],@ahora)
		From [_Datos].[dbo].[m_EstadosPanel]
	Where  [mep_iMinutos]>0
		And [mep_idCuenta]=@iIdCuenta
		And [mep_cAlarmaControl]=@cCodAlarma
		And ( [mep_iUsuarioControl]=@iUsuario Or [mep_iUsuarioControl]=0)

	--Si el query trae algun valor
	If ( @tLimite Is Not  Null ) 
	Begin

		--@iUsuarioEsperado guarda [usu_idKey] y necesito usu_iCodigo
		Select @iUsuarioEsperado=usu_iCodigo From [_Datos].[dbo].[m_usuarios]  With (NOLOCK)
			Where [usu_idKey]=@iUsuarioEsperado

		--p_EventosTimer--
		If OBJECT_ID('[_Datos].[dbo].[p_EventosTimer]') Is Not NULL
		Begin
			Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | [SGSP_ControlEstadoPanel] | Grabacion de p_EventosTimer | IdCuenta => '+ Rtrim(Cast(@iIdCuenta As Varchar(10)))+' | RecId => '+ Rtrim(Cast(@iRecId As Varchar(10)))+' | Usuario Esperado => '+ Rtrim(Cast(@iUsuarioEsperado As varchar(10)))+' | Alarma Esperada => '+ @cAlarmaEsperada+' | FechaHora Limite => '+ Rtrim(Convert(VarChar, @tLimite,120) )+' | Alarma a Generar => '+ @cAlarmaAGenerar
			
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			Insert Into [_Datos].[dbo].[p_EventosTimer] ([pet_cTipo],[pet_idCuenta],[pet_iRecId],[pet_tFechaHora],[pet_cAlarma],[pet_cZona],[pet_iUsuario],[pet_iRecId_NR],[pet_tLimite_NR],[pet_cEvento_NR],[pet_iMinutos_NR],[pet_cAlarmaAGenerar_NR],[pet_cZona_NR])
				Values ('P',@iIdCuenta,@iRecId,@ahora,@cCodAlarma,'',@iUsuarioEsperado,0,@tLimite,@cAlarmaEsperada,@iMinutos,@cAlarmaAGenerar,'')

		End
		------------------
	End

Set NoExec Off
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
END CATCH

GO
/****** Object:  StoredProcedure [dbo].[SGSP_ControlExcesoEventos]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SGSP_ControlExcesoEventos]  As
--Controla Exceso en Eventos Recibidos y genera alerta
--Autor :Pablo O. Canónico
--Fecha :05/11/2014
SET NOCOUNT ON
Declare @iControl Int
Set @iControl = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='EXCCONTROL' )
If @iControl Is Null
	Set @iControl = 1

If @iControl = 0
	Begin
		-- Aviso que la tarea no cumple las condiciones para funcionar
		Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'ControlExcesoEventos', @Repetition = 20, @Date = null, @Status = 0
		Set NoExec On
	End	

-- Aviso que la tarea esta funcionando
Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'ControlExcesoEventos', @Repetition = 20
--	
	
Declare @iMinutos Int = ( Select Case When par_ivalor < 60 Then 60 Else par_ivalor End  From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='EXCTIEMPO' )		
Declare @iMax Int =  ( Select Case When par_ivalor < 5 Then 2 Else par_ivalor End  From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='EXCMAXEVE' )

--Busco acumulados--
Declare @idCuenta Int
Declare @cAlarma char(3)
Declare @iCant Int
Declare @iDiff Int = 0

DECLARE cExcesos CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
	Select [rxa_idCuenta],[rxa_cAlarma],Count(*) As nCant,Max(DATEDIFF(MINUTE,rxa_tFechaHora,GETDATE())) As iDiff
	  FROM [_Datos].[dbo].[p_RXAcumulado]
	  --Where DATEDIFF(MINUTE,rxa_tFechaHora,GETDATE()) = @iMinutos
	  GROUP By [rxa_idCuenta],[rxa_cAlarma]
	Having Count(*) >= @iMax

OPEN cExcesos
FETCH NEXT FROM cExcesos INTO @idCuenta,@cAlarma,@iCant,@iDiff
	WHILE @@FETCH_STATUS = 0
		Begin
		If @iDiff >= @iMinutos
		   EXEC _Desktop.dbo.AlarmaGenerar @idCuenta, '_XC'  

		FETCH NEXT FROM cExcesos INTO @idCuenta,@cAlarma,@iCant,@iDiff
		End

CLOSE cExcesos
DEALLOCATE cExcesos


--Elimino los que ya cumplieron su tiempo--
DELETE FROM p_RXAcumulado Where DATEDIFF(MINUTE,rxa_tFechaHora,GETDATE()) >= @iMinutos

Set NoExec Off

GO
/****** Object:  StoredProcedure [dbo].[SGSP_ControlFalsasAlarmas]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SGSP_ControlFalsasAlarmas]  As
--Verifica Falsas Alarmas | Actualiza Status
--Autor :Pablo O. Canónico
--Fecha :02/12/2014
--Modificado 19-04-2016 Cambio rutina insert en pRecepcion
--Modificado 30-05-2016 Se actualiza m_Status

SET NOCOUNT ON
-- Aviso que la tarea esta funcionando
Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'ControlFalsasAlarmas', @Repetition = 30
--	

Declare @iEnviaMail Int = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='MAILSERVICE' )		
If @iEnviaMail Is Null
	Set @iEnviaMail = 0

Declare @Query	nVarChar(255)='',
 @cFrom			nVarChar(150)=( Select Cast(par_cValor As nVarChar(150)) From _Tablas.dbo.t_parametros Where par_ccodigo = 'MAILSENDER'),
 @cFromName		nVarChar(100)=( Select Cast(par_cValor As nVarChar(100)) From _Tablas.dbo.t_parametros Where par_ccodigo = 'MAILSENDERNAME'),
 @cTo			nVarChar(150)=( Select Cast(par_cValor As nVarChar(150)) From _Tablas.dbo.t_parametros Where par_ccodigo = 'MAILFALSASALARMAS'),
 @cSubject		nVarChar(100)='',
 @cMessage		nVarChar(4000)='',
 @cMessageMerge nVarChar(max)='',
 @cImagenes     nVarChar(max)='',
 @cMail			nVarChar(100)='',
 @cToOriginal	nVarChar(150)='',
 @cMailDealer	nVarChar(100)=''

Declare @translation nVarChar(Max) = ''
Execute [_Desktop].[dbo].[LocalizationGetLocale] @Name = N'Alcanzo Limite de Falsas Alarmas', @soloOutput=1, @translation = @translation OUTPUT
Set @cSubject = @translation 

Declare @nFin	int=1,
 @iParametro    Int=0,
 @iidCuenta		int=0,
 @iSituacion	int=0

Declare @dDiaHoy DateTime = GetDate()

Declare @cCuenta	Char(10)='',
 @cGrabo			Char(1)='S',
 @cFecha			Char(10)=(Select Convert(Char(10), @dDiaHoy,103)),
 @cHora				Char(10)=(Select Convert(Char(10), @dDiaHoy,108)),
 @cResolucion		Char(3)=''

Set @cFrom = Ltrim(Rtrim(@cFrom))
Set @cFromName = Ltrim(Rtrim(@cFromName))
Set @cTo = Ltrim(Rtrim(@cTo))

Declare @nEstado Numeric(1,0)=0

Declare cFalsas CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
	Select sta_iidCuenta,( Select est_iidcuenta From m_estado_cuenta_Cab A With (NOLOCK) 
							 Where est_iidCuenta=sta_iidCuenta And ( est_nEstado=2 OR 
						( est_nEstado=1 And @dDiaHoy BetWeen est_dfechadesde And est_dfechahasta )
						)) As iSituacion 
	From m_status 
	Inner Join m_falsas On fal_iidCuenta=sta_iidCuenta
	Where fal_nMargen > 0 And sta_ncontadorfa >= fal_nMargen And sta_nEnvioMailFA = 0
	
OPEN cFalsas
FETCH NEXT FROM cFalsas INTO @iidCuenta,@iSituacion
	WHILE @@FETCH_STATUS = 0
		Begin
			If @iSituacion Is Null	--No esta Deshabilitada o en Prueba
				Begin
					--Tengo que grabar Evento _LF : Supero Limite Falsas Alarmas
					Set @cResolucion =''
					Set @nEstado = 0
				    Set @iParametro = ( SELECT cod_nalerta From _Tablas.dbo.t_codigos_alarma With (NOLOCK) Where cod_ccodigo='_LF' )

					--Si es un Evento de NO GENERAR, NO se graba p_recepcion			
					If @iParametro < 2
						Begin	
							--Si NO Genera Alerta (0) lo grabo con estado 5
							If @iParametro = 0
								Set @nEstado = 5

							If @cGrabo = 'S'	
								Begin
									BEGIN TRY

									EXEC [dbo].[SGSP_pRecepcionINS]
											@rec_iidcuenta = @iidCuenta,
											@rec_calarma = '_LF',
											@rec_tfechahora  = @dDiaHoy,
											@rec_nestado  = @nEstado,
											@rec_idResolucion = @cResolucion,
											@rec_tFechaRecepcion = @dDiaHoy,
											@rec_nOrigen = 8,
											@iValor = @iParametro OUTPUT
									END TRY
									BEGIN CATCH
										Print 'EXEC [dbo].[SGSP_pRecepcionINS] Volvio con error'
										Set @iParametro=0
									END CATCH

									if @iParametro > 0
									Begin
										--Tengo que actualizar Status con ultima alarma y fecha
										UPDATE m_status Set sta_cultimaalarma = '_LF', sta_dfechautimaalarma = CONVERT(DateTime, CONVERT(Varchar(20), @dDiaHoy, 120),111) 
											Where sta_iidCuenta=@iidCuenta
									End
								End	
						End

					--Tengo que enviar aviso x mail a Supervisor
					If @iEnviaMail > 0
						Begin

							Set @cMail = @cTo 
							Set @cMailDealer = ( Select lin_cmail FROM _Tablas.dbo.t_lineas Inner Join m_cuentas On lin_ccodigo=cue_clinea Where cue_iid=@iidCuenta )	
							IF @cMailDealer Is Not Null And @cMailDealer <> ''
								Begin
									If @cMail <> ''
										Set @cMail = @cMail +';'+@cMailDealer +';'	
									Else
										Set @cMail = @cMailDealer +';'	
								End				
							Else 				
								Begin
									If @cMail <> ''
										Set @cMail = @cMail +';'
								End	
						
							Set @cCuenta	= ( SELECT cue_clinea+'-'+cue_ncuenta FROM m_cuentas Where cue_iid=@iidCuenta )	
							Set @cMessage = 'En cuenta '+@cCuenta 

							WHILE CHARINDEX(';',@cMail) > 0
							BEGIN
								Set @nFin = CHARINDEX(';',@cMail)	
								Set @cTo=SUBSTRING( @cMail, 1, @nFin-1 )
			
								Set @Query = 'Select '+CHAR(39)+@cTo+CHAR(39)+' As Email'
			
								If @cGrabo = 'S' And @iEnviaMail = 1		
									EXEC _Sistema.dbo.sp_SendMail @cFrom, @cTo, @cSubject, @cMessage	

								If @cGrabo = 'S' And @iEnviaMail = 2		
									Begin	
									    Set @cMessageMerge = ''
										EXEC SGSP_TextMerge	@iidCuenta,'','','_LF',@cFecha,@cHora,0, @cMessageMerge OUTPUT, @cImagenes OUTPUT
										If @cMessageMerge Is Null
											Set @cMessageMerge = @cMessage

										EXEC _Datos.dbo.SmartMail_ProgramCreate @cFromName, @cFrom, @cSubject, @cMessageMerge, @dDiaHoy, 1, @Query, 'MAIL', @cImagenes, 802, @iidCuenta
									End

								Set @cMail = SUBSTRING( @cMail, @nFin+1, 100-@nFin )
							End
	
							Set @cTo = Ltrim(Rtrim(@cToOriginal))

							--Tengo que marcar la cuenta para indicar el status de envio de Mail
							UPDATE [_Datos].[dbo].[m_status] Set sta_nEnvioMailFA=1 Where sta_iidcuenta=@iidCuenta
							--

						End
						--
				End

			FETCH NEXT FROM cFalsas INTO @iidCuenta,@iSituacion
		End

CLOSE cFalsas
DEALLOCATE cFalsas

GO
/****** Object:  StoredProcedure [dbo].[SGSP_ControlLogOutVigicontrol]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SGSP_ControlLogOutVigicontrol] As
--Controla el tiempo de logueo de los guardias de Vigicontrol
--Autor :Pablo O. Canónico
--Fecha :23/01/2024
SET NOCOUNT ON

-- Aviso que la tarea esta funcionando
Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'ControlLogOutVC', @Repetition = 10
--	
Declare @message nVarChar(Max) = '',
		@StartDateTimeText VarChar(max)=''

Declare @iMinutos Int = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='TIEMPODESLOGUEO' )		
If @iMinutos Is Null
Begin
	Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_ControlLogOutVigicontrol] Sin tiempo configurado. No controla!!!'
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	Set NoExec On
End

Declare @iUsuario Int=0,
		@idCuenta Int=0,
		@iValor Int=0,
		@vcid Int=0

Declare	@cObs nVarChar(Max) = '',
		@cPushToken VarChar(1024) = ''

DECLARE CursorCTLOVC CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
Select Distinct [vus_iusuario],[vus_idcuenta]
	From [_Datos].[dbo].[VigicontrolUserSessions]
  Where [vus_dlogout] Is Null
	And [vus_dlogin] > DateAdd(DAY,-5,Getdate())
	And DateAdd(MINUTE,@iMinutos,[vus_dlogin]) < Getdate()
	Order By [vus_iusuario],[vus_idcuenta]

OPEN CursorCTLOVC
FETCH NEXT FROM CursorCTLOVC INTO @iUsuario, @idCuenta
WHILE @@FETCH_STATUS = 0
	Begin
		Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | [SGSP_ControlLogOutVigicontrol] | Genero V97 para @idCuenta => '+Cast(@idCuenta As Varchar(10))+ ' con @iUsuario => '+Cast(@iUsuario As Varchar(10))
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

		Set @cObs = 'Control LogOut Vigicontrol'
		Execute [_Datos].[dbo].[SGSP_AlarmaGenerar] @idCta=@idCuenta, @cAlarma='V97',@cObs=@cObs, @iUsuario=@iUsuario, @iValor=@iValor OUTPUT

		If @iValor > 0
		Begin
			Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | [SGSP_ControlLogOutVigicontrol] | Busco PushToken'
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
			
			Select @cPushToken=[pushToken],@vcid=[Id]
				From [_Datos].[dbo].[SmartTrack] With (NOLOCK)
			Inner Join [_Datos].[dbo].[VigicontrolUserCurrentSession] ON [Id]=[vucs_vcid]
			Where [vucs_cueiid]=@idCuenta

			If @cPushToken != '' And @cPushToken Is Not Null
			Begin
				Insert Into [_Datos].[dbo].[p_push_queue] (
					[ppq_msg]
					,[ppq_estado]
					,[ppq_fechacreacion]
					,[ppq_idmessage]
					,[ppq_idcuenta])
				Values (
					'{ 
						"message":{
							"data": {
								"action": "LOGOUT",
								"content_available":"true"
									},
							"token":"' + @cPushToken + '"
							}
					}'
					/*
					'{ 
						"data": {
							"action": "ALARM_LOGOUT"
						},
						"notification" : {
							"content_available": true
						},
						"to":"'+@cPushToken+'"
					}'
					*/
					,0
					,GETDATE()
					,@vcid*(-1)
					,@idCuenta )
			End
			Else
			Begin
				Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | [SGSP_ControlLogOutVigicontrol] | NO hay PushToken configurado'
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
			End

			Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | [SGSP_ControlLogOutVigicontrol] | Execute [_Desktop].[dbo].[VigicontrolCreateUserSessions]'
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			Execute [_Desktop].[dbo].[VigicontrolCreateUserSessions]
		End 
		FETCH NEXT FROM CursorCTLOVC INTO @iUsuario, @idCuenta
	End

CLOSE CursorCTLOVC
DEALLOCATE CursorCTLOVC

Set NoExec Off
GO
