CREATE PROCEDURE [dbo].[SGSP_ControlTesteoVigicontrol] As
--Controla el test periodico enviado por los dispositivos que utilizan Vigicontrol
--Autor :Pablo O. Canónico
--Fecha :02/10/2017
--2019-09-02 : Se agrego control solamente sobre los VC logueados
--2019-09-02 : Se incluye el usuario del dispositivo al generar VFH
--2019-10-14 : Se decidio por BC tener una tolerancia de +1 minuto
SET NOCOUNT ON

-- Aviso que la tarea esta funcionando
Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'ControlTesteoVC', @Repetition = 5
--	

Declare @IMEI nVarChar(128)='',
		@Nombre nVarChar(256)='',
		@cObs nVarChar(Max) = ''
Declare @ID Int=0,
		@iValor Int=0,
		@EnFallo Int=0,
		@CuentaID Int=0,
		@UsuarioID Int=0

DECLARE CursorTSTVC CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
Select [IMEI],[Id],[CuentaID],IsNull([EnFalloDeTesteo],0) As EnFalloDeTesteo,[Nombre]
	From [dbo].[SmartTrack] With (NOLOCK)
Where [Config] Like '%"HBcontrol":true%' And IMEI <>''
	And ( Select Top 1 [sp_iid] From [dbo].[p_posicionesSP] With (NOLOCK) Where [sp_cIMEI]=[IMEI] And [sp_tfechahora] Between DATEADD( MINUTE,-[HBTime]-1,GetDate() ) And GetDate() Order By [sp_iid] Desc )  Is Null
	Order By [IMEI],[CuentaId]

OPEN CursorTSTVC
FETCH NEXT FROM CursorTSTVC INTO @IMEI, @ID, @CuentaID, @EnFallo, @Nombre
WHILE @@FETCH_STATUS = 0
	Begin
		Print 'Controlo que no este en falla [IMEI]='+@IMEI
		--1.Controlo que no este en falla
		IF @EnFallo=0
			Begin
				--2.Me fijo si esta logueado
				Print 'Me fijo si esta logueado [CuentaID]='+Cast(@CuentaID As Varchar(10)) + ' - [Id]='+Cast(@ID As Varchar(10))
				If (Select Top 1 [vucs_vcid] from [_Datos].[dbo].[VigicontrolUserCurrentSession] With (NOLOCK) Where [vucs_cueiid]=@CuentaID And [vucs_vcid]=@ID) > 0
				Begin
					Print 'Esta Logueado [IMEI]='+@IMEI
					Select @UsuarioID = IsNull([usu_iid],0) From [_Datos].[dbo].[VigicontrolUserCurrentSession] With (NOLOCK)
						Left Join [_Datos].[dbo].[m_usuarios] On [usu_idKey] = [vucs_usuidkey]
					Where [vucs_cueiid]=@CuentaID And [vucs_vcid]=@ID

					--3.Genero VFH 
					Set @cObs = Rtrim(@IMEI)+' - '+Rtrim(@Nombre)
					Execute [_Datos].[dbo].[SGSP_AlarmaGenerar] @CuentaID, 'VFH', 'SoftGuard' , @cObs, '', @UsuarioID, @iValor OUTPUT
					
					--4.Actualizo Status
					Update [dbo].[SmartTrack] With (UPDLOCK) Set [EnFalloDeTesteo] = 1, [EnFalloDeTesteoDesde] = GetDate() Where [Id]=@ID
				End
				Else
					Print 'No esta Logueado [IMEI]='+@IMEI
			End
		Else
			Print 'Ya esta en FallaDeTesteoVC [IMEI]='+@IMEI

		FETCH NEXT FROM CursorTSTVC INTO @IMEI, @ID, @CuentaID, @EnFallo, @Nombre
	End

CLOSE CursorTSTVC
DEALLOCATE CursorTSTVC

GO
/****** Object:  StoredProcedure [dbo].[SGSP_ControlTSTConexion]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SGSP_ControlTSTConexion]
AS
--Control de test por conexion
--Autor : Pablo O. Canónico
--Fecha : 12/11/2019

Set NoCount ON
BEGIN TRY
	Declare @message nVarChar(Max) = '',
			@StartDateTimeText VarChar(max) = ''

	Declare @DiaHoy DateTime=GetDate()
	Declare @iProceso Int = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='PROCESATSTCONN' )
	--Indica si se realiza el control de Testeo. 0:No / 1:Si / 2:Si, en cuentas que no esten en FallaTST

	If @iProceso > 0
		Begin	
			-- Aviso que la tarea esta funcionando
			Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'ControlTSTConexion', @Repetition = 10
			--	
	
			Declare TSTConexion CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
			With ControlOrigen As (
			Select [txc_idKey],[txc_idCuenta],[txc_cAlarmaAGenerar],[txc_cAlarmaAutoprocesa] ,[txc_tFechaUltimaRX],
				tLimite=DATEADD( MINUTE,[txc_iMinutos],[txc_tFechaUltimaRX] ) ,
				( Select est_iidcuenta From m_estado_cuenta_Cab A With (NOLOCK) 
					 Where est_iidCuenta=[txc_idCuenta] 
					 And ( est_nEstado=2 OR ( est_nEstado=1 And @DiaHoy BetWeen est_dfechadesde And est_dfechahasta ) )
				) As iDesactivada
			From [m_TSTConexion] With (NOLOCK)
			Left Outer Join m_status On sta_iidCuenta=[txc_idCuenta]
			Where [txc_iMinutos]>0 And [txc_cAlarmaAGenerar] != ''
				And (CASE WHEN @iProceso = 2 Then [txc_tEnFalloDeDesde] Else Null END) Is Null
									)
			Select txc_idKey,txc_idCuenta,txc_cAlarmaAGenerar,txc_cAlarmaAutoprocesa--,tLimite,iDesactivada
				From ControlOrigen
				Where tLimite <= @DiaHoy
				And iDesactivada Is Null
			Order By tLimite

			Declare @idKey Int = 0,
					@idCuenta Int = 0,
					@iValor Int=0	

			Declare @cAlarmaAGenerar Char(3) = '',
					@cAlarmaAutoprocesa VarChar(200) = ''

			Declare @FechaUltimaRX DateTime
		
			OPEN TSTConexion
			FETCH NEXT FROM TSTConexion INTO @idKey,@idCuenta,@cAlarmaAGenerar,@cAlarmaAutoprocesa
			WHILE @@FETCH_STATUS = 0
			BEGIN
				Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | [SGSP_ControlTSTConexion] | IdCuenta => '+ Rtrim(Cast(@idCuenta As Varchar(10)))+' | Alarma a Generar => '+ @cAlarmaAGenerar+' | AutoProcesa => '+ @cAlarmaAutoprocesa
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

				Execute [dbo].[SGSP_AlarmaGenerar] @idCta=@idCuenta, @cAlarma=@cAlarmaAGenerar, @cQuien ='SoftGuard', @iValor=@iValor OUTPUT

				Set @FechaUltimaRX = GetDate()

				UPDATE [m_TSTConexion] Set [txc_tFechaUltimaRX] = @FechaUltimaRX Where [txc_idKey]=@idKey

				--Tengo q actualizar desde cuando esta en Fallo pero solo si la fecha esta null
				UPDATE [m_TSTConexion] Set [txc_tEnFalloDeDesde] = @FechaUltimaRX Where [txc_idKey]=@idKey And [txc_tEnFalloDeDesde] Is Null

				--Si se configuro @cAlarmaAutoprocesa entonces hay que insertar en [EventosEnFalloTesteo]
				If @cAlarmaAutoprocesa <> ''
				Begin
					Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
					Set @message = 'Start DateTime : %s | [SGSP_ControlTSTConexion] | Grabacion de EventosEnFalloTesteo'
					RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

					Set @cAlarmaAutoprocesa = 'C|,'+@cAlarmaAutoprocesa
					Execute [dbo].[SGSP_Fill_EventosEnFalloTesteo]	@idRecNoRes=@iValor, @idCuenta=@idCuenta, @tEventoFechaHora=@DiaHoy, @cAlarmaAutoprocesa=@cAlarmaAutoprocesa
				End

				FETCH NEXT FROM TSTConexion INTO @idKey,@idCuenta,@cAlarmaAGenerar,@cAlarmaAutoprocesa
			End

			CLOSE TSTConexion
			DEALLOCATE TSTConexion
		End
	Else	-- Aviso que la tarea no cumple las condiciones para funcionar
		Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'ControlTSTConexion', @Repetition = 10, @Date = null, @Status = 0	

Set NoExec Off
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
END CATCH

GO
/****** Object:  StoredProcedure [dbo].[SGSP_CreoETDepurado]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SGSP_CreoETDepurado]
	@cCierre [char](6), @nError [int] = 0 OUTPUT
As
--Crea el historico de EventosTimeLine
--Autor : Pablo O. Canónico
--Fecha : 14/09/2017
Set NoCount ON
Declare @cSQL nVarChar(Max)

IF OBJECT_ID('EventosTimeLine'+@cCierre) Is NOT Null
   Set @nError = -5
Else
Begin
	BEGIN TRY
	  Set @nError = 0
	  Set @cSQL = 'CREATE TABLE [dbo].[EventosTimeLine' +  @cCierre  +  '] (
			[etl_idKey] [bigint] NULL ,
			[etl_iRecID] [int] NULL,
			[etl_iCuenta] [int] NULL,
			[etl_tFechaHora] [datetime] NULL,
			[etl_cAccion] [varchar](100) NULL,
			[etl_cObservacion] [varchar](MAX) NULL,
			[etl_cOwner] [varchar](MAX) NULL,
			[etl_iOperador] [int] NULL,
			[etl_iAccionCode] [int] NULL,
		) ON [PRIMARY] TEXTIMAGE_ON [PRIMARY] ' 
	  Exec (@cSQL )
	  Set @nError = @@Error
	  IF @nError = 0	
		Begin
			Declare @cTableName Char(21) = 'EventosTimeLine' +  @cCierre 
			Print @cTableName
			
			Declare @cIndxName VarChar(100) = 'PK_'+Rtrim(@cTableName)
			Set @cSQL = 'CREATE UNIQUE CLUSTERED INDEX   [' + @cIndxName+']  ON [dbo].[' + @cTableName + '] ([etl_idKey])'
			Print @cSQL
			Exec (@cSQL )
			
			Set @cIndxName = 'NC_'+Rtrim(@cTableName)+'FechaHora'
			Set @cSQL = 'CREATE NONCLUSTERED INDEX  [' + @cIndxName+']  ON [dbo].[' + @cTableName + '] ([etl_tFechaHora]) INCLUDE ([etl_idKey])'
			Print @cSQL
			Exec (@cSQL )

			Set @cIndxName = 'NC_'+Rtrim(@cTableName)+'iRecID'
			Set @cSQL = 'CREATE NONCLUSTERED INDEX  [' + @cIndxName+']  ON [dbo].[' + @cTableName + '] ([etl_iRecID]) INCLUDE ([etl_idKey], [etl_iCuenta], [etl_tFechaHora], [etl_cAccion], [etl_cObservacion], [etl_cOwner], [etl_iOperador], [etl_iAccionCode])'
			Print @cSQL
			Exec (@cSQL )

			Declare @cname Varchar(512), @cnombres Varchar(1024)
			Set @cNombres = ''

			Declare c_users CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY For 
				Select name From sysusers Where ( Left(Name,2) = 'SG' Or Left(Name,9) = 'SoftGuard' ) And Left(Name,9) <> 'SGSERVER\'	

			Open c_users
			Fetch Next From c_users Into @cname
			While @@FETCH_STATUS = 0
			Begin
				Set @cNombres = @cNombres + Rtrim(@cName) + ','

				Fetch Next From c_users Into @cname
			End
			Close c_users
			Deallocate c_users

			If Len(@cNombres) > 0
				Set @cNombres = Left(@cNombres,Len(@cNombres)-1)
			Else
				Set @cnombres = '[SoftGuard],[SGCSAccess]' --,[SGWebAccess],[SGAgentAccess],[SGDesktopAccess]'

			Set @cSQL = 'GRANT  REFERENCES ,  SELECT ,  UPDATE ,  INSERT ,  DELETE  ON  [dbo].[' +  @cTableName + '] TO ' + @cNombres
			Print @cSQL
			Exec (@cSQL )
		End
	END TRY

	BEGIN CATCH
		PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
		PRINT 'Error Message : ' + ERROR_MESSAGE();
		PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
		PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
		PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
		PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
		Set @nError = -9
	END CATCH
End


