CREATE PROCEDURE [dbo].[SGSP_DepuracionMensual] AS
--Mueve los registros de p_recepcion a Historicos y que NO fueron depurados por el proceso diario
--Refactoring de SP_MueveAHistoriaMensual
--Autor :Pablo O. Canónico
--Fecha :07/12/2016
--05-11-2018 : Se modifico para loopear y no traer/depurar millones de registros
SET NOCOUNT ON
Declare @nMeses numeric(2)
Set @nMeses = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='MESESDEPURACION' )
If @nMeses > 0
Begin
	-- Aviso que la tarea esta funcionando	60min * 24hs *32 dias = 46080
	Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'MueveAHistoriaMensual', @Repetition = 46080
	--	
	DBCC TRACEON (1224)

	Declare @cCierre Char(6) = '',
		   @cCierreHasta Char(8) = '',
		   @cDia Char(8) = '',
		   @cDesde Char(8) = '',
		   @cHasta Char(8) = ''
   
	Declare @cSQL nVarChar(Max) = '',
   		   @message nVarChar(Max) = '',
		   @StartDateTimeText VarChar(max) = ''

	Declare @nError Int = 0,
		   @nRows Int = 0,
		   @iMax Int = 0,
		   @iLoop Int = 0,
		   @iDelLoop Int = 0, 
		   @iTop Int = 30000

	Declare @dFecha Datetime = Getdate()

	--1.Busco el dia y mes a depurar
	Set @dFecha = getdate()
	Set @cCierreHasta = CONVERT(CHAR(8), DateAdd(Month,-@nMeses,@dFecha), 112)

	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --1.Busco el dia y mes a depurar-- | @nMeses => '+ Cast(@nMeses As varchar(10)) +' | @cCierreHasta => '+ @cCierreHasta
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	Declare TmpCursor CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY For
		Select Distinct Left(CONVERT(CHARACTER, rec_tfechahora, 112),6) As Cierre
		From [_Datos].[dbo].[p_recepcion]
		Where  rec_tfechahora<@cCierreHasta 
		Order By 1

	Open TmpCursor
	FETCH NEXT FROM TmpCursor INTO @cCierre
	WHILE @@FETCH_STATUS = 0
		Begin
			--2.Creo los Historicos Necesarios--
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | --2.Creo los Historicos Necesarios-- | SP_CreoHistoria '+ @cCierre
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			IF OBJECT_ID('p_recepcion'+@cCierre) Is Null
				Execute @nError = SP_CreoHistoria @cCierre

			--3.Si se creo nuevo o ya existia es lo mismo hago MERGE
			--3.1.Armo desde/hasta
			Set @dFecha = @cCierre+'01'
			Set @cDesde = CONVERT(Char(8), DATEADD(m, DATEDIFF(m,0,@dFecha), 0) ,112) 
			Set @cHasta = CONVERT(Char(8), DATEADD(m, 1, DATEADD(m, DATEDIFF(m,0,@dFecha), 0)) ,112) 
			If @cHasta > @cCierreHasta
				Set @cHasta = @cCierreHasta

			--4.Depuracion--
			Set @iMax=0
			Select @iMax = Count(rec_iid) From [dbo].[p_recepcion] With (NOLOCK) Where rec_nestado > 2 And rec_tfechahora >= @cDesde  And rec_tfechahora < @cHasta
			If @iMax Between 1 And 29999
				Set @iMax = 30000

			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | --4.Depuracion-- | Total de Registros => '+ Cast(@iMax As varchar(10))+' | Loops Necesarios Reales => '+ Cast(@iMax / @iTop As varchar(10))
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			Set @iMax = @iMax / @iTop

			Set @iLoop = 0
			WHILE @iLoop <= @iMax And @iMax > 0
				BEGIN
					Set @iLoop = @iLoop + 1
					Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
					Set @message = 'Start DateTime : %s | Loop => '+ Cast(@iLoop As varchar(10)) +' / '+ Cast(@iMax As varchar(10))
					RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

					Set @cSQL = 'MERGE INTO [dbo].[p_recepcion' +  @cCierre  +  '] AS TGT
					USING ( Select Top ('+Rtrim(Cast(@iTop As Varchar(10)))+') *, (Case When rec_nOrigen=1 Then ''%TI : Evento de Control%'' When rec_nOrigen=2 And rec_iPuerto < 100 Then ''%PG :%'' When rec_nOrigen=2 Then ''%IR :%'' When rec_nOrigen=3 Then ''%MAN : Evento Generado Manualmente%'' When rec_nOrigen=6 And rec_iPuerto < 0 Then ''%TR : Terminal Remota%'' 
						When rec_nOrigen=6 Then ''%SMS :% '' When rec_nOrigen=7 Then ''%SCH : Evento Programado%'' When rec_nOrigen=8 Then ''%JOB : Tarea Programada%'' Else ''%SG : Evento Interno%'' End ) +Space(1)+ Ltrim( (Case When rec_iPuerto<=0 Then '''' Else Cast(rec_iPuerto As Char(5)) End ) ) As _Origen,
						--Cast(rec_iPuerto As VarChar(6)) As _Puerto
						Case When rec_cAlarma = ''_DI'' Then rec_cContenido Else Cast(rec_iPuerto As VarChar(6)) End As _Puerto
						From [dbo].[p_recepcion] With (NOLOCK)
						Where  rec_nestado > 2 And
						rec_tfechahora >= '+ CHAR(39) +  @cDesde + CHAR(39) +' And rec_tfechahora <= '+ CHAR(39) + Rtrim(@cHasta) + CHAR(39)+'
					) AS SRC ON TGT.rec_iid = SRC.rec_iid'
					--4.1.Actualizo/Inserto con Merge los registros que le corresponden 	
					Set @cSQL = @cSQL +'
					WHEN MATCHED THEN
						UPDATE SET
						TGT.rec_nestado=SRC.rec_nestado,
						TGT.rec_cContenido=SRC.rec_cContenido,
						TGT.rec_tFechaProceso=SRC.rec_tFechaProceso,
						TGT.rec_ioperador=SRC.rec_ioperador,
						TGT.rec_cObservaciones=SRC.rec_cObservaciones,
						TGT.rec_cTerminal=SRC.rec_cTerminal,
						TGT.rec_idResolucion=SRC.rec_idResolucion,
						TGT.rec_cCategorizacion=SRC.rec_cCategorizacion,
						TGT.rec_iNYR=SRC.rec_iNYR,
						TGT.rec_iTE=SRC.rec_iTE,
						TGT.rec_tFechaRecepcion=SRC.rec_tFechaRecepcion,
						TGT.rec_iMinutosEspera=SRC.rec_iMinutosEspera,
						TGT.rec_iPrioridad=SRC.rec_iPrioridad,
						TGT.usuario_iCodigo=SRC.rec_iusuario,
						TGT.zonas_cCodigo=SRC.rec_cZona,
						TGT._Origen=SRC._Origen,
						TGT._Puerto=SRC._Puerto
					
					WHEN NOT MATCHED THEN 
						INSERT ([rec_iid], [rec_iidcuenta], [rec_calarma], [rec_czona], [rec_iusuario], [rec_tfechahora], [rec_nestado], [rec_cContenido], [rec_tFechaProceso], [rec_ioperador], [rec_cObservaciones], [rec_cTerminal], [rec_idResolucion], [rec_idReceptor], [rec_cCategorizacion], [rec_iNYR], [rec_iTE], [rec_tFechaRecepcion], [rec_nOrigen], [rec_idMap], [rec_idFwd], [rec_iMinutosEspera], [rec_iPuerto], [rec_idLoc], [rec_iPrioridad], [usuario_iCodigo], [usuario_cNombre], [zonas_cCodigo], [zonas_cDescripcion], [_Origen], [_Puerto] )
						VALUES(SRC.rec_iid,SRC.rec_iidcuenta,SRC.rec_calarma,SRC.rec_czona,SRC.rec_iusuario,SRC.rec_tfechahora,SRC.rec_nestado,SRC.rec_cContenido,SRC.rec_tFechaProceso,SRC.rec_ioperador,SRC.rec_cObservaciones,SRC.rec_cTerminal,SRC.rec_idResolucion,SRC.rec_idReceptor,SRC.rec_cCategorizacion,SRC.rec_iNYR,SRC.rec_iTE,SRC.rec_tFechaRecepcion,SRC.rec_nOrigen,SRC.rec_idMap,SRC.rec_idFwd,SRC.rec_iMinutosEspera,SRC.rec_iPuerto,SRC.rec_idLoc,SRC.rec_iPrioridad,SRC.rec_iusuario,'''',SRC.rec_cZona,'''',SRC._Origen,SRC._Puerto);
					'

					Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
					Set @message = 'Start DateTime : %s | --4.Depuracion-- | cSQL => '+ Replace(@cSQL,'%','')
					RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

					Exec (@cSQL )

   					Select @nError = @@ERROR,@nRows = @@ROWCOUNT;

					If @nError = 0	
	 					Begin
							IF @nRows = 0
								Print 'Warning: No rows were merged'

	   						--5.Saco los registros copiados
							Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | --5.Sacos los registros copiados--'
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

							Set @iDelLoop = 0
							WHILE @iDelLoop < 15
								BEGIN
									Set @iDelLoop = @iDelLoop + 1
									Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
									Set @message = 'Start DateTime : %s | Delete Loop => '+ Cast(@iDelLoop As varchar(10)) +' / 15'
									RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

									Set @cSQL = 'Delete Top (2000) From [dbo].[p_recepcion]  Where rec_nestado > 2 And rec_tfechahora >= '+CHAR(39)+@cDesde+CHAR(39)+ ' And rec_tfechahora < '+CHAR(39)+@cHasta+CHAR(39)

									Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
									Set @message = 'Start DateTime : %s | --5.Sacos los registros copiados-- | cSQL => '+ @cSQL
									RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

									Exec (@cSQL )

									IF @@ROWCOUNT = 0
										Set @iDelLoop = 16 
								END
						End
				END

		FETCH NEXT FROM  TmpCursor INTO @cCierre
		End

    Close TmpCursor
    DEALLOCATE TmpCursor
End
Else	-- Aviso que la tarea no cumple las condiciones para funcionar
	Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'MueveAHistoriaMensual', @Repetition = 46080, @Date = null, @Status = 0

					


GO
/****** Object:  StoredProcedure [dbo].[SGSP_DepuracionMensualPost]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

Create PROCEDURE [dbo].[SGSP_DepuracionMensualPost] AS
--Elimina registros de tablas inexistentes y crea depurados a futuro
--Autor :Pablo O. Canónico
--Fecha :20/02/2019

SET NOCOUNT ON
-- Aviso que la tarea esta funcionando	60min * 24hs *32 dias = 46080
Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'DepuracionMensualPost', @Repetition = 46080
--	
DBCC TRACEON (1224)

Declare @cSQL nVarChar(Max) = '',
   		@message nVarChar(Max) = '',
		@StartDateTimeText VarChar(max) = ''

Declare @nError Int = 0,
	   @iMax Int = 0,
	   @iLoop Int = 0,
	   @DeleteTop int = 10000,
	   @iTop Int = 30000

--Elimino registros de tablas depuradas inexistentes
BEGIN TRY
	--Delete  From  [_Datos].[dbo].[_RegistrosAEliminar]
	--Where [rae_cTabla] NOT IN ( Select table_name From information_schema.columns )

	Set @iLoop = 0
	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --Elimino registros de tablas depuradas inexistentes--'
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
	
	Select @iMax = Count(*) From [_RegistrosAEliminar] 
		Where [rae_cTabla] NOT IN ( Select table_name From information_schema.columns Group By table_name )

	WHILE @iLoop < @iTop And @iMax > 0
	Begin
		Set @iLoop = @iLoop + 1
		Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | --Elimino registros de tablas depuradas inexistentes => '+ Cast(@iMax As varchar(10))+' | Loop => '+ Cast(@iLoop As varchar(10)) +' / '+ Cast(@iTop As varchar(10))
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

		Delete Top(@DeleteTop) From [_RegistrosAEliminar]
			Where [rae_cTabla] NOT IN ( Select table_name From information_schema.columns Group By table_name )

		If @@ROWCOUNT = 0 Or @@ROWCOUNT < @DeleteTop
			BREAK;
	End
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
END CATCH

--Genero archivos de depuracion a futuro
BEGIN TRY
	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --Genero archivos de depuracion a futuro--'
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	Declare @cCierre Char(6)
	Declare @dFecha Datetime
	Set @dFecha = Getdate()
	Declare @LoopCount Int=0  
	WHILE @LoopCount <= 2
	BEGIN
		Set @cCierre = CONVERT(CHAR(6), DateAdd(Month,@LoopCount,@dFecha), 112)

		Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | --Genero archivos de depuracion a futuro-- | OBJECT_ID => '+ 'p_recepcion'+@cCierre+' | Loop => '+ Cast(@LoopCount As varchar(10))
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
		IF OBJECT_ID('p_recepcion'+@cCierre) Is Null
			Execute @nError = SP_CreoHistoria @cCierre

		Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | --Genero archivos de depuracion a futuro-- | OBJECT_ID => '+ 'EventosTimeLine'+@cCierre+' | Loop => '+ Cast(@LoopCount As varchar(10))
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
		IF OBJECT_ID('EventosTimeLine'+@cCierre) Is Null
			Execute @nError = SGSP_CreoETDepurado @cCierre

		Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | --Genero archivos de depuracion a futuro-- | OBJECT_ID => '+ 'p_recepcion_proceso'+@cCierre+' | Loop => '+ Cast(@LoopCount As varchar(10))
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
		IF OBJECT_ID('p_recepcion_proceso'+@cCierre) Is Null
			Execute @nError = SGSP_CreoPRPDepurado @cCierre

		Set @LoopCount=@LoopCount + 1
	End
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
END CATCH

GO
/****** Object:  StoredProcedure [dbo].[SGSP_DepuracionRXLog]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SGSP_DepuracionRXLog] As
--Depura la tabla [p_RXLog] dejando en linea los mismos ID que hay en [p_recepcion]
--Autor :Pablo O. Canónico
--Fecha :20/03/2013
--Modificacion 08/06/2015 Se cambio a Delete Output
--Modificacion 29/01/2016 Se depura por lotes para bases de datos con mucho trafico
--Modificacion 07/05/2018 Se depura por registros inexistentes en pRecepcion
--Modificacion 07/12/2018 Se bajo a 2500 la cantidad de registros para que sean mas loops pero con menos cantidad
SET NOCOUNT ON

-- Aviso que la tarea esta funcionando	60min * 25hs  = 1500
Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'DepuracionRXLog', @Repetition = 1500
--	

BEGIN TRY
	DBCC TRACEON (1224)

	Declare @nError Int = 0,
			@iMax Int = 0,
			@iTop Int = 2500,
			@iLoop Int = 0

	Declare @message nVarChar(Max) = '',
			@StartDateTimeText nVarChar(max)=''

	Select @iMax = Count([rxl_iId])  FROM [dbo].[p_RXLog]
		Where [rxl_iRecId] Not In ( Select rec_iid From p_recepcion )

	If @iMax < @iTop
		Set @iMax = @iTop

	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | Total de Registros => ' + Cast(@iMax As varchar(10))+' | Loops Necesarios Reales => '+ Cast(@iMax / @iTop As varchar(10))
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	Print @iMax / @iTop
	If @iMax / @iTop > 100
		Set @iMax = 100
	Else
		Set @iMax = @iMax / @iTop

	WHILE @iLoop <= @iMax
	BEGIN
	 Set @iLoop = @iLoop + 1
	 
	 Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	 Set @message = 'Start DateTime : %s | Loop => '+ Cast(@iLoop As varchar(10)) +' / '+ Cast(@iMax As varchar(10))
	 RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	 ;WITH 
	 cteDEP ([rxl_iRecId])
	 AS
	 (
		Select [rxl_iRecId] From [dbo].[p_RXLog] Where [rxl_iRecId] Not In ( Select rec_iid From p_recepcion )
	 )
	  DELETE TOP (@iTop) FROM [dbo].[p_RXLog]
		OUTPUT
		  Deleted.[rxl_iId],
		  Deleted.[rxl_iRecId], 
		  Deleted.[rxl_cLog],
		  Deleted.[rxl_cDll],
  		  Deleted.[rxl_cEvento],
		  Deleted.[rxl_cLineCard] 
		  INTO [dbo].[p_RXLogDep]
  		WHERE [rxl_iRecId] In ( Select [rxl_iRecId] From cteDEP )

	  IF @@ROWCOUNT = 0 BREAK;
	END;

	Select @nError = @@Error
    If @nError > 0	
		Raiserror('%s',16,1,'Depuracion RxLog')

END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
END CATCH


GO
/****** Object:  StoredProcedure [dbo].[SGSP_DepuracionTablasAuxiliares]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SGSP_DepuracionTablasAuxiliares] AS
--Depura las tablas [p_Recepcion_D] / [EventosPendientes] / [EventosTimeLine] / [p_recepcion_proceso] / [p_SMSqueue] / [p_nivelsenal] / [SmartMail_Program] / [p_push_queue]  / [Message]
--Autor :Pablo O. Canónico
--Fecha :07/12/2016
--30-08-2017 Depura las tablas [p_PosicionesGPS] / [p_posicionesSP]
--26-02-2018 Depura [p_recepcion_proceso]
--20-03-2018 Depura [Message]
--18-07-2019 Modificacion para depurados en _History
--05-03-2021 Depura [FrameworkAudit]
--05-05-2022 Depuracion [EventosTimeLine] y [p_recepcion_proceso] No depurados oportunamente 
SET NOCOUNT ON
-- Aviso que la tarea esta funcionando	60min * 25hs * 7d = 10500
Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'DepuracionTablasAuxiliares', @Repetition = 10500

BEGIN TRY
	DBCC TRACEON (1224)

	Declare	@cSQL nVarChar(MAX) = '',
			@ParmDefinition nvarchar(500) = '',
   		    @message nVarChar(Max) = '',
		    @StartDateTimeText VarChar(max) = ''

	Declare @iMax Int = 0,
		    @iLoop Int = 0,
			@nError Int = 0

	/*			
	--1.Elimino p_Recepcion_D ya depurados--
	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --1.Elimino p_Recepcion_D ya depurados--'
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
	  
	Select @iMax = Max(rec_iRecId)  From [dbo].[p_Recepcion_D] Where rec_iRecId Not In ( Select rec_iid From p_recepcion )
	If @iMax Between 1 And 999
		Set @iMax = 1000

	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --1.Elimino p_Recepcion_D ya depurados-- | Total de Registros => '+ Cast(@iMax As varchar(10))+' | Loops Necesarios Reales => '+ Cast(@iMax / 1000 As varchar(10))
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	Set @iMax = @iMax / 1000

	Set @iLoop = 0
	WHILE @iLoop <= @iMax And @iMax > 0 And @iLoop <= 500
		BEGIN
			Set @iLoop = @iLoop + 1
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | Maximo 500 | Loop => '+ Cast(@iLoop As varchar(10)) +' / '+ Cast(@iMax As varchar(10))
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
			
			Set @cSQL = 'Delete Top (1000) From [dbo].[p_Recepcion_D] Where rec_iRecId Not In ( Select rec_iid From p_recepcion )'
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | cSQL => '+ @cSQL
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			Exec (@cSQL )

	  		IF @@ROWCOUNT = 0 BREAK;
		END;
	*/

	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --------------------------------------------------------------- | '
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT


	--2.Elimino EventosPendientes que no fueron borrados por el trigger--
	Set @cSQL = 'Delete From [dbo].[EventosPendientes] Where [rec_iid] Not In ( Select rec_iid From [dbo].[p_recepcion] ) '
	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --2.Elimino EventosPendientes que no fueron borrados por el trigger-- | cSQL => '+ @cSQL
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	Exec (@cSQL )
			
	--3.Depuracion [EventosTimeLine]--
	Delete Top (1000) From [dbo].[EventosTimeLine] Where [etl_iRecID] = 0
	Delete Top (1000) From [dbo].[EventosTimeLine] Where [etl_iRecID] = Null

	Declare @nMeses numeric(2) = IsNull(( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='MESESDEPURACION' ),2)
	Declare @cHasta Char(8) = '',
			@cDesde Char(8) = '',
			@cCierre Char(6) = '',
			@cCierreHasta Char(8) = ''

	Declare @dFecha Datetime = Getdate()
	Set @cCierreHasta = CONVERT(CHAR(8), DateAdd(Month,-@nMeses,@dFecha), 112)
	Set @cCierre = @cCierreHasta

	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --------------------------------------------------------------- | '
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

    --3.1.Creo los Historicos Necesarios--
	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --3.Depuracion [EventosTimeLine]-- '
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
	Set @message = 'Start DateTime : %s | --3.1.Creo los Historicos Necesarios-- | SGSP_CreoETDepurado '+ @cCierre
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	IF OBJECT_ID('EventosTimeLine'+@cCierre) Is Null
		Execute @nError = SGSP_CreoETDepurado @cCierre
	
	/*
	Execute @nError = [_History].[dbo].[SGSP_CreoETDepurado] @cCierre, @cDebug='N'

	If @nError = 0	
		Execute @nError = [SGSP_CreoViewETDepurado] @cCierre, @cDebug='N'
    */

	If @nError = 0	
		Begin
			Set @dFecha = @cCierre+'01'
			Set @cDesde = CONVERT(Char(8), DATEADD(m, DATEDIFF(m,0,@dFecha), 0) ,112) 
			Set @cHasta = CONVERT(Char(8), DATEADD(m, 1, DATEADD(m, DATEDIFF(m,0,@dFecha), 0)) ,112) 
			If @cHasta > @cCierreHasta
				Set @cHasta = @cCierreHasta

			Select @iMax = Count([etl_idKey])  From [dbo].[EventosTimeLine] Where [etl_tFechaHora] >= @cDesde And  [etl_tFechaHora] < @cHasta
			If @iMax Between 1 And 999
				Set @iMax = 1000

			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | --3.1.Depuracion [EventosTimeLine]-- | @cDesde => '+ @cDesde +' | @cHasta => '+ @cHasta +' | Total de Registros => '+ Cast(@iMax As varchar(10))+' | Loops Necesarios Reales => '+ Cast(@iMax / 1000 As varchar(10))
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			Set @iMax = @iMax / 1000

			Set @iLoop = 0
			WHILE @iLoop <= @iMax And @iMax > 0 And @iLoop <= 500
				BEGIN
					Set @iLoop = @iLoop + 1
					Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
					Set @message = 'Start DateTime : %s | Maximo 500 | Loop => '+ Cast(@iLoop As varchar(10)) +' / '+ Cast(@iMax As varchar(10))
					RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
			
					Set @cSQL = 'Delete Top (1000) From [dbo].[EventosTimeLine] OUTPUT deleted.* Into [dbo].[EventosTimeLine'+@cCierre+'] Where [etl_tFechaHora] >= '+CHAR(39)+@cDesde+CHAR(39)+' And [etl_tFechaHora] < '+CHAR(39)+@cHasta+CHAR(39)
					
					Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
					Set @message = 'Start DateTime : %s | cSQL => '+ @cSQL
					RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

					Set @ParmDefinition = N'@cCierre Char(6), @cDesde Char(8), @cHasta Char(8)'

					Execute sp_executesql @cSQL, @ParmDefinition, @cCierre = @cCierre, @cDesde=@cDesde, @cHasta=@cHasta

	  				IF @@ROWCOUNT = 0 BREAK;
				End;
		End

	--3.2.Depuracion [EventosTimeLine] Antiguos No depurados--
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --3.2.Depuracion [EventosTimeLine] Antiguos No depurados-- '
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	Declare @cAAAAMM Char(6) = ''
	Declare @periodo_inicio Char(8) = ''
	Declare @periodo_fin Date

	Declare cDel CURSOR LOCAL STATIC READ_ONLY FORWARD_ONLY
	For	Select Distinct Left(CONVERT(CHARACTER, [etl_tFechaHora], 112),6) From [dbo].[EventosTimeLine] Where [etl_tFechaHora] < @cDesde Order By 1

    Open cDel
    Fetch Next From cDel Into @cAAAAMM
    While @@FETCH_STATUS = 0
	Begin
			Set @periodo_inicio = @cAAAAMM + '01'
			Set @periodo_fin = convert(varchar(12),EOMONTH(@periodo_inicio),112) 	
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | --3.2.Depuracion [EventosTimeLine] Antiguos No depurados-- | @cAAAAMM : '+@cAAAAMM + ' | @periodo_inicio  : ' + @periodo_inicio + ' | @periodo_fin  : '+Cast(@periodo_fin As Varchar(10))
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT	
			
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | --3.2.Creo los Historicos Necesarios-- | SGSP_CreoETDepurado '+ @cAAAAMM
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			Set @nError=0
			IF OBJECT_ID('EventosTimeLine'+@cAAAAMM) Is Null
				Execute @nError = SGSP_CreoETDepurado @cAAAAMM			
			
			IF @nError = 0	
			Begin
				Set @cSQL = 'Delete From [dbo].[EventosTimeLine] Where [etl_idKey] In ( Select [etl_idKey] From [dbo].[EventosTimeLine'+@cAAAAMM+'] ) '
				Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | --3.2.0.Elimino EventosTimeLine que ya estan depurados-- | cSQL => '+ @cSQL
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

				Exec (@cSQL )

				Select @iMax = Count([etl_idKey])  From [dbo].[EventosTimeLine] Where [etl_tFechaHora] < @periodo_fin
				If @iMax Between 1 And 999
					Set @iMax = 1000
				
				Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | --3.2.1.Depuracion [EventosTimeLine] Antiguos No depurados-- | @cDesde => '+ @periodo_inicio +' | @cHasta => '+ CONVERT(varchar, @periodo_fin,120) +' | Total de Registros => '+ Cast(@iMax As varchar(10))+' | Loops Necesarios Reales => '+ Cast(@iMax / 1000 As varchar(10))
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
				
				Set @iMax = @iMax / 1000

				Set @iLoop = 0
				WHILE @iLoop <= @iMax And @iMax > 0 And @iLoop <= 500
					BEGIN
						Set @iLoop = @iLoop + 1
						Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
						Set @message = 'Start DateTime : %s | Maximo 500 | Loop => '+ Cast(@iLoop As varchar(10)) +' / '+ Cast(@iMax As varchar(10))
						RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
				
						Set @cSQL = 'Delete Top (1000) From [dbo].[EventosTimeLine] OUTPUT deleted.* Into [dbo].[EventosTimeLine'+@cAAAAMM+'] Where [etl_tFechaHora] >= '+CHAR(39)+@periodo_inicio+CHAR(39)+' And [etl_tFechaHora] < '+CHAR(39)+CONVERT(varchar, @periodo_fin,120)+CHAR(39)
						
						Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
						Set @message = 'Start DateTime : %s | cSQL => '+ @cSQL
						RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

						Set @ParmDefinition = N'@cCierre Char(6), @cDesde Char(8), @cHasta Char(8)'

						Execute sp_executesql @cSQL, @ParmDefinition, @cCierre = @cCierre, @cDesde=@cDesde, @cHasta=@cHasta

						IF @@ROWCOUNT = 0 BREAK;
					End;
			End
		
        Fetch Next From cDel Into @cAAAAMM
    End

    Close cDel
    Deallocate cDel

	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --------------------------------------------------------------- | '
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	Set @dFecha = @cCierre+'01'
	Set @cDesde = CONVERT(Char(8), DATEADD(m, DATEDIFF(m,0,@dFecha), 0) ,112) 
	Set @cHasta = CONVERT(Char(8), DATEADD(m, 1, DATEADD(m, DATEDIFF(m,0,@dFecha), 0)) ,112) 
	If @cHasta > @cCierreHasta
		Set @cHasta = @cCierreHasta

