		Set @iMax = 1000

	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --9.Depuracion [Message]-- | @cHasta => '+ @cHasta +' | Total de Registros => '+ Cast(@iMax As varchar(10))+' | Loops Necesarios Reales => '+ Cast(@iMax / 1000 As varchar(10))
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	Set @iMax = @iMax / 1000
	Set @iLoop = 0
	WHILE @iLoop <= @iMax And @iMax > 0 And @iLoop <= 500
		BEGIN
			Set @iLoop = @iLoop + 1
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | Maximo 500 | Loop => '+ Cast(@iLoop As varchar(10)) +' / '+ Cast(@iMax As varchar(10))
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			Set @cSQL = 'DELETE TOP (1000) FROM [dbo].[Message] WHERE [DateCreated] <='+CHAR(39)+@cHasta+CHAR(39)
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | cSQL => '+ @cSQL
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			Exec (@cSQL )
	  
			IF @@ROWCOUNT = 0 BREAK;
		End;

	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --------------------------------------------------------------- | '
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

    --Desde aca cambia el valor de @cHasta
	--10.Depuracion [dbo].[p_PosicionesGPS]--
	Set @nMeses  = IsNull(( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='MESESDEPPOSICIONES' ),6)
	Set @cCierre = CONVERT(CHAR(6), DateAdd(Month,-@nMeses,@dFecha), 112)
	Set @cHasta = @cCierre+'01'

	Select @iMax = Count([gps_iid])  From [dbo].[p_PosicionesGPS] Where [gps_tfechahora] <= @cHasta
	If @iMax Between 1 And 999
		Set @iMax = 1000

	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --10.Depuracion [dbo].[p_PosicionesGPS]-- | @cHasta => '+ @cHasta +' | Total de Registros => '+ Cast(@iMax As varchar(10))+' | Loops Necesarios Reales => '+ Cast(@iMax / 1000 As varchar(10))
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	Set @iMax = @iMax / 1000

	Set @iLoop = 0
	WHILE @iLoop <= @iMax And @iMax > 0 And @iLoop <= 250
		BEGIN
			Set @iLoop = @iLoop + 1
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | Maximo 250 | Loop => '+ Cast(@iLoop As varchar(10)) +' / '+ Cast(@iMax As varchar(10))
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
			
			Set @cSQL = 'Delete Top (1000) From [dbo].[p_PosicionesGPS] Where [gps_tfechahora] <='+CHAR(39)+@cHasta+CHAR(39)
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | cSQL => '+ @cSQL
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			Exec (@cSQL )

	  		IF @@ROWCOUNT = 0 BREAK;
		End;

	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --------------------------------------------------------------- | '
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	--11.Depuracion [dbo].[p_PosicionesSP]--
	Select @iMax = Count([sp_iid])  From [dbo].[p_PosicionesSP] Where [sp_tfechahora] <= @cHasta
	If @iMax Between 1 And 999
		Set @iMax = 1000

	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --11.Depuracion [dbo].[p_PosicionesSP]-- | @cHasta => '+ @cHasta +' | Total de Registros => '+ Cast(@iMax As varchar(10))+' | Loops Necesarios Reales => '+ Cast(@iMax / 1000 As varchar(10))
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	Set @iMax = @iMax / 1000

	Set @iLoop = 0
	WHILE @iLoop <= @iMax And @iMax > 0 And @iLoop <= 250
		BEGIN
			Set @iLoop = @iLoop + 1
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | Maximo 250 | Loop => '+ Cast(@iLoop As varchar(10)) +' / '+ Cast(@iMax As varchar(10))
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
			
			Set @cSQL = 'Delete Top (1000) From [dbo].[p_PosicionesSP] Where [sp_tfechahora] <='+CHAR(39)+@cHasta+CHAR(39)
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | cSQL => '+ @cSQL
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			Exec (@cSQL )

	  		IF @@ROWCOUNT = 0 BREAK;
		End;

	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --------------------------------------------------------------- | '
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

    --Desde aca vuelve a cambiar el valor de @cHasta
	--12.Depuracion [dbo].[FrameworkAudit]--
	Set @nMeses  = 12
	Set @cCierre = CONVERT(CHAR(6), DateAdd(Month,-@nMeses,@dFecha), 112)
	Set @cHasta = @cCierre+'01'

	Select @iMax = Count(*)  From [_Audit].[dbo].[FrameworkAudit]
		Where [AuditDate] < @cHasta
	
	If @iMax Between 1 And 999
		Set @iMax = 1000

	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | --12.Depuracion [dbo].[FrameworkAudit]-- | @cHasta => '+ @cHasta +' | Total de Registros => '+ Cast(@iMax As varchar(10))+' | Loops Necesarios Reales => '+ Cast(@iMax / 1000 As varchar(10))
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	Set @iMax = @iMax / 1000

	Set @iLoop = 0
	WHILE @iLoop <= @iMax And @iMax > 0 And @iLoop <= 250
		BEGIN
			Set @iLoop = @iLoop + 1
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | Maximo 250 | Loop => '+ Cast(@iLoop As varchar(10)) +' / '+ Cast(@iMax As varchar(10))
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
			
			Set @cSQL = 'Delete Top (1000) From [_Audit].[dbo].[FrameworkAudit] Where [AuditDate] <='+CHAR(39)+@cHasta+CHAR(39)
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | cSQL => '+ @cSQL
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			Exec (@cSQL )

	  		IF @@ROWCOUNT = 0 BREAK;
		End;

END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
END CATCH

