/****** Object:  StoredProcedure [dbo].[SGSP_FillAccesosPendientes]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


create PROCEDURE  [dbo].[SGSP_FillAccesosPendientes]
	@idRec [int] = 0,
	@idCta [int] = 0,
	@cIdExtendido [varchar](100)=''	,
	@tEventoFechaHora [datetime] = Null,
	@iPuntoAcceso [int] = 0
AS
--Inserta datos para control de accesos
--Autor :Pablo O. Canónico
--Fecha :25/10/2021
SET NOCOUNT ON;
BEGIN TRY
	Declare @cLinea [char](3) ='',
			@cCuenta [char](10) = '',
			@cNombre [nVarChar](100) ='',
			@cUsuarioNombre [varchar](256) = '', 
			@cUsuarioFoto [varchar](100) = '',
			@cVehiculoDominio [varchar](50) = '',
			@cVehiculoFoto [varchar](100) = '',
			@cIdentificacion [varchar](50) = ''

	;With ControlAccesos As (
		Select cue_clinea,cue_ncuenta, cue_cnombre, usu_cnombre,usu_cimagen,
				Cast(JSON_VALUE([usu_cmetadata],'$.domain') As Varchar(10)) As Patente,
				Cast(JSON_VALUE([usu_cmetadata],'$.photo') As Varchar(100)) As FotoVehiculo,
				usu_cIdExtendido, usu_cidentificacion
		From [_Datos].[dbo].[m_cuentas]
		Inner join [_Datos].[dbo].[m_usuarios] ON [cue_iid] = [usu_iidcuenta] 
		Where  [usu_cmetadata] Like '%"domain"%' 
			And cue_iid=@idCta
			And usu_cIdExtendido=@cIdExtendido
		Union All 
		(
		Select cue_clinea,cue_ncuenta, cue_cnombre, usu_cnombre,usu_cimagen,
			Space(10) As Patente,
			Space(100) As FotoVehiculo,
			usu_cIdExtendido, usu_cidentificacion
				From [_Datos].[dbo].[m_cuentas]
				Inner join [_Datos].[dbo].[m_usuarios] ON cue_iid = [usu_iidcuenta] 
		Where  [usu_cmetadata] Not Like '%"domain"%' 
		And cue_iid=@idCta
		And usu_cIdExtendido=@cIdExtendido
		)
	)
	Select @cLinea=cue_clinea, @cCuenta=cue_ncuenta, @cNombre=cue_cnombre, @cUsuarioNombre=usu_cnombre, @cUsuarioFoto=usu_cimagen, @cVehiculoDominio=Patente, @cVehiculoFoto=FotoVehiculo, @cIdentificacion=usu_cIdExtendido
		From ControlAccesos

	--Inserto Datos--
	INSERT INTO [dbo].[AccesosPendientes]
			   ([acp_iPuntoAcceso]
			   ,[acp_iRecID]
			   ,[acp_tEventoFechaHora]
			   ,[acp_iidCuenta]
			   ,[acp_cLinea]
			   ,[acp_cCuenta]
			   ,[acp_cNombre]
			   ,[acp_cIdentificacion]
			   ,[acp_cIdExtendido]
			   ,[acp_cUsuarioNombre]
			   ,[acp_cUsuarioFoto]
			   ,[acp_cVehiculoDominio]
			   ,[acp_cVehiculoFoto]
			   )
		 VALUES
			   (@iPuntoAcceso
			   ,@idRec
			   ,@tEventoFechaHora
			   ,@idCta
			   ,@cLinea
			   ,@cCuenta
			   ,@cNombre
			   ,@cIdentificacion
			   ,@cIdExtendido
			   ,@cUsuarioNombre
			   ,@cUsuarioFoto
			   ,@cVehiculoDominio
			   ,@cVehiculoFoto
			   )
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
END CATCH


GO
/****** Object:  StoredProcedure [dbo].[SGSP_GenerateCommand]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


create   Procedure [dbo].[SGSP_GenerateCommand]
	@idCta [int] = 0,
	@cReference [varchar](100) = '',
	@iReceptor [int] = 0
AS
--Es el store que ejecuta IPRS_packetProcesor para obetener la clave del panel y generar un comando a futuro
--Autor :Pablo O. Canónico
--Fecha :02/11/2021

Set NoCount On

BEGIN TRY
	Declare @message VarChar(Max) = '',
			@StartDateTimeText VarChar(Max) = ''

	Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_GenerateCommand] Busco clave del panel'
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
				
	Declare @cClavePanel VarChar(20) = ''
	Select @cClavePanel=[pan_cClavePanel]
		From [_Datos].[dbo].[m_paneles]
	Where [pan_iidcuenta]=@idCta 

	If @cClavePanel!='' And @cClavePanel Is Not Null
	Begin
		Set @message = 'Start DateTime : %s | [SGSP_GenerateCommand] Clave panel : ' + @cClavePanel
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

		Declare @FechaHora DateTime = DATEADD(SECOND, 30, Getdate())
		Insert Into [_Datos].[dbo].[p_comandos_ip]
				   ([cmd_tfechahora]
				   ,[cmd_idCuenta]
				   ,[cmd_idReceptor]
				   ,[cmd_iComando]
				   ,[cmd_cValores]
				   ,[cmd_nEstado]
				   ,[cmd_cObservaciones]
				   ,[cmd_iEsCustom]
				   )
			 Values
				   (@FechaHora
				   ,@idCta
				   ,@iReceptor
				   ,0
				   ,'$IMG['+@cClavePanel+'|'+@cReference+']'
				   ,1
				   ,'Login para solicitar imagen'
				   ,0
				   )
	End
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
	print 'ROLLBACK'
	IF @@TRANCOUNT>0
		ROLLBACK TRAN

END CATCH



GO
/****** Object:  StoredProcedure [dbo].[SGSP_GetAccessControl]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [dbo].[SGSP_GetAccessControl]
	@cMarca [VarChar](150) = '',
	@cModelo [VarChar](150) = '',
	@cDealer [VarChar](150) = '',
	@cCual [VarChar](10) = '',
	@iPlatform Int = 64

WITH EXECUTE AS CALLER
AS
--Es el store que ejecuta el servicio de AccessControl para obetener configuracion del panel y custom commands si los tuviera
--Autor :Pablo O. Canónico
--Fecha :06/08/2019
--2023-05-02 : Pablo. Comandos en formato jSon (Library.AccessControlList usa cmd_iid, lo dejo para no modificar todo el servicio)
Set NoCount On
BEGIN TRY
	Declare @cSQL [VarChar](max)  = ''

	If @iPlatform = 64
	Begin
		Set @cMarca = 'Siera'',''HikVision'',''Dahua'
		Set @cModelo = 'SAC3000'',''HikvisionHPPAccessController'',''Access Controller'
	End
	Else
	Begin
		Set @cMarca = 'Intelektron'',''HikVision'
		Set @cModelo = 'ITKCOM'',''HikvisionAccessController'
	End

	Set @cSQL =';With AccessControl As (
	Select [pan_iidcuenta],[pan_cConfig],Replace([rec_cdll],''PacketParser'',''AccessControl'') As cDll 
		From [dbo].[m_Paneles]  WITH (NOLOCK)
		Inner Join  [_Tablas].[dbo].[T_ReceptorProtocolModel]  WITH (NOLOCK) On [rpm_idKey]=[pan_rpmidKey]
		Inner Join [dbo].[m_receptores_cab] WITH (NOLOCK) On [rpm_iReceptor] = [rec_iid]
		Inner Join [dbo].[m_cuentas] WITH (NOLOCK) On [cue_iid] = [pan_iidcuenta]
	Where [rpm_cMarca] IN('+CHAR(39)+@cMarca+CHAR(39)+') And [rpm_cModelo] IN('+CHAR(39)+@cModelo+CHAR(39)+') And [pan_cConfig]!='''' '

	If @cDealer!=''
		Set @cSQL += ' And [cue_clinea] IN('+CHAR(39)+Replace(@cDealer,',',CHAR(39)+','+CHAR(39))+CHAR(39)+')'

	If @cCual='Next'
		Begin
			Set @cSQL +=')
			Select [pan_iidcuenta],[pan_cConfig],Replace([cdll],''HikVision'',''HikVisionHPP'') As [cDll], 0 As cmd_iid
				,Comandos = (Select IsNull([cmd_iid],0) As cmd_iid,IsNull([cmd_cValores],'''') As cmd_cValores,IsNull([cmd_nEstado],0) As cmd_nEstado,IsNull([cmd_cRespuesta],'''') As cmd_cRespuesta
				From [p_comandos_ip] Where [cmd_idCuenta]=[pan_iidcuenta] And [cmd_nEstado] = 1 AND [cmd_iEsCustom] = 2	Order By[cmd_tFechaHora] FOR JSON PATH, ROOT (''Comandos'') )		
				,UserABM = (Select [acc_idKey],[acc_iStatus],IsNull([usu_cnombre],''--Eliminado--'') As cNombre,IsNull([usu_cclave],'''') As cClave,IsNull([usu_ntipo],0) As nTipo,[acc_cIdExtendido],IsNull([usu_cidentificacion],[acc_cIdentificacion]) As cIdentificacion,[usu_iCodigo],Rtrim(Cast([usu_mobservacion] As VarChar(100))) As cObs 
				FROM [dbo].[m_UsuariosAccesos]
				Left Outer Join [_Datos].[dbo].[m_usuarios] On [usu_iidcuenta]=[acc_iCtaId] And [usu_idKey]=[acc_iUsuIdK]
				Where [acc_iCtaId]=[pan_iidcuenta] FOR JSON PATH, ROOT (''UsersAccess''))
				From AccessControl
				Order By [cDll],[pan_iidcuenta]'
		End
	Else
		Begin
			Set @cSQL +=')
			Select [pan_iidcuenta],[pan_cConfig],Replace([cdll],''HikVision'',''HikVisionHPP'') As [cDll], 0 As cmd_iid,'''' As Comandos,'''' As UserABM
				From AccessControl
				Order By [cDll],[pan_iidcuenta]'
		End

	--Print @cSql
	Exec (@cSQL)

END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');

END CATCH


GO
/****** Object:  StoredProcedure [dbo].[SGSP_GetAlarmCameras]    Script Date: 4/21/2026 10:44:40 AM ******/
