CREATE PROCEDURE [dbo].[SGSP_GetAlarmCameras]
	@cDealer [VarChar](150) = ''
WITH EXECUTE AS CALLER
AS
--Es el store que ejecuta CameraAlarmsReceiverService para obetener los links de video de las camaaras que envian alarma
--Autor :Pablo O. Canónico
--Fecha :11/04/2019
--2019-11-01 : Se agrego HAR-Hikvision Alarm Receiver
--2023-03-21 : Se agrego DAP-Dahua Alarm Receiver P2P Mode
--2024-08-12 : DK-297 Se agrego IAR:Intelbras Alarm Receiver P2P Mode
Set NoCount On
BEGIN TRY
	Select tvi_iid,cuv_iidCuenta As idCta,cue_ncuenta,cue_cIMEI,cuv_cLinkDSS As cLinkDSS,'' As Zona
		From [dbo].[m_cuentas]
			Inner Join [dbo].[m_cuentas_video] On cue_iid=cuv_iidCuenta
			Inner Join [_Tablas].[dbo].[t_VideoID] ON [tvi_iid]=cuv_iVideoID
			where [tvi_cdescripcion] IN('DAR:','HAR:','DAP:','IAR:')
			And ( [cue_clinea] = @cDealer Or @cDealer = '' )
	Union All
	(
	Select tvi_iid,cvl_iidCuenta As idCta,cue_ncuenta,cue_cIMEI,cvl_cLinkDSS As cLinkDSS,cvl_cZona As Zona
		From [dbo].[m_cuentas]
			Inner Join [dbo].[m_cuentas_video_links] cuv  On cue_iid=cvl_iidCuenta
			Inner Join [_Tablas].[dbo].[t_VideoID] ON [tvi_iid]=cvl_iVideoID
			where [tvi_cdescripcion] IN('DAR:','HAR:','DAP:','IAR:')
			And ( [cue_clinea] = @cDealer Or @cDealer = '' )
			)

	Order By tvi_iid,idCta

	Set NoExec Off		
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');

END CATCH


GO
/****** Object:  StoredProcedure [dbo].[SGSP_GetDateTimeOffSet]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SGSP_GetDateTimeOffSet] @iCta int, @tFechaHora Datetime AS
Declare @FechaOffSet DatetimeOffSet 
Set @FechaOffSet = ( Select  SWITCHOFFSET (TODATETIMEOFFSET (@tFechaHora, DATENAME ( TZoffset , SYSDATETIMEOFFSET() )),
	IsNull(TZ.ttz_nOffSet,0.00)*60 ) 
	From _Datos.dbo.m_cuentas MC
	Left Outer Join _Tablas.dbo.t_TimeZone TZ On TZ.ttz_idKey=MC.cue_iZonaHoraria
	Where MC.cue_iid = @iCta )
	
Select Cast ( @FechaOffSet As Datetime ) As FechaOffSet	


GO
/****** Object:  StoredProcedure [dbo].[SGSP_GetDSCConfig]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


Create PROCEDURE [dbo].[SGSP_GetDSCConfig]

WITH EXECUTE AS CALLER
AS
--Es el store que ejecuta el servicio de TSPIntegration para obetener configuracion del panel
--Autor :Pablo O. Canónico
--Fecha :31/07/2023

Set NoCount On

Select [pan_iidcuenta],[pan_cConfig]
	From [dbo].[m_Paneles] mp WITH (NOLOCK)
	Inner Join [_Tablas].[dbo].[t_paneles] tp On tp.[pan_ccodigo]=mp.[pan_ccodigo] 
	Inner Join [dbo].[m_estado_cuenta_cab] On [pan_iidcuenta] = [est_iidcuenta] 
Where tp.[pan_iModelo]=14 And [est_nEstado]=0 And [pan_cConfig] Like '%_integrationid%'
Order By [pan_iidcuenta]


GO
/****** Object:  StoredProcedure [dbo].[SGSP_GetSocketListener]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [dbo].[SGSP_GetSocketListener]
	@cMarca [VarChar](150) = '',
	@cModelo [VarChar](150) = '',
	@cDealer [VarChar](150) = '',
	@cCual [VarChar](10) = ''

WITH EXECUTE AS CALLER
AS
--Es el store que ejecuta el servicio de SokcetListener para obetener configuracion del panel y custom commands si los tuviera
--Autor :Pablo O. Canónico
--Fecha :01/12/2022
--
Set NoCount On
BEGIN TRY
	Declare @cSQL [VarChar](max)  = ''

	If @cMarca=''
	Begin 
		Set @cMarca = 'KSENIA'
		Set @cModelo = 'KseniaWsock'
	End 

	Set @cSQL =';With Listener As (
	Select [pan_iidcuenta],[pan_cConfig],Replace([rec_cdll],''PacketParser'',''Listener'') As cDll 
		From [dbo].[m_Paneles]  WITH (NOLOCK)
		Inner Join  [_Tablas].[dbo].[T_ReceptorProtocolModel]  WITH (NOLOCK) On [rpm_idKey]=[pan_rpmidKey]
		Inner Join [dbo].[m_receptores_cab] WITH (NOLOCK) On [rpm_iReceptor] = [rec_iid]
		Inner Join [dbo].[m_cuentas] WITH (NOLOCK) On [cue_iid] = [pan_iidcuenta]
	Where [rpm_cMarca] IN('+CHAR(39)+@cMarca+CHAR(39)+') And [rpm_cModelo] IN('+CHAR(39)+@cModelo+CHAR(39)+') And [pan_cConfig]!='''' '

	If @cDealer!=''
		Set @cSQL += ' And [cue_clinea] IN('+CHAR(39)+Replace(@cDealer,',',CHAR(39)+','+CHAR(39))+CHAR(39)+')'

	If @cCual='Next'
		Begin
			Set @cSQL +=')
			Select [pan_iidcuenta],[pan_cConfig],[cDll], IsNull([cmd_iid],0) As cmd_iid,IsNull([cmd_cValores],'''') As cmd_cValores,IsNull([cmd_nEstado],0) As cmd_nEstado,IsNull([cmd_cRespuesta],'''') As cmd_cRespuesta
				From Listener
			Left Outer Join [p_comandos_ip] On [cmd_idCuenta]=[pan_iidcuenta] And [cmd_nEstado] = 1 AND [cmd_iEsCustom] = 3
				Order By [cDll],[pan_iidcuenta],[cmd_tFechaHora]'
		End
	Else
		Begin
			Set @cSQL +=')
			Select [pan_iidcuenta],[pan_cConfig],[cDll], 0 As cmd_iid, '''' As cmd_cValores, 0 As cmd_nEstado, '''' As cmd_cRespuesta
				From Listener
				Order By [cDll],[pan_iidcuenta]'
		End


	--Print @cSql
	Exec (@cSQL)

END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');

END CATCH


GO
/****** Object:  StoredProcedure [dbo].[SGSP_Inactividad]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SGSP_Inactividad] AS 
--Detecta Inactividad de los puertos-conexiones ip
--Autor .Pablo O. Canónico 25-10-2006
--Modificado 04-04-2007 para tomar tambien HB
--Modificado 01-10-2007 Controla Corte de Linea para Pegasus 3i
--Modificado 05-08-2010 Asigna cuenta SG-INTE si no existe 0000
--Modificado 10-01-2013 Envia x SMS
--Modificado 19-04-2016 Cambio rutina insert en pRecepcion
--Modificado 30-05-2016 Se actualiza m_Status
--Modificado 03-11-2017 Se agrego control sobre conexiones de IRS
--Modificado 13-11-2017 Solamente asigna cuenta SG-INTE no utiliza mas 0000
--Modificado 26-09-2018 Si no existe el idRec en pRecepcion se busca en la depurada ( TST )
--Modificado 22-10-2018 Se controla sobre iStatus=A en conexiones IRS
--Modificado 04-08-2021 Se agrego conexion para poder controlar TCPClient porque todos tienen puerto 1025
--Modificado 06-08-2021 Se agrego grabacion de [p_RXtraInfo] con el valor de la conexion
--Modificado 06-01-2022 Se agrego control de conexion en de [p_heartbeats]
SET NOCOUNT ON
-- Aviso que la tarea esta funcionando	
Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'Inactividad', @Repetition = 4
--	
Set DateFormat ymd
Declare @dUltimoEvento  DateTime,
 @dDiaHoy     			DateTime=GetDate(),
 @tFechaProceso			DateTime,
 @dUltimoHB				DateTime

Declare @iIdInterno	Int=0,
 @iTiempo			Int=0,
 @iInactivo			Int=0,
 @iIdCuenta			Int=0,
 @iError 			Int=0,
 @iReceptor			Int=0,
 @iModemSMS 		Int=0,
 @nFin 				Int=0,
 @iprsiid 			Int=0

Declare @cGrabo	Char(1)='S',
 @cAlarma		Char(3)='_DI'

Declare @cReceptorDesc	nVarChar(40)='',
 @cToSMS 				nVarChar(150)='',
 @cDestinoSMS 			nVarChar(150)='',
 @cSubject 				nVarChar(150)=(SELECT cod_cdescripcion From _Tablas.dbo.t_codigos_alarma With (NOLOCK) Where cod_ccodigo=@cAlarma),
 @cMessage 				nVarChar(140)='',
 @Limite				VarChar(20),
 @cDll					VarChar(50)

Declare @nPuerto	Numeric(5,0)=0,
 @nGeneraAlerta		Numeric(1,0)=0,
 @nEstado			Numeric(1,0)=0,
 @nResetHB			Numeric(1,0)=0,
 @iConexion			Int=0

Declare @message nVarChar(Max) = '',
	    @StartDateTimeText VarChar(max) = ''

If @cSubject Is Null
   Set @cSubject = 'Deteccion Inactividad en Receptor'

DECLARE Puertos_Cursor CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
SELECT pue_cdescripcion,pue_npuerto,pue_itiempoinactividad,pue_ireceptor,pue_cresetxhb,'' As rec_cdll,0 As iprsc_iprsiid,0 As iConexion FROM _Tablas.dbo.t_puertos With (NOLOCK)
	Where pue_nestado= 2 And pue_itiempoinactividad > 0
Union All
SELECT ipc_cdescripcion,ipc_nport,ipc_itiempoinactividad,ipc_ireceptor,ipc_cresetxhb,'' As rec_cdll,0 As iprsc_iprsiid,0 As iConexion FROM _Tablas.dbo.t_ip_con With (NOLOCK)
Inner Join _Datos.dbo.m_receptores_cab On rec_iid=ipc_ireceptor
	Where ipc_nestado= 2 And ipc_itiempoinactividad > 0 And rec_iEsIRS=0
Union All
SELECT ipc_cdescripcion,ipc_nport,ipc_itiempoinactividad,ipc_ireceptor,ipc_cresetxhb,rec_cdll,iprsc_iprsiid,iConexion=[ipc_idKey] FROM _Tablas.dbo.t_ip_con With (NOLOCK)
Inner Join _Datos.dbo.m_receptores_cab On rec_iid=ipc_ireceptor
Inner Join _Tablas.dbo.t_IPRSConn On ipc_idKey=iprsc_ipcidkey
	Where iprsc_status='A' And ipc_itiempoinactividad > 0 --And rec_iEsIRS=1
Order By 2

OPEN Puertos_Cursor
FETCH NEXT FROM Puertos_Cursor INTO @cReceptorDesc,@nPuerto,@iTiempo,@iReceptor,@nResetHB,@cDll,@iprsiid,@iConexion
WHILE @@FETCH_STATUS = 0
BEGIN
	Set @Limite = Replace(convert(varchar, DATEADD(MINUTE,-@iTiempo,@dDiaHoy),120),'-','')
	
	Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | SGSP_Inactividad | Control de Inactividad | ==========================================================='
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	Set @message = 'Start DateTime : %s | SGSP_Inactividad | Control de Inactividad | Receptor => ' +@cReceptorDesc +' Puerto => '+ Rtrim(Cast(@nPuerto As Varchar(10)))+' | Tiempo => '+ Rtrim(Cast(@iTiempo As varchar(10)))+' | Conexion => '+ Rtrim(Cast(@iConexion As varchar(10)))+' | ResetHB => '+ Rtrim(Cast(@nResetHB As varchar(10)))+' | Limite => '+ Rtrim(Convert(VarChar, @Limite,120))+' | DiaHoy => '+ Rtrim(Convert(VarChar, @dDiaHoy,120))
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	Set @dUltimoEvento = Null

	Select Top 1 @dUltimoEvento=rec_tFechaRecepcion
		FROM p_recepcion With (NOLOCK)
	Inner Join p_RXtraInfo On rxt_iRecId=rec_iid
	Inner Join _Tablas.dbo.t_ip_con On [ipc_idKey]=[rxt_iConexion]
		WHERE rec_iPuerto=@nPuerto
		And ( @iConexion=0 Or [ipc_idKey]=@iConexion)
		And rec_nOrigen IN(2,8)
		And rec_tFechaRecepcion >= @Limite
	   		And rec_tFechaRecepcion <= @dDiaHoy
		ORDER BY rec_tFechaRecepcion DESC 

	If @dUltimoEvento Is Null
	Begin
		--Busco en la depurada
		Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | SGSP_Inactividad | Control de Inactividad | No hay UltimoEvento en pRecepcion. Busco en la depurada'
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

		Declare @cCierre Char(6) = Convert(Char(6),Getdate(), 112)
		IF OBJECT_ID('p_recepcion'+@cCierre) Is Not Null
		Begin		
			Declare @cSQL nVarchar(MAX)
				
			Set @cSQL = 'Select Top 1 @dUltimoEvento=rec_tFechaRecepcion From [dbo].[p_recepcion' +  @cCierre  + '] With (NOLOCK)
						Inner Join [dbo].[p_RXtraInfo' +  @cCierre  + '] On rxt_iRecId=rec_iid
						Inner Join _Tablas.dbo.t_ip_con On [ipc_idKey]=[rxt_iConexion]
						WHERE rec_iPuerto='+Rtrim(Cast(@nPuerto As Varchar(5)))+' And rec_nOrigen IN(2,8) 
						And rec_tFechaRecepcion >= '+Char(39)+@Limite+Char(39)+ ' And rec_tFechaRecepcion <= '+Char(39)+Replace(convert(varchar,@dDiaHoy,120),'-','') +Char(39)+'
						And ( '+Cast(@iConexion As Varchar(5))+'=0 Or [ipc_idKey]='+Cast(@iConexion As Varchar(5))+')
						ORDER BY rec_tFechaRecepcion DESC '

			Declare @DynamicSqlParams NVarchar(MAX)
			Set @DynamicSqlParams = '@dUltimoEvento DateTime OUTPUT'
			Execute sp_executesql @cSQL, @DynamicSqlParams, @dUltimoEvento=@dUltimoEvento OUTPUT
		End
	End
	Else
	Begin
		Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | SGSP_Inactividad | Control de Inactividad | UltimoEvento => '+ Rtrim(Convert(VarChar, @dUltimoEvento,120))
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
	End

	If @nResetHB = 1
      Begin		
		Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | SGSP_Inactividad | Control de Inactividad | Busco HB puerto => '+ Rtrim(Cast(@nPuerto As Varchar(10)))+' | Conexion => '+ Rtrim(Cast(@iConexion As varchar(10)))+' | Limite => '+ Rtrim(Convert(VarChar, @Limite,120))+' | DiaHoy => '+ Rtrim(Convert(VarChar, @dDiaHoy,120))
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	    Set @dUltimoHB = Null
		Select Top 1 @dUltimoHB=hbs_tfechahora
  			  FROM p_heartbeats With (NOLOCK)
		WHERE hbs_ipuerto=@nPuerto
			  And hbs_tfechahora >= @Limite
	   		  --And hbs_tfechahora <= @dDiaHoy
			  And ( @iConexion=0 Or [hbs_iConexion]=@iConexion )
		ORDER BY hbs_tfechahora DESC

		If @dUltimoHB Is Not Null 
		Begin
			Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | SGSP_Inactividad | Control de Inactividad | UltimoHB => '+ Rtrim(Convert(VarChar, @dUltimoHB,120))
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
			
			If @dUltimoEvento Is Null Or @dUltimoHB > @dUltimoEvento  
				Set @dUltimoEvento = @dUltimoHB

			Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | SGSP_Inactividad | Control de Inactividad | HB es UltimoEvento => '+ Rtrim(Convert(VarChar, @dUltimoEvento,120))
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
		End
		Else
		Begin
			Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | SGSP_Inactividad | Control de Inactividad | UltimoHB => NO HAY'
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
		End
      End

   --Controlo
   If @dUltimoEvento Is Null
 	Begin

       If @cGrabo = 'S'	
	   Begin
		    Set @iIdCuenta = (Select Top 1 cue_iid From m_cuentas With (NOLOCK)
				Where cue_clinea='_SG' And cue_ncuenta = 'INTE' )

			Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | SGSP_Inactividad | Control de Inactividad | idCta => '+ Rtrim(Cast(@iIdCuenta As Varchar(10)))+' | Puerto => '+ Rtrim(Cast(@nPuerto As Varchar(10)))+' | Conexion => '+ Rtrim(Cast(@iConexion As varchar(10)))
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			If @iIdCuenta Is Not Null
			Begin
				--
				Set @nEstado = 0
				Set @nGeneraAlerta = (SELECT cod_nalerta From _Tablas.dbo.t_codigos_alarma With (NOLOCK) Where cod_ccodigo=@cAlarma)

				Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | SGSP_Inactividad | Control de Inactividad | GeneraAlerta => '+ Rtrim(Cast(@nGeneraAlerta As Varchar(10)))
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

				If @nGeneraAlerta Is Null
				   Set @nEstado = 0
				Else
				   Begin
					If @nGeneraAlerta = 2  	   --Es un Evento de NO GENERAR, NO se graba p_recepcion
					   Set @nEstado = 9
					Else 	
					   If @nGeneraAlerta = 0	--Si NO Genera Alerta (0) lo grabo con estado 5
						Set @nEstado = 5
				   End
				--

				Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | SGSP_Inactividad | Control de Inactividad | Estado => '+ Rtrim(Cast(@nEstado As Varchar(10)))
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

				If @nEstado < 9
				   Begin
						Select @tFechaProceso = (Case When @nEstado = 5 Then @dDiaHoy Else Null End)

						BEGIN TRY
							EXEC [dbo].[SGSP_pRecepcionINS]
									@rec_iidcuenta = @iidCuenta,
									@rec_calarma = @cAlarma,
									@rec_tfechahora  = @dDiaHoy,
									@rec_nestado  = @nEstado,
									@rec_cContenido = @cReceptorDesc,
									@rec_tFechaProceso = @tFechaProceso,
									@rec_idReceptor = @iReceptor,
									@rec_tFechaRecepcion = @dDiaHoy,
									@rec_iPuerto = @nPuerto,
									@rec_nOrigen = 8,
									@iValor = @iIdInterno OUTPUT
						END TRY
						BEGIN CATCH
							Print 'EXEC [dbo].[SGSP_pRecepcionINS] Volvio con error'
							Set @iIdInterno=0
						END CATCH

						if @iIdInterno > 0
						Begin

							--Tengo que actualizar [p_RXtraInfo] con el valor de la conexion
							If @iConexion > 0
							Begin
								Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
								Set @message = 'Start DateTime : %s | SGSP_Inactividad | Control de Inactividad | Actualizo p_RXtraInfo con iConexion => '+ Rtrim(Cast(@iConexion As Varchar(10)))
								RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
		
								MERGE INTO [_Datos].[dbo].[p_RXtraInfo] AS TGT
								USING ( Select @iConexion As iConexion, @iIdInterno As iRecId ) AS SRC 
									ON TGT.[rxt_iRecId] = SRC.[iRecId]
								WHEN MATCHED THEN
									UPDATE SET
										TGT.[rxt_iConexion] = SRC.[iConexion]
 								WHEN NOT MATCHED THEN 
									INSERT ([rxt_iRecId],[rxt_iConexion])
									VALUES (SRC.[iRecId],@iConexion);
							End 

							--Tengo que actualizar Status con ultima alarma y fecha
							Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | SGSP_Inactividad | Control de Inactividad | Tengo que actualizar Status con ultima alarma y fecha'
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
	
							UPDATE m_status WITH (UPDLOCK) 
								Set sta_cultimaalarma = @cAlarma, sta_dfechautimaalarma = CONVERT(DateTime, CONVERT(Varchar(20), @dDiaHoy, 120),111) 
							Where sta_iidCuenta=@iidCuenta

							--Si es Alari generar comando en RemoteCallQueue
							If (@cDll = 'Alari3PacketParser')
							Begin
								Declare @cURLDesktop nVarChar(1000)= ( Select par_cValor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='URLDESKTOP' )
								If Upper(Rtrim(@cURLDesktop)) = Upper('http://DesktopURL:PORT')
								Begin
									Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
									Set @message = 'Start DateTime : %s | SGSP_Inactividad | Control de Inactividad | Falta configurar el parametro URLDESKTOP'
									RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
								End
								Else
								Begin
									Declare @cLocalIP Varchar(250) = ''
									Declare @iCmdPort Int = 0
									Select @cLocalIP=[iprs_localip], @iCmdPort=[iprs_commandport]
										From [_Sistema].[dbo].[s_iprservicios]
										Where [iprs_idKey]=@iprsiid

									If @cLocalIP Is Null Or @cLocalIP='' Or @iCmdPort Is Null Or @iCmdPort=0
									Begin
										Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
										Set @message = 'Start DateTime : %s | SGSP_Inactividad | Control de Inactividad | No existen valores de IP y Puerto de comandos para iprsiid '+Cast(@iprsiid As VarChar(10))
										RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
									End
									Else
									Begin
										--DATEDIFF_BIG funciona en 2016 o superior
										--Declare @Tick Varchar(30) = ( Select DATEDIFF_BIG( microsecond, '00010101', GetDate() ) * 10 +( DATEPART( NANOSECOND, GetDate() ) % 1000 ) / 100 )
										Declare @Tick Varchar(30) = ( Select  (DATEDIFF(DAY, '01/01/0001', CAST(Getdate() AS DATE)) * 864000000000.0)
																		+ (DATEDIFF(SECOND, '00:00', CAST(Getdate() AS TIME(7))) * 10000000.0) + (DATEPART(NANOSECOND, Getdate()) / 100.0) )
										Set @Tick = Substring(@Tick,1,18)
										
										Declare @rcq_url Varchar(500) = Ltrim(@cURLDesktop) + '/handler/IRS_RESETALL_handler?_dc' + Rtrim(@Tick) + '&ip=' + Rtrim(@cLocalIP) + '&port=' + Rtrim(Cast(@iCmdPort As VarChar(5)))
										INSERT INTO [dbo].[RemoteCallQueue] (
											[rcq_estado],
											[rcq_tipo],
											[rcq_url]
											)
										VALUES (
											0,
											'HTTPGET',
											@rcq_url
											)
									End
								End
							End

							--Envio de SMS
							Set @cMessage = @cSubject +' '+ Rtrim(@cReceptorDesc) + ' | ' +CONVERT(char(19), GetDate(),120)  

							Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | SGSP_Inactividad | Control de Inactividad | Envio de SMS | Message => '+ Rtrim(@cMessage)
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
	
							Select Top 1 @cToSMS=sms_csmsparaeventos, @iModemSMS=sms_imodemsms From m_sms
			 					  Where ( CHARINDEX(@cAlarma, sms_meventos) > 0  Or
							 ( sms_iNotificarAlertas=1 And @cAlarma IN (Select cod_ccodigo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And cod_nalerta=1)))
								  And sms_csmsparaeventos<> '' And sms_imodemsms > 0 And sms_iidCuenta=@iidCuenta 

							Set @cToSMS = Ltrim(Rtrim(@cToSMS))+';'
	
							WHILE CHARINDEX(';',@cToSMS) > 0 And @iModemSMS > 0
							BEGIN
							  Set @nFin = CHARINDEX(';',@cToSMS)	
							  Set @cDestinoSMS=SUBSTRING( @cToSMS, 1, @nFin-1 )
							  If @cGrabo = 'S'
								Insert Into p_SMSqueue (que_idCuenta,que_iModemSMS,que_cAsunto,que_cDestino)
								Values (@iidCuenta,@iModemSMS,Left(@cMessage,140),@cDestinoSMS)
			
								Set @cToSMS = SUBSTRING( @cToSMS, @nFin+1, 150-@nFin )
							END
						End
					End
			End
	     End
	End	

   FETCH NEXT FROM Puertos_Cursor INTO @cReceptorDesc,@nPuerto,@iTiempo,@iReceptor,@nResetHB,@cDll,@iprsiid,@iConexion
End

CLOSE Puertos_Cursor
DEALLOCATE Puertos_Cursor


--Analizo si hay Pegasus 3i con corte o restauracion de lineas telefonicas
Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
Set @message = 'Start DateTime : %s | SGSP_Inactividad | Analizo si hay Pegasus 3i con corte o restauracion de lineas telefonicas'
RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

Declare @cCorteLinea	Char(3)=''
Declare @cIMEI 			nVarChar(20)=''
Declare @iidHB			Integer=0

DECLARE pegasus_Cursor CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
Select ipc_cdescripcion,ipc_nport,ipc_ireceptor,hbs_cCorteLinea,hbs_cIMEI,hbs_iid
 FROM _Tablas.dbo.t_ip_con With (NOLOCK)
 Inner Join _Datos.dbo.m_receptores_cab With (NOLOCK) On rec_iid = ipc_ireceptor
 Inner Join _Datos.dbo.p_heartbeats With (NOLOCK) On hbs_ipuerto = ipc_nport
	Where ipc_nestado= 2 And rec_cdll='PEGASUS' And hbs_cIMEI Not In('    ','####') And hbs_cCorteLinea Not In('   ') 
Order By hbs_cIMEI

OPEN pegasus_Cursor
FETCH NEXT FROM pegasus_Cursor INTO @cReceptorDesc,@nPuerto,@iReceptor,@cCorteLinea,@cIMEI,@iidHB
WHILE @@FETCH_STATUS = 0
BEGIN
   If Right(@cCorteLinea,1) <> '*'
	Begin

     If @cGrabo = 'S'	
      Begin

		--Busco ID de cuenta del cIMEI
		Set @iIdCuenta = (Select Top 1 cue_iid From m_cuentas With (NOLOCK)
				Inner Join  _Tablas.Dbo.t_port_alias
					On cue_clinea=tpa_cdealer
				Inner Join  _Tablas.dbo.t_ip_con
					On ipc_icodigo=tpa_iportip
				Where ipc_nport = @nPuerto	
				And cue_ncuenta = @cIMEI
				   Order By cue_iid )

		If @iIdCuenta Is Null
		   Set @iIdCuenta = (Select Top 1 cue_iid From m_cuentas With (NOLOCK)
			Where cue_clinea='_SG' And cue_ncuenta = 'INTE' )

		If @iIdCuenta Is Null
		   Set @iIdCuenta = 0

		--
		Set @nEstado = 0
		If @cCorteLinea = '55'
	   	   Set @cAlarma = '_CL'	
		Else	--C5 / D5 / E5
	   	   Set @cAlarma = '_RL'	

		Set @nGeneraAlerta = (SELECT cod_nalerta From _Tablas.dbo.t_codigos_alarma With (NOLOCK) Where cod_ccodigo=@cAlarma)

		If @nGeneraAlerta Is Null
		   Set @nEstado = 0
		Else
		   Begin
				If @nGeneraAlerta = 2  	   --Es un Evento de NO GENERAR, NO se graba p_recepcion
					Set @nEstado = 9
				Else 	
					If @nGeneraAlerta = 0	--Si NO Genera Alerta (0) lo grabo con estado 5
					Set @nEstado = 5
				End

				If @nEstado < 9
					Begin
					--1ero genero alerta
						Select @tFechaProceso = (Case When @nEstado = 5 Then @dDiaHoy Else Null End)

						BEGIN TRY
							EXEC [dbo].[SGSP_pRecepcionINS]
									@rec_iidcuenta = @iidCuenta,
									@rec_calarma = @cAlarma,
									@rec_tfechahora  = @dDiaHoy,
									@rec_nestado  = @nEstado,
									@rec_cContenido = @cReceptorDesc,
									@rec_tFechaProceso = @tFechaProceso,
									@rec_idReceptor = @iReceptor,
									@rec_tFechaRecepcion = @dDiaHoy,
									@rec_iPuerto = @nPuerto,
									@rec_nOrigen = 8,
									@iValor = @iIdInterno OUTPUT
						END TRY
						BEGIN CATCH
							Print 'EXEC [dbo].[SGSP_pRecepcionINS] Volvio con error'
							Set @iIdInterno=0
						END CATCH

						if @iIdInterno > 0
						Begin
							--Tengo que actualizar Status con ultima alarma y fecha
							UPDATE m_status WITH (UPDLOCK)
								Set sta_cultimaalarma = @cAlarma, sta_dfechautimaalarma = CONVERT(DateTime, CONVERT(Varchar(20), @dDiaHoy, 120),111) 
							Where sta_iidCuenta=@iidCuenta

							--2do actualizo cortelinea
							UPDATE p_heartbeats WITH (UPDLOCK)
								Set hbs_cCorteLinea=Substring(hbs_cCorteLinea,1,2)+'*'
							Where hbs_iid=@iidHB
						End
					End
	      End
	End 

   FETCH NEXT FROM pegasus_Cursor INTO @cReceptorDesc,@nPuerto,@iReceptor,@cCorteLinea,@cIMEI,@iidHB
End
CLOSE pegasus_Cursor
DEALLOCATE pegasus_Cursor

GO
/****** Object:  StoredProcedure [dbo].[SGSP_IRSAlariEstadosDinamicos]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SGSP_IRSAlariEstadosDinamicos]
	@iCuenta [int] = 0,
	@cEvt nVarChar(10) = '',
	@iGenera [int] = 0 OUTPUT
AS
--Analizador de Eventos con estados dinamicos para IRServices EXCLUSIVO para la dll de Alari
--Autor : Pablo O. Canónico
--Fecha : 08/08/2017

Set NoCount ON
BEGIN TRY
Declare @message nVarChar(Max) = '',
	    @StartDateTimeText VarChar(Max) = ''

Declare @cCodigo nVarChar(10)=''
Declare @iValor Int=0

Set @cEvt = Right(Rtrim(@cEvt),2)
Declare @iEvt Int = ( Select ( Case When @cEvt='00' Then 0 When @cEvt='01' Then 1 When @cEvt='02' Then 2
								When @cEvt='03' Then 3 When @cEvt='04' Then 4 When @cEvt='05' Then 5 
								When @cEvt='06' Then 6 When @cEvt='07' Then 7 When @cEvt='08' Then 8
								When @cEvt='09' Then 9 When @cEvt='0A' Then 10 When @cEvt='0B' Then 11 
								When @cEvt='0C' Then 12 When @cEvt='0D' Then 13 When @cEvt='0E' Then 14
								When @cEvt='0F' Then 15 Else 0 End ) )

--Primero hay que consultar el estado actual por idCta
Select @iValor = [ped_iValor]
	FROM [_Datos].[dbo].[p_EstadosDinamicos]
	Where [ped_iCtaId]=@iCuenta And [ped_cCodigo]= '_UltEvt'

--Actualizo con ultimo valor
MERGE INTO [dbo].[p_EstadosDinamicos] AS TGT
USING ( Select '_UltEvt' As cCodigo, @iEvt As iValor, @iCuenta As iCtaId) AS SRC 
		ON TGT.[ped_iCtaId] = SRC.[iCtaId] And TGT.[ped_cCodigo] = SRC.[cCodigo]
WHEN MATCHED THEN
	UPDATE SET
		TGT.[ped_iValor] = SRC.[iValor]
WHEN NOT MATCHED THEN 
	INSERT ([ped_cCodigo],[ped_iValor],[ped_iCtaId])
	VALUES (SRC.[cCodigo],SRC.[iValor],SRC.[iCtaId]);

--Tercero comparar iValor con el Hex2Dec del evento recibido
If @iValor <> @iEvt
	Set @iGenera = 1

Set NoExec Off		
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
END CATCH


GO
/****** Object:  StoredProcedure [dbo].[SGSP_IRSBuscoFormato]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SGSP_IRSBuscoFormato]
	@iReceptor [int] = 0,
	@iCuenta [int] = 0,
	@iTipo [int] = 0,
	@cEvento [VarChar](10) = '',
	@cZona [VarChar](10) = '',
	@cProtocolo [VarChar](10) = '',
	@iConexion [int] = 0,
	@cAlarma [Char](3) = '' OUTPUT,
	@iCtaMap [int] = 0 OUTPUT,
	@iCtaFwd [int] = 0 OUTPUT,
	@iLoopCtrl [int] = 0 OUTPUT,
	@cDebug Char(2) = 'No'	--'Si' 
AS
--Busca Formato para IRServices
--Devuelve codigo de alarma y el idCta si sale por MAP o FWD
--Autor : Pablo O. Canónico
--Fecha : 10/04/2017
--@iTipo => 0 : Resuelve por evento
--       => 1 : Resuelve por evento+zona
--2017-12-15 : Se modifico para considerar Evento al no encontrar Evento+Zona
--2018-09-05 : Se le saca el 0 a izquierda al @cFormato si @cProtocolo = '4+2'
--2018-11-07 : Se agrego @iMapFwd para mantener el iCta por llamado recursivo
--2020-12-04 : Se agrego protocolo '1/3' 'PIMA' que vienen de PG
--2022-06-27 : Se agrego @iConexion para buscar formatos por dll+conexion
--2022-07-20 : Se cambio control de busqueda para que considere primero el @iTipo y en @cProtocolo 4+2 que no le saque el 0 a izquierda a expresiones con 0 y letra
--2022-07-21 : Se agrego And @iTipo = 0 en 4+2 x que si tiene que pegar Evento+Zona ya deja a @cFormato como @cZona y despues pega @cZona + @cZona
--2022-10-25 : Se agrego Conexion=0 para buscar formatos por dll sin conexion
Set NoCount On
BEGIN TRY
Declare @message nVarChar(Max) = '',
	    @StartDateTimeText VarChar(Max) = '',
		@cFormato nVarChar(10) = '',
		@cOriginal nVarChar(10) = ''

If @iCuenta=0
	Set @iCuenta = NUll

IF (@iCuenta IS NULL)
BEGIN
	Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] Se descarto por iCuenta null';
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	Set NoExec On
END

IF @cDebug = 'Si'
Begin
	Print '[SGSP_IRSBuscoFormato]  @iReceptor  : ' + CONVERT(VARCHAR(10), @iReceptor)
	Print '[SGSP_IRSBuscoFormato]  @iCuenta    : ' + CONVERT(VARCHAR(10), @iCuenta)
	Print '[SGSP_IRSBuscoFormato]  @iTipo      : ' + CONVERT(VARCHAR(10), @iTipo)
	Print '[SGSP_IRSBuscoFormato]  @cEvento    : ' + @cEvento
	Print '[SGSP_IRSBuscoFormato]  @cZona      : ' + @cZona
	Print '[SGSP_IRSBuscoFormato]  @cProtocolo : ' + @cProtocolo
	Print '[SGSP_IRSBuscoFormato]  @iConexion  : ' + CONVERT(VARCHAR(10), @iConexion)
End

Declare @iMapFwd Int = 0 

Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | @iLoopCtrl ('+Cast(@iLoopCtrl As Varchar(10))+')'
RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

Set @iLoopCtrl = @iLoopCtrl + 1
If @iLoopCtrl > 5
	Begin
		Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | @iLoopCtrl ('+Cast(@iLoopCtrl As Varchar(10))+') No Procesa '
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

		Set NoExec On
	End

Set @cFormato = Rtrim(@cEvento)
If Len(@cProtocolo) >= 3
	Set @cProtocolo = Left(@cProtocolo,3)

/*
If @cProtocolo IN('4+2','1/3','PIMA')	--Si es 4+2 no hay resolucion por evento+zona
	Begin
		If @cZona<>''
			Set @cFormato = @cZona
		Else
			Begin
				If Len(@cFormato)=2 And Left(@cFormato,1)='0'
					Set @cFormato = Right(@cFormato,1)
			End
	End
Else
	Begin 
		If @iTipo = 1
			Begin
				Set @cOriginal = @cFormato
				Set @cFormato = @cFormato+@cZona
			End
	End
*/

If @cProtocolo IN('4+2','1/3','PIMA')
Begin
	If @cZona!='' And @iTipo = 0
		Set @cFormato = @cZona
	Else
		Begin
			If Len(@cFormato)=2 And Left(@cFormato,1)='0' And @cFormato!='00' And ( Select ISNUMERIC(Right(@cFormato,1)) ) > 0 
				Set @cFormato = Right(@cFormato,1)
		End
End

If @iTipo = 1
	Begin
		Set @cOriginal = @cFormato
		Set @cFormato = @cFormato+@cZona
	End

Set @cFormato = Ltrim(Rtrim(@cFormato))

Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | Busco cFormato ('+@cFormato+') en las Zonas de la Cuenta id ('+Cast(@iCuenta As Varchar(10))+')' 
RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
Select Top 1 @cAlarma=zon_codigoalarma From m_zonas Where zon_iidcuenta=@iCuenta And zon_ccodigo=@cFormato

If @cAlarma Is Null Or @cAlarma=''
	Begin	
		Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | Busco cFormato ('+@cFormato+') con *'
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
		Select Top 1 @cAlarma=zon_codigoalarma From m_zonas Where zon_iidcuenta=@iCuenta And zon_ccodigo=Left(@cFormato,1)+'*'

		If @cAlarma Is Null Or @cAlarma=''
			Begin
				Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | Busco en Zonas de la Cuenta si tiene un MAP'
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			    Select Top 1 @iCtaMap=cue_iid From m_cuentas
					Inner Join m_zonas ON cue_clinea=zon_cdealer And cue_ncuenta=zon_ccuenta 
				Where zon_iidcuenta=@iCuenta And zon_ccodigo='MAP' 
	
				If @iCtaMap > 0 And @iLoopCtrl = 1
					Begin
						--Set @cAlarma = '@M@'
						Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
						Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | MAP ejecuto recursivo [SGSP_IRSBuscoFormato]'
						RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
						IF @cDebug = 'Si'
						Begin
							Print ' @iReceptor  : ' + CONVERT(VARCHAR(10), @iReceptor)
							Print ' @iCuenta    : ' + CONVERT(VARCHAR(10), @iCtaMap)
							Print ' @iTipo      : ' + CONVERT(VARCHAR(10), @iTipo)
							Print ' @cEvento    : ' + @cEvento
							Print ' @cZona      : ' + @cZona
							Print ' @cProtocolo : ' + @cProtocolo
						End
						
						Set @iMapFwd = @iCtaMap
						Execute [dbo].[SGSP_IRSBuscoFormato] @iReceptor = @iReceptor, @iCuenta = @iCtaMap, @iTipo = @iTipo,	@cEvento = @cEvento, @cZona = @cZona, @cProtocolo = @cProtocolo, @cAlarma = @cAlarma OUTPUT, @iCtaMap = @iCtaMap OUTPUT, @iCtaFwd = @iCtaFwd OUTPUT, @iLoopCtrl = @iLoopCtrl OUTPUT
						Set @iCtaMap = @iMapFwd
					End
				Else
					Begin
						Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
						Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | Busco en Zonas de la Cuenta si tiene un FWD'
						RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

						Select Top 1 @iCtaFwd=cue_iid From m_cuentas
							Inner Join m_zonas ON cue_clinea=zon_cdealer And cue_ncuenta=zon_ccuenta 
						Where zon_iidcuenta=@iCuenta And zon_ccodigo='FWD'
	
						If @iCtaFwd > 0 And @iLoopCtrl = 1
							Begin
								--Set @cAlarma = '@F@'
								Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
								Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | FWD ejecuto recursivo [SGSP_IRSBuscoFormato]'
								RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
								Set @iMapFwd = @iCtaFwd
								IF @cDebug = 'Si'
								Begin
									Print ' @iReceptor  : ' + CONVERT(VARCHAR(10), @iReceptor)
									Print ' @iCuenta    : ' + CONVERT(VARCHAR(10), @iMapFwd)
									Print ' @iTipo      : ' + CONVERT(VARCHAR(10), @iTipo)
									Print ' @cEvento    : ' + @cEvento
									Print ' @cZona      : ' + @cZona
									Print ' @cProtocolo : ' + @cProtocolo
								End

								Execute [dbo].[SGSP_IRSBuscoFormato] @iReceptor = @iReceptor, @iCuenta = @iMapFwd, @iTipo = @iTipo,	@cEvento = @cEvento, @cZona = @cZona, @cProtocolo = @cProtocolo, @cAlarma = @cAlarma OUTPUT, @iCtaMap = @iCtaMap OUTPUT, @iCtaFwd = @iCtaFwd OUTPUT, @iLoopCtrl = @iLoopCtrl OUTPUT
								Set @iCtaFwd = @iMapFwd
							End
						Else
							Begin
								Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)
								Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | No encontro. Busco cFormato Original ('+@cOriginal+') en las Zonas de la Cuenta id ('+Cast(@iCuenta As Varchar(10))+')' 
								RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
								Select Top 1 @cAlarma=zon_codigoalarma From m_zonas Where zon_iidcuenta=@iCuenta And zon_ccodigo=@cOriginal

								If @cAlarma Is Null Or @cAlarma=''And @iConexion > 0
								Begin
									Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
									Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | No encontro ni en Zonas ni * ni MAP ni FWD. Busco cFormato ('+@cFormato+') en formatos del receptor que envio el evento utilizando conexion ('+Convert(VarChar(10), @iConexion)+')'
									RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

									Select Top 1 @cAlarma=for_calarma From m_receptores_cab a
										Inner Join m_receptores_item b On b.rec_iid=a.rec_iid
										Inner Join m_formatos On for_ccodigo=b.rec_cformato
									Where a.rec_iid = @iReceptor And for_cformato = @cFormato And b.rec_iConexion=@iConexion
								End

								If @cAlarma Is Null Or @cAlarma=''
								Begin 
									Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
									Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | No encontro ni en Zonas ni * ni MAP ni FWD. Busco cFormato ('+@cFormato+') en formatos del receptor que envio el evento'
									RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

									Select Top 1 @cAlarma=for_calarma From m_receptores_cab a
										Inner Join m_receptores_item b On b.rec_iid=a.rec_iid
										Inner Join m_formatos On for_ccodigo=b.rec_cformato
									Where a.rec_iid = @iReceptor And for_cformato = @cFormato And b.rec_iConexion=0
								End			

								If @cAlarma Is Null Or @cAlarma=''
									Begin 
										If @cOriginal<>''	--Si no encontro con EVENTO+ZONA busco con EVENTO
										Begin
											If @iConexion > 0
											Begin
												Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
												Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | No encontro. Busco cFormato Original ('+@cOriginal+') en formatos del receptor que envio el evento utilizando conexion ('+Convert(VarChar(10), @iConexion)+')'
												RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

												Select Top 1 @cAlarma=for_calarma From m_receptores_cab a
													Inner Join m_receptores_item b On b.rec_iid=a.rec_iid
													Inner Join m_formatos On for_ccodigo=b.rec_cformato
												Where a.rec_iid = @iReceptor And for_cformato = @cOriginal And b.rec_iConexion=@iConexion
											End
											
											If @cAlarma Is Null Or @cAlarma=''
											Begin 

												Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
												Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | No encontro. Busco cFormato Original ('+@cOriginal+')'
												RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

												Select Top 1 @cAlarma=for_calarma From m_receptores_cab a
													Inner Join m_receptores_item b On b.rec_iid=a.rec_iid
													Inner Join m_formatos On for_ccodigo=b.rec_cformato
												Where a.rec_iid = @iReceptor And for_cformato = @cOriginal And b.rec_iConexion=0
											End

											If @cAlarma Is Null Or @cAlarma=''
											Begin 
												Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
												Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | Busco cFormato ('+@cOriginal+') con *'
												RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
												Select Top 1 @cAlarma=zon_codigoalarma From m_zonas Where zon_iidcuenta=@iCuenta And zon_ccodigo=Left(@cOriginal,1)+'*'

												If @cAlarma Is Null Or @cAlarma=''
													Begin
														Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
														Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | Busco en Zonas de la Cuenta si tiene un MAP'
														RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

														Select Top 1 @iCtaMap=cue_iid From m_cuentas
															Inner Join m_zonas ON cue_clinea=zon_cdealer And cue_ncuenta=zon_ccuenta 
														Where zon_iidcuenta=@iCuenta And zon_ccodigo='MAP' 
	
														If @iCtaMap > 0 And @iLoopCtrl = 1
															Begin
																--Set @cAlarma = '@M@'
																Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
																Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | MAP ejecuto recursivo'
																RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
																Execute [dbo].[SGSP_IRSBuscoFormato] @iReceptor = @iReceptor, @iCuenta = @iCtaMap, @iTipo = @iTipo,	@cEvento = @cEvento, @cZona = @cZona, @cProtocolo = @cProtocolo, @cAlarma = @cAlarma OUTPUT, @iCtaMap = @iCtaMap OUTPUT, @iCtaFwd = @iCtaFwd OUTPUT, @iLoopCtrl = @iLoopCtrl OUTPUT
																Set @iCtaMap = 0
															End
														Else
														Begin
															Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
															Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | Busco en Zonas de la Cuenta si tiene un FWD'
															RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

															Select Top 1 @iCtaFwd=cue_iid From m_cuentas
																Inner Join m_zonas ON cue_clinea=zon_cdealer And cue_ncuenta=zon_ccuenta 
															Where zon_iidcuenta=@iCuenta And zon_ccodigo='FWD'
	
															If @iCtaFwd > 0 And @iLoopCtrl = 1
																Begin
																	--Set @cAlarma = '@F@'
																	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
																	Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | FWD ejecuto recursivo'
																	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
																	Execute [dbo].[SGSP_IRSBuscoFormato] @iReceptor = @iReceptor, @iCuenta = @iCtaFwd, @iTipo = @iTipo,	@cEvento = @cEvento, @cZona = @cZona, @cProtocolo = @cProtocolo, @cAlarma = @cAlarma OUTPUT, @iCtaMap = @iCtaMap OUTPUT, @iCtaFwd = @iCtaFwd OUTPUT, @iLoopCtrl = @iLoopCtrl OUTPUT
																	Set @iCtaFwd = 0
																End
															Else
																Begin
																	If @cAlarma Is Null Or @cAlarma=''
																	Begin 
																		Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
																		Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | No encontro ni en Zonas ni * ni MAP ni FWD. Busco cFormato ('+@cOriginal+') en formatos del receptor que envio el evento'
																		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

																		Select Top 1 @cAlarma=for_calarma From m_receptores_cab a
																			Inner Join m_receptores_item b On b.rec_iid=a.rec_iid
																			Inner Join m_formatos On for_ccodigo=b.rec_cformato
																		Where a.rec_iid = @iReceptor And for_cformato = @cOriginal And b.rec_iConexion=0
																	End	
	        													End
														End
												End
										End
									End
								End
								If @cAlarma Is Null Or @cAlarma=''
									Set @cAlarma = '_NE'
								
	        				End
					End
			End
	End	

	--Select @cAlarma As cAlarma, @iCtaMap As iCtaMap, @iCtaFwd As iCtaFwd
	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_IRSBuscoFormato] | Alarma => '+@cAlarma+' | iCtaMap => '+Cast(@iCtaMap As Varchar(10))+' | iCtaFwd => '+Cast(@iCtaFwd As Varchar(10)) 
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	Set NoExec Off		
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
END CATCH


GO
/****** Object:  StoredProcedure [dbo].[SGSP_IRSBuscoIdCuenta]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SGSP_IRSBuscoIdCuenta]
	@iPuerto [int] = 0,
	@cCuenta [char](4) = '',
	@iConexion [int] = 0,
	@cLineCard [char](3) = '',
	@iIdCta [int] = 0 OUTPUT,
	@cLinea [char](3) = '' OUTPUT,
	@cue_cProvincia [char](3) = '' OUTPUT
AS
BEGIN
	--Busca Cuenta para IRServices
	--Devuelve el ID,la linea y la Pcia de una cuenta, usando el Puerto, la linea y el Codigo de Cuenta que leen las Dlls de los receptores
	--Autor : Pablo O. Canónico
	--Fecha : 13/04/2018
	--10-07-2019 Se modifico para resolver por IRS con puertos seriales
	Set NoCount ON
	BEGIN TRY
	
	If @cLineCard = '' Or @cLineCard = '000'
		Set @cLineCard='1'

	Declare @iLineCard Int = Cast(@cLineCard As Int)

	If @iConexion=0		--Viene de CS
	Begin
		Select Top 1 @iIdCta = C.cue_iid, @cLinea = C.cue_clinea, @cue_cProvincia = cue_cProvincia
			From m_cuentas C With (NOLOCK)
				Inner Join  _Tablas.Dbo.t_port_alias On C.cue_clinea=tpa_cdealer
				Inner Join  _Tablas.Dbo.t_puertos On pue_icodigo=tpa_ipuerto
				Inner Join _Tablas.Dbo.t_LineasXPuerto On lxp_iAlias=tpa_icodigo
			Where pue_npuerto = @iPuerto And C.cue_ncuenta = @cCuenta And pue_nestado<>1
						And lxp_nLinea=@iLineCard And lxp_nEstado=1
						--And ( @iConexion=0 Or [pue_idKey]=@iConexion )

		If @iIdCta Is null Or @iIdCta=0
			Select Top 1 @iIdCta = C.cue_iid, @cLinea = C.cue_clinea, @cue_cProvincia = cue_cProvincia
				From m_cuentas C With (NOLOCK)
					Inner Join  _Tablas.Dbo.t_port_alias On C.cue_clinea=tpa_cdealer
					Inner Join  _Tablas.Dbo.t_puertos On pue_icodigo=tpa_ipuerto
				Where pue_npuerto = @iPuerto And C.cue_ncuenta = 'XXXX'
	End
	Else
	Begin
		Select Top 1 @iIdCta = C.cue_iid, @cLinea = C.cue_clinea, @cue_cProvincia = cue_cProvincia
			From m_cuentas C With (NOLOCK)
				Inner Join  _Tablas.Dbo.t_port_alias On C.cue_clinea=tpa_cdealer
				Inner Join  _Tablas.Dbo.t_ip_con On ipc_icodigo=tpa_iportip
				Inner Join _Tablas.Dbo.t_LineasXPuerto On lxp_iAlias=tpa_icodigo
			Where ipc_nport = @iPuerto And C.cue_ncuenta = @cCuenta And ipc_nestado<>1
						And lxp_nLinea=@iLineCard And lxp_nEstado=1
						And ( @iConexion=0 Or [ipc_idKey]=@iConexion )

		If @iIdCta Is null Or @iIdCta=0
			Select Top 1 @iIdCta = C.cue_iid, @cLinea = C.cue_clinea, @cue_cProvincia = cue_cProvincia
				From m_cuentas C With (NOLOCK)
					Inner Join  _Tablas.Dbo.t_port_alias On C.cue_clinea=tpa_cdealer
					Inner Join  _Tablas.Dbo.t_ip_con On ipc_icodigo=tpa_iportip
				Where ipc_nport = @iPuerto And C.cue_ncuenta = 'XXXX'
	End
	END TRY
	BEGIN CATCH
		IF ERROR_NUMBER() = 2627
		BEGIN
			PRINT 'Handling PK violation...';
		END;
		ELSE IF ERROR_NUMBER() = 547
		BEGIN
			PRINT 'Handling CHECK/FK constraint violation...';
		END;
		ELSE IF ERROR_NUMBER() = 515
		BEGIN
			PRINT 'Handling NULL violation...';
		END;
		ELSE IF ERROR_NUMBER() = 245
		BEGIN
			PRINT 'Handling conversion error...';
		END;
		ELSE
		BEGIN
			PRINT 'Re-throwing error...';
		END;

		PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VarChar(10));
		PRINT 'Error Message : ' + ERROR_MESSAGE();
		PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
		PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
		PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
		PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
	END CATCH
END


GO
