/****** Object:  StoredProcedure [dbo].[SGSP_IRSEventosEnFalloTesteo]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE   PROCEDURE [dbo].[SGSP_IRSEventosEnFalloTesteo]
	@cAlarma [Char](3) = '',
	@idCta [int] = 0
AS
--Verifica si hay eventos en Fallo de Testeo
--Autor : Pablo O. Canónico
--Fecha : 27/06/2024
Set NoCount On
BEGIN TRY
Declare @message nVarChar(Max) = '',
	    @StartDateTimeText VarChar(Max) = ''

Declare @iOperador Int = 0,
		@idRec Int = 0,
		@iEstado Int = 0
Declare @cCual Char(1) = '1'

Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
Set @message = 'Start DateTime : %s | [SGSP_IRSEventosEnFalloTesteo] | Verifico si hay eventos para ('+@cAlarma+') de la Cuenta id ('+Cast(@idCta As Varchar(10))+')' 
RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

--For perfomance issues--
If Exists ( Select Top 1 [eft_idKey] From [_Datos].[dbo].[EventosEnFalloTesteo] With (NOLOCK)
	Inner Join [_Datos].[dbo].[p_recepcion] With (NOLOCK) On [rec_iid] = [eft_iRecID]
	Where CHARINDEX(@cAlarma, eft_cAlarmaAutoprocesa) > 0 
		And [eft_iidCuenta] = @idCta 
		--And [rec_nEstado] In(0,2)
		)

	Begin
		Declare cCtrl CURSOR LOCAL STATIC READ_ONLY FORWARD_ONLY
			For	Select [eft_iRecID],Left([eft_cAlarmaAutoprocesa],1),[rec_ioperador],[rec_nestado]
				From [_Datos].[dbo].[EventosEnFalloTesteo] With (NOLOCK)
				Inner Join [_Datos].[dbo].[p_recepcion] With (NOLOCK) On [rec_iid] = [eft_iRecID]
				Where CHARINDEX(@cAlarma, eft_cAlarmaAutoprocesa) > 0 
					And [eft_iidCuenta] = @idCta 
					--And [rec_nEstado] In(0,2)
				Order By [eft_iRecID]

		Open cCtrl
		Fetch Next From cCtrl Into @idRec,@cCual,@iOperador,@iEstado
		While @@FETCH_STATUS = 0
		Begin
			If @idRec > 0
				Begin
					If @iEstado In(0,2)
					Begin
						--1ero actualizo pRecepcion--	
						Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
						Set @message = 'Start DateTime : %s | [SGSP_IRSEventosEnFalloTesteo] | Actualizo pRecepcion recId '+Cast(@idRec As Varchar(10)) 
						RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

						Update [_Datos].[dbo].[p_recepcion]
							Set rec_nEstado = 3, rec_tFechaProceso = GetDate()
						Where rec_iid = @idRec
			
						--2do Inserto TimeLine
						Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
						Set @message = 'Start DateTime : %s | [SGSP_IRSEventosEnFalloTesteo] | Inserto TimeLine'
						RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

						Insert Into [_Datos].[dbo].[EventosTimeLine]
									([etl_iRecID]
									,[etl_iCuenta]
									,[etl_tFechaHora]
									,[etl_cAccion]
									,[etl_cObservacion]
									,[etl_cOwner]
									,[etl_iOperador])
							Values
									(@idRec
									,@idCta
									,GetDate()
									,'Autoproceso'
									,'%Procesado Automaticamente x Evento : %'+@cAlarma
									,'%SISTEMA%'
									,@iOperador)
					End

					--3ro Actualizo mStatus
					Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
					Set @message = 'Start DateTime : %s | [SGSP_IRSEventosEnFalloTesteo] | Actualizo mStatus'
					RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

					If @cCual = '1'
						Update [_Datos].[dbo].[m_status] Set sta_ncuentaenfallodetst=0 Where sta_iidcuenta=@idCta
					Else If @cCual = '2'
						Update [_Datos].[dbo].[m_status] Set sta_ncuentaenfallo2dotst=0 Where sta_iidcuenta=@idCta
					Else If @cCual = '3'
						Update [_Datos].[dbo].[m_status] Set sta_ncuentaenfallo3ertst=0 Where sta_iidcuenta=@idCta

					--4to Elimino de [EventosEnFalloTesteo]
					Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
					Set @message = 'Start DateTime : %s | [SGSP_IRSEventosEnFalloTesteo] | Elimino de [EventosEnFalloTesteo] | [eft_iRecID] => '+Cast(@idRec As Varchar(10)) 
					RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

					Delete From [_Datos].[dbo].[EventosEnFalloTesteo]
						Where  [eft_iRecID] = @idRec
						And [eft_iidCuenta] = @idCta 

				End

			Fetch Next From cCtrl Into @idRec,@cCual,@iOperador,@iEstado
		End

		Close cCtrl
		Deallocate cCtrl
	End
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
END CATCH

GO
/****** Object:  StoredProcedure [dbo].[SGSP_IRSHeartBeats]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [dbo].[SGSP_IRSHeartBeats]
	@iPuerto Int = 0,
	@tFechaHora DateTime = Null,
	@cIMEI nVarChar(20) = '',
	@cCorteLinea Char(3) = '',
	@cEntDigital Char(2) = '',
	@iNivel Int = 0,
	@iTension Int = 0,
	@iConexion Int = 0
As
--Actualiza pHeartBeats  para IRServices
--Autor : Pablo O. Canónico
--Fecha : 03/07/2017
--Modificado 05-01-2022 Se agrego grabacion con el valor de la conexion

Set NoCount ON
BEGIN TRY
Declare @message nVarChar(Max) = '',
	    @StartDateTimeText VarChar(Max) = ''

If @cIMEI = '' Or @iPuerto = 0
	Begin
		Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | IMEI o Puerto sin valor'
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

		Set NoExec On
	End

Declare @cInfoExtra nVarChar(200) = ''
If @cCorteLinea IN('ED','SC','RK','NT','AL','WI')		--En @cEntDigital viene info extra de los Nanocomm,Scanner,RKTracker,NTCom,AlonsoUniversal y WiConnect
	Set @cInfoExtra= Rtrim(@cEntDigital)

MERGE INTO [dbo].[p_HeartBeats] AS TGT
USING ( Select @tFechaHora As tFechaHora, @iPuerto As iPuerto, @cIMEI As cIMEI, @cCorteLinea As cCorteLinea, @cEntDigital As cEntDigital, @iNivel As iNivel, @cInfoExtra As cInfoExtra, @iConexion As iConexion ) As SRC 
		ON TGT.[hbs_ipuerto] = SRC.[iPuerto] And TGT.[hbs_cIMEI] = SRC.[cIMEI] And TGT.[hbs_iConexion] = SRC.[iConexion]
WHEN MATCHED THEN
	UPDATE SET
	   TGT.[hbs_tfechahora] = SRC.[tFechaHora],
       TGT.[hbs_cCorteLinea] = SRC.[cCorteLinea],
       TGT.[hbs_cEntDigital] = SRC.[cEntDigital],
       TGT.[hbs_nNivel] = SRC.[iNivel],
       TGT.[hbs_cInfoExtra] = SRC.[cInfoExtra]	  
WHEN NOT MATCHED THEN 
	INSERT  ([hbs_tfechahora],[hbs_ipuerto],[hbs_cIMEI],[hbs_cCorteLinea],[hbs_cEntDigital],[hbs_nNivel],[hbs_cInfoExtra],[hbs_iConexion])
     VALUES (SRC.[tFechaHora],[iPuerto],[cIMEI],[cCorteLinea],[cEntDigital],[iNivel],[cInfoExtra],[iConexion]);

/*Se paso a un trigger
If @cIMEI <> '' And @cIMEI <> '####'
	Begin
		--Actualizo 2do Testeo
		Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | --Actualizo 2do Testeo--'
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

		Declare @iCta Int = 0
		Select Top 1 @iCta=cue_iid From m_cuentas 
			Left Outer Join m_tst_prueba On cue_iid=tst_iidCuenta
			Where ( cue_ncuenta=@cIMEI Or cue_cIMEI=@cIMEI )
			And tst_ncada2>0 And tst_calarmaesperada ='_KA' 

		If @iCta > 0 
			UPDATE m_status
				SET sta_dfechaultimo2dotst=GetDate(), sta_nCuentaEnFallo2doTST = 0 
				Where sta_iidcuenta=@iCta
	End
*/
Set NoExec Off		
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
END CATCH


GO
/****** Object:  StoredProcedure [dbo].[SGSP_IRSRedirectorEventos]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [dbo].[SGSP_IRSRedirectorEventos]
	@iCuenta [int] = 0,
	@iRecID [int] = 0,
	@cAlarma Char(3) = ''
AS
--Redirector de Eventos para IRServices
--Autor : Pablo O. Canónico
--Fecha : 19/06/2017
--2020-12-23 : Se controla VERSIONREDIRECTOR
--2024-06-14 : Si es RedirectorSoftGuardWAAutomation se cambia de estado al evento
Set NoCount ON
BEGIN TRY
Declare @message nVarChar(Max) = '',
	    @StartDateTimeText VarChar(Max) = ''

Declare @cDealer Char(3) = ''
--1ro. busco el dealer de la cuenta
Select @cDealer=cue_cLinea From m_cuentas Where cue_iid=@iCuenta

If @cDealer Is Null
	Begin
		Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | [SGSP_IRSRedirectorEventos] | Busco el dealer de iCta ('+Cast(@iCuenta As Varchar(10))+') devolvio null'
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

		Set NoExec On
	End

--2do. busco si hay Destino a los cuales redirigir el evento
Declare	@cHandlerURL nVarChar(1000)=''

Select Top 1 @cHandlerURL=rrd_cURL
	From _Tablas.dbo.t_ReDirector
	Inner Join _Tablas.dbo.t_ReDirectorDestino On rrd_idKey=trd_iDestino
	Where CHARINDEX(@cAlarma,trd_cEventos) > 0   And (trd_cDealer=@cDealer or trd_cDealer = '')

If @cHandlerURL Is Null Or @cHandlerURL=''
	Begin
		Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | [SGSP_IRSRedirectorEventos] | No hay Destino al cual redirigir el evento'
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

		Set NoExec On
	End


--3ro. si hay que redirigir verifico la URL
Declare @cURLDesktop nVarChar(1000)= ( Select par_cValor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='URLDESKTOP' )
If Upper(Rtrim(@cURLDesktop)) = Upper('http://DesktopURL:PORT')
	Begin
		Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | [SGSP_IRSRedirectorEventos] | Falta configurar el parametro URLDESKTOP'
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

		Set NoExec On
	End

Declare @cParamURL nVarChar(10) = 'rec_iid'
Declare @idGps Int = 0
--4to. si @iRecID viene con 0 quiere decir que es una posicion y no se guardo en pRecepcion por lo tanto tengo que informar el gps_iid en lugar de rec_iid
If @iRecID = 0
	Begin
		Select Top 1 @iRecID=[gps_iid] From p_posicionesGPS
			Where [gps_idCuenta] = @iCuenta And [gps_idRec] = 0
			Order By [gps_iid] Desc

		If @iRecID = 0
			Begin
				Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | [SGSP_IRSRedirectorEventos] | @iRecID viene con 0 y No hay posiciones guardadas'
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

				Set NoExec On
			End

		Set @cParamURL = 'gps_iid'
		Set @idGps = @iRecID
	End

--5to. si llego por parametro el tiRecId > 0 o se obtuvo el valor en el paso Cuarto puedo seguir
--Ver version del redirector    0=version remotecall (legacy)  1=Version redirector (new service)
Declare	@iVersion int = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='VERSIONREDIRECTOR' )
Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
Set @message = 'Start DateTime : %s | [SGSP_IRSRedirectorEventos] | iVersion => '+ Cast(@iVersion As VarChar(10)) 
RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

If @iVersion = 0
Begin
	;WITH cReDirector 
	AS
	(Select rrd_cURL
		From _Tablas.dbo.t_ReDirector
		Inner Join _Tablas.dbo.t_ReDirectorDestino On rrd_idKey=trd_iDestino
		Where CHARINDEX(@cAlarma,trd_cEventos) > 0  And (trd_cDealer=@cDealer or trd_cDealer = '')
	)
	INSERT INTO [dbo].[RemoteCallQueue]
		Select 0 ,'HTTPGET',Ltrim(@cURLDesktop)+Ltrim(rrd_cURL)+'?'+@cParamURL+'='+Ltrim(Cast(@iRecID As Varchar(10))),Null,Null,Null,Null,Null
		From cReDirector 

End
Else
Begin
	;WITH cReDirector 
	AS
	(Select trd_idKey,rrd_cURL
		From _Tablas.dbo.t_ReDirector
		Inner Join _Tablas.dbo.t_ReDirectorDestino On rrd_idKey=trd_iDestino
		Where CHARINDEX(@cAlarma,trd_cEventos) > 0  And (trd_cDealer=@cDealer or trd_cDealer = '')
		)
	INSERT INTO [dbo].[RedirectorQueue] ([rdq_iReDirector], [rdq_idRec], [rdq_idGps], [rdq_tFechaHora], [rdq_cLlamado], [rdq_cRespuesta])  
		Select trd_idKey,Case When @idGps=0 Then @iRecID Else 0 End,@idGps,Getdate(), Ltrim(@cURLDesktop)+Ltrim(rrd_cURL)+'?'+@cParamURL+'='+Ltrim(Cast(@iRecID As Varchar(10))),Null 
		From cReDirector 

		If @iRecID > 0
		Begin
			Declare @Exists Int = 0
			Select Top 1 @Exists=[trd_idkey]
				From _Tablas.dbo.t_ReDirector
				Inner Join _Tablas.dbo.t_ReDirectorDestino On rrd_idKey=trd_iDestino
				Where CHARINDEX(@cAlarma,trd_cEventos) > 0  And (trd_cDealer=@cDealer or trd_cDealer = '') And [rrd_cNombre]='RedirectorSoftGuardWAAutomation'
	
			IF @Exists > 0
			Begin
				Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | [SGSP_IRSRedirectorEventos] | Se dispara RedirectorSoftGuardWAAutomation. Hay que cambiar estado del evento'
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

				Declare @Obs nVarchar(max) = ''
				Declare @iEstado Int = 0
				Select @Obs=rec_cobservaciones, @iEstado=rec_nestado From [_Datos].[dbo].[p_recepcion] Where rec_iid = @iRecId
				
				If @iEstado = 0 -- Evento Nuevo/Pendiente	
				Begin
					Declare @cObservaciones nVarchar(Max)
					Declare @translation nVarchar(Max)=''

					Execute [_Desktop].[dbo].[LocalizationGetLocale] @Name = N'En Espera Automaticamente aguardando notificacion por WhatsApp ', @soloOutput=1, @translation = @translation OUTPUT
					Set @cObservaciones = '['+Convert(Varchar, GetDate(), 103)+' ' +Substring(Convert(Varchar, GetDate(), 114), 1, 5)+  '] [Sistema] '+ Rtrim(@translation)

					Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
					Set @message = 'Start DateTime : %s | SGSP_IRSRedirectorEventos | Update => '+ @cObservaciones
					RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

					If (@Obs Is Not Null And @Obs != '')
						Set @Obs += Char(13) + @cObservaciones
					Else
						Set @Obs = @cObservaciones
					
					Declare @iMinutosEspera Int = 0
					Select @iMinutosEspera=par_ivalor From [_Tablas].[dbo].[t_parametros] Where [par_ccodigo] = 'TIEMPOREDIRECTORWA'
					
					If (@iMinutosEspera Is null Or @iMinutosEspera=0)
						Set @iMinutosEspera = 10

					Update p_recepcion	
						Set rec_nEstado=2, rec_cObservaciones=@Obs, rec_iMinutosEspera=@iMinutosEspera
					Where rec_iid = @iRecId
				End
				Else
				Begin
					Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
					Set @message = 'Start DateTime : %s | [SGSP_IRSRedirectorEventos] | El evento no esta pendiente. Estado =>' + Cast(@iEstado As Char(1))
					RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
				End
			End
		End
End

Set NoExec Off		
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
END CATCH

GO
/****** Object:  StoredProcedure [dbo].[SGSP_IRSRespuestaComandos]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



Create   Procedure [dbo].[SGSP_IRSRespuestaComandos]
	@iRecId [int] = 0,
	@cRespuesta [VarChar](1000) = '',
	@iReceptor  [int] = 0

AS
--Guarda la respuesta de los comandos de IBR-AMT recibidos en IRS
--Autor :Pablo O. Canónico
--Fecha :30/09/2020
--crx_iStatus Descripcion
--	0		Pendiente
--	1		Con Respuesta
--	2		Procesado

Set NoCount On

BEGIN TRY

	Declare @message VarChar(Max) = '',
		    @StartDateTimeText VarChar(Max) = '',
			@cComando VarChar(200) = ''

	Declare @idKey Int = 0
	Declare @iCmdId Int = 0
	Select Top (1) @idKey = [crx_idKey], @iCmdId = [crx_iCmdId] From [dbo].[p_ComandosRX] 
		Inner Join [dbo].[p_comandos_ip] On [cmd_iid]=[crx_iCmdId] 
	Where [crx_iStatus]=0 And [cmd_idReceptor]=@iReceptor Order By [crx_tFechaHora]
	
	If @iCmdId Is Null Or @iCmdId = 0
	Begin
		Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | [SGSP_IRSRespuestaComandos] | Id Key en cero. No hay [p_ComandosRX] pendientes para Receptor : '+ CONVERT(VARCHAR(10), @iReceptor)
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

		Set NoExec On
	End

	Update [dbo].[p_ComandosRX]
		Set [crx_iRecId] = @iRecId
		   ,[crx_iStatus] = 1
		   ,[crx_tStatusExec] = GetDate()
	Where [crx_idKey]=@idKey

	Update [dbo].[p_comandos_ip]
		Set [cmd_cRespuesta] = @cRespuesta
	Where [cmd_iid] = @iCmdId

	Set NoExec Off		
END TRY
BEGIN CATCH
		IF ERROR_NUMBER() = 2627
		BEGIN
			PRINT 'Handling PK violation...';
		END;
		ELSE IF ERROR_NUMBER() = 547
		BEGIN
			PRINT 'Handling CHECK/FK constraint violation...';
		END;
		ELSE IF ERROR_NUMBER() = 515
		BEGIN
			PRINT 'Handling NULL violation...';
		END;
		ELSE IF ERROR_NUMBER() = 245
		BEGIN
			PRINT 'Handling conversion error...';
		END;
		ELSE
		BEGIN
			PRINT 'Re-throwing error...';
		END;

		PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
		PRINT 'Error Message : ' + ERROR_MESSAGE();
		PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
		PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
		PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
		PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
END CATCH

GO
/****** Object:  StoredProcedure [dbo].[SGSP_jSonMailParser]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
