CREATE PROCEDURE [dbo].[SGSP_jSonMailParser] @json As nVarChar(max) As
--Parsea el jSon de los mails recibidos de HikVision
--Autor :Pablo O. Canónico
--Fecha :05/05/2016
--27/03/2018	NO PUEDEN SER NVARCHAR x que romper el parseo hacia la dll de IR
SET NOCOUNT ON
Declare @name As VarChar(max) = '',
 @stringValue As VarChar(max) = '',
 @subject As VarChar(250) = '',
 @body As VarChar(2000) = '',
 @path As VarChar(1000) = ''
--No son VarChar(Max) for backguard compatibility

If Len(@json) > 2
Begin
	Declare jCursor Cursor Scroll
		For Select Name,StringValue From _Datos.dbo.parseJSON(@json) 

		Open jCursor
		FETCH NEXT FROM jCursor INTO @name,@stringValue

		WHILE @@FETCH_STATUS = 0
		Begin
			If @name ='subject'
				Set @subject = @stringValue
			Else
				If @name ='body'
					Set @body = @stringValue
				Else
					If @name ='path'
						Set @path = @path + @stringValue +'|'

			FETCH NEXT FROM  jCursor INTO @name,@stringValue
		End

	Close jCursor
	DEALLOCATE jCursor
End
Select @subject As Subject, @body As Body, @path As Path


GO
/****** Object:  StoredProcedure [dbo].[SGSP_MGSGetMensajes]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SGSP_MGSGetMensajes]
	@cTerminal [char](3) = '',
	@iModemSMS [int] = 0,
	@iEstado [int] = 0

WITH EXECUTE AS CALLER
AS
--Es el store que ejecuta MessagingGatewayService para obetener los mensajes pendientes de enviar
--Autor :Pablo O. Canónico
--Fecha :17/07/2018
--
--Estado en p_SMSqueue
--que_nEstado= 0		Pendiente
--que_nEstado= 1		Enviado
--que_nEstado= 2		Rechazado
--que_nEstado= 3		Conmuto a Mail
--que_nEstado= 4		En proceso

Set NoCount On
BEGIN TRY
	--Para buscar los mensajes pendientes mayores a una hora hacia atras
	Declare @tFechaHoraInicio DateTime = DATEADD(hh, -1, GetDate())

	--Le cambio el estado al mensaje
	;WITH Updates 
	AS
	(Select [que_nEstado] From [dbo].[p_SMSqueue]
			Inner Join [_Tablas].[dbo].[t_modems_sms] On [que_iModemSMS]=[sms_icodigo]
			Inner Join [_Tablas].[dbo].[t_GatewaysMSG] On [sms_igateway]=[tgm_idKey]
		Where [que_nEstado] = @iEstado And que_tfechahora >= @tFechaHoraInicio
		  And [sms_cterminal] = @cTerminal
		  And [que_iModemSMS] = @iModemSMS
		  And [que_nEstado] NOT IN(1,3) 
	) UPDATE Updates
	Set [que_nEstado] = 4

	--Devuelvo todos los que se estan procesando ;)
	Select que_iid,que_tfechahora,que_idCuenta,que_cAsunto,que_cDestino,que_idCmd
		From [dbo].[p_SMSqueue]
			Inner Join [_Tablas].[dbo].[t_modems_sms] On [que_iModemSMS]=[sms_icodigo]
			Inner Join [_Tablas].[dbo].[t_GatewaysMSG] On [sms_igateway]=[tgm_idKey]
		Where [que_nEstado] = 4 And que_tfechahora >= @tFechaHoraInicio
		  And [sms_cterminal] = @cTerminal
		  And [que_iModemSMS] = @iModemSMS
		Order By que_tfechahora,que_iid

	Set NoExec Off		
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');

END CATCH


GO
