Create PROCEDURE [dbo].[SGSP_p_grabacion_audioINS] 
	@iidcuenta [int] = 0,
	@iidrecepcion [int] = 0,
	@dfechahora [datetime] = '',
	@carchivo [varchar](30) = '',
	@nduracion [numeric](10, 2) = 0,
	@ioperador [int] = 0,
	@cTerminal [char](3) = '',
	@iidLlamado [int] = 0,
	@nestado [numeric] (1, 0) = 0,
	@ctelefono [varchar] (30) = '',
	@iValor [int] = 0 OUTPUT
AS
--Es el store que ejecuta la insercion en p_grabacion_audio de _History
--Autor :Pablo O. Canónico
--Fecha :01/08/2023
Set NoCount On
BEGIN TRY
	Declare @message nVarChar(Max) = '',
	    @StartDateTimeText VarChar(max) = ''
	
	Declare @cCierre Char(6) = CONVERT(CHAR(6), @dfechahora, 112)
	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_p_grabacion_audioINS] | cCierre : '+@cCierre
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	--Creo el Historico necesario
	Declare	@nError Int = 0
	IF OBJECT_ID('[_History].[dbo].p_grabacion_audio'+@cCierre) Is Null
	Begin
		Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | [SGSP_p_grabacion_audioINS] | Execute [_History].[dbo].[SGSP_CreoGRADepurado]' 
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

		Execute @nError = [_History].[dbo].[SGSP_CreoGRADepurado] @cCierre=@cCierre , @cDebug = 'N', @nError = 0
	End
	If @nError = -9	--No pudo crear historico
		Begin
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | [SGSP_p_grabacion_audioINS] | [SGSP_CreoGRADepurado] Volvio con error. No se pudo crear historico' 
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
		End
	Else
		Begin		
			Declare @cSQL nVarchar(MAX)
			Set @cSQL = 'INSERT INTO [_History].[dbo].[p_grabacion_audio' +  @cCierre  + '] ([gra_iidcuenta],[gra_iidrecepcion],[gra_dfechahora],[gra_carchivo],[gra_nduracion],[gra_ioperador],[gra_cTerminal],[gra_iidLlamado],[gra_nestado],[gra_ctelefono])'
			Set @cSQL += 'VALUES (@iidcuenta,@iidrecepcion,@dfechahora,@carchivo,@nduracion,@ioperador,@cTerminal,@iidLlamado,@nestado,@ctelefono)'

			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | [SGSP_p_grabacion_audioINS] | cSQL : ' + @cSQL
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			Declare @DynamicSqlParams NVarchar(MAX)
			Set @DynamicSqlParams = '@iidcuenta [int],@iidrecepcion [int],@dfechahora [datetime],@carchivo [varchar](30),@nduracion [numeric](10, 2),@ioperador [int],@cTerminal [char](3),@iidLlamado [int],@nestado [numeric] (1, 0),@ctelefono [varchar] (30)'

			Set @message = 'Start DateTime : %s | [SGSP_p_grabacion_audioINS] | DynamicSqlParams : ' + @DynamicSqlParams
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			Execute sp_executesql @cSQL, @DynamicSqlParams, @iidcuenta=@iidcuenta, @iidrecepcion=@iidrecepcion, @dfechahora=@dfechahora, @carchivo=@carchivo, @nduracion=@nduracion,	@ioperador=@ioperador, @cTerminal=@cTerminal, @iidLlamado=@iidLlamado, @nestado=@nestado, @ctelefono=@ctelefono
										
			Select @iValor = SCOPE_IDENTITY()	--Para el OUTPUT
			--Select @iValor As iValor			--Para tener cursor de devolucion

			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | [SGSP_p_grabacion_audioINS] | iValor ('+Cast(@iValor As Varchar(10))+')' 
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
		End

	Set NoExec Off	
		
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');

END CATCH


GO
