CREATE PROCEDURE [dbo].[SGSP_p_PosicionesINS] 
	@tFechahora [Datetime] = NULL,
	@idCuenta [Int] = 0,
	@idRec [Int] = 0,
	@rLatitud [Real] = 0,
	@rLongitud [Real] = 0,
	@iRumbo [Int] = 0,
	@tRawfechahora [Datetime] = NULL,
	@iVelocidad [Int] = 0,
	@iOdometro [Int] = 0,
	@cDireccion [nVarchar](300) = '',
	@cIMEI [Varchar](128) = '',
	@rAccuracy [Real] = 0,
	@cMethod [Varchar](10) = '',
	@iBattery [Int] = 0,
	@iExtBattery [Int] = 0,
	@iNivelSenial [Int] = 0,
	@iSatelites [Int] = 0,
	@iSecuencia [Int] = 0,
	@iFuel [Int] = 0,
	@iEngineStatus [Int] = 0,
	@iValor [int] = 0 OUTPUT
AS
--Es el store que ejecuta la insercion en p_Posiciones
--Autor :Pablo O. Canónico
--Fecha :04/10/2018
Set NoCount On
BEGIN TRY
	Declare @message nVarChar(Max) = '',
	    @StartDateTimeText VarChar(max) = ''

	If @idCuenta = 0
		Begin
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | [SGSP_p_PosicionesINS] | idCuenta en cero. No graba!!!' 
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			Set NoExec On
		End
	
	If @tfechahora Is Null
		Begin
			Set @tfechahora = GetDate()
			Set @tRawfechahora = GetDate()
		End
	
	Declare @cCierre Char(6) = CONVERT(CHAR(6), @tfechahora, 112)
	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_p_PosicionesINS] | cCierre : '+@cCierre
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	--Creo el Historico necesario
	Declare	@nError Int = 0
	IF OBJECT_ID('[_History].[dbo].p_Posiciones'+@cCierre) Is Null
	Begin
		Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | [SGSP_p_PosicionesINS] | Execute [_History].[dbo].[SGSP_CreoPOSDepurado]' 
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

		Execute @nError = [_History].[dbo].[SGSP_CreoPOSDepurado] @cCierre=@cCierre , @cDebug = 'N', @nError = 0
	End
	If @nError = -9	--No pudo crear historico
		Begin
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | [SGSP_p_PosicionesINS] | [SGSP_CreoPOSDepurado] Volvio con error. No se pudo crear historico' 
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
		End
	Else
		Begin		
			Declare @cSQL nVarchar(MAX)
			Set @cSQL = 'INSERT INTO [_History].[dbo].[p_Posiciones' +  @cCierre  + '] ([pos_tfechahora],[pos_idCuenta],[pos_idRec],[pos_rLatitud],[pos_rLongitud],[pos_iRumbo],[pos_tRawfechahora],[pos_iVelocidad],[pos_iOdometro],[pos_cDireccion],[pos_cIMEI],[pos_rAccuracy],[pos_cMethod],[pos_iBattery],[pos_iExtBattery],[pos_iNivelSenial],[pos_iSatelites],[pos_iSecuencia],[pos_iFuel],[pos_iEngineStatus])'
			Set @cSQL = @cSQL + 'VALUES (@tfechahora,@idCuenta,@idRec,@rLatitud,@rLongitud,@iRumbo,@tRawfechahora,@iVelocidad,@iOdometro,@cDireccion,@cIMEI,@rAccuracy,@cMethod,@iBattery,@iExtBattery,@iNivelSenial,@iSatelites,@iSecuencia,@iFuel,@iEngineStatus)'

			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | [SGSP_p_PosicionesINS] | cSQL : ' + @cSQL
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			Declare @DynamicSqlParams NVarchar(MAX)
			Set @DynamicSqlParams = '@tfechahora [Datetime],@idCuenta [Int],@idRec [Int],@rLatitud [Real],@rLongitud [Real],@iRumbo [Int],@tRawfechahora [Datetime],@iVelocidad [Int],@iOdometro [Int],@cDireccion [nVarchar](300),@cIMEI [Varchar](128),@rAccuracy [Real],@cMethod [Varchar](10),@iBattery [Int],@iExtBattery [Int],@iNivelSenial [Int],@iSatelites [Int],@iSecuencia [Int],@iFuel [Int],@iEngineStatus [Int]'

			Set @message = 'Start DateTime : %s | [SGSP_p_PosicionesINS] | DynamicSqlParams : ' + @DynamicSqlParams
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			Execute sp_executesql @cSQL, @DynamicSqlParams, @tFechahora=@tFechahora, @idCuenta=@idCuenta, @idRec=@idRec, @rLatitud=@rLatitud ,@rLongitud=@rLongitud, @iRumbo=@iRumbo, @tRawfechahora=@tRawfechahora, @iVelocidad=@iVelocidad, @iOdometro=@iOdometro, @cDireccion=@cDireccion, @cIMEI=@cIMEI, @rAccuracy=@rAccuracy, @cMethod=@cMethod, @iBattery=@iBattery, @iExtBattery=@iExtBattery, @iNivelSenial=@iNivelSenial, @iSatelites=@iSatelites, @iSecuencia=@iSecuencia, @iFuel=@iFuel, @iEngineStatus=@iEngineStatus
										
			Select @iValor = SCOPE_IDENTITY()	--Para el OUTPUT
			--Select @iValor As iValor			--Para tener cursor de devolucion

			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | [SGSP_p_PosicionesINS] | iValor ('+Cast(@iValor As Varchar(10))+')' 
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
		End

	Set NoExec Off	
		
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');

END CATCH


GO
/****** Object:  StoredProcedure [dbo].[SGSP_Permisos]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO


CREATE PROCEDURE [dbo].[SGSP_Permisos]  AS
--Asigna permisos a TODAS las tablas,vistas,sp y funciones a TODOS los usuarios de la plataforma SoftGuard
--Autor .Pablo O. Canónico
--Fecha :16/07/2015

--Primero busco los usuarios de SoftGaurd de la Base de Datos
SET NOCOUNT ON

Declare @id int, @cname Varchar(512), @cnombres Varchar(1024), @cXtype Char(2)
Set @cNombres = ''

Declare c_users CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY For 
	Select uid,name From sysusers Where ( Left(Name,2) = 'SG' Or Left(Name,9) = 'SoftGuard' ) And Left(Name,9) <> 'SGSERVER\'	

Open c_users
Fetch Next From c_users Into @id,@cname
While @@FETCH_STATUS = 0
Begin
   Set @cNombres = @cNombres + Rtrim(@cName) + ','

   Fetch Next From c_users Into @id,@cname
End
Close c_users
Deallocate c_users

If Len(@cNombres) > 0
	Set @cNombres = Left(@cNombres,Len(@cNombres)-1)

Print '---INICIO---'
Print 'cNombres '+@cNombres
If @cNombres = ''
	Set NoExec On

--Segundo busco las tablas,vistas,sp y funciones de la base de datos en donde se ejecuta
Declare @cTablas Varchar(Max)
Declare @cSelect Varchar(Max)

--Le doy permiso de creacion de tablas para poder depurar
--Set @cSelect = ' GRANT CREATE TABLE TO ' +@cNombres
--Print @cSelect
--Exec ( @cSelect)

Set @cTablas = ''
Declare c_tables CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY for 
	Select name,xtype from sysobjects where xtype='U'  or (xtype='P' and category=0) or (xtype='V' and category=0) or (xtype In ('FS','FT','T','TF','FN') and category=0)
	Order By xtype,name

--Tercero asigno permisos All
Open c_tables
Fetch next from c_tables into @cname,@cXtype
While @@FETCH_STATUS = 0
Begin
   If @cXtype = 'TF'	--Le doy solo permiso de Select si es una Funcion Table-Valued
      Set @cSelect = ' GRANT SELECT ON '+Rtrim(@cName)+' TO ' +@cNombres
   Else
	  If @cXtype In ('P','FS','FT','T','TF','FN')	--Le doy solo permiso de Ejecucion si es un SP o Funcion Scalar-Valued
         Set @cSelect = ' GRANT EXECUTE ON '+Rtrim(@cName)+' TO ' +@cNombres
      Else
	  Begin
		 If Lower(Rtrim(@cName)) = 'm_usuarios'
			Set @cSelect = ' GRANT SELECT,INSERT,UPDATE,DELETE,ALTER ON '+Rtrim(@cName)+' TO ' +@cNombres
		 Else
			Set @cSelect = ' GRANT SELECT,INSERT,UPDATE,DELETE ON '+Rtrim(@cName)+' TO ' +@cNombres
	  End
   Print @cSelect
   Exec ( @cSelect)

   Fetch Next From c_tables Into @cname,@cXtype
End
Close c_tables

Deallocate c_tables

Set NoExec Off		
Print '---FIN---'

GO
/****** Object:  StoredProcedure [dbo].[SGSP_pRecepcionINS]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [dbo].[SGSP_pRecepcionINS] 
	@rec_iidcuenta [int] = 0,
	@rec_calarma [char](3) = '',
	@rec_czona [char](3) = '',
	@rec_iusuario [int] = 0,
	@rec_tfechahora [datetime] = Null,
	@rec_nestado [numeric](1, 0) = 0,
	@rec_cContenido [nVarChar](255) = '',
	@rec_tFechaProceso [datetime] = Null,
	@rec_ioperador [int] = 0,
	@rec_cObservaciones [ntext] = '',
	@rec_cTerminal [char](3) = '',
	@rec_idResolucion [char](3) = '',
	@rec_idReceptor [int] = 0,
	@rec_cCategorizacion [char](3) = '',
	@rec_iNYR [int] = 0,
	@rec_iTE [int] = 0,
	@rec_tFechaRecepcion [datetime] = Null,
	@rec_nOrigen [numeric](1, 0) = 0,
	@rec_idMap [int] = 0,
	@rec_idFwd [int] = 0,
	@rec_iMinutosEspera [int] = 0,
	@rec_iPuerto [int] = 0,
	@rec_idLoc [int] = 0,
	@rec_iPrioridad [int] = 0,
	@spGeoAutoproceso [int] = 0,
	@iValor [int] = 0 OUTPUT
AS
--Es el store que ejecuta la insercion en p_Recepcion con rec_iid Identity
--Autor :Pablo O. Canónico
--Fecha :19/04/2016
--30/06/2017 : Se agrego control de automonitoreo
--18-08-2017 : Se agrego control de eventos de cambio de situacion
--18-01-2019 : Se agrego control de autoproceso por Geocerca
--14-03-2019 : Se agrega control de zonas vacias
--03-04-2019 : Se agrego control de autoprocesamiento	
Set NoCount On
BEGIN TRY
	If @rec_iidcuenta = 0
		Begin
			Print 'idCuenta en cero. No graba!!!'
			Set NoExec On
		End
	If @rec_tfechahora Is Null
		Begin
			Set @rec_tfechahora = GetDate()
			Set @rec_tFechaRecepcion = GetDate()
		End

	Declare @translation nVarChar(Max)=''

	--Si son eventos de cambio de situacion no controlo la situacion de la cuenta--
	If @rec_calarma IN('_CS','_SH','_SP','_SN','_SZ','_EC','_FP')
		Print 'Es evento de cambio de situacion no controlo la situacion de la cuenta!!!'
	Else
	Begin
		--Controlo la situacion de la cuenta para no generar eventos en cuentas deshabilitadas--
		Declare @_SituacionCuenta nVarChar(100)
		Select @_SituacionCuenta=(Case When est_nEstado=1 And GetDate() BetWeen est_dfechadesde And est_dfechahasta Then 'Prueba' When est_nEstado=2 Then 'No Habilitado' 
			When est_nEstado=3 Then 'Prueba x Zonas' Else 'Habilitado' End )
			From m_estado_cuenta_cab Where est_iidcuenta = @rec_iidcuenta

		If @_SituacionCuenta='No Habilitado' 
			Begin
				Print 'Cuenta en situacion -No Habilitado-. No graba pendientes!!!'
				Set @rec_nestado=7
				Set @rec_tFechaProceso= GetDate()
				Set @rec_idResolucion = (Select CAST(IsNull(par_ivalor,999) As Char(3)) As cValor FROM [_Tablas].[dbo].[t_parametros] With (NOLOCK) Where par_ccodigo='MODO NO HABILITADO')
				Set @rec_idResolucion = Stuff('000',4-Len(@rec_idResolucion),Len(@rec_idResolucion),@rec_idResolucion)
				Execute [_Desktop].[dbo].[LocalizationGetLocale] @Name = N'Cuenta Configurada en Modo No Habilitado', @soloOutput=1, @translation = @translation OUTPUT
				Set @rec_cObservaciones = '['+Convert(Varchar, GetDate(), 103)+' ' +Substring(Convert(Varchar, GetDate(), 114), 1, 5)+  '] [IRS] '+ Rtrim(@translation)
			End
	
		If @_SituacionCuenta='Prueba' 
			Begin
				If ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='SETEOMODODEPRUEBA' ) = 1
					Begin		
						Print 'Cuenta en situacion -Prueba-. No graba pendientes!!!'
						Set @rec_nestado=6
						Set @rec_tFechaProceso= GetDate()
						Set @rec_idResolucion = (Select CAST(IsNull(par_ivalor,999) As Char(3)) As cValor FROM [_Tablas].[dbo].[t_parametros] Where par_ccodigo='MODO PRUEBA')
						Set @rec_idResolucion = Stuff('000',4-Len(@rec_idResolucion),Len(@rec_idResolucion),@rec_idResolucion)
						Execute [_Desktop].[dbo].[LocalizationGetLocale] @Name = N'Cuenta Configurada en Modo de Prueba', @soloOutput=1, @translation = @translation OUTPUT
						Set @rec_cObservaciones = '['+Convert(Varchar, GetDate(), 103)+' ' +Substring(Convert(Varchar, GetDate(), 114), 1, 5)+  '] [IRS] '+ Rtrim(@translation)
					End
			End

		If @_SituacionCuenta='Prueba x Zonas' 
			Begin
				--Como es x zonas solo busco en Item
				If @rec_czona<>'' And Exists ( Select Top 1 est_idKey From m_estado_cuenta_item With (NOLOCK) Where est_iidcuenta = @rec_iidcuenta And est_czona=@rec_czona )
					Begin
						If ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='SETEOMODODEPRUEBA' ) = 1
							Begin		
								Print 'Cuenta en situacion -Prueba x Zonas-. No graba pendientes!!!'
								Set @rec_nestado=6
								Set @rec_tFechaProceso= GetDate()
								Set @rec_idResolucion = (Select CAST(IsNull(par_ivalor,999) As Char(3)) As cValor FROM [_Tablas].[dbo].[t_parametros] Where par_ccodigo='MODO PRUEBA')
								Set @rec_idResolucion = Stuff('000',4-Len(@rec_idResolucion),Len(@rec_idResolucion),@rec_idResolucion)
								Execute [_Desktop].[dbo].[LocalizationGetLocale] @Name = N'Cuenta Configurada en Modo de Prueba por Zonas', @soloOutput=1, @translation = @translation OUTPUT
								Set @rec_cObservaciones = '['+Convert(Varchar, GetDate(), 103)+' ' +Substring(Convert(Varchar, GetDate(), 114), 1, 5)+  '] [IRS] '+ Rtrim(@translation)
							End
					End
				Else	--Si NO esta en Modo de Prueba por zonas en la zona a grabar me fijo Si esta en Modo Prueba por codigos de alarma
					Begin
					If Exists ( Select Top 1 est_idKey From m_estado_cuenta_item With (NOLOCK) Where est_iidcuenta = @rec_iidcuenta And est_czona='_COD_' And CHARINDEX(@rec_calarma, est_cData) > 0 )
						Begin
							If ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='SETEOMODODEPRUEBA' ) = 1
								Begin		
									Print 'Cuenta en situacion -Prueba x Codigo de Alarmas -. No graba pendientes!!!'
									Set @rec_nestado=6
									Set @rec_tFechaProceso= GetDate()
									Set @rec_idResolucion = (Select CAST(IsNull(par_ivalor,999) As Char(3)) As cValor FROM [_Tablas].[dbo].[t_parametros] Where par_ccodigo='MODO PRUEBA')
									Set @rec_idResolucion = Stuff('000',4-Len(@rec_idResolucion),Len(@rec_idResolucion),@rec_idResolucion)
									Execute [_Desktop].[dbo].[LocalizationGetLocale] @Name = N'Cuenta Configurada en Modo de Prueba por Codigo de Alarmas', @soloOutput=1, @translation = @translation OUTPUT
									Set @rec_cObservaciones = '['+Convert(Varchar, GetDate(), 103)+' ' +Substring(Convert(Varchar, GetDate(), 114), 1, 5)+  '] [IRS] '+ Rtrim(@translation)
								End
						End
					End
			End
	End

	--Prioridad--
	If (@rec_iPrioridad Is Null) Or (@rec_iPrioridad = 0)
		Begin
			Declare @nAlarmaPrioridad numeric(1,0) = 1
			Set @nAlarmaPrioridad = (Select TOP 1 ( Case When cod_nprioridad=0 Then 1 Else cod_nprioridad End )  From _Tablas.dbo.t_codigos_alarma With (NOLOCK) Where cod_ccodigo=@rec_calarma)
			If (@nAlarmaPrioridad Is Not Null)
				Begin
					Declare @iImportancia int = 0

					Select @iImportancia = IsNull(cue_iImportancia,4) From  m_CuentasXtraInfo Where cue_iidCuenta = @rec_iidcuenta
					If (@iImportancia Is Not Null)
						Begin
							If @iImportancia = 0
								Set @iImportancia = 4

							Declare @cSuma char(2) = ''
							Select @cSuma = Cast(@nAlarmaPrioridad As Char(1)) + Cast(@iImportancia As Char(1))
							Set @rec_iPrioridad = Cast(@cSuma As int)
						End
				End
		End


	--AutoProcesamiento--
	If @rec_nestado=0
	Begin
		Declare @iAutoProcesamiento Int = (Select IsNull(par_ivalor,0) FROM [_Tablas].[dbo].[t_parametros] With (NOLOCK) Where par_ccodigo='AUTOPROCESAMIENTO')
		If @iAutoProcesamiento = 0
			Print 'AUTOPROCESAMIENTO configurado en No'
		Else
			Begin
				Declare @iAutoProcesa Int = 0
				If @iAutoProcesamiento = 1
					Begin
						Print 'AUTOPROCESAMIENTO configurado en Si'
						Set @iAutoProcesa = 1
					End
				Else
					Begin
						Print 'AUTOPROCESAMIENTO configurado en Si, solamente a los dealers habilitados'
						Select @iAutoProcesa=IsNull(lin_iAutoProcesa,0) From  [_Tablas].[dbo].[t_lineas] 
							Inner Join m_cuentas On cue_clinea=lin_ccodigo
								Where cue_iid = @rec_iidcuenta 
					End

				If @iAutoProcesa = 1
					Begin
						Set @rec_nestado=7
						Set @rec_tFechaProceso= GetDate()
						Set @rec_idResolucion = (Select CAST(IsNull(par_ivalor,999) As Char(3)) As cValor FROM [_Tablas].[dbo].[t_parametros] With (NOLOCK) Where par_ccodigo='CATAUTOPROCESAMIENTO')
						Set @rec_idResolucion = Stuff('000',4-Len(@rec_idResolucion),Len(@rec_idResolucion),@rec_idResolucion)
						Execute [_Desktop].[dbo].[LocalizationGetLocale] @Name = N'Sistema Configurado para Auto Procesamiento', @soloOutput=1, @translation = @translation OUTPUT
						Set @rec_cObservaciones = '['+Convert(Varchar, GetDate(), 103)+' ' +Substring(Convert(Varchar, GetDate(), 114), 1, 5)+  '] [IRS] '+ Rtrim(@translation)
					End
			End
	End	

	--AutoMonitoreo--
	If @rec_nestado=0
	Begin	
		Declare @nPrioridad Int=0,
				@nAutoMonitoreo Int=0
		Declare @cHoraAperturaAutomonitoreo VarChar(5)='',
				@cHoraCierreAutomonitoreo VarChar(5)='',
				@cHoraActual VarChar(5)=''

		Select @nPrioridad=[cue_nPrioridad],@nAutoMonitoreo=[cue_nAutoMonitoreo],
				@cHoraAperturaAutomonitoreo=Ltrim(Rtrim(REPLACE(IsNull([cue_cHoraAperturaAutomonitoreo],''),':',''))),
				@cHoraCierreAutomonitoreo=Ltrim(Rtrim(REPLACE(IsNull([cue_cHoraCierreAutomonitoreo],''),':',''))), 
				@cHoraActual=Ltrim(Rtrim(REPLACE(CONVERT(VARCHAR(5),GETDATE(),108),':',''))) 
			From [m_cuentas] With (NOLOCK)
	  		Left Outer Join [m_CuentasXtraInfo] With (NOLOCK) On [cue_iId] = [cue_iIdCuenta] 
			Where cue_iid=@rec_iidcuenta
			And cue_nAutoMonitoreo = 1

		If @nAutoMonitoreo  = 1
		Begin
			--2do veo la prioridad del codigo de alarma y la comparo con la configurada en la cuenta solo si es mayor a 1 x que si es 1 es todos los eventos se automonitorean
			Declare @cOK Char(1) = 'S'
			If @nPrioridad > 1
			Begin
				Set @cOK = 'N'
				Declare @iAlarmaPrioridad Int = 1
				Set @iAlarmaPrioridad = (Select TOP 1 ( Case When cod_nprioridad=0 Then 1 Else cod_nprioridad End )  From _Tablas.dbo.t_codigos_alarma With (NOLOCK) Where cod_ccodigo=@rec_calarma)
				If (@iAlarmaPrioridad Is Not Null) And @iAlarmaPrioridad >= @nPrioridad
					Set @cOK = 'S'
		
				--3ro tengo que ver si se configuraron horarios		
				If @cOK = 'S'
				Begin
					Set @cOK = 'N'
					--Los horarios pueden ser de un solo dia, o de un dia para el otro.	Ej 1125 - 1605  o  1930 - 0345	
					
					If @cHoraCierreAutomonitoreo > @cHoraAperturaAutomonitoreo		--1125 - 1605
					Begin
						If @cHoraActual Between @cHoraAperturaAutomonitoreo And @cHoraCierreAutomonitoreo
							Set @cOK = 'S'
					End
					Else
					Begin
						If @cHoraCierreAutomonitoreo < @cHoraAperturaAutomonitoreo		--1930 - 0345	
						Begin
							If (@cHoraActual Between @cHoraAperturaAutomonitoreo And '2359') Or (@cHoraActual Between '0000' And @cHoraCierreAutomonitoreo)
								Set @cOK = 'S'
						End 	
						Else	--No se configuraron horarios
							Set @cOK = 'S'
					End
				End 
			End

			If @cOK = 'S'
			Begin
				Set @rec_nestado=7
				Set @rec_tFechaProceso= GetDate()
				Set @rec_idResolucion = (Select CAST(IsNull(par_ivalor,999) As Char(3)) As cValor FROM [_Tablas].[dbo].[t_parametros] With (NOLOCK) Where par_ccodigo='CATAUTOMONITOREO')
				Set @rec_idResolucion = Stuff('000',4-Len(@rec_idResolucion),Len(@rec_idResolucion),@rec_idResolucion)
				Execute [_Desktop].[dbo].[LocalizationGetLocale] @Name = N'Cuenta Configurada para Auto Monitoreo', @soloOutput=1, @translation = @translation OUTPUT
				Set @rec_cObservaciones = '['+Convert(Varchar, GetDate(), 103)+' ' +Substring(Convert(Varchar, GetDate(), 114), 1, 5)+  '] [IRS] '+ Rtrim(@translation)
			End
		End
		Else
		Begin
			If @spGeoAutoproceso = 1	--Evento fuera de la Geocerca de Cobertura
			Begin
				Set @rec_nestado=7
				Set @rec_tFechaProceso= GetDate()
				Set @rec_idResolucion = (Select CAST(IsNull(par_ivalor,999) As Char(3)) As cValor FROM [_Tablas].[dbo].[t_parametros] With (NOLOCK) Where par_ccodigo='CATFUERACOBERTURA')
				Set @rec_idResolucion = Stuff('000',4-Len(@rec_idResolucion),Len(@rec_idResolucion),@rec_idResolucion)
				Execute [_Desktop].[dbo].[LocalizationGetLocale] @Name = N'Evento Fuera del Area de Cobertura', @soloOutput=1, @translation = @translation OUTPUT
				Set @rec_cObservaciones = '['+Convert(Varchar, GetDate(), 103)+' ' +Substring(Convert(Varchar, GetDate(), 114), 1, 5)+  '] [IRS] '+ Rtrim(@translation)
			End
		End
	End
	Print 'ANTES DE INSETAR EN p_recepcion'
	Insert InTo [_Datos].[dbo].[p_recepcion] (rec_calarma, rec_iidcuenta,  rec_czona, rec_iusuario, rec_tfechahora, rec_nestado, rec_cContenido, rec_tFechaProceso, rec_ioperador, rec_cObservaciones, rec_cTerminal, rec_idResolucion, rec_idReceptor, rec_cCategorizacion, rec_iNYR, rec_iTE, rec_tFechaRecepcion, rec_nOrigen, rec_idMap, rec_idFwd, rec_iMinutosEspera, rec_iPuerto, rec_idLoc, rec_iPrioridad)
		Values (@rec_calarma, @rec_iidcuenta,  @rec_czona, @rec_iusuario, @rec_tfechahora, @rec_nestado, @rec_cContenido, @rec_tFechaProceso, @rec_ioperador, @rec_cObservaciones, @rec_cTerminal, @rec_idResolucion, @rec_idReceptor, @rec_cCategorizacion, @rec_iNYR, @rec_iTE, @rec_tFechaRecepcion, @rec_nOrigen, @rec_idMap, @rec_idFwd, @rec_iMinutosEspera, @rec_iPuerto, @rec_idLoc, @rec_iPrioridad)
										
	/**
		12/02/2022 Daniel Orlando Medina
		se anula scope_identity() porque dió problemas con la tarea:
		https://softguard.atlassian.net/browse/DSS-144
	*/
	Select @iValor =   SCOPE_IDENTITY()	--Para el OUTPUT
	--Select @iValor As iValor			--Para tener cursor de devolucion
	


	Set NoExec Off	
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
END CATCH

Select @iValor As iValor			--Para tener cursor de devolucion aun con el Catch

GO
/****** Object:  StoredProcedure [dbo].[SGSP_ProcesoEscalamiento]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [dbo].[SGSP_ProcesoEscalamiento]
WITH EXECUTE AS CALLER
AS
SET NOCOUNT ON
Declare @DiaHoy DateTime  = GetDate()

Declare @iID Int = 0,
	@iidCuenta Int = 0,
	@iEnviaMail Int = 0,
	@iControla Int = 0,
	@iOperador Int = 0,
	@iTiempo Int = 0,
	@iPrioridad Int = 0

Declare @cFecha Char(10) = '',
	@cHora Char(10) = '',
	@cAlarma Char(3) = '',
	@cCuenta Char(10) = '',
	@cGrabo Char(1) = 'S'

--1ero verifico si hay escalamiento para verificar
--Deberia existir al menos una prioridad con controla en SI y tiempo > 0
Set @iControla =(SELECT Top 1 [tep_iid] From [_Tablas].[dbo].[t_EscalamientoPrioridades] With (NOLOCK) Where [tep_nControla]=1 And [tep_iTiempo]>0) 
If @iControla Is Null Or @iControla = 0
Begin
	--Deberia existir al menos una prioridad con controla en SI y tiempo > 0 para la organizacion
	Set @iControla =(SELECT Top 1 [teo_iid] From [_Tablas].[dbo].[t_EscalamientoPorOrganizacion] With (NOLOCK) Where [teo_nControla]=1 And [teo_iTiempo]>0) 
End
If @iControla > 0
   Begin
	-- Aviso que la tarea esta funcionando	
	Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'ProcesoEscalamiento', @Repetition = 6
	--	   

	Set @iEnviaMail = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='MAILSERVICE' )		
	
	Declare @Query nVarChar(255) = '',  
			@cFrom nVarChar(100) = ( Select par_cValor From _Tablas.dbo.t_parametros Where par_ccodigo = 'MAILSENDER' ),
			@cFromName nVarChar(100) = ( Select par_cValor From _Tablas.dbo.t_parametros Where par_ccodigo = 'MAILSENDERNAME' ),
			@cTo nVarChar(100) = '',
			@cToOriginal nVarChar(100) = ( Select par_cValor From _Tablas.dbo.t_parametros Where par_ccodigo = 'MAILDEMORAENPROCESAR' ),
			@cSubject nVarChar(100) = '',
			@cMessage nVarChar(4000) = '',
			@cMessageMerge nVarChar(max) = '',
			@cImagenes nVarChar(max) = '',
			@cMail As nVarChar(100) = '',
			@cDonde Char(3) = '',
			@AlarmaGenerar Char(3) = '',
			@cNombre As nVarChar(100) = '',
			@cDescripcion As nVarChar(100) = '',
			@cObs As nVarChar(max) = ''

	Declare @nFin Int = 1,
			@idOrganizacion Int = 0,
			@iDiez Int = 10,
			@iIdSGInte Int = 0,
			@iValor Int = 0,
			@iEscala Int = 1,	--1-Si / 2-No
			@iTipoAlarma Int = 1

	Set @cFrom = Ltrim(Rtrim(@cFrom))
	Set @cFromName = Ltrim(Rtrim(@cFromName))
	Set @cTo = Ltrim(Rtrim(@cToOriginal))

	Set @iIdSGInte = (Select Top 1 cue_iid From m_cuentas With (NOLOCK)	Where cue_clinea='_SG' And cue_ncuenta = 'INTE' )

	Declare @translation nVarChar(Max)=''
	Execute [_Desktop].[dbo].[LocalizationGetLocale] @Name = N'Demora en Procesar', @soloOutput=1, @translation = @translation OUTPUT
	Set @cSubject = @translation 

	Declare cEspera CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR 
	Select rec_iid,CONVERT(char(10), rec_tFechaHora,103),CONVERT(char(10), rec_tFechaHora,108),rec_iidCuenta,rec_cAlarma,rec_iOperador,rec_iPrioridad,_idOrganizacion,Case When IsNull([tep_iid],0) > 0 Then 'CRA' When IsNull([teo_iid],0) > 0 Then 'ORG' Else 'CRA' End,
		cue_cLinea+'-'+cue_nCuenta,cue_cNombre,EP.cod_cDescripcion,IsNull(lin_iEscala,1) As iEscala,CA.cod_ntipo As iTipoAlarma
			From [dbo].[EventosPendientes] EP
			Left Outer Join [_Tablas].[dbo].[t_EscalamientoPrioridades] On [tep_iid]=Left([rec_iPrioridad],1) And [_idOrganizacion] = 0
			Left Outer Join [_Tablas].[dbo].[t_EscalamientoPorOrganizacion] On [teo_iid]=Left([rec_iPrioridad],1) And [_idOrganizacion] > 0
			Left Outer Join [_Tablas].[dbo].[t_lineas] On [cue_cLinea]=[lin_ccodigo]
			Inner Join [_Tablas].[dbo].[t_codigos_alarma] CA On [cod_cCodigo]=[rec_cAlarma]
		Where [rec_nEstado]=0
	--Where [rec_nEstado] IN(0,1,4,9)
	--Estado  Descripcion
	--                0             Evento Nuevo/Pendiente           
	--                1             Evento esta siendo Procesado
	--                4             Evento esta siendo Procesado en Espera
	--                9             Evento en estado Temporal usado por ProcesaTodo
	--Se pidio por BC el 14-09-2018 que solo escale los eventos pendientes
		And (( [tep_nControla]=1 And [tep_iTiempo]>0 And DATEADD(MINUTE,[tep_iTiempo],IsNull([rec_tFechaRecepcion],[rec_tFechaHora]))<@DiaHoy )
		    Or  ( [teo_nControla]=1 And [teo_iTiempo]>0 And DATEADD(MINUTE,[teo_iTiempo],IsNull([rec_tFechaRecepcion],[rec_tFechaHora]))<@DiaHoy ))

	Open cEspera
	Fetch Next From cEspera Into @iID,@cFecha,@cHora,@iidCuenta,@cAlarma,@iOperador,@iPrioridad,@idOrganizacion,@cDonde,@cCuenta,@cNombre,@cDescripcion,@iEscala,@iTipoAlarma
	While @@FETCH_STATUS = 0
	Begin
	   If @cGrabo = 'S'	
	      Begin		
		  
			--Print 'rec_iid'
			--Print @iID  

			--Se pidio por BC que siga escalando cuando llegue a 1 pero que no suba la prioridad
			--If Left(@iPrioridad,1) > 1	--Cuando llego a prioridad 1 ya no escala
			--	Begin
			If Left(@iPrioridad,1) = 1
				Set @iDiez = 0
			Else
				Set @iDiez = 10

			UPDATE [p_recepcion] WITH (ROWLOCK)
				SET rec_tFechaRecepcion=@DiaHoy,rec_cContenido=Left(Rtrim(Ltrim(rec_cContenido))+' |NPR',50),rec_iPrioridad=rec_iPrioridad-@iDiez
				WHERE rec_iid=@iID

			--If @idOrganizacion > 0
			If @iEscala = 1 --Si
				UPDATE [EventosPendientes] WITH (ROWLOCK) SET _idOrganizacion=0 WHERE rec_iid=@iID

			Insert Into [dbo].[EventosTimeLine]
					([etl_iRecID]
					,[etl_iCuenta]
					,[etl_tFechaHora]
					,[etl_cAccion]
					,[etl_cObservacion]
					,[etl_cOwner]
					,[etl_iOperador])
				Values
					(@iID
					,@iidCuenta
					,GETDATE()
					,'Escalamiento'
					,'%Escaló a Prioridad% '+Cast( Left(@iPrioridad-@iDiez,1) As nVarChar(10))
					,'%SISTEMA%'
					,@iOperador)
				--End

				If @iTipoAlarma = 7	-- (Asignacion de tarea)
					Set @AlarmaGenerar = '_ET'
				Else
				Begin
					If @cDonde = 'CRA'
						Set @AlarmaGenerar = '_ES'
					Else
						Set @AlarmaGenerar = '_EO'
				End

				If @iIdSGInte Is Null
					Print '@iIdSGInte es null. No genera evento interno'
				Else
					Begin
						Set @cObs = @cCuenta + ' ' + Rtrim(@cNombre) +' '+ @cAlarma + ' '+ Rtrim(@cDescripcion )+ ' '+ @cFecha + ' ' + @cHora 
						EXEC _Datos.dbo.SGSP_AlarmaGenerar @idCta=@iIdSGInte, @cAlarma=@AlarmaGenerar,@cObs=@cObs, @iValor=@iValor OUTPUT
					End
          End

	   If @cTo <> ''
	      Begin
		   Set @cMail = @cTo +';'
		   --2018-08-12 Ahora se resuelve en el query del cursor
		   --Set @cCuenta	= ( SELECT cue_clinea+'-'+cue_ncuenta FROM m_cuentas Where cue_iid=@iidCuenta )	
		   Set @cMessage = @cCuenta + ' ' +@cAlarma + ' '+ @cFecha + ' '+ @cHora 

		   WHILE CHARINDEX(';',@cMail) > 0
		   BEGIN
			Set @nFin = CHARINDEX(';',@cMail)	
			Set @cTo = SUBSTRING( @cMail, 1, @nFin-1 )
			Set @Query = 'Select '+CHAR(39)+@cTo+CHAR(39)+' As Email'
			
			If @cGrabo = 'S' And @iEnviaMail = 1		
				EXEC _Sistema.dbo.sp_SendMail @cFrom, @cTo, @cSubject, @cMessage	

		    If @cGrabo = 'S' And @iEnviaMail = 2		
			   Begin	
			    Set @cMessageMerge = ''
				EXEC SGSP_TextMerge	@iidCuenta,'',@cAlarma,'NPR',@cFecha,@cHora,@iID, @cMessageMerge OUTPUT, @cImagenes OUTPUT
				If @cMessageMerge Is Null
					Set @cMessageMerge = @cMessage

				EXEC _Datos.dbo.SmartMail_ProgramCreate @cFromName, @cFrom, @cSubject, @cMessageMerge, @DiaHoy, 1, @Query, 'MAIL', @cImagenes, 802, @iidCuenta							
			  End

			Set @cMail = SUBSTRING( @cMail, @nFin+1, 100-@nFin )
		   END
	
		   Set @cTo = Ltrim(Rtrim(@cToOriginal))
	      End

	   Fetch Next From cEspera Into @iID,@cFecha,@cHora,@iidCuenta,@cAlarma,@iOperador,@iPrioridad,@idOrganizacion,@cDonde,@cCuenta,@cNombre,@cDescripcion,@iEscala,@iTipoAlarma
	End
	Close cEspera
	Deallocate cEspera
   End
Else	-- Aviso que la tarea no cumple las condiciones para funcionar
	Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'ProcesoEscalamiento', @Repetition = 6, @Date = null, @Status = 0   	


GO
/****** Object:  StoredProcedure [dbo].[SGSP_PushNotification]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SGSP_PushNotification]
	@idRec [int] = 0
WITH EXECUTE AS CALLER
AS
--Autor :Pablo O. Canónico
--Fecha :03/03/2017
--17/05/2017 Se cambio el asunto a 2 parametros MAILSENDERNAME/MAILNOTIFICACIONASUNTO
--30/10/2017 Se envia como @Customdata un Json con la descripcion del codigo de alarma
--09/01/2018 Si no existe el idRec en pRecepcion se busca en la depurada ( TST )
--11/04/2018 Para eventos de cuentas deshabilitadas no se generan push	
--30/08/2018 Se agrego control para no notificar al origen si el evento lo envio un SmartPanics
--03/09/2018 Se agrego nombre de usuario que genero el evento
--24/09/2018 Se controla que por automonitoreo se sigan enviando notificaciones
--21/12/2018 Se cambio Join contra [m_receptores_cab], porque los eventos internos no tienen idReceptor
--19/09/2019 Se rearmo el Customdata, que es el mensaje que se ven en los push
--20/11/2020 Se agrega envio por CheckPoint para VC
--18/03/2021 Se modifico el campo [cod_cGrupo] para contener varios grupos
--21/05/2021 Se contempla no procesar idPush de SP sin IMEI ( no asignados )
--29/06/2021 Se contempla que el idPush de SP puede no ser del idCta del evento
--12/04/2022 Se evitan @cidsPushSmartpanic con ;;
--15/07/2022 Se agrego harcodeo de sound en push
--04/11/2022 Dejo de ser harcodeo de sound en push y ahora se usa la configuracion que se guardo en m_sms

SET NOCOUNT ON
Declare	@idCta [int] = 0,
	@cCodigoAlarma [char](3) = '',
	@cZona [char](3) = '',
	@nEstado [int] = 0,
	@iUsuario [int] = 0,
	@cDll [varchar](100) = '',
	@idResolucion Char(3) = '999',
	@translation nVarChar(Max)=''

Declare @cResolucion Char(3) = Right('000'+ Rtrim((Select CAST(IsNull(par_ivalor,999) As Char(3)) From [_Tablas].[dbo].[t_parametros] Where par_ccodigo='CATAUTOMONITOREO')),3)

Declare @message nVarChar(Max) = '',
		@StartDateTimeText VarChar(max)=''

Select @idCta = [rec_iidcuenta], @cCodigoAlarma = [rec_cAlarma], @cZona = [rec_czona], @nEstado = [rec_nestado], @iUsuario = [rec_iUsuario], @cDll = IsNull([rec_cdll],''), @idResolucion = IsNull([rec_idResolucion],'') From p_recepcion PR
	Left Outer Join [dbo].[m_receptores_cab] RC On RC.[rec_iid]=[rec_idReceptor]
	Where PR.[rec_iid] = @idRec

If @idCta Is Null Or @idCta = 0
	Begin
		--Busco el recid en la depurada
		Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | [SGSP_PushNotification] No existe en pRecepcion. Busco el @idRec en la depurada'
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

		Declare @cCierre Char(6) = Convert(Char(6),Getdate(), 112)
		IF OBJECT_ID('p_recepcion'+@cCierre) Is Not Null
			Begin		
				Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | [SGSP_PushNotification] Busco en p_recepcion'+@cCierre
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

				Declare @cSQL nVarchar(MAX)
				Set @cSQL = 'Select @idCta = rec_iidcuenta, @cCodigoAlarma = rec_cAlarma, @cZona = rec_czona, @nEstado = rec_nestado, @iUsuario = rec_iUsuario, @cDll = rec_cdll From [dbo].[p_recepcion' +  @cCierre  +  '] PR	Inner Join [dbo].[m_receptores_cab] RC On RC.[rec_iid]=[rec_idReceptor] Where PR.[rec_iId]='+Cast(@idRec As Varchar(10))

				Declare @DynamicSqlParams NVarchar(MAX)
				Set @DynamicSqlParams = '@idRec Int,@idCta Int OUTPUT, @cCodigoAlarma Char(3) OUTPUT, @cZona Char(10) OUTPUT, @nEstado Int OUTPUT, @iUsuario Int OUTPUT, @cDll VarChar(100) OUTPUT'
				Execute sp_executesql @cSQL, @DynamicSqlParams, @idRec=@idRec, @idCta=@idCta OUTPUT, @cCodigoAlarma=@cCodigoAlarma OUTPUT, @cZona=@cZona OUTPUT, @nEstado=@nEstado OUTPUT, @iUsuario=@iUsuario OUTPUT, @cDll=@cDll OUTPUT
			End

		If @idCta Is Null Or @idCta = 0
			Begin
				Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | [SGSP_PushNotification] idCta en cero!!! '
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
	
				Set NoExec On
			End
	End


If @nEstado = 7 And @idResolucion<>@cResolucion	--No Habiitado/Automonitoreo
	Begin
		Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | [SGSP_PushNotification] Cuenta en situacion -No Habilitado-'
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
	
		Set NoExec On
	End

Declare @iAlerta Int = 0
Select @iAlerta = cod_nalerta From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cCodigoAlarma 

If @iAlerta Is Null Or @iAlerta >= 2
	Begin
		Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | [SGSP_PushNotification] No Genera Evento!!!'
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

		Set NoExec On
	End

Declare @cFecha Char(10) = (Select Convert(Char(10), GetDate(),103))
Declare @cHora Char(10) = (Select Convert(Char(10), GetDate(),108))

Declare @cidsPushSmartpanic nVarChar(1000) = '',
		@cidPush nVarChar(1000) = '',
		@cSPToken nVarChar(1024) = '',
		@cSubject nVarChar(100) = '',
		@cMessageMerge nVarChar(max) = '',
		@cImagenes nVarChar(max) = '',
		@cTo nVarChar(150) = '',
		@Customdata nVarChar (max) = '',
		@cDesc nVarChar(100) = '',
		@cTelefono nVarChar(30) = '',
		@cNombre nVarChar(50) = '',
		@cCheckPoint nVarChar(10) = '',
		@cImei nVarChar(128) = '',
		@cSonido Char(1) = ''

Declare @cPlantilla Char(3) = ''

Declare @nFin int = 0,
		@iIDSP Int = 0,
		@iSigo Int = 1

Declare @dHoy DateTime = GetDate()

Declare @cFromName nVarChar(100) = ( Select Cast(par_cvalor As nVarChar(100)) From _Tablas.dbo.t_parametros Where par_ccodigo = 'MAILSENDERNAME')
Declare @cNotificacionAsunto nVarChar(100) = ( Select Cast(par_cvalor As nVarChar(100)) From _Tablas.dbo.t_parametros Where par_ccodigo = 'MAILNOTIFICACIONASUNTO')
Declare @cAsunto nVarChar(max) = Rtrim(@cFromName)+' '+Rtrim(@cNotificacionAsunto)

Declare cPushlxEvento CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR 
	  	Select sms_cidsPushSmartpanic,sms_cPlantillaPush,pls_cdescripcion,IsNull(sms_czona,''),sms_cSonido From m_sms
			Inner Join _Tablas.dbo.t_plantillas_sms On pls_ccodigo=sms_cPlantillaPush
 		Where sms_cidsPushSmartpanic<>'' And sms_cPlantillaPush<>'' And sms_iidCuenta=@idCta And 
			  ( CHARINDEX(@cCodigoAlarma, sms_meventos) > 0 Or
			  ( sms_iNotificarAlertas=1 And @cCodigoAlarma IN (Select cod_ccodigo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cCodigoAlarma And cod_nalerta=1) ) Or
			  ( sms_iGrupoAlarmas>0 And sms_iGrupoAlarmas IN (Select gru_idKey From _Tablas.dbo.t_Grupos TG	Where EXISTS ( Select cod_cGrupo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cCodigoAlarma And CHARINDEX(TG.gru_ccodigo,cod_cGrupo) > 0 ) ) ) )

Open cPushlxEvento
Fetch Next From cPushlxEvento Into @cidsPushSmartpanic,@cPlantilla,@cSubject,@cCheckPoint,@cSonido
While @@FETCH_STATUS = 0
Begin
	Set @cCheckPoint = Rtrim(@cCheckPoint)
	Set @cZona = Rtrim(@cZona)

	Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_PushNotification] CheckPoint ('+@cCheckPoint+'). Zona del evento ('+@cZona+')'
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	if @cCheckPoint = ''  Or ( @cCheckPoint != '' And @cCheckPoint = @cZona )
	Begin
		Set @cidsPushSmartpanic = Replace(@cidsPushSmartpanic,';;','')
		Set @cidPush = @cidsPushSmartpanic +';'
		WHILE CHARINDEX(';',@cidPush) > 0
		Begin
			Set @nFin = CHARINDEX(';',@cidPush)	
			Set @cTo=SUBSTRING( @cidPush, 1, @nFin-1 )
			If @cTo != ''
			Begin
				Set @iSigo = 1

				Select Top 1 @cImei=Imei From [dbo].[SmartPanic]
					Where [ID]=Rtrim(@cTo) And [CuentaID]=@idCta
				
				If @cImei Is Null Or @cImei=''
				Begin
					Set @message = 'Start DateTime : %s | [SGSP_PushNotification] SmartPanics destino no es de la cuenta a la cual llego el evento. Busco sin IdCta'
					RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

					Select Top 1 @cImei=Imei From [dbo].[SmartPanic]
					Where [ID]=Rtrim(@cTo)
				End

				Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | [SGSP_PushNotification] To ('+@cTo+'). Imei ('+@cImei+')'
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT					

				If @cImei Is Null Or @cImei=''
				Begin
					Set @message = 'Start DateTime : %s | [SGSP_PushNotification] SmartPanics sin IMEI. NO se envia push'
					RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
				End
				Else
				Begin
					Select @cNombre=IsNull([usu_cnombre],Cast(@iUsuario As  nVarChar(50)))
						From [dbo].[m_usuarios]
						Where [usu_iidcuenta]=@idCta And [usu_icodigo]=@iUsuario
					/*
					If @cNombre Is Null Or @cNombre=''
						Set @cNombre = ''
					Else
						Set @cNombre = ' : '+@cNombre
					*/
					
					--Si el evento lo envio un SmartPanics no hay que notificar al origen
					If @cDll='SmartPanicsPacketParser'
					Begin
						Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
						Set @message = 'Start DateTime : %s | [SGSP_PushNotification] Si el evento lo envio un SmartPanics no hay que notificar al origen'
						RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

						Select @cTelefono=[tel_ctelefono],@iIDSP=[id] From p_recepcion
							Inner Join [dbo].[m_telefonos] On tel_iidcuenta=[rec_iidCuenta]
							Inner Join [dbo].[SmartPanic] On [tel_iidcuenta]=[CuentaId] And Right(Ltrim(Rtrim([Telefono])),8)=Right(Ltrim(Rtrim([tel_ctelefono])),8)
						Where [rec_iidCuenta]=@idCta
						  And [rec_iid] = @idRec
						  And [tel_iid] + 700 = [rec_iUsuario]

						If @cTelefono Is Null Or @cTelefono = ''
							Set @iSigo = 1
						Else
							Begin
								If Rtrim(Cast(@iIDSP As nVarChar(150)))=@cTo
									Set @iSigo = 0
							End
					End

					if @iSigo = 1
						Begin
							EXEC SGSP_TextMerge	@idCta,@cZona,@cCodigoAlarma,@cPlantilla,@cFecha,@cHora,@idRec, @cMessageMerge OUTPUT, @cImagenes OUTPUT
							If @cMessageMerge Is Null
								Set @cMessageMerge = @cSubject

							Declare @Msg VarChar(100) = ''

							If @cCodigoAlarma IN('_IG','_EG')
							Begin
								Declare @GeocercaNombre nVarChar(max) = ''
								Select Top 1 @GeocercaNombre = IsNull(rxt_cGeoFenceName,'') From p_RXtraInfo WITH (NOLOCK) Where rxt_iRecId = @idRec

								Set @Msg = 'ha salido de Geocerca'
								If @cCodigoAlarma = '_IG'
									Set @Msg = 'ha ingresado a Geocerca'

								Execute [_Desktop].[dbo].[LocalizationGetLocale] @Name = @Msg, @soloOutput=1, @translation = @translation OUTPUT
								Set @Msg = Rtrim(@translation)

								Set @Customdata = '{"cod_cdescripcion":"'+Rtrim(@cNombre)+' '+Rtrim(@Msg) +' '+Rtrim(@GeocercaNombre)+'","rec_iid":"'+CONVERT(varchar(20), @idRec)+'"}'
							End
							Else
							Begin
								Declare @CtaName nVarchar(100) =  ''
								Select @CtaName=IsNull([cue_cNombre],'') 
									From [dbo].[m_cuentas] WITH (NOLOCK)
									Where[cue_iid]=@idCta

								Declare @iResuelve Int = 0
								--cod_nResuelve	Descripcion
								--	0	Por Zona
								--	1	Por Usuario
								--	2	Nada
								--	3	Ambos	
								--https://basecamp.com/2249105/projects/14758734/todos/398239270				

								Select @cDesc=IsNull([cod_cdescripcion],@cCodigoAlarma), @iResuelve=IsNull([cod_nResuelve],0) 
									From [_Tablas].[dbo].[t_codigos_alarma] WITH (NOLOCK)
									Where [cod_ccodigo]=@cCodigoAlarma

								Set @Customdata = '{"cod_cdescripcion":"'+Rtrim(@CtaName)+'. '+Rtrim(@cDesc)
					
								If @iResuelve=0
								Begin
									Set @Msg = 'en zona'

									Execute [_Desktop].[dbo].[LocalizationGetLocale] @Name = @Msg, @soloOutput=1, @translation = @translation OUTPUT
									Set @Msg = Rtrim(@translation)

									Declare @ZonaDesc nVarchar(100) =  ''
									Select @ZonaDesc=IsNull([zon_cdescripcion],@cZona) 
										From [dbo].[m_zonas] WITH (NOLOCK)
										Where[zon_iidcuenta]=@idCta And [zon_ccodigo]=@cZona

									Set @Customdata += ' '+Rtrim(@Msg) + ' ' + Rtrim(@ZonaDesc)
								End
					
								If @iResuelve=1 OR @iResuelve=3
								Begin
									Set @Msg = 'del usuario'

									Execute [_Desktop].[dbo].[LocalizationGetLocale] @Name = @Msg, @soloOutput=1, @translation = @translation OUTPUT
									Set @Msg = Rtrim(@translation)

									Set @Customdata += +' '+Rtrim(@Msg) + ' ' + Rtrim(@cNombre)
								End

								Set @Customdata += '","rec_iid":"'+CONVERT(Varchar(20), @idRec)+'"}'
							End


							/*							
							--{"cod_cdescripcion":"FAMILIA RODRIGUEZ. Intrusión en zona ","rec_iid":"62871906","notification_sound":"Push-Sonido1.mp3"}
							Ahora en caso que el usuario seleccione un sonido, debera agregarse al Customdata el sonido que selecciono, que pueden ser

							Push-Sonido1.mp3
							Push-Sonido2.mp3
							Push-Sonido3.mp3
							Push-Sonido4.mp3
							Push-Sonido5.mp3
							*/
							If (Rtrim(@cSonido) != '' And @cSonido IN('1','2','3','4','5'))
							Begin
								Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
								Set @message = 'Start DateTime : %s | [SGSP_PushNotification] @cSonido = ' + @cSonido
								RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
								Set @Customdata = Replace(@Customdata,'}','')
								Set @Customdata += ',"notification_sound":"Push-Sonido'+@cSonido+'.mp3"}'
							End

							Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | [SGSP_PushNotification] @Customdata = ' + @Customdata
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

							--EXEC [_Desktop].[dbo].[MessageIns] @Name = @cAsunto, @Body = @cMessageMerge, @DateCreated = @dHoy, @FromTypeId = 0, @FromId = 0, @ToTypeId = 3067, @ToId = @cTo, @Customdata = @Customdata, @EventoID = @idRec, @CuentaID = @idCta
							--2020-04-08 : Pablo x que el MessageIns daba error al devolver el registro insertado
							Insert Into _datos..Message ( [Name], [Body],[DateCreated],[FromTypeId],[FromId],[ToTypeId],[ToId],[Customdata],[EventoID],[CuentaID])
				 			Values (@cAsunto, @cMessageMerge, @dHoy, 0, 0, 3067, @cTo, @Customdata, @idRec, @idCta)

						End
					Else
						Begin
							Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | [SGSP_PushNotification] @iIDSP=@cTo. No genero notificacion'
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
						End

				End
			End
			Set @cidPush = SUBSTRING( @cidPush, @nFin+1, 1000-@nFin );
		End
	End
	Fetch Next From cPushlxEvento Into @cidsPushSmartpanic,@cPlantilla,@cSubject,@cCheckPoint,@cSonido
End
Close cPushlxEvento
Deallocate cPushlxEvento
Set NoExec Off		

GO
/****** Object:  StoredProcedure [dbo].[SGSP_ReFillEventosPendientes]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
