/****** Object:  StoredProcedure [dbo].[SGSP_SearchNroOrdenServicio]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE   Procedure [dbo].[SGSP_SearchNroOrdenServicio]
	@idRec [int] = 0 ,
	@iValor [int] = 0 OUTPUT
AS
--Es el store que ejecuta Textmerge para buscar el numero de orden de servicio de un evento de finalizacion
--Autor :Pablo O. Canónico
--Fecha :20/01/2022
--2023-09-19 : Se agrego '_NS'

Set NoCount On
BEGIN TRY
	Declare @message VarChar(Max) = '',
		    @StartDateTimeText VarChar(Max) = ''

	Declare @iID Int = 0
	Declare @stringValue VarChar(max)
	Declare @cObs varchar(max) = (Select Cast(rec_cObservaciones As Varchar(max)) From [dbo].[p_recepcion] Where rec_calarma IN ('_ST','_NS') And rec_iid=@idRec)

	Declare TmpSearch Cursor Scroll	For
		Select Id,Value From [dbo].[SplitDelimited](@cObs,':') 

		Open TmpSearch
		FETCH NEXT FROM TmpSearch INTO @iID, @stringValue

		WHILE @@FETCH_STATUS = 0
		Begin
			If @iID=3
				Break

			FETCH NEXT FROM  TmpSearch INTO @iID, @stringValue
		End
	Close TmpSearch
	DEALLOCATE TmpSearch

	If @iID<1
	Begin
		Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | [SGSP_SearchNroOrdenServicio] | No hay Nro de Orden de ST para idRec = '+Cast(@idRec As VarChar(10))
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
	
		Set NoExec On
	End
	
	Declare @cValue NVarchar(100) = ''
	Select Top (1) @cValue=Value From [dbo].[SplitDelimited](@stringValue,']') 

	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_SearchNroOrdenServicio] | Nro de Orden de ST = '+@cValue
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	--En las ordenes _NS el stringValue viene con chars invisibles que no permiten castear a int
	If ISNUMERIC(@cValue) = 1
		Set @iValor = CONVERT(INT,Rtrim(Ltrim(@cValue)))
	Else
	Begin
		WHILE PATINDEX('%[^0-9]%', @cValue) > 0
		BEGIN
			SET @cValue = STUFF(@cValue, PATINDEX('%[^0-9]%', @cValue), 1, '')
		END
		Set @iValor = TRY_CONVERT(INT,Rtrim(Ltrim(@cValue)))
	End
	
	Set NoExec Off		
	
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
	IF @@TRANCOUNT>0
		ROLLBACK TRAN

END CATCH

GO
/****** Object:  StoredProcedure [dbo].[SGSP_Test]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE  [dbo].[SGSP_Test] AS 

Set DateFormat ymd

Declare @iidCuenta Int=0,
	@iReinicio        Int=0,
	@intParameter     Int=0,
	@iDiferencia      Int=0,
	@iDesactivada     Int=0,
	@iParametro       Int=0,
	@iEnviaMail       Int=0

Declare @nCada    Numeric(3,0)=0,
	@nTipo           Numeric(1,0)=0,
	@nEstado         Numeric(1,0)=0

Declare @dfechaultimotst DateTime,
	@Fecha_Hasta_aux DateTime,
	@UltimoTSTRec    DateTime,
	@Fecha_NSR_ANT   DateTime,
	@DiaHoy     	  DateTime=GetDate()

Declare @cAlarma Char(3)='',
	@cResolucion	 Char(3)='',
	@cGrabo	     Char(1)='S',
	@cUpdateStatus  Char(1)='N',
	@cPlantilla	 Char(3)=''

Declare @cAutoprocesa nVarChar(150)=''
Declare @message nVarChar(Max) = '',
	    @StartDateTimeText VarChar(max) = ''

Set @iEnviaMail = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='MAILSERVICE' )

Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
Set @message = 'Start DateTime : %s | [SGSP_Test] | EnviaMail => '+ Rtrim(Cast(@iEnviaMail As Varchar(10)))
RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

Declare @FechaHora VarChar(19)= ( Select CONVERT(char(19), GetDate(),120) ),
	@EventoFecha VarChar(max),
	@EventoHora VarChar(max)

Declare @Query	nVarChar(255)='',
	@cFrom			nVarChar(100)=( Select par_cValor From _Tablas.dbo.t_parametros Where par_ccodigo = 'MAILSENDER'),
	@cFromName		nVarChar(100)=( Select par_cValor From _Tablas.dbo.t_parametros Where par_ccodigo = 'MAILSENDERNAME'),
	@cTo			nVarChar(100)='',
	@cToOriginal	nVarChar(100)=( Select par_cValor From _Tablas.dbo.t_parametros Where par_ccodigo = 'MAILFALLOTEST'),
	@cMailDealer	nVarChar(100)='',	
	@cSubject		nVarChar(100)='Fallo de Testeo',
	@cMessage		nVarChar(4000)='',
	@cMessageMerge  nVarChar(max),
	@cImagenes      nVarChar(max),
	@cMail			nVarChar(300)='',
	@cToSMS		    nVarChar(150)='',
	@cDestinoSMS	nVarChar(150)=''

Declare @cCuenta	Char(80)='',
	@aut_ccodigo	Char(3)='',
	@aut_cdealer	Char(3)='',
	@aut_cprovincia	Char(3)='',
	@cue_cLinea		Char(3)='',
	@cue_cProvincia	Char(3)='',
	@cEsAP			Char(1)='',
	@Dealer			Char(3) = ''

Declare @nFin		Int=1,
	    @iModemSMS	Int=0,
		@iEnviaMailPorFalloTest Int=2	--2 es No
		
Declare @nInsert Numeric(1,0)=0
		
Set @cFrom = Ltrim(Rtrim(@cFrom))
Set @cFromName = Ltrim(Rtrim(@cFromName))

Declare @iProceso Int = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='PROCESATST' )
--Indica si se realiza el control de Testeo. 0:No / 1:Si / 2:Si, en cuentas que no esten en FallaTST
Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
Set @message = 'Start DateTime : %s | [SGSP_Test] | Proceso => '+ Rtrim(Cast(@iProceso As Varchar(10)))
RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

If @iProceso > 0
    Begin	
		-- Aviso que la tarea esta funcionando
		Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'ControlTST', @Repetition = 10
		--	
		DECLARE m_tst_prueba_Cursor CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
		SELECT tst_iidCuenta,tst_cAlarma,sta_dFechaultimotst ,
			  (CASE WHEN tst_ntipo = 0 THEN DATEADD( MINUTE,tst_ncada,sta_dfechaultimotst ) 
					WHEN tst_ntipo = 1 THEN DATEADD( HOUR,tst_ncada,sta_dfechaultimotst ) 
					WHEN tst_ntipo = 2 THEN DATEADD( DAY,tst_ncada,sta_dfechaultimotst ) 
			   END ) AS Fecha_Hasta_aux ,
			  ( Select est_iidcuenta FROM m_estado_cuenta_Cab A With (NOLOCK) 
					 Where est_iidCuenta=tst_iidCuenta And ( est_nEstado=2 OR 
				( est_nEstado=1 And @DiaHoy BetWeen est_dfechadesde And est_dfechahasta )
			   )) As iDesactivada,tst_cAlarmaAutoprocesa 
			 FROM m_tst_prueba With (NOLOCK)
			 Left Outer Join m_status On sta_iidCuenta=tst_iidCuenta
			 WHERE tst_ncada>0 And tst_cAlarma <> ''
			 	And (CASE WHEN @iProceso = 2 Then sta_ncuentaenfallodetst Else 0 END) = 0
				And (CASE WHEN tst_ntipo = 0 THEN DATEADD( MINUTE,tst_ncada,sta_dfechaultimotst ) 
					   WHEN tst_ntipo = 1 THEN DATEADD( HOUR,tst_ncada,sta_dfechaultimotst ) 
					   WHEN tst_ntipo = 2 THEN DATEADD( DAY,tst_ncada,sta_dfechaultimotst ) 
				 END ) <= GetDate()
			Order By Fecha_Hasta_aux

		Set @cTo = Ltrim(Rtrim(@cToOriginal))

		OPEN m_tst_prueba_Cursor
		FETCH NEXT FROM m_tst_prueba_Cursor INTO @iidCuenta , @cAlarma, @dFechaultimotst, @Fecha_Hasta_aux, @iDesactivada, @cAutoprocesa
		WHILE @@FETCH_STATUS = 0
		BEGIN
			Set @iDiferencia = DateDiff(minute,GETDATE(),@Fecha_Hasta_aux)	
			
			Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | IdCuenta => '+ Rtrim(Cast(@iidCuenta As Varchar(10)))+' | Alarma => '+ @cAlarma+' | FechaHora Ultimo TST => '+CONVERT(varchar, @dFechaultimotst,120) +' | FechaHora Hasta => '+CONVERT(varchar, @Fecha_Hasta_aux,120) + ' | Desactivada => '+ Rtrim(Cast(@iDesactivada As Varchar(10)))+' | AutoProcesa => '+ @cAutoprocesa + ' | Diferencia => '+ Rtrim(Cast(@iDiferencia As Varchar(10)))
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			IF @iDiferencia Is Null Or @iDiferencia <= 0
				Begin
					Set @cResolucion =''
					Set @nEstado = 0
					Set @cUpdateStatus = 'S'
					If NOT @iDesactivada Is Null
						Begin	
							--La cuenta esta Desactivada.Grabo con Resolucion Desactivada y Estado 7
							Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | --La cuenta esta Desactivada. Grabo con Resolucion Desactivada y Estado 7--'
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

							Set @cResolucion = (Select CAST(par_ivalor As Char(3)) As cValor FROM [_Tablas].[dbo].[t_parametros] Where par_ccodigo='MODO NO HABILITADO')
							Set @cResolucion = Stuff('000',4-Len(@cResolucion),Len(@cResolucion),@cResolucion)
							Set @nEstado = 7
							Set @cUpdateStatus = 'N'
						End	

					--Si viene categorizado como NoHabilitada se trata como un Evento de NO GENERAR, NO se graba p_recepcion			
					If @nEstado = 7
					   Set @iParametro = 2
					Else
					   Set @iParametro = ( SELECT cod_nalerta From _Tablas.dbo.t_codigos_alarma With (NOLOCK) Where cod_ccodigo=@cAlarma )

					Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
					Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Parametro => '+ Rtrim(Cast(@iParametro As Varchar(10)))
					RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

					--2 Es un Evento de NO GENERAR, NO se graba p_recepcion			
					If @iParametro < 2
						Begin	
							--Si NO Genera Alerta (0) lo grabo con estado 5
							If @iParametro = 0
								Set @nEstado = 5

							If @cGrabo = 'S'	
								Begin
									BEGIN TRY
										Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
										Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Execute [dbo].[SGSP_pRecepcionINS] con @nEstado => '+ Rtrim(Cast(@nEstado As Varchar(10)))
										RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

										EXEC [dbo].[SGSP_pRecepcionINS]
											@rec_iidcuenta = @iidCuenta,
											@rec_calarma = @cAlarma,
											@rec_tfechahora  = @DiaHoy,
											@rec_nestado  = @nEstado,
											@rec_ioperador = 0,
											@rec_idResolucion = @cResolucion,
											@rec_tFechaRecepcion = @DiaHoy,
											@rec_nOrigen = 8,
											@iValor = @intParameter OUTPUT
									END TRY
									BEGIN CATCH
										Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
										Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Execute [dbo].[SGSP_pRecepcionINS] Volvio con error'
										RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
										Set @intParameter=0
									END CATCH

									if @intParameter > 0
									Begin
										Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
										Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Execute [dbo].[SGSP_pRecepcionINS] Volvio con ID => '+ Rtrim(Cast(@intParameter As Varchar(10)))
										RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

										--Dealer para notificaciones x mail--
										Select @Dealer = IsNull(cue_clinea,'') From m_cuentas Where cue_iid = @iidCuenta
										
										Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
										Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Dealer para notificaciones x mail => '+ @Dealer
										RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

										--PushNotification--
										--Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Execute [dbo].[SGSP_PushNotification] con @intParameter => '+ Rtrim(Cast(@intParameter As Varchar(10)))
										--RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
										--Execute SGSP_PushNotification @intParameter
										--2023-12-28 : Pablo. Se cambio a [SGSP_AlarmaSMS] para tambien tener notificaciones por dealer
										Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Execute [dbo].[SGSP_AlarmaSMS]'
										RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
										Execute [dbo].[SGSP_AlarmaSMS] @idCta = @iidCuenta, @cCodigoAlarma = @cAlarma, @idRec = @intParameter

										--Reporte Autoridades
										--Primero busco si hay autoridades y eventos automaticos/autoProcesados a controlar 
										Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
										Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Reporte Autoridades | --Primero busco si hay autoridades y eventos automaticos/autoProcesados a controlar--'
										RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

										DECLARE cAutoridad CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
											Select aut_ccodigo,aut_cdealer,aut_cprovincia, (Case When CHARINDEX(@cAlarma,aut_cAutoProcesados) > 0 Then 'S' Else 'N' End) As cEsAP
												From _Tablas.dbo.t_autoridades
												Where CHARINDEX(@cAlarma,aut_meventosauto) > 0 Or  CHARINDEX(@cAlarma,aut_cAutoProcesados) > 0 

										OPEN cAutoridad
										FETCH NEXT FROM cAutoridad INTO @aut_ccodigo,@aut_cdealer,@aut_cprovincia,@cEsAP
										WHILE @@FETCH_STATUS = 0
										BEGIN
											--Segundo busco la provincia y el dealer de la cuenta
											Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
											Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Reporte Autoridades | --Segundo busco la provincia y el dealer de la cuenta--'
											RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

											DECLARE cCta CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
							   					Select cue_cLinea ,cue_cProvincia From m_cuentas
												Where cue_iid=@iidCuenta
							
											OPEN cCta
											FETCH NEXT FROM cCta INTO @cue_cLinea,@cue_cProvincia
											WHILE @@FETCH_STATUS = 0
											BEGIN
												Set @nInsert = 0
	
												If @aut_cdealer = @cue_cLinea And @aut_cprovincia = @cue_cProvincia
													Set @nInsert = 1
												Else 
													If Ltrim(Rtrim(@aut_cdealer))= '' And @aut_cprovincia = @cue_cProvincia
														Set @nInsert = 1
													Else
														If @aut_cdealer = @cue_cLinea And Ltrim(Rtrim(@aut_cprovincia))= ''
															Set @nInsert = 1
														Else
															If Ltrim(Rtrim(@aut_cdealer))= '' And Ltrim(Rtrim(@aut_cprovincia))= ''
																Set @nInsert = 1
									 
												If @nInsert = 1
												   Begin
												   		Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
														Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Reporte Autoridades | Insert Into p_reporte_autoridades'
														RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

														Insert Into p_reporte_autoridades(rep_cautoridad,rep_iidcuenta,rep_calarma,rep_dfechahora,rep_czona,rep_iidrecepcion)
														VALUES(@aut_ccodigo,@iidCuenta,@cAlarma,GetDate(),'',@intParameter)
									  
														If @cEsAP = 'S' And @cGrabo = 'S'	And @nEstado <> 5
															Begin
																--Busco Categorizacion de Reporte Autoridad Auto Procesado
																Set @cResolucion = (Select CAST(par_ivalor As Char(3)) As cValor FROM [_Tablas].[dbo].[t_parametros] Where par_ccodigo='CATREPAUTORIDADAP')
																Set @cResolucion = Stuff('000',4-Len(@cResolucion),Len(@cResolucion),@cResolucion)

																Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
																Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Reporte Autoridades | UPDATE p_recepcion con Categorizacion de Reporte Autoridad Auto Procesado => ' + @cResolucion
																RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

																UPDATE p_recepcion Set rec_nestado=5, rec_idResolucion=@cResolucion Where rec_iid=@intParameter
															End

												   End
								
											   FETCH NEXT FROM cCta INTO @cue_cLinea,@cue_cProvincia
											End
					
										   CLOSE cCta
										   DEALLOCATE cCta

										FETCH NEXT FROM cAutoridad INTO @aut_ccodigo,@aut_cdealer,@aut_cprovincia,@cEsAP
										End
					
										CLOSE cAutoridad
										DEALLOCATE cAutoridad
									End
								End --del If grabo								

							--Envio Mail
							Set @cCuenta = ( SELECT cue_clinea+'-'+Rtrim(cue_ncuenta)+' '+cue_cnombre FROM m_cuentas Where cue_iid=@iidCuenta )	
							Set @cMessage = 'En cuenta ' + Rtrim(@cCuenta) + ' | ' +@cAlarma+' | '+CONVERT(char(19), GetDate(),120)  

							Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Envio Mail | Message => ' + @cMessage
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

							Set @cMail = @cTo 
							Set @cMailDealer = ''
							Set @iEnviaMailPorFalloTest = 2

							SELECT @cMailDealer=lin_cmail, @iEnviaMailPorFalloTest=lin_iEnviaMailPorFalloTest FROM _Tablas.dbo.t_lineas Inner Join m_cuentas On lin_ccodigo=cue_clinea Where cue_iid=@iidCuenta 

							If @iEnviaMailPorFalloTest = 2 Or @iEnviaMailPorFalloTest Is Null
								Set @cMailDealer = ''

							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Envio Mail | Mail => ' + @cMail + ' | MailDealer => ' + @cMailDealer
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

							IF @cMailDealer Is Not Null And @cMailDealer <> ''
								Begin
									If @cMail <> ''
										Set @cMail = @cMail +';'+@cMailDealer +';'	
									Else
										Set @cMail = @cMailDealer +';'	
								End				
							Else 				
								Begin
									If @cMail <> ''
										Set @cMail = @cMail +';'
								End	
						
							WHILE CHARINDEX(';',@cMail) > 0
							BEGIN
							   Set @nFin = CHARINDEX(';',@cMail)	
							   Set @cTo=SUBSTRING( @cMail, 1, @nFin-1 )
							   Set @Query = 'Select '+CHAR(39)+@cTo+CHAR(39)+' As Email'
							
							   Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
							   Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Envio Mail | Query => ' + @Query
							   RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

							   If @cGrabo = 'S' And @iEnviaMail = 1		
								  EXEC _Sistema.dbo.sp_SendMail @cFrom, @cTo, @cSubject, @cMessage	

							   If @cGrabo = 'S' And @iEnviaMail = 2		
								  Begin	
									Set @EventoFecha = LEFT(@FechaHora,11) 
									Set @EventoHora = RIGHT(@FechaHora,8) 
									Set @cMessageMerge = ''
									Execute SGSP_TextMerge	@iidCuenta,'',@cAlarma,@cAlarma,@EventoFecha,@EventoHora,@intParameter, @cMessageMerge OUTPUT, @cImagenes OUTPUT
									If @cMessageMerge Is Null
										Set @cMessageMerge = @cMessage
									Else
										Begin
											--Uso el nombre de la plantilla como Subject
											Set @cSubject = ( Select [pls_cdescripcion] From _Tablas.dbo.t_plantillas_sms WHere pls_ccodigo=@cAlarma )
											If @cSubject Is Null Or @cSubject = ''
												Set @cSubject = 'Fallo de Testeo'
										End

										Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
										Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Envio Mail | Execute _Datos.dbo.SmartMail_ProgramCreate | FromName => ' + @cFromName + ' | From => ' + @cFrom + ' | Subject => ' + @cSubject + ' | MessageMerge => ' + @cMessageMerge + ' | Query => ' + @Query + ' | IdCuenta => ' + Rtrim(Cast(@iidCuenta As Varchar(10))) 
										RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
										
										Execute _Datos.dbo.SmartMail_ProgramCreate @cFromName, @cFrom, @cSubject, @cMessageMerge, @DiaHoy, 1, @Query, 'MAIL', @cImagenes, 802, @iidCuenta

								  End
							   
							   Set @cMail = SUBSTRING( @cMail, @nFin+1, 300-@nFin )
							END
							--

							--Envio de Mail x Evento
							Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Envio Mail x Evento | Alarma => ' + @cAlarma
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	  						Select Top 1 @cMail=sms_cmailparaeventos,@cPlantilla=sms_cplantillamail,@cSubject=pls_cdescripcion From m_sms
								Inner Join _Tablas.dbo.t_plantillas_sms On pls_ccodigo=sms_cplantillamail
 							  Where sms_cmailparaeventos<> ''  And sms_cplantillamail<>'' And sms_iidCuenta=@iidCuenta And
									( CHARINDEX(@cAlarma, sms_meventos) > 0  Or
									( sms_iNotificarAlertas=1 And @cAlarma IN (Select cod_ccodigo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And cod_nalerta=1)) Or
									( sms_iGrupoAlarmas>0 And sms_iGrupoAlarmas IN (Select gru_idKey From _Tablas.dbo.t_Grupos TG	Where EXISTS ( Select cod_cGrupo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And CHARINDEX(TG.gru_ccodigo,cod_cGrupo) > 0 ) ) ) )

							If @cMail <> ''
								Set @cMail = @cMail +';'

							Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Envio Mail x Evento | Mail => ' + @cMail
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

							WHILE CHARINDEX(';',@cMail) > 0
							BEGIN
							   Set @nFin = CHARINDEX(';',@cMail)	
							   Set @cTo=SUBSTRING( @cMail, 1, @nFin-1 )
							   Set @Query = 'Select '+CHAR(39)+@cTo+CHAR(39)+' As Email'
							
							   If @cGrabo = 'S' And @iEnviaMail = 1		
								  EXEC _Sistema.dbo.sp_SendMail @cFrom, @cTo, @cSubject, @cMessage	

							   If @cGrabo = 'S' And @iEnviaMail = 2		
								  Begin	
								    --Si ya proceso la plantilla para mail x dealer/parametro NO la uso x que puede ser otra plantilla
									Set @EventoFecha = LEFT(@FechaHora,11) 
									Set @EventoHora = RIGHT(@FechaHora,8) 
									Set @cMessageMerge = ''
									EXEC SGSP_TextMerge	@iidCuenta,'',@cAlarma,@cPlantilla,@EventoFecha,@EventoHora,@intParameter, @cMessageMerge OUTPUT, @cImagenes OUTPUT

									If @cMessageMerge Is Null
										Set @cMessageMerge = @cMessage

									Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120) 
									Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Envio Mail x Evento | Execute _Datos.dbo.SmartMail_ProgramCreate | FromName => ' + @cFromName + ' | From => ' + @cFrom + ' | Subject => ' + @cSubject + ' | MessageMerge => ' + @cMessageMerge + ' | Query => ' + @Query + ' | IdCuenta => ' + Rtrim(Cast(@iidCuenta As Varchar(10))) 
									RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

									Execute _Datos.dbo.SmartMail_ProgramCreate @cFromName, @cFrom, @cSubject, @cMessageMerge, @DiaHoy, 1, @Query, 'MAIL', @cImagenes, 802, @iidCuenta

								  End
							   
							   Set @cMail = SUBSTRING( @cMail, @nFin+1, 300-@nFin )
							END
							Set @cTo = Ltrim(Rtrim(@cToOriginal))	--Dejo el original para el loop
							Set @cToSMS = ''
							Set @iModemSMS = 0
							--							

							--Mail por evento para Dealer
						    If @cGrabo = 'S' And @iEnviaMail = 2		
							Begin	
								Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
								Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Envio Mail x Evento para Dealer | Dealer => ' + @Dealer
								RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
								
								If @Dealer <> ''
								Begin
									Declare cMailxEvento CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR 
	  									Select [tnd_cMail],[tnd_cPlantillaMail],[pls_cdescripcion]
											From [_Tablas].[dbo].[T_Notificaciones_Dealer]
											Inner Join [_Tablas].[dbo].[t_plantillas_sms] On [pls_ccodigo]=[tnd_cPlantillaMail]
 										Where [tnd_cMail]<> '' And [tnd_cPlantillaMail]<>'' And [tnd_cDealer]=@Dealer And [tnd_iTipo]=0 And
											  ( CHARINDEX(@cAlarma, [tnd_cAlarmas]) > 0  Or
	 										  ( [tnd_iNotificarAlertas]=1 And @cAlarma IN (Select cod_ccodigo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And cod_nalerta=1) ) Or
											  ( [tnd_iGrupoAlarmas]>0 And [tnd_iGrupoAlarmas] IN (Select gru_idKey From _Tablas.dbo.t_Grupos TG	Where EXISTS ( Select cod_cGrupo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And CHARINDEX(TG.gru_ccodigo,cod_cGrupo) > 0 ) ) ) )
	
									Open cMailxEvento
									Fetch Next From cMailxEvento Into @cMail,@cPlantilla,@cSubject
									While @@FETCH_STATUS = 0
									Begin
										If @cMail <> ''
											Set @cMail = @cMail +';'

										WHILE CHARINDEX(';',@cMail) > 0
										Begin
											Set @nFin = CHARINDEX(';',@cMail)	
											Set @cTo = SUBSTRING( @cMail, 1, @nFin-1 )
											Set @Query = 'Select '+CHAR(39)+@cTo+CHAR(39)+' As Email'
			
											--Blanqueo para que el loop no los tenga con datos
											Set @cMessageMerge = ''
											Set @cImagenes = ''
											--

											Set @EventoFecha = LEFT(@FechaHora,11) 
											Set @EventoHora = RIGHT(@FechaHora,8) 
											Set @cMessageMerge = ''
											EXEC SGSP_TextMerge	@iidCuenta,'',@cAlarma,@cPlantilla,@EventoFecha,@EventoHora,@intParameter, @cMessageMerge OUTPUT, @cImagenes OUTPUT

											If @cMessageMerge Is Null
												Set @cMessageMerge = @cSubject

											Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120) 
											Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Envio Mail x Evento para Dealer | Execute _Datos.dbo.SmartMail_ProgramCreate | FromName => ' + @cFromName + ' | From => ' + @cFrom + ' | Subject => ' + @cSubject + ' | MessageMerge => ' + @cMessageMerge + ' | Query => ' + @Query + ' | IdCuenta => ' + Rtrim(Cast(@iidCuenta As Varchar(10))) 
											RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

											Execute _Datos.dbo.SmartMail_ProgramCreate @cFromName, @cFrom, @cSubject, @cMessageMerge, @DiaHoy, 1, @Query, 'MAIL', @cImagenes, 802, @iidCuenta

											Set @cMail = SUBSTRING( @cMail, @nFin+1, 300-@nFin );
										End
	
									   Fetch Next From cMailxEvento Into @cMail,@cPlantilla,@cSubject
									End
									Close cMailxEvento
									Deallocate cMailxEvento

									Set @cTo = Ltrim(Rtrim(@cToOriginal))	--Dejo el original para el loop
									Set @cToSMS = ''
									Set @iModemSMS = 0
								End
							End
							--

							--Envio de SMS
							Select Top 1 @cToSMS=sms_csmsparaeventos, @iModemSMS=sms_imodemsms, @cPlantilla=sms_cplantillasms, @cSubject=pls_cdescripcion From m_sms
								Inner Join _Tablas.dbo.t_plantillas_sms On pls_ccodigo=sms_cplantillasms
			 				  Where sms_csmsparaeventos<>'' And sms_cplantillasms<>'' And sms_imodemsms>0 And sms_iidCuenta=@iidCuenta And
								 ( CHARINDEX(@cAlarma, sms_meventos) > 0  Or
								 ( sms_iNotificarAlertas=1 And @cAlarma IN (Select cod_ccodigo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And cod_nalerta=1)) Or
								 ( sms_iGrupoAlarmas>0 And sms_iGrupoAlarmas IN (Select gru_idKey From _Tablas.dbo.t_Grupos TG	Where EXISTS ( Select cod_cGrupo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And CHARINDEX(TG.gru_ccodigo,cod_cGrupo) > 0 ) ) ) )

							Set @cToSMS = Ltrim(Rtrim(@cToSMS))+';'

							Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Envio de SMS | ToSMS => ' + @cToSMS
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

							WHILE CHARINDEX(';',@cToSMS) > 0 And @iModemSMS > 0
							BEGIN
							   Set @nFin = CHARINDEX(';',@cToSMS)	
							   Set @cDestinoSMS=SUBSTRING( @cToSMS, 1, @nFin-1 )
							   If @cGrabo = 'S'
								Begin
									Set @EventoFecha = LEFT(@FechaHora,11) 
									Set @EventoHora = RIGHT(@FechaHora,8) 
									Set @cMessageMerge = ''
									Execute SGSP_TextMerge	@iidCuenta,'',@cAlarma,@cPlantilla,@EventoFecha,@EventoHora,@intParameter, @cMessageMerge OUTPUT, @cImagenes OUTPUT

									If @cMessageMerge Is Null
										Set @cMessageMerge = @cMessage

									Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120) 
									Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Envio de SMS | Execute SGSP_SaveSMSQueue | IdCuenta => ' + Rtrim(Cast(@iidCuenta As Varchar(10))) + ' | ModemSMS => ' + Rtrim(Cast(@iModemSMS As Varchar(10))) + ' | MessageMerge => ' + @cMessageMerge + ' | DestinoSMS => ' + @cDestinoSMS 
									RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

									Execute SGSP_SaveSMSQueue @iidCuenta,@iModemSMS,@cMessageMerge,@cDestinoSMS	
									--Insert Into p_SMSqueue (que_idCuenta,que_iModemSMS,que_cAsunto,que_cDestino)
									--Values (@iidCuenta,@iModemSMS,@cMessageMerge,@cDestinoSMS)
									----Values (@iidCuenta,@iModemSMS,@cSubject+' : '+@cMessage,@cDestinoSMS)
								End
								
							   Set @cToSMS = SUBSTRING( @cToSMS, @nFin+1, 150-@nFin )
							END
							--							
					    End

						Set @UltimoTSTRec = GETDATE()

						If @cGrabo = 'S'	
							Begin  
								---Actualizo el m_status
								Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
								Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Actualizo el m_status | IdCuenta => '+ Rtrim(Cast(@iidCuenta As Varchar(10))) + ' | FechaHora Ultimo TST => '+CONVERT(varchar, @UltimoTSTRec,120) 
								RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

								UPDATE m_status Set sta_dFechaultimotst = @UltimoTSTRec Where sta_iidCuenta=@iidCuenta
								---Si la cuenta esta NoHabilitada NO actualizo fallodetst
								If @cUpdateStatus = 'S'
	   						      Begin	
									UPDATE m_status Set sta_ncuentaenfallodetst = 1, sta_cultimaalarma = @cAlarma, sta_dfechautimaalarma = CONVERT(DateTime, CONVERT(Varchar(20), @DiaHoy, 120),111) Where sta_iidCuenta=@iidCuenta

									--Tengo q actualizar desde cuando esta en Fallo pero solo si la fecha esta null
									UPDATE m_status Set sta_tEnFalloDeTSTDesde = @UltimoTSTRec Where sta_iidCuenta=@iidCuenta And sta_tEnFalloDeTSTDesde Is Null

									--Si se configuro @cAutoprocesa entonces hay que insertar en [EventosEnFalloTesteo]
									If @cAutoprocesa <> ''
									Begin
										Set @cAutoprocesa = '1|,'+@cAutoprocesa
										
										Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
										Set @message = 'Start DateTime : %s | [SGSP_Test] | Control de TST | Execute [dbo].[SGSP_Fill_EventosEnFalloTesteo] | Autoprocesa => '+@cAutoprocesa
										RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

										Execute [dbo].[SGSP_Fill_EventosEnFalloTesteo]	@idRecNoRes = @intParameter, @idCuenta = @iidCuenta, @tEventoFechaHora = @DiaHoy, @cAlarmaAutoprocesa = @cAutoprocesa
									End

								  End	
							End			

				End

		   FETCH NEXT FROM m_tst_prueba_Cursor INTO @iidCuenta , @cAlarma, @dFechaultimotst, @Fecha_Hasta_aux, @iDesactivada, @cAutoprocesa
		End

		CLOSE m_tst_prueba_Cursor
		DEALLOCATE m_tst_prueba_Cursor

    End
Else	-- Aviso que la tarea no cumple las condiciones para funcionar
	Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'ControlTST', @Repetition = 10, @Date = null, @Status = 0	

------------------------------------------------------------------------------------------------
----2do TST
------------------------------------------------------------------------------------------------
Set @iProceso = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='PROCESA2TST' )
--Indica si se realiza el control de Testeo. 0:No / 1:Si / 2:Si, en cuentas que no esten en FallaTST
Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Proceso => '+ Rtrim(Cast(@iProceso As Varchar(10)))
RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
If @iProceso > 0
    Begin	
		-- Aviso que la tarea esta funcionando
		Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'Control2TST', @Repetition = 10
		--	

		DECLARE m_tst_prueba_Cursor CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
		SELECT tst_iidCuenta,tst_cAlarmaGenerar,sta_dFechaultimo2dotst ,
			  (CASE WHEN tst_ntipo2 = 0 THEN DATEADD( MINUTE,tst_ncada2,sta_dfechaultimo2dotst ) 
					WHEN tst_ntipo2 = 1 THEN DATEADD( HOUR,tst_ncada2,sta_dfechaultimo2dotst ) 
					WHEN tst_ntipo2 = 2 THEN DATEADD( DAY,tst_ncada2,sta_dfechaultimo2dotst ) 
			   END ) AS Fecha_Hasta_aux ,
			  ( Select est_iidcuenta FROM m_estado_cuenta_Cab A With (NOLOCK) 
					 Where est_iidCuenta=tst_iidCuenta And ( est_nEstado=2 OR 
				( est_nEstado=1 And @DiaHoy BetWeen est_dfechadesde And est_dfechahasta )
			   )) As iDesactivada,tst_cAlarma2Autoprocesa 
			 FROM m_tst_prueba With (NOLOCK)
			 Left Outer Join m_status On sta_iidCuenta=tst_iidCuenta
			 WHERE tst_ncada2>0 And tst_cAlarmaGenerar <> ''
			 And (CASE WHEN @iProceso = 2 Then sta_ncuentaenfallo2dotst Else 0 END) = 0
			 And (CASE WHEN tst_ntipo2 = 0 THEN DATEADD( MINUTE,tst_ncada2,sta_dfechaultimo2dotst ) 
				 WHEN tst_ntipo2 = 1 THEN DATEADD( HOUR,tst_ncada2,sta_dfechaultimo2dotst ) 
				  WHEN tst_ntipo2 = 2 THEN DATEADD( DAY,tst_ncada2,sta_dfechaultimo2dotst ) 
				 END ) <= GetDate()
			Order By Fecha_Hasta_aux

		Set @cSubject = 'Fallo de 2do Testeo'
		Set @cTo = Ltrim(Rtrim(@cToOriginal))
		OPEN m_tst_prueba_Cursor
		FETCH NEXT FROM m_tst_prueba_Cursor INTO @iidCuenta , @cAlarma, @dFechaultimotst, @Fecha_Hasta_aux, @iDesactivada, @cAutoprocesa
		WHILE @@FETCH_STATUS = 0
		BEGIN
			Set @iDiferencia = DateDiff(minute,GETDATE(),@Fecha_Hasta_aux)
			
			Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | IdCuenta => '+ Rtrim(Cast(@iidCuenta As Varchar(10)))+' | Alarma => '+ @cAlarma+' | FechaHora Ultimo TST => '+CONVERT(varchar, @dFechaultimotst,120) +' | FechaHora Hasta => '+CONVERT(varchar, @Fecha_Hasta_aux,120) + ' | Desactivada => '+ Rtrim(Cast(@iDesactivada As Varchar(10)))+' | AutoProcesa => '+ @cAutoprocesa + ' | Diferencia => '+ Rtrim(Cast(@iDiferencia As Varchar(10)))
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			IF @iDiferencia Is Null Or @iDiferencia <= 0
				Begin
					Set @cResolucion =''
					Set @nEstado = 0
					Set @cUpdateStatus = 'S'
					If NOT @iDesactivada Is Null
						Begin	
							--La cuenta esta Desactivada.Grabo con Resolucion Desactivada y Estado 7
							Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | --La cuenta esta Desactivada. Grabo con Resolucion Desactivada y Estado 7--'
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
							
							Set @cResolucion = (Select CAST(par_ivalor As Char(3)) As cValor FROM [_Tablas].[dbo].[t_parametros] Where par_ccodigo='MODO NO HABILITADO')
							Set @cResolucion = Stuff('000',4-Len(@cResolucion),Len(@cResolucion),@cResolucion)
							Set @nEstado = 7
							Set @cUpdateStatus = 'N'
						End	

					--Si viene categorizao como NoHabilitada se trata como un Evento de NO GENERAR, NO se graba p_recepcion			
					If @nEstado = 7
					   Set @iParametro = 2
					Else
					   Set @iParametro = ( SELECT cod_nalerta From _Tablas.dbo.t_codigos_alarma With (NOLOCK) Where cod_ccodigo=@cAlarma )

					Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
					Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Parametro => '+ Rtrim(Cast(@iParametro As Varchar(10)))
					RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

					--2 Es un Evento de NO GENERAR, NO se graba p_recepcion			
					If @iParametro < 2
						Begin	
							--Si NO Genera Alerta (0) lo grabo con estado 5
							If @iParametro = 0
								Set @nEstado = 5

							If @cGrabo = 'S'	
								Begin 
									BEGIN TRY
										Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
										Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Execute [dbo].[SGSP_pRecepcionINS] con @nEstado => '+ Rtrim(Cast(@nEstado As Varchar(10)))
										RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

										Execute [dbo].[SGSP_pRecepcionINS]
												@rec_iidcuenta = @iidCuenta,
												@rec_calarma = @cAlarma,
												@rec_tfechahora  = @DiaHoy,
												@rec_nestado  = @nEstado,
												@rec_ioperador = 0,
												@rec_idResolucion = @cResolucion,
												@rec_tFechaRecepcion = @DiaHoy,
												@rec_nOrigen = 8,
												@iValor = @intParameter OUTPUT
									END TRY
									BEGIN CATCH
										Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
										Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Execute [dbo].[SGSP_pRecepcionINS] Volvio con error'
										RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

										Set @intParameter=0
									END CATCH

									if @intParameter > 0
									Begin
										Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
										Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Execute [dbo].[SGSP_pRecepcionINS] Volvio con ID => '+ Rtrim(Cast(@intParameter As Varchar(10)))
										RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

										--Dealer para notificaciones x mail--
										Select @Dealer = IsNull(cue_clinea,'') From m_cuentas Where cue_iid = @iidCuenta
										Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
										Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Dealer para notificaciones x mail => '+ @Dealer
										RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

										--PushNotification--
										Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Execute [dbo].[SGSP_PushNotification] con @intParameter => '+ Rtrim(Cast(@intParameter As Varchar(10)))
										RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
										Execute SGSP_PushNotification @intParameter

										--Reporte Autoridades
										--Primero busco si hay autoridades y eventos automaticos/autoProcesados a controlar 
										Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
										Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Reporte Autoridades | --Primero busco si hay autoridades y eventos automaticos/autoProcesados a controlar--'
										RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
										DECLARE cAutoridad CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
											Select aut_ccodigo,aut_cdealer,aut_cprovincia, (Case When CHARINDEX(@cAlarma,aut_cAutoProcesados) > 0 Then 'S' Else 'N' End) As cEsAP
												From _Tablas.dbo.t_autoridades
												Where CHARINDEX(@cAlarma,aut_meventosauto) > 0 Or  CHARINDEX(@cAlarma,aut_cAutoProcesados) > 0 

										OPEN cAutoridad
										FETCH NEXT FROM cAutoridad INTO @aut_ccodigo,@aut_cdealer,@aut_cprovincia,@cEsAP
										WHILE @@FETCH_STATUS = 0
										BEGIN
											--Segundo busco la provincia y el dealer de la cuenta
											Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
											Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Reporte Autoridades | --Segundo busco la provincia y el dealer de la cuenta--'
											RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

											DECLARE cCta CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
							   					Select cue_cLinea ,cue_cProvincia From m_cuentas
												Where cue_iid=@iidCuenta
							
											OPEN cCta
											FETCH NEXT FROM cCta INTO @cue_cLinea,@cue_cProvincia
											WHILE @@FETCH_STATUS = 0
											BEGIN
												Set @nInsert = 0
	
												If @aut_cdealer = @cue_cLinea And @aut_cprovincia = @cue_cProvincia
													Set @nInsert = 1
												Else 
													If Ltrim(Rtrim(@aut_cdealer))= '' And @aut_cprovincia = @cue_cProvincia
														Set @nInsert = 1
													Else
														If @aut_cdealer = @cue_cLinea And Ltrim(Rtrim(@aut_cprovincia))= ''
															Set @nInsert = 1
														Else
															If Ltrim(Rtrim(@aut_cdealer))= '' And Ltrim(Rtrim(@aut_cprovincia))= ''
																Set @nInsert = 1
									 
												If @nInsert = 1
													Begin
												   		Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
														Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Reporte Autoridades | Insert Into p_reporte_autoridades'
														RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

														Insert Into p_reporte_autoridades(rep_cautoridad,rep_iidcuenta,rep_calarma,rep_dfechahora,rep_czona,rep_iidrecepcion)
														VALUES(@aut_ccodigo,@iidCuenta,@cAlarma,GetDate(),'',@intParameter)
									  
														If @cEsAP = 'S' And @cGrabo = 'S'	And @nEstado <> 5
														Begin
															--Busco Categorizacion de Reporte Autoridad Auto Procesado
															Set @cResolucion = (Select CAST(par_ivalor As Char(3)) As cValor FROM [_Tablas].[dbo].[t_parametros] Where par_ccodigo='CATREPAUTORIDADAP')
															Set @cResolucion = Stuff('000',4-Len(@cResolucion),Len(@cResolucion),@cResolucion)

															Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
															Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Reporte Autoridades | UPDATE p_recepcion con Categorizacion de Reporte Autoridad Auto Procesado => ' + @cResolucion
															RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

															UPDATE p_recepcion Set rec_nestado=5, rec_idResolucion=@cResolucion Where rec_iid=@intParameter
														End
													 End
								
												FETCH NEXT FROM cCta INTO @cue_cLinea,@cue_cProvincia
											End
					
											CLOSE cCta
											DEALLOCATE cCta

							
									FETCH NEXT FROM cAutoridad INTO @aut_ccodigo,@aut_cdealer,@aut_cprovincia,@cEsAP
									End
					
									CLOSE cAutoridad
									DEALLOCATE cAutoridad
								End
							End --del If grabo									

							--Envio Mail
							Set @cCuenta = ( SELECT cue_clinea+'-'+Rtrim(cue_ncuenta)+' '+cue_cnombre FROM m_cuentas Where cue_iid=@iidCuenta )	
							Set @cMessage = 'En cuenta ' + Rtrim(@cCuenta) + ' | ' +@cAlarma+' | '+CONVERT(char(19), GetDate(),120)  

							Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Envio Mail | Message => ' + @cMessage
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

							Set @cMail = @cTo 
							Set @cMailDealer = ''
							Set @iEnviaMailPorFalloTest = 2

							SELECT @cMailDealer=lin_cmail, @iEnviaMailPorFalloTest=lin_iEnviaMailPorFalloTest FROM _Tablas.dbo.t_lineas Inner Join m_cuentas On lin_ccodigo=cue_clinea Where cue_iid=@iidCuenta 

							If @iEnviaMailPorFalloTest = 2 Or @iEnviaMailPorFalloTest Is Null
								Set @cMailDealer = ''

							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Envio Mail | Mail => ' + @cMail + ' | MailDealer => ' + @cMailDealer
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

							IF @cMailDealer Is Not Null And @cMailDealer <> ''
								Begin
									If @cMail <> ''
										Set @cMail = @cMail +';'+@cMailDealer +';'	
									Else
										Set @cMail = @cMailDealer +';'	
								End				
							Else 				
								Begin
									If @cMail <> ''
										Set @cMail = @cMail +';'
								End	
						
							WHILE CHARINDEX(';',@cMail) > 0
							BEGIN
							   Set @nFin = CHARINDEX(';',@cMail)	
							   Set @cTo=SUBSTRING( @cMail, 1, @nFin-1 )
							   Set @Query = 'Select '+CHAR(39)+@cTo+CHAR(39)+' As Email'
					
							   Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
							   Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Envio Mail | Query => ' + @Query
							   RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
					
							   If @cGrabo = 'S' And @iEnviaMail = 1		
								  EXEC _Sistema.dbo.sp_SendMail @cFrom, @cTo, @cSubject, @cMessage	

							   If @cGrabo = 'S' And @iEnviaMail = 2		
								  Begin	
									Set @EventoFecha = LEFT(@FechaHora,11) 
									Set @EventoHora = RIGHT(@FechaHora,8) 
									Set @cMessageMerge = ''
									EXEC SGSP_TextMerge	@iidCuenta,'',@cAlarma,@cAlarma,@EventoFecha,@EventoHora,@intParameter, @cMessageMerge OUTPUT, @cImagenes OUTPUT
									If @cMessageMerge Is Null
										Set @cMessageMerge = @cMessage
									Else
										Begin
											--Uso el nombre de la plantilla como Subject
											Set @cSubject = ( Select [pls_cdescripcion] From _Tablas.dbo.t_plantillas_sms WHere pls_ccodigo=@cAlarma )
											If @cSubject Is Null Or @cSubject = ''
												Set @cSubject = 'Fallo de 2do Testeo'
										End

									Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
									Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Envio Mail | Execute _Datos.dbo.SmartMail_ProgramCreate | FromName => ' + @cFromName + ' | From => ' + @cFrom + ' | Subject => ' + @cSubject + ' | MessageMerge => ' + @cMessageMerge + ' | Query => ' + @Query + ' | IdCuenta => ' + Rtrim(Cast(@iidCuenta As Varchar(10))) 
									RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

									Execute _Datos.dbo.SmartMail_ProgramCreate @cFromName, @cFrom, @cSubject, @cMessageMerge, @DiaHoy, 1, @Query, 'MAIL',@cImagenes, 802, @iidCuenta
								  End
							   
							   Set @cMail = SUBSTRING( @cMail, @nFin+1, 300-@nFin )
							END
							--

							--Envio de Mail x Evento
							Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Envio Mail x Evento | Alarma => ' + @cAlarma
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	  						Select Top 1 @cMail=sms_cmailparaeventos,@cPlantilla=sms_cplantillamail,@cSubject=pls_cdescripcion From m_sms
								Inner Join _Tablas.dbo.t_plantillas_sms On pls_ccodigo=sms_cplantillamail
 							  Where sms_cmailparaeventos<> '' And sms_cplantillamail<>'' And sms_iidCuenta=@iidCuenta And 
									 ( CHARINDEX(@cAlarma, sms_meventos) > 0  Or
									 ( sms_iNotificarAlertas=1 And @cAlarma IN (Select cod_ccodigo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And cod_nalerta=1)) Or
									 ( sms_iGrupoAlarmas>0 And sms_iGrupoAlarmas IN (Select gru_idKey From _Tablas.dbo.t_Grupos TG	Where EXISTS ( Select cod_cGrupo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And CHARINDEX(TG.gru_ccodigo,cod_cGrupo) > 0 ) ) ) )

							If @cMail <> ''
								Set @cMail = @cMail +';'

							Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Envio Mail x Evento | Mail => ' + @cMail
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

							WHILE CHARINDEX(';',@cMail) > 0
							BEGIN
							   Set @nFin = CHARINDEX(';',@cMail)	
							   Set @cTo = SUBSTRING( @cMail, 1, @nFin-1 )
							   Set @Query = 'Select '+CHAR(39)+@cTo+CHAR(39)+' As Email'
							
							   If @cGrabo = 'S' And @iEnviaMail = 1		
								  EXEC _Sistema.dbo.sp_SendMail @cFrom, @cTo, @cSubject, @cMessage	

							   If @cGrabo = 'S' And @iEnviaMail = 2		
								  Begin	
								    --Si ya proceso la plantilla para mail x dealer/parametro NO la uso x que puede ser otra plantilla
									Set @EventoFecha = LEFT(@FechaHora,11) 
									Set @EventoHora = RIGHT(@FechaHora,8) 
									Set @cMessageMerge = ''
									EXEC SGSP_TextMerge	@iidCuenta,'',@cAlarma,@cPlantilla,@EventoFecha,@EventoHora,@intParameter, @cMessageMerge OUTPUT, @cImagenes OUTPUT

									If @cMessageMerge Is Null
										Set @cMessageMerge = @cMessage

									Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120) 
									Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Envio Mail x Evento | Execute _Datos.dbo.SmartMail_ProgramCreate | FromName => ' + @cFromName + ' | From => ' + @cFrom + ' | Subject => ' + @cSubject + ' | MessageMerge => ' + @cMessageMerge + ' | Query => ' + @Query + ' | IdCuenta => ' + Rtrim(Cast(@iidCuenta As Varchar(10))) 
									RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

									Execute _Datos.dbo.SmartMail_ProgramCreate @cFromName, @cFrom, @cSubject, @cMessageMerge, @DiaHoy, 1, @Query, 'MAIL', @cImagenes, 802, @iidCuenta
								  End
							   
							   Set @cMail = SUBSTRING( @cMail, @nFin+1, 300-@nFin )
							END 
							Set @cTo = Ltrim(Rtrim(@cToOriginal))	--Dejo el original para el loop
							Set @cToSMS = ''
							Set @iModemSMS = 0
							--							

							--Mail por evento para Dealer
						    If @cGrabo = 'S' And @iEnviaMail = 2		
							Begin	
								Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
								Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Envio Mail x Evento para Dealer | Dealer => ' + @Dealer
								RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

								If @Dealer <> ''
								Begin
									Declare cMailxEvento CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR 
	  									Select [tnd_cMail],[tnd_cPlantillaMail],[pls_cdescripcion]
											From [_Tablas].[dbo].[T_Notificaciones_Dealer]
											Inner Join [_Tablas].[dbo].[t_plantillas_sms] On [pls_ccodigo]=[tnd_cPlantillaMail]
 										Where [tnd_cMail]<> '' And [tnd_cPlantillaMail]<>'' And [tnd_cDealer]=@Dealer And [tnd_iTipo]=0 And
											  ( CHARINDEX(@cAlarma, [tnd_cAlarmas]) > 0  Or
											  ( [tnd_iNotificarAlertas]=1 And @cAlarma IN (Select cod_ccodigo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And cod_nalerta=1) ) Or
											  ( [tnd_iGrupoAlarmas]>0 And [tnd_iGrupoAlarmas] IN (Select gru_idKey From _Tablas.dbo.t_Grupos TG	Where EXISTS ( Select cod_cGrupo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And CHARINDEX(TG.gru_ccodigo,cod_cGrupo) > 0 ) ) ) )
	
									Open cMailxEvento
									Fetch Next From cMailxEvento Into @cMail,@cPlantilla,@cSubject
									While @@FETCH_STATUS = 0
									Begin
										If @cMail <> ''
											Set @cMail = @cMail +';'

										WHILE CHARINDEX(';',@cMail) > 0
										Begin
											Set @nFin = CHARINDEX(';',@cMail)	
											Set @cTo = SUBSTRING( @cMail, 1, @nFin-1 )
											Set @Query = 'Select '+CHAR(39)+@cTo+CHAR(39)+' As Email'
			
											--Blanqueo para que el loop no los tenga con datos
											Set @cMessageMerge = ''
											Set @cImagenes = ''
											--

											Set @EventoFecha = LEFT(@FechaHora,11) 
											Set @EventoHora = RIGHT(@FechaHora,8) 
											Set @cMessageMerge = ''
											EXEC SGSP_TextMerge	@iidCuenta,'',@cAlarma,@cPlantilla,@EventoFecha,@EventoHora,@intParameter, @cMessageMerge OUTPUT, @cImagenes OUTPUT

											If @cMessageMerge Is Null
												Set @cMessageMerge = @cSubject

											Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120) 
											Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Envio Mail x Evento para Dealer | Execute _Datos.dbo.SmartMail_ProgramCreate | FromName => ' + @cFromName + ' | From => ' + @cFrom + ' | Subject => ' + @cSubject + ' | MessageMerge => ' + @cMessageMerge + ' | Query => ' + @Query + ' | IdCuenta => ' + Rtrim(Cast(@iidCuenta As Varchar(10))) 
											RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

											Execute _Datos.dbo.SmartMail_ProgramCreate @cFromName, @cFrom, @cSubject, @cMessageMerge, @DiaHoy, 1, @Query, 'MAIL', @cImagenes, 802, @iidCuenta

											Set @cMail = SUBSTRING( @cMail, @nFin+1, 300-@nFin );
										End
	
									   Fetch Next From cMailxEvento Into @cMail,@cPlantilla,@cSubject
									End
									Close cMailxEvento
									Deallocate cMailxEvento

									Set @cTo = Ltrim(Rtrim(@cToOriginal))	--Dejo el original para el loop
									Set @cToSMS = ''
									Set @iModemSMS = 0
								End
							End
							--

							--Envio de SMS
							Select Top 1 @cToSMS=sms_csmsparaeventos, @iModemSMS=sms_imodemsms, @cPlantilla=sms_cplantillasms, @cSubject=pls_cdescripcion From m_sms
								Inner Join _Tablas.dbo.t_plantillas_sms On pls_ccodigo=sms_cplantillasms
			 				  Where sms_csmsparaeventos<>'' And sms_cplantillasms<>'' And sms_imodemsms>0 And sms_iidCuenta=@iidCuenta And
								 ( CHARINDEX(@cAlarma, sms_meventos) > 0  Or
								 ( sms_iNotificarAlertas=1 And @cAlarma IN (Select cod_ccodigo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And cod_nalerta=1)) Or
								 ( sms_iGrupoAlarmas>0 And sms_iGrupoAlarmas IN (Select gru_idKey From _Tablas.dbo.t_Grupos TG	Where EXISTS ( Select cod_cGrupo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And CHARINDEX(TG.gru_ccodigo,cod_cGrupo) > 0 ) ) ) )

							Set @cToSMS = Ltrim(Rtrim(@cToSMS))+';'
							
							Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Envio de SMS | ToSMS => ' + @cToSMS
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

							WHILE CHARINDEX(';',@cToSMS) > 0 And @iModemSMS > 0
							BEGIN
							   Set @nFin = CHARINDEX(';',@cToSMS)	
							   Set @cDestinoSMS=SUBSTRING( @cToSMS, 1, @nFin-1 )
							   If @cGrabo = 'S'
								Begin
									Set @EventoFecha = LEFT(@FechaHora,11) 
									Set @EventoHora = RIGHT(@FechaHora,8) 
									Set @cMessageMerge = ''
									EXEC SGSP_TextMerge	@iidCuenta,'',@cAlarma,@cPlantilla,@EventoFecha,@EventoHora,@intParameter, @cMessageMerge OUTPUT, @cImagenes OUTPUT

									If @cMessageMerge Is Null
										Set @cMessageMerge = @cMessage

									Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120) 
									Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Envio de SMS | Execute SGSP_SaveSMSQueue | IdCuenta => ' + Rtrim(Cast(@iidCuenta As Varchar(10))) + ' | ModemSMS => ' + Rtrim(Cast(@iModemSMS As Varchar(10))) + ' | MessageMerge => ' + @cMessageMerge + ' | DestinoSMS => ' + @cDestinoSMS 
									RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

									Execute SGSP_SaveSMSQueue @iidCuenta,@iModemSMS,@cMessageMerge,@cDestinoSMS	
									--Insert Into p_SMSqueue (que_idCuenta,que_iModemSMS,que_cAsunto,que_cDestino)
									--Values (@iidCuenta,@iModemSMS,@cMessageMerge,@cDestinoSMS)
									----Values (@iidCuenta,@iModemSMS,@cSubject+' : '+@cMessage,@cDestinoSMS)
								End
							
							   Set @cToSMS = SUBSTRING( @cToSMS, @nFin+1, 150-@nFin )
							END
							--														
					    End

						Set @UltimoTSTRec = GETDATE()
						If @cGrabo = 'S'	
							Begin  
								---Actualizo el m_status
								Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
								Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Actualizo el m_status | IdCuenta => '+ Rtrim(Cast(@iidCuenta As Varchar(10))) + ' | FechaHora Ultimo TST => '+CONVERT(varchar, @UltimoTSTRec,120) 
								RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

								UPDATE m_status Set sta_dFechaultimo2dotst = @UltimoTSTRec Where sta_iidCuenta=@iidCuenta
								---Si la cuenta esta NoHabilitada NO actualizo fallodetst
								If @cUpdateStatus = 'S'
									Begin	
										UPDATE m_status Set sta_ncuentaenfallo2dotst = 1, sta_cultimaalarma = @cAlarma, sta_dfechautimaalarma = CONVERT(DateTime, CONVERT(Varchar(20), @DiaHoy, 120),111) Where sta_iidCuenta=@iidCuenta
									
										--Tengo q actualizar desde cuando esta en Fallo pero solo si la fecha esta null
										UPDATE m_status Set sta_tEnFalloDeTST2Desde = @UltimoTSTRec Where sta_iidCuenta=@iidCuenta And sta_tEnFalloDeTST2Desde Is Null

										--Si se configuro @cAutoprocesa entonces hay que insertar en [EventosEnFalloTesteo]
										If @cAutoprocesa <> ''
										Begin
											Set @cAutoprocesa = '2|,'+@cAutoprocesa
										
											Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
											Set @message = 'Start DateTime : %s | [SGSP_Test] | Control2TST | Execute [dbo].[SGSP_Fill_EventosEnFalloTesteo] | Autoprocesa => '+@cAutoprocesa
											RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

											Execute [dbo].[SGSP_Fill_EventosEnFalloTesteo]	@idRecNoRes = @intParameter, @idCuenta = @iidCuenta, @tEventoFechaHora = @DiaHoy, @cAlarmaAutoprocesa = @cAutoprocesa
										End


									End	
							End 
				End

			FETCH NEXT FROM m_tst_prueba_Cursor INTO @iidCuenta , @cAlarma, @dFechaultimotst, @Fecha_Hasta_aux, @iDesactivada, @cAutoprocesa
		End

		CLOSE m_tst_prueba_Cursor
		DEALLOCATE m_tst_prueba_Cursor

    End
Else	-- Aviso que la tarea no cumple las condiciones para funcionar
	Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'Control2TST', @Repetition = 10, @Date = null, @Status = 0	

------------------------------------------------------------------------------------------------
----3er TST
------------------------------------------------------------------------------------------------
Set  @iProceso = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='PROCESA3TST' )
--Indica si se realiza el control de Testeo. 0:No / 1:Si / 2:Si, en cuentas que no esten en FallaTST
Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Proceso => '+ Rtrim(Cast(@iProceso As Varchar(10)))
RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
If @iProceso > 0
    Begin	
		-- Aviso que la tarea esta funcionando
		Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'Control3TST', @Repetition = 10
		--	

		DECLARE m_tst_prueba_Cursor CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
		SELECT tst_iidCuenta,tst_cAlarma3Generar,sta_dFechaultimo3ertst ,
			  (CASE WHEN tst_ntipo3 = 0 THEN DATEADD( MINUTE,tst_ncada3,sta_dfechaultimo3ertst ) 
					WHEN tst_ntipo3 = 1 THEN DATEADD( HOUR,tst_ncada3,sta_dfechaultimo3ertst ) 
					WHEN tst_ntipo3 = 2 THEN DATEADD( DAY,tst_ncada3,sta_dfechaultimo3ertst ) 
			   END ) AS Fecha_Hasta_aux ,
			  ( Select est_iidcuenta FROM m_estado_cuenta_Cab A With (NOLOCK) 
					 Where est_iidCuenta=tst_iidCuenta And ( est_nEstado=2 OR 
				( est_nEstado=1 And @DiaHoy BetWeen est_dfechadesde And est_dfechahasta )
			   )) As iDesactivada,tst_cAlarma3Autoprocesa 
			 FROM m_tst_prueba With (NOLOCK)
			 Left Outer Join m_status On sta_iidCuenta=tst_iidCuenta
			 WHERE tst_ncada3>0 And tst_cAlarma3Generar <> ''
			 And (CASE WHEN @iProceso = 2 Then sta_ncuentaenfallo3ertst Else 0 END) = 0
			 And (CASE WHEN tst_ntipo3 = 0 THEN DATEADD( MINUTE,tst_ncada3,sta_dfechaultimo3ertst ) 
				 WHEN tst_ntipo3 = 1 THEN DATEADD( HOUR,tst_ncada3,sta_dfechaultimo3ertst ) 
				  WHEN tst_ntipo3 = 2 THEN DATEADD( DAY,tst_ncada3,sta_dfechaultimo3ertst ) 
				 END ) <= GetDate() And sta_nEstado = 0
			Order By Fecha_Hasta_aux

		Set @cSubject = 'Fallo de Test Seguidor'
		Set @cTo = Ltrim(Rtrim(@cToOriginal))		

		OPEN m_tst_prueba_Cursor
		FETCH NEXT FROM m_tst_prueba_Cursor INTO @iidCuenta , @cAlarma, @dFechaultimotst, @Fecha_Hasta_aux, @iDesactivada, @cAutoprocesa
		WHILE @@FETCH_STATUS = 0
		BEGIN
			Set @iDiferencia = DateDiff(minute,GETDATE(),@Fecha_Hasta_aux)

			Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | IdCuenta => '+ Rtrim(Cast(@iidCuenta As Varchar(10)))+' | Alarma => '+ @cAlarma+' | FechaHora Ultimo TST => '+CONVERT(varchar, @dFechaultimotst,120) +' | FechaHora Hasta => '+CONVERT(varchar, @Fecha_Hasta_aux,120) + ' | Desactivada => '+ Rtrim(Cast(@iDesactivada As Varchar(10)))+' | AutoProcesa => '+ @cAutoprocesa + ' | Diferencia => '+ Rtrim(Cast(@iDiferencia As Varchar(10)))
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			IF @iDiferencia Is Null Or @iDiferencia <= 0
				Begin
					Set @cResolucion =''
					Set @nEstado = 0
					Set @cUpdateStatus = 'S'
					If NOT @iDesactivada Is Null
						Begin	
							--La cuenta esta Desactivada.Grabo con Resolucion Desactivada y Estado 7
							Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | --La cuenta esta Desactivada. Grabo con Resolucion Desactivada y Estado 7--'
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
	
							Set @cResolucion = (Select CAST(par_ivalor As Char(3)) As cValor FROM [_Tablas].[dbo].[t_parametros] Where par_ccodigo='MODO NO HABILITADO')
							Set @cResolucion = Stuff('000',4-Len(@cResolucion),Len(@cResolucion),@cResolucion)
							Set @nEstado = 7
							Set @cUpdateStatus = 'S'
						End	

					--Si viene categorizao como NoHabilitada se trata como un Evento de NO GENERAR, NO se graba p_recepcion			
					If @nEstado = 7
					   Set @iParametro = 2
					Else
					   Set @iParametro = ( SELECT cod_nalerta From _Tablas.dbo.t_codigos_alarma With (NOLOCK) Where cod_ccodigo=@cAlarma )

					Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
					Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Parametro => '+ Rtrim(Cast(@iParametro As Varchar(10)))
					RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

					--2 Es un Evento de NO GENERAR, NO se graba p_recepcion			
					If @iParametro < 2
						Begin	
							--Si NO Genera Alerta (0) lo grabo con estado 5
							If @iParametro = 0
								Set @nEstado = 5
								If @cGrabo = 'S'	
									Begin  
										BEGIN TRY
											Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
											Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Execute [dbo].[SGSP_pRecepcionINS] con @nEstado => '+ Rtrim(Cast(@nEstado As Varchar(10)))
											RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

											Execute [dbo].[SGSP_pRecepcionINS]
														@rec_iidcuenta = @iidCuenta,
														@rec_calarma = @cAlarma,
														@rec_tfechahora  = @DiaHoy,
														@rec_nestado  = @nEstado,
														@rec_ioperador = 0,
														@rec_idResolucion = @cResolucion,
														@rec_tFechaRecepcion = @DiaHoy,
														@rec_nOrigen = 8,
														@iValor = @intParameter OUTPUT
										END TRY
										BEGIN CATCH
											Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
											Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Execute [dbo].[SGSP_pRecepcionINS] Volvio con error'
											RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

											Set @intParameter=0
										END CATCH

										if @intParameter > 0
										Begin
											Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
											Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Execute [dbo].[SGSP_pRecepcionINS] Volvio con ID => '+ Rtrim(Cast(@intParameter As Varchar(10)))
											RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

											--Dealer para notificaciones x mail--
											Select @Dealer = IsNull(cue_clinea,'') From m_cuentas Where cue_iid = @iidCuenta

											--Dealer para notificaciones x mail--
											Select @Dealer = IsNull(cue_clinea,'') From m_cuentas Where cue_iid = @iidCuenta
											Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
											Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Dealer para notificaciones x mail => '+ @Dealer
											RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

											--PushNotification--
											Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Execute [dbo].[SGSP_PushNotification] con @intParameter => '+ Rtrim(Cast(@intParameter As Varchar(10)))
											RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
											Execute SGSP_PushNotification @intParameter

											--Reporte Autoridades
											--Primero busco si hay autoridades y eventos automaticos/autoProcesados a controlar 
											Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
											Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Reporte Autoridades | --Primero busco si hay autoridades y eventos automaticos/autoProcesados a controlar--'
											RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

											DECLARE cAutoridad CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
												Select aut_ccodigo,aut_cdealer,aut_cprovincia, (Case When CHARINDEX(@cAlarma,aut_cAutoProcesados) > 0 Then 'S' Else 'N' End) As cEsAP
													From _Tablas.dbo.t_autoridades
													Where CHARINDEX(@cAlarma,aut_meventosauto) > 0 Or  CHARINDEX(@cAlarma,aut_cAutoProcesados) > 0 

											OPEN cAutoridad
											FETCH NEXT FROM cAutoridad INTO @aut_ccodigo,@aut_cdealer,@aut_cprovincia,@cEsAP
											WHILE @@FETCH_STATUS = 0
											BEGIN
												--Segundo busco la provincia y el dealer de la cuenta
												Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
												Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Reporte Autoridades | --Segundo busco la provincia y el dealer de la cuenta--'
												RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
												
												DECLARE cCta CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
							   						Select cue_cLinea ,cue_cProvincia From m_cuentas
													Where cue_iid=@iidCuenta
							
												OPEN cCta
												FETCH NEXT FROM cCta INTO @cue_cLinea,@cue_cProvincia
												WHILE @@FETCH_STATUS = 0
												BEGIN
													Set @nInsert = 0
	
													If @aut_cdealer = @cue_cLinea And @aut_cprovincia = @cue_cProvincia
														Set @nInsert = 1
													Else 
														If Ltrim(Rtrim(@aut_cdealer))= '' And @aut_cprovincia = @cue_cProvincia
															Set @nInsert = 1
														Else
															If @aut_cdealer = @cue_cLinea And Ltrim(Rtrim(@aut_cprovincia))= ''
																Set @nInsert = 1
															Else
																If Ltrim(Rtrim(@aut_cdealer))= '' And Ltrim(Rtrim(@aut_cprovincia))= ''
																	Set @nInsert = 1
									 
												If @nInsert = 1
													Begin
												   		Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
														Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Reporte Autoridades | Insert Into p_reporte_autoridades'
														RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

														Insert Into p_reporte_autoridades(rep_cautoridad,rep_iidcuenta,rep_calarma,rep_dfechahora,rep_czona,rep_iidrecepcion)
														VALUES(@aut_ccodigo,@iidCuenta,@cAlarma,GetDate(),'',@intParameter)
									  
														If @cEsAP = 'S' And @cGrabo = 'S'	And @nEstado <> 5
														Begin
															--Busco Categorizacion de Reporte Autoridad Auto Procesado
															Set @cResolucion = (Select CAST(par_ivalor As Char(3)) As cValor FROM [_Tablas].[dbo].[t_parametros] Where par_ccodigo='CATREPAUTORIDADAP')
															Set @cResolucion = Stuff('000',4-Len(@cResolucion),Len(@cResolucion),@cResolucion)

															Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
															Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Reporte Autoridades | UPDATE p_recepcion con Categorizacion de Reporte Autoridad Auto Procesado => ' + @cResolucion
															RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

															UPDATE p_recepcion Set rec_nestado=5, rec_idResolucion=@cResolucion Where rec_iid=@intParameter
														End
												    End
								
													FETCH NEXT FROM cCta INTO @cue_cLinea,@cue_cProvincia
											   End
					
											   CLOSE cCta
											   DEALLOCATE cCta
							
											FETCH NEXT FROM cAutoridad INTO @aut_ccodigo,@aut_cdealer,@aut_cprovincia,@cEsAP
											End
					
											CLOSE cAutoridad
											DEALLOCATE cAutoridad
									End
								End --del If grabo										
						  
							--Envio Mail
							Set @cCuenta = ( SELECT cue_clinea+'-'+Rtrim(cue_ncuenta)+' '+cue_cnombre FROM m_cuentas Where cue_iid=@iidCuenta )	
							Set @cMessage = 'En cuenta ' + Rtrim(@cCuenta) + ' | ' +@cAlarma+' | '+CONVERT(char(19), GetDate(),120)  
							
							Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Envio Mail | Message => ' + @cMessage
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

							Set @cMail = @cTo 
							Set @cMailDealer = ''
							Set @iEnviaMailPorFalloTest = 2

							SELECT @cMailDealer=lin_cmail, @iEnviaMailPorFalloTest=lin_iEnviaMailPorFalloTest FROM _Tablas.dbo.t_lineas Inner Join m_cuentas On lin_ccodigo=cue_clinea Where cue_iid=@iidCuenta 

							If @iEnviaMailPorFalloTest = 2 Or @iEnviaMailPorFalloTest Is Null
								Set @cMailDealer = ''

							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Envio Mail | Mail => ' + @cMail + ' | MailDealer => ' + @cMailDealer
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

							IF @cMailDealer Is Not Null And @cMailDealer <> ''
								Begin
									If @cMail <> ''
										Set @cMail = @cMail +';'+@cMailDealer +';'	
									Else
										Set @cMail = @cMailDealer +';'	
								End				
							Else 				
								Begin
									If @cMail <> ''
										Set @cMail = @cMail +';'
								End	
						
							WHILE CHARINDEX(';',@cMail) > 0
							BEGIN
							   Set @nFin = CHARINDEX(';',@cMail)	
							   Set @cTo=SUBSTRING( @cMail, 1, @nFin-1 )
							   Set @Query = 'Select '+CHAR(39)+@cTo+CHAR(39)+' As Email'
							
							   Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
							   Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Envio Mail | Query => ' + @Query
							   RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

							   If @cGrabo = 'S' And @iEnviaMail = 1		
								  EXEC _Sistema.dbo.sp_SendMail @cFrom, @cTo, @cSubject, @cMessage	

							   If @cGrabo = 'S' And @iEnviaMail = 2		
								  Begin	
									Set @EventoFecha = LEFT(@FechaHora,11) 
									Set @EventoHora = RIGHT(@FechaHora,8) 
									Set @cMessageMerge = ''
									EXEC SGSP_TextMerge	@iidCuenta,'',@cAlarma,@cAlarma,@EventoFecha,@EventoHora,@intParameter, @cMessageMerge OUTPUT, @cImagenes OUTPUT
									If @cMessageMerge Is Null
										Set @cMessageMerge = @cMessage
									Else
										Begin
											--Uso el nombre de la plantilla como Subject
											Set @cSubject = ( Select [pls_cdescripcion] From _Tablas.dbo.t_plantillas_sms WHere pls_ccodigo=@cAlarma )
											If @cSubject Is Null Or @cSubject = ''
												Set @cSubject = 'Fallo de Test Seguidor'
										End

									Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
									Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Envio Mail | Execute _Datos.dbo.SmartMail_ProgramCreate | FromName => ' + @cFromName + ' | From => ' + @cFrom + ' | Subject => ' + @cSubject + ' | MessageMerge => ' + @cMessageMerge + ' | Query => ' + @Query + ' | IdCuenta => ' + Rtrim(Cast(@iidCuenta As Varchar(10))) 
									RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

									Execute _Datos.dbo.SmartMail_ProgramCreate @cFromName, @cFrom, @cSubject, @cMessageMerge, @DiaHoy, 1, @Query, 'MAIL', @cImagenes, 802, @iidCuenta
								  End
							   
							   Set @cMail = SUBSTRING( @cMail, @nFin+1, 300-@nFin )
							END
							--

							--Envio de Mail x Evento
							Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Envio Mail x Evento | Alarma => ' + @cAlarma
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	  						Select Top 1 @cMail=sms_cmailparaeventos,@cPlantilla=sms_cplantillamail,@cSubject=pls_cdescripcion From m_sms
								Inner Join _Tablas.dbo.t_plantillas_sms On pls_ccodigo=sms_cplantillamail
 							  Where sms_cmailparaeventos<> '' And sms_cplantillamail<>'' And sms_iidCuenta=@iidCuenta And
									( CHARINDEX(@cAlarma, sms_meventos) > 0  Or
									( sms_iNotificarAlertas=1 And @cAlarma IN (Select cod_ccodigo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And cod_nalerta=1)) Or
									( sms_iGrupoAlarmas>0 And sms_iGrupoAlarmas IN (Select gru_idKey From _Tablas.dbo.t_Grupos TG	Where EXISTS ( Select cod_cGrupo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And CHARINDEX(TG.gru_ccodigo,cod_cGrupo) > 0 ) ) ) )

							If @cMail <> ''
								Set @cMail = @cMail +';'
							
							Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Envio Mail x Evento | Mail => ' + @cMail
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

							WHILE CHARINDEX(';',@cMail) > 0
							BEGIN
							   Set @nFin = CHARINDEX(';',@cMail)	
							   Set @cTo=SUBSTRING( @cMail, 1, @nFin-1 )
							   Set @Query = 'Select '+CHAR(39)+@cTo+CHAR(39)+' As Email'
							
							   If @cGrabo = 'S' And @iEnviaMail = 1		
								  EXEC _Sistema.dbo.sp_SendMail @cFrom, @cTo, @cSubject, @cMessage	

							   If @cGrabo = 'S' And @iEnviaMail = 2		
								  Begin	
									Set @EventoFecha = LEFT(@FechaHora,11) 
									Set @EventoHora = RIGHT(@FechaHora,8) 
									Set @cMessageMerge = ''
									EXEC SGSP_TextMerge	@iidCuenta,'',@cAlarma,@cPlantilla,@EventoFecha,@EventoHora,@intParameter, @cMessageMerge OUTPUT, @cImagenes OUTPUT

									If @cMessageMerge Is Null
										Set @cMessageMerge = @cMessage

									Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120) 
									Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Envio Mail x Evento | Execute _Datos.dbo.SmartMail_ProgramCreate | FromName => ' + @cFromName + ' | From => ' + @cFrom + ' | Subject => ' + @cSubject + ' | MessageMerge => ' + @cMessageMerge + ' | Query => ' + @Query + ' | IdCuenta => ' + Rtrim(Cast(@iidCuenta As Varchar(10))) 
									RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
									
									Execute _Datos.dbo.SmartMail_ProgramCreate @cFromName, @cFrom, @cSubject, @cMessageMerge, @DiaHoy, 1, @Query, 'MAIL', @cImagenes, 802, @iidCuenta

								  End
							   
							   Set @cMail = SUBSTRING( @cMail, @nFin+1, 300-@nFin )
							END
							Set @cTo = Ltrim(Rtrim(@cToOriginal))	--Dejo el original para el loop							
							Set @cToSMS = ''
							Set @iModemSMS = 0
							--							

							--Mail por evento para Dealer
						    If @cGrabo = 'S' And @iEnviaMail = 2		
							Begin	
								Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
								Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Envio Mail x Evento para Dealer | Dealer => ' + @Dealer
								RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

								If @Dealer <> ''
								Begin
									Declare cMailxEvento CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR 
	  									Select [tnd_cMail],[tnd_cPlantillaMail],[pls_cdescripcion]
											From [_Tablas].[dbo].[T_Notificaciones_Dealer]
											Inner Join [_Tablas].[dbo].[t_plantillas_sms] On [pls_ccodigo]=[tnd_cPlantillaMail]
 										Where [tnd_cMail]<> '' And [tnd_cPlantillaMail]<>'' And [tnd_cDealer]=@Dealer And [tnd_iTipo]=0 And
											  ( CHARINDEX(@cAlarma, [tnd_cAlarmas]) > 0  Or
 											  ( [tnd_iNotificarAlertas]=1 And @cAlarma IN (Select cod_ccodigo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And cod_nalerta=1) ) Or
											  ( [tnd_iGrupoAlarmas]>0 And [tnd_iGrupoAlarmas] IN (Select gru_idKey From _Tablas.dbo.t_Grupos TG	Where EXISTS ( Select cod_cGrupo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And CHARINDEX(TG.gru_ccodigo,cod_cGrupo) > 0 ) ) ) )
	
									Open cMailxEvento
									Fetch Next From cMailxEvento Into @cMail,@cPlantilla,@cSubject
									While @@FETCH_STATUS = 0
									Begin
										If @cMail <> ''
											Set @cMail = @cMail +';'

										WHILE CHARINDEX(';',@cMail) > 0
										Begin
											Set @nFin = CHARINDEX(';',@cMail)	
											Set @cTo = SUBSTRING( @cMail, 1, @nFin-1 )
											Set @Query = 'Select '+CHAR(39)+@cTo+CHAR(39)+' As Email'
			
											--Blanqueo para que el loop no los tenga con datos
											Set @cMessageMerge = ''
											Set @cImagenes = ''
											--

											Set @EventoFecha = LEFT(@FechaHora,11) 
											Set @EventoHora = RIGHT(@FechaHora,8) 
											Set @cMessageMerge = ''
											EXEC SGSP_TextMerge	@iidCuenta,'',@cAlarma,@cPlantilla,@EventoFecha,@EventoHora,@intParameter, @cMessageMerge OUTPUT, @cImagenes OUTPUT

											If @cMessageMerge Is Null
												Set @cMessageMerge = @cSubject
											
											Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120) 
											Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Envio Mail x Evento para Dealer | Execute _Datos.dbo.SmartMail_ProgramCreate | FromName => ' + @cFromName + ' | From => ' + @cFrom + ' | Subject => ' + @cSubject + ' | MessageMerge => ' + @cMessageMerge + ' | Query => ' + @Query + ' | IdCuenta => ' + Rtrim(Cast(@iidCuenta As Varchar(10))) 
											RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

											Execute _Datos.dbo.SmartMail_ProgramCreate @cFromName, @cFrom, @cSubject, @cMessageMerge, @DiaHoy, 1, @Query, 'MAIL', @cImagenes, 802, @iidCuenta

											Set @cMail = SUBSTRING( @cMail, @nFin+1, 300-@nFin );
										End
	
									   Fetch Next From cMailxEvento Into @cMail,@cPlantilla,@cSubject
									End
									Close cMailxEvento
									Deallocate cMailxEvento

									Set @cTo = Ltrim(Rtrim(@cToOriginal))	--Dejo el original para el loop
									Set @cToSMS = ''
									Set @iModemSMS = 0
								End
							End
							--

							--Envio de SMS
							Select Top 1 @cToSMS=sms_csmsparaeventos, @iModemSMS=sms_imodemsms, @cPlantilla=sms_cplantillasms, @cSubject=pls_cdescripcion From m_sms
								Inner Join _Tablas.dbo.t_plantillas_sms On pls_ccodigo=sms_cplantillasms
			 				  Where sms_csmsparaeventos<>'' And sms_cplantillasms<>'' And sms_imodemsms>0 And sms_iidCuenta=@iidCuenta And
									( CHARINDEX(@cAlarma, sms_meventos) > 0  Or
									( sms_iNotificarAlertas=1 And @cAlarma IN (Select cod_ccodigo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And cod_nalerta=1)) Or
									( sms_iGrupoAlarmas>0 And sms_iGrupoAlarmas IN (Select gru_idKey From _Tablas.dbo.t_Grupos TG	Where EXISTS ( Select cod_cGrupo From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma And CHARINDEX(TG.gru_ccodigo,cod_cGrupo) > 0 ) ) ) )

							Set @cToSMS = Ltrim(Rtrim(@cToSMS))+';'
							
							Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
							Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Envio de SMS | ToSMS => ' + @cToSMS
							RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

							WHILE CHARINDEX(';',@cToSMS) > 0 And @iModemSMS > 0
							BEGIN
							   Set @nFin = CHARINDEX(';',@cToSMS)	
							   Set @cDestinoSMS=SUBSTRING( @cToSMS, 1, @nFin-1 )
							   If @cGrabo = 'S'
								Begin
									Set @EventoFecha = LEFT(@FechaHora,11) 
									Set @EventoHora = RIGHT(@FechaHora,8) 
									Set @cMessageMerge = ''
									EXEC SGSP_TextMerge	@iidCuenta,'',@cAlarma,@cPlantilla,@EventoFecha,@EventoHora,@intParameter, @cMessageMerge OUTPUT, @cImagenes OUTPUT

									If @cMessageMerge Is Null
										Set @cMessageMerge = @cMessage

									Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120) 
									Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Envio de SMS | Execute SGSP_SaveSMSQueue | IdCuenta => ' + Rtrim(Cast(@iidCuenta As Varchar(10))) + ' | ModemSMS => ' + Rtrim(Cast(@iModemSMS As Varchar(10))) + ' | MessageMerge => ' + @cMessageMerge + ' | DestinoSMS => ' + @cDestinoSMS 
									RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

									Execute SGSP_SaveSMSQueue @iidCuenta,@iModemSMS,@cMessageMerge,@cDestinoSMS	
									--Insert Into p_SMSqueue (que_idCuenta,que_iModemSMS,que_cAsunto,que_cDestino)
									--Values (@iidCuenta,@iModemSMS,@cMessageMerge,@cDestinoSMS)
									----Values (@iidCuenta,@iModemSMS,@cSubject+' : '+@cMessage,@cDestinoSMS)
								End
							
							   Set @cToSMS = SUBSTRING( @cToSMS, @nFin+1, 150-@nFin )
							END
							--														
					    End

						Set @UltimoTSTRec = GETDATE()

						If @cGrabo = 'S'	
							Begin  
								---Actualizo el m_status
								Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
								Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Actualizo el m_status | IdCuenta => '+ Rtrim(Cast(@iidCuenta As Varchar(10))) + ' | FechaHora Ultimo TST => '+CONVERT(varchar, @UltimoTSTRec,120) 
								RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

								UPDATE m_status Set sta_dFechaultimo3ertst = @UltimoTSTRec Where sta_iidCuenta=@iidCuenta
								---Si la cuenta esta NoHabilitada NO actualizo fallodetst
								If @cUpdateStatus = 'S'
							      Begin	
									UPDATE m_status Set sta_ncuentaenfallo3ertst = 1, sta_cultimaalarma = @cAlarma, sta_dfechautimaalarma = CONVERT(DateTime, CONVERT(Varchar(20), @DiaHoy, 120),111) Where sta_iidCuenta=@iidCuenta
	
									--Tengo q actualizar desde cuando esta en Fallo pero solo si la fecha esta null
							        UPDATE m_status Set sta_tEnFalloDeTST3Desde = @UltimoTSTRec Where sta_iidCuenta=@iidCuenta And sta_tEnFalloDeTST3Desde Is Null

									--Si se configuro @cAutoprocesa entonces hay que insertar en [EventosEnFalloTesteo]
									If @cAutoprocesa <> ''
									Begin
										Set @cAutoprocesa = '3|,'+@cAutoprocesa

										Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
										Set @message = 'Start DateTime : %s | [SGSP_Test] | Control3TST | Execute [dbo].[SGSP_Fill_EventosEnFalloTesteo] | Autoprocesa => '+@cAutoprocesa
										RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

										Execute [dbo].[SGSP_Fill_EventosEnFalloTesteo]	@idRecNoRes = @intParameter, @idCuenta = @iidCuenta, @tEventoFechaHora = @DiaHoy, @cAlarmaAutoprocesa = @cAutoprocesa
									End

							      End	
							End 
				End

			FETCH NEXT FROM m_tst_prueba_Cursor INTO @iidCuenta , @cAlarma, @dFechaultimotst, @Fecha_Hasta_aux, @iDesactivada, @cAutoprocesa
		End

		CLOSE m_tst_prueba_Cursor
		DEALLOCATE m_tst_prueba_Cursor

    End
Else	-- Aviso que la tarea no cumple las condiciones para funcionar
	Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'Control3TST', @Repetition = 10, @Date = null, @Status = 0	

GO
/****** Object:  StoredProcedure [dbo].[SGSP_TestUsoCuenta]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SGSP_TestUsoCuenta]
As
--Busca Cuentas sin uso del panel que NO esten en situacion NoHabilitada y se haya configurado el control
--Autor : Pablo O. Canónico
--Fecha : 11/06/2019
Set NoCount ON
-- Aviso que la tarea esta funcionando	
Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'ControlTesteoUsoCuenta', @Repetition = 360

BEGIN TRY

	Declare @message nVarChar(Max) = '',
			@StartDateTimeText VarChar(max) = ''

	Declare @DiaHoy DateTime = GetDate()

	Declare @idCuenta Int = 0,
			@iValor Int = 0,
			@iCtrlExec Int = 0
	Declare @AlarmaGenerar Char(3) = ''
	Declare @tHoraLimite Datetime

	Declare TestCuenta CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
	WITH ControlEstado AS (
	SELECT [cue_iid]
		  --,[cue_clinea],[cue_ncuenta],[cue_cnombre]
		  --,Case When [sta_nestado]= 1 Then 'Abierto' Else 'Cerrado' End As EstadoPanel
		  ,[sta_dFechaUltimoOC],[sta_dfechaOPNdesde],[cue_dFechaOPN],[cue_dFechaCLO]
		  ,Case When [sta_nestado]= 1 Then DATEADD(DAY, [tst_iTiempoCtrl], [cue_dFechaOPN] ) Else DATEADD(DAY, [tst_iTiempoCtrl], [cue_dFechaCLO] ) End As HoraLimite
		  --,DATEADD(DAY, 2, [cue_dFechaOPN] ) As HoraLimiteOPN,DATEADD(DAY, 2, [cue_dFechaCLO] ) As HoraLimiteCLO
		  ,[tst_cAlarmaCtrlGenerar],[tst_iCtrlExec]
	FROM [dbo].[m_cuentas]
		Inner Join [dbo].[m_status] On [cue_iid]=[sta_iidcuenta]
		Left Outer Join [dbo].[m_CuentasXtraInfo] On [cue_iidCuenta]=[cue_iid]
		Left Outer Join [dbo].[m_estado_cuenta_cab] On [cue_iid] = [est_iidcuenta]
		Left Outer Join [dbo].[m_tst_prueba] On [tst_iidcuenta] = [cue_iid]
	Where [cue_clinea] Not IN('_MP','_SG') And [est_nEstado]!=2 And [tst_iTiempoCtrl]>0 And [tst_iCtrlExec]=0
	)
	Select [cue_iid],[HoraLimite],[tst_cAlarmaCtrlGenerar],[tst_iCtrlExec]
		From ControlEstado
	Where HoraLimite<=@DiaHoy	

	OPEN TestCuenta
	FETCH NEXT FROM TestCuenta INTO @idCuenta,@tHoraLimite,@AlarmaGenerar,@iCtrlExec
	WHILE @@FETCH_STATUS = 0
	BEGIN

		Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | SGSP_TestUsoCuenta | IdCuenta => '+ Rtrim(Cast(@idCuenta As Varchar(10)))+' | FechaHora Limite => '+ Rtrim(Convert(VarChar, @tHoraLimite,120) )+' | Alarma a Generar => '+ @AlarmaGenerar
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

		Execute [dbo].[SGSP_TimerGeneroEVT] @idCuenta = @idCuenta, 	@AlarmaGenerar = @AlarmaGenerar, @iValor = @iValor OUTPUT

		If @iValor > 0
			Begin
				--Actualizo ejecucion de control
				Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | SGSP_TestUsoCuenta | --Actualizo ejecucion de control-- '
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

				Update [_Datos].[dbo].[m_tst_prueba] 
					Set [tst_iCtrlExec]=1
				Where [tst_iidcuenta]=@idCuenta
			End

	FETCH NEXT FROM TestCuenta INTO @idCuenta,@tHoraLimite,@AlarmaGenerar,@iCtrlExec
	End

	CLOSE TestCuenta
	DEALLOCATE TestCuenta;

END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
END CATCH

GO
/****** Object:  StoredProcedure [dbo].[SGSP_TextMerge]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE PROCEDURE [dbo].[SGSP_TextMerge]
	@idCta [int] = 0,
	@cZona [nvarchar](10) = '',
	@cAlarma [char](3) = '',
	@cCodPlantilla [char](3) = '',
	@cFecha [varchar](10) = '',
	@cHora [varchar](8) = '',
	@idRec [int] = 0,
	@cTextMerge [nvarchar](max) = '' OUTPUT,
	@cImagenes [nvarchar](max) = '' OUTPUT
WITH EXECUTE AS CALLER
AS
BEGIN
	--TextMerge de Plantilla de Mail/SMS 
	--Autor :Pablo O. Canónico
	--Fecha :05/03/2013
	--29-08-2017 Se agrego parseo de Tags para DispositivosMoviles y GPSs
	--24-11-2017 Se agrego procesamiento de '[[EVENTOIMAGEN]]'
	--26-09-2018 Se agrego procesamiento de '[[EVENTONOVEDAD]]'
	--26-02-2019 Si la cuenta tiene configurado Default Time Offset, NO se hace el cambio de horario
	--14-06-2019 Se controla que la plantilla tenga <<EVENTOPOSICION>> para evitar buscar en pPosicionesGPS
	--02-09-2020 Se agrego procesamiento de '<<TAREAPROGRAMADA>>'
	--22-12-2020 Se agrego procesamiento de '<<TAGVIAJES>>'
	--21-01-2022 Se agrego procesamiento de tags de Servicio Tecnico
	--02-03-2023 Se agrego procesamiento de '[[EVENTOOBSERVACION]]'
	SET NOCOUNT ON
	BEGIN TRY
	Declare @json As nVarChar(max)
	Declare @message nVarChar(Max) = '',
			@StartDateTimeText nVarChar(Max) = ''

	--Set @cFecha = Replace(@cFecha,'/','-')
	--Cuenta/Nombre/Dealer/Zona
	/*
	Select @json = '[' + STUFF(( Select Top 1
				',{"<<CTACODIGO>>":"' + Rtrim(MC.cue_ncuenta) + '"'			
				+ ',"<<CTANOMBRE>>":"' + REPLACE(Rtrim(Cast(MC.cue_cnombre As nVarChar)),'"','\"') + '"'	
				+ ',"<<CTADIR>>":"' + REPLACE(Rtrim(Cast(MC.cue_ccalle As nvarchar)),'"','\"') + '"'	
				+ ',"<<CTALOC>>":"' + REPLACE(Rtrim(Cast(MC.cue_clocalidad As nvarchar)),'"','\"') + '"'	
				+ ',"<<CTACPOSTAL>>":"' + REPLACE(Rtrim(Cast(MC.cue_ccodigopostal As nvarchar)),'"','\"') + '"'	
				+ ',"<<DEALERNOMBRE>>":"' + REPLACE(Rtrim(Cast(MD.lin_crazonsocial As nvarchar)),'"','\"') + '"'
				+ ',"<<DEALERTELEFONO>>":"' + Rtrim(Cast(MD.lin_ctelfono As nvarchar)) + '"'
				+ ',"<<EVENTOCODZONA>>":"' + Rtrim(Cast(@cZona As nvarchar)) + '"'
				+ ',"<<EVENTODESZONA>>":"' + REPLACE(Rtrim(Cast(Isnull(MZ.zon_cdescripcion,'') As nvarchar)),'"','\"') + '"'
				+'}'
				*/
	Select @json = '[' + STUFF(( Select Top 1
				',{"<<CTACODIGO>>":"' + Rtrim(MC.cue_ncuenta) + '"'			
				+ ',"<<CTADEALER>>":"' + REPLACE(Rtrim(MC.cue_clinea),'"','\"') + '"'
				+ ',"<<CTANOMBRE>>":"' + REPLACE(Rtrim(MC.cue_cnombre),'"','\"') + '"'	
				+ ',"<<CTADIR>>":"' + REPLACE(Rtrim(MC.cue_ccalle),'"','\"') + '"'	
				+ ',"<<CTALOC>>":"' + REPLACE(Rtrim(MC.cue_clocalidad),'"','\"') + '"'	
				+ ',"<<CTACPOSTAL>>":"' + REPLACE(Rtrim(MC.cue_ccodigopostal),'"','\"') + '"'	
				+ ',"<<DEALERNOMBRE>>":"' + REPLACE(Rtrim(MD.lin_crazonsocial),'"','\"') + '"'
				+ ',"<<DEALERTELEFONO>>":"' + Rtrim(MD.lin_ctelfono) + '"'
				+ ',"<<EVENTOCODZONA>>":"' + Rtrim(@cZona) + '"'
				+ ',"<<EVENTODESZONA>>":"' + REPLACE(Rtrim(Isnull(MZ.zon_cdescripcion,'')),'"','\"') + '"'
				+'}'
			From _Datos.dbo.m_cuentas MC
				Inner Join _Tablas.dbo.t_lineas MD On MD.lin_ccodigo=MC.cue_clinea
				Left Outer Join _Datos.dbo.m_zonas MZ On MZ.zon_iidcuenta=MC.cue_iid And MZ.zon_ccodigo=@cZona
			Where MC.cue_iid=@IdCta
			For xml path(''), type
		).value('.', 'nVarChar(max)'), 1, 1, '') + ']'

	If @jSon Is Null
		Begin
			Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --Cuenta/Nombre/Dealer/Zona-- | jSon es null!!!'
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT    

			Set NoExec On
		End
	
	Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --Cuenta/Nombre/Dealer/Zona-- | jSon : '+@json
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT    

	--Ver si es de Opn/Clo
	Declare @nTipo Numeric(1,0) = 0
	Declare @EVENTODESC nVarChar(max)
	Declare @cPlantilla nVarChar(max)

	Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | @cCodPlantilla => '+@cCodPlantilla
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT    

	Select @nTipo = cod_nTipo, @EVENTODESC = cod_cdescripcion From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@cAlarma
	If @nTipo IN(1,2)	--Opn/Clo
		Set @cPlantilla = ( Select [pls_mplantillaOpnClo] From _Tablas.dbo.t_plantillas_sms WHere pls_ccodigo=@cCodPlantilla)
	Else 
		Set @cPlantilla = ( Select [pls_mplantilla] From _Tablas.dbo.t_plantillas_sms WHere pls_ccodigo=@cCodPlantilla)

	If @cPlantilla Is Null
		Begin
			Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | No existe Plantilla => '+@cCodPlantilla
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT    

			Set NoExec On
		End
	
	Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --Ver si es de Opn/Clo-- | @cPlantilla : '+@cPlantilla
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT    

	Declare TmpCursor Cursor STATIC LOCAL READ_ONLY FORWARD_ONLY 
		For Select * from _Datos.dbo.parseJSON(@json) 

		Declare @elementiID As Int
		Declare @parentID As Int 
		Declare @objectID As Int 
		Declare @name As nVarChar(max)
		Declare @stringValue As nVarChar(max)
		Declare @type As nVarChar(max)

		Open TmpCursor
		FETCH NEXT FROM  TmpCursor INTO @elementiID,@parentID,@objectID,@name,@stringValue,@type

		WHILE @@FETCH_STATUS = 0
		Begin
			if Left(@name,2)='<<'
				Begin
					Set @cTextMerge = ( Select REPLACE(@cPlantilla,@name,@stringValue) )
					Set @cPlantilla = @cTextMerge
				End 

			FETCH NEXT FROM  TmpCursor INTO @elementiID,@parentID,@objectID,@name,@stringValue,@type
		End
	
	Close TmpCursor
	DEALLOCATE TmpCursor

	--Provincia/Estado
	Declare @CTAPROVEST nVarChar(Max) = ''
	Select  @CTAPROVEST= IsNull([pro_cdescripcion],'') From _Datos.dbo.m_cuentas 
		Left Outer Join [_Tablas].[dbo].[t_provincias] On [pro_ccodigo] = [cue_cprovincia]
		Where cue_iid=@IdCta
	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<CTAPROVEST>>',@CTAPROVEST) )
	Set @cPlantilla = @cTextMerge

	Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --Provincia/Estado-- | @cPlantilla : '+@cPlantilla
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT    

	--Evento/Fecha/Hora
	If @EVENTODESC Is Null
		Set @EVENTODESC = @cAlarma

	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<EVENTODESC>>',@EVENTODESC) )
	Set @cPlantilla = @cTextMerge

	Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --Evento-- | @cPlantilla : '+@cPlantilla
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT    

	Declare @EVENTOHORA varchar(max)
	Declare @EVENTOFECHA varchar(max)
	Declare @iAjustaHora Int
	Set @iAjustaHora = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='AJUSTAHORARIO' )		
	If @iAjustaHora = 1 And @idRec > 0
		Begin
			--Pasar Fecha/Hora a zona horaria de la cuenta

			Declare @tFechaHora Datetime
			Declare @iZonaHoraria Int = 0
			Select Top 1 @tFechaHora = rec_tfechahora,@iZonaHoraria = IsNull(cue_iZonaHoraria,0) 
				From p_Recepcion 
				Inner Join  _Datos.dbo.m_cuentas On cue_iid=rec_iidcuenta
				Where rec_iid = @idRec

			If @iZonaHoraria > 0
			Begin
				Declare @FechaOffSet DatetimeOffSet 

				set @FechaOffSet = ( Select  SWITCHOFFSET (TODATETIMEOFFSET (@tFechaHora, DATENAME ( TZoffset , SYSDATETIMEOFFSET() )),
					IsNull(TZ.ttz_nOffSet,0.00)*60 ) 
					From _Datos.dbo.m_cuentas MC
					Left Outer Join _Tablas.dbo.t_TimeZone TZ On TZ.ttz_idKey=MC.cue_iZonaHoraria
					Where MC.cue_iid = @IdCta )
	
				Set @EVENTOFECHA = (Select Convert(Char(10), @FechaOffSet,103))
				Set @EVENTOHORA = (Select Convert(Char(8), @FechaOffSet,108))
			End
			Else
			Begin
				Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --Fecha/Hora-- | Tiene TimeZone default. No se transform'
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT    
				Set @EVENTOHORA = @cHora 
				Set @EVENTOFECHA = @cFecha
			End
		End
	Else
		Begin
			Set @EVENTOHORA = @cHora 
			Set @EVENTOFECHA = @cFecha
		End

	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<EVENTOHORA>>',@EVENTOHORA) )
	Set @cPlantilla = @cTextMerge

	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<EVENTOFECHA>>',@EVENTOFECHA) )
	Set @cPlantilla = @cTextMerge

	Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --Fecha/Hora-- | @cPlantilla : '+@cPlantilla
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT  
 
	--Empresa
	Declare @EMPRESA nVarChar(max)
	Set @EMPRESA = (Select par_cValor From _Tablas.dbo.t_parametros Where par_cCodigo ='MAILSENDERNAME')

	Declare @EMPRESATELEFONO nVarChar(max)
	Set @EMPRESATELEFONO = (Select par_cValor From _Tablas.dbo.t_parametros Where par_cCodigo ='MAILTELEFONO')

	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<EMPRESA>>',@EMPRESA) )
	Set @cPlantilla = @cTextMerge

	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<EMPRESATELEFONO>>',@EMPRESATELEFONO) )
	Set @cPlantilla = @cTextMerge

	Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --Empresa-- | @cPlantilla : '+@cPlantilla
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT  

	--Posicion
	Declare @EVENTOPOSICION nVarChar(max) = 'Sin Datos'
	Declare @GPSVELOCIDAD nVarChar(10) = ''
	Declare @GPSBAT nVarChar(10) = ''
	Declare @MEITRACKBATEXT nVarChar(10) = ''
	Declare @MEITRACKBATAMP nVarChar(10) = ''

	If @idRec > 0 And @cPlantilla Like '%<<EVENTOPOSICION>>%'
		Begin 
			Declare @rLatitud real
			Declare @rLongitud real
			Declare @iVelocidad Int
			Declare @iBattery Float
			Declare @iExtBattery Float

			Select Top 1 @rLatitud=gps_rLatitud, @rLongitud=gps_rLongitud, @iVelocidad=gps_iVelocidad ,@iBattery=gps_iBattery, @iExtBattery=gps_iExtBattery From p_PosicionesGPS WITH (NOLOCK) Where gps_idRec = @idRec
			If @rLatitud Is Null Or @rLongitud Is Null
				Set @EVENTOPOSICION = 'Sin Datos'
			Else
				Set @EVENTOPOSICION = 'http://maps.google.com/maps?q='+Rtrim(CAST(@rLatitud As nVarChar(10) ))+','+Rtrim(CAST(@rLongitud As nVarChar(10) ))

			If @iVelocidad Is Not Null
				Set @GPSVELOCIDAD = Rtrim(CAST(@iVelocidad As nVarChar(10)))

			If @iBattery Is Not Null
				Begin
					Set @GPSBAT = Rtrim(CAST(@iBattery As nVarChar(10)))
					Set @MEITRACKBATAMP = Rtrim(Ltrim(Str(@iBattery/100, 10, 2)))
				End

			If @iExtBattery Is Not Null
				Set @MEITRACKBATEXT = Rtrim(Ltrim(Str(@iExtBattery/100, 10, 2)))
		End

	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<EVENTOPOSICION>>',@EVENTOPOSICION) )
	Set @cPlantilla = @cTextMerge
	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<GPSVELOCIDAD>>',@GPSVELOCIDAD) )
	Set @cPlantilla = @cTextMerge
	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<GPSBAT>>',@GPSBAT) )
	Set @cPlantilla = @cTextMerge
	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<MEITRACKBATEXT>>',@MEITRACKBATEXT) )
	Set @cPlantilla = @cTextMerge
	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<MEITRACKBATAMP>>',@MEITRACKBATAMP) )
	Set @cPlantilla = @cTextMerge

	Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --Posicion-- | @cPlantilla : '+@cPlantilla
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT  

	--Codigo Usuario y Nombre / Tarea Programada
	If @idRec > 0
		Begin
			Declare @EVENTOCODUSUARIO nVarChar(10) = ''
			Declare @EVENTONOMUSUARIO nVarChar(max) = ''
			Declare @TAREAPROGRAMADA nVarChar(Max) = ''
		
			If @cPlantilla Like '%<<TAREAPROGRAMADA>>%'
				Begin 
					Select Top 1 @EVENTOCODUSUARIO = IsNull(Cast(usu_iid As nVarChar(10)),Cast(rec_iUsuario As nVarChar(10))), @EVENTONOMUSUARIO = IsNull(usu_cnombre,''), @TAREAPROGRAMADA = IsNull(rec_cObservaciones,'') From p_recepcion
						Left Outer Join m_usuarios On usu_iidcuenta=rec_iIdCuenta And usu_iid=rec_iUsuario And usu_iCodigo<>0
					Where rec_iId = @idRec

					Set @TAREAPROGRAMADA = Replace(@TAREAPROGRAMADA,'[SISTEMA]','')
					Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<TAREAPROGRAMADA>>',@TAREAPROGRAMADA) )
					Set @cPlantilla = @cTextMerge
				End
			Else
				Begin 
					Select Top 1 @EVENTOCODUSUARIO = IsNull(Cast(usu_iid As nVarChar(10)),Cast(rec_iUsuario As nVarChar(10))), @EVENTONOMUSUARIO = IsNull(usu_cnombre,'') From p_recepcion
						Left Outer Join m_usuarios On usu_iidcuenta=rec_iIdCuenta And usu_iid=rec_iUsuario And usu_iCodigo<>0
					Where rec_iId = @idRec
				End

			Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<EVENTOCODUSUARIO>>',@EVENTOCODUSUARIO) )
			Set @cPlantilla = @cTextMerge

			Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<EVENTONOMUSUARIO>>',@EVENTONOMUSUARIO) )
			Set @cPlantilla = @cTextMerge

			
			Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --Codigo Usuario y Nombre / Tarea Programada-- | @cPlantilla : '+@cPlantilla
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT  
		End

	--DispositivoMovil
	If @idCta > 0
		Begin
			Declare @MOVMARCA nVarChar(128) = ''
			Declare @MOVMODELO nVarChar(128) = ''
			Declare @MOVCOLOR nVarChar(256) = ''
			Declare @MOVNROCHASIS nVarChar(256) = ''
			Declare @MOVNROMOTOR nVarChar(256) = ''
			Declare @MOVYEAR nVarChar(10) = ''
			Declare @MOVDOMINIO nVarChar(128) = ''
			Declare @MOVVELMAX nVarChar(10) = ''
			Declare @MOVIDCOND nVarChar(30) = ''

			Select @MOVMARCA=IsNull(VB.Name,''), @MOVMODELO=IsNull(VM.Name,''), @MOVCOLOR=IsNull([Colour],''), @MOVNROCHASIS=IsNull([NroChasis],''), @MOVNROMOTOR=IsNull([NroMotor],''), 
				@MOVYEAR=Rtrim(CAST(IsNull([Year],0) As varchar(10))), @MOVDOMINIO=IsNull([Domain],''), @MOVVELMAX=IsNull([MaxSpeed],''), @MOVIDCOND=IsNull(MU.usu_cNombre,'')
			  FROM [_Datos].[dbo].[DispositivoMovil] DM 
			  Left Outer Join [_Tablas].[dbo].[VehicleBrand] VB On VB.Id = DM.VehicleBrand
			  Left Outer Join  [_Tablas].[dbo].[VehicleModel] VM On VM.Id = DM.VehicleModel
			  Left Outer Join [_Datos].[dbo].[m_usuarios] MU On Mu.usu_iid = DM.DriverId And MU.usu_iidcuenta = DM.OwnerId
			  Where [OwnerId]=@IdCta

			Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<MOVMARCA>>',@MOVMARCA) )
			Set @cPlantilla = @cTextMerge
			Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<MOVMODELO>>',@MOVMODELO) )
			Set @cPlantilla = @cTextMerge
			Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<MOVCOLOR>>',@MOVCOLOR) )
			Set @cPlantilla = @cTextMerge
			Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<MOVNROCHASIS>>',@MOVNROCHASIS) )
			Set @cPlantilla = @cTextMerge
			Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<MOVNROMOTOR>>',@MOVNROMOTOR) )
			Set @cPlantilla = @cTextMerge
			Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<MOVYEAR>>',@MOVYEAR) )
			Set @cPlantilla = @cTextMerge
			Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<MOVDOMINIO>>',@MOVDOMINIO) )
			Set @cPlantilla = @cTextMerge
			Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<MOVVELMAX>>',@MOVVELMAX) )
			Set @cPlantilla = @cTextMerge
			Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<MOVIDCOND>>',@MOVIDCOND) )
			Set @cPlantilla = @cTextMerge
	
			Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --DispositivoMovil-- | @cPlantilla : '+@cPlantilla
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT  
		End

	--Nombre GeoCerca y Ruta Movil
	Declare @GEOCERCANOMBRE nVarChar(max)
	Declare @MOVILRUTA nVarChar(max)
	Set @GEOCERCANOMBRE = ''
	Set @MOVILRUTA = ''

	If @idRec > 0
		Select Top 1 @GEOCERCANOMBRE = IsNull(rxt_cGeoFenceName,''), @MOVILRUTA = IsNull(rxt_cRoute,'') From p_RXtraInfo Where rxt_iRecId = @idRec

	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<GEOCERCANOMBRE>>',@GEOCERCANOMBRE) )
	Set @cPlantilla = @cTextMerge

	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<MOVILRUTA>>',@MOVILRUTA) )
	Set @cPlantilla = @cTextMerge

	Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --Nombre GeoCerca y Ruta Movil-- | @cPlantilla : '+@cPlantilla
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT  

	--Set @cTextMerge = ( Select REPLACE(@cPlantilla,'[[EVENTOIMAGEN]]','') )
	--Set @cPlantilla = @cTextMerge

	--Set @cTextMerge = ( Select REPLACE(@cPlantilla,'[[EVENTONOVEDAD]]','') )
	--Set @cPlantilla = @cTextMerge

	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'[[GEOCERCAIMAGEN]]','') )
	Set @cPlantilla = @cTextMerge

	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'[[LF]]','<BR>') )
	Set @cPlantilla = @cTextMerge

	If @idRec > 0
	Begin
		--QRCode/ActivarionLink
		Select @json = IsNull(rxt_cData,'#NoData#')  From _Datos.dbo.p_RXtraInfo Where rxt_iRecId = @idRec

		If @jSon <> '#NoData#' And Left(@jSon,2) = '{"'
			Begin
				Declare TmpCursor Cursor STATIC LOCAL READ_ONLY FORWARD_ONLY 
					For Select Name,StringValue From _Datos.dbo.parseJSON(@json) 

					Open TmpCursor
					FETCH NEXT FROM TmpCursor INTO @name,@stringValue

					WHILE @@FETCH_STATUS = 0
					Begin
						If @name ='qrcodeLink'
							Set @cTextMerge = ( SELECT REPLACE(@cPlantilla,'<<QRCODE>>',@stringValue) )
						Else
							If @name ='activationLink'
								Set @cTextMerge = ( SELECT REPLACE(@cPlantilla,'<<QRLINK>>',@stringValue) )

						Set @cPlantilla = @cTextMerge						
						FETCH NEXT FROM  TmpCursor INTO @name,@stringValue
					End

				Close TmpCursor
				DEALLOCATE TmpCursor

				Set @cPlantilla = @cTextMerge

				Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --QRCode/ActivarionLink-- | @cPlantilla : '+@cPlantilla
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT  
			End	

			--[[EVENTOIMAGEN]]
			If CHARINDEX('[[EVENTOIMAGEN]]', @cPlantilla ) > 0
			Begin
				--2018-08-02 Rodrigo pidio que se guarde tal cual esta en RXImg 
				--Select @cImagenes = IsNull(@cImagenes + ',', '') + _Datos.dbo.GetFileName([rxi_cImg])
				Select @cImagenes = IsNull(@cImagenes + ',', '') + [rxi_cImg]
				From [dbo].[p_RXImg]
				Where [rxi_iRecId] = @idRec

				Select @cImagenes = IsNull(@cImagenes,'')

				Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --[[EVENTOIMAGEN]]-- | @cImagenes : '+@cImagenes
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT  
			End

			--[[EVENTONOVEDAD]]
			If CHARINDEX('[[EVENTONOVEDAD]]', @cPlantilla ) > 0
			Begin
				Declare @cNews As nVarChar(max)=''		
				If @jSon <> '#NoData#' And Left(@jSon,1) = '{'
					Begin
						Declare TmpCursor Cursor STATIC LOCAL READ_ONLY FORWARD_ONLY 
							For Select Id,Value From _Datos.dbo.SplitDelimited(@json,',') 

							Open TmpCursor
							FETCH NEXT FROM TmpCursor INTO @name,@stringValue

							WHILE @@FETCH_STATUS = 0
							Begin
								If Left(@stringValue,5) ='news:'
								Begin
									Set @cNews = Ltrim(SUBSTRING(@stringValue, 7, Len(@stringValue)-7))
									Break
								End
								FETCH NEXT FROM  TmpCursor INTO @name,@stringValue
							End

						Close TmpCursor
						DEALLOCATE TmpCursor

					End	

				Set @cTextMerge = ( Select REPLACE(@cPlantilla,'[[EVENTONOVEDAD]]',@cNews) )
				Set @cPlantilla = @cTextMerge

				Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --EVENTONOVEDAD-- | @cPlantilla : '+@cPlantilla
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT  
			End

			--[[EVENTOOBSERVACION]]
			If CHARINDEX('[[EVENTOOBSERVACION]]', @cPlantilla ) > 0
			Begin
				Declare @cObs As nVarChar(max)=''		

				Select @cObs=[rec_cobservaciones] From _Datos.dbo.p_recepcion Where rec_iid=@idRec
				Declare @cValor As nVarChar(max)=''		
				Select @cValor=[Value] From _Datos.dbo.SplitDelimited(@cObs, ']') Where [Id] = 3

				Set @cTextMerge = ( Select REPLACE(@cPlantilla,'[[EVENTOOBSERVACION]]',@cValor) )
				Set @cPlantilla = @cTextMerge

				Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --EVENTOOBSERVACION-- | @cPlantilla : '+@cPlantilla
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT  
			End

			If @cPlantilla Like '%<<TAGVIAJES>>%'
			Begin 
				Declare @idViaje As VarChar(20)=''
				Declare @identificador As VarChar(20)=''
				Declare @TAGVIAJES varchar(max)=''
				Declare @txt varchar(max)=''

				Declare @cContenido VarChar(Max) = 0
				Select Top 1 @cContenido = rec_cContenido
					From p_Recepcion 
				Where rec_iid=@idRec

				Declare TmpCursor Cursor STATIC LOCAL READ_ONLY FORWARD_ONLY 
					For Select Name,StringValue From _Datos.dbo.parseJSON(@cContenido) 

					Open TmpCursor
					FETCH NEXT FROM TmpCursor INTO @name,@stringValue

					WHILE @@FETCH_STATUS = 0
					Begin
						If @name ='idViaje'
							Set @idViaje = @stringValue
						Else
							If @name ='identificador'
								Set @identificador = @stringValue

						FETCH NEXT FROM  TmpCursor INTO @name,@stringValue
					End

				Close TmpCursor
				DEALLOCATE TmpCursor

				If @idViaje!='' And @identificador!=''
				Begin
					Declare @metadata nVarchar(max),
							@fechainicio DateTime,
							@fechafin Datetime,
							@GeoInicio nVarChar(128),
							@GeoFin nVarChar(128),
							@NombreCliente nVarChar(128),
							@NombreTransportista nVarChar(100),
							@lugarInicio nVarChar(500),
							@lugarFin nVarChar(500)

					Select @metadata=tgv_metadata, @fechainicio=tgv_fechainicio, @fechafin=tgv_fechafin, @GeoInicio= IsNull((Select [name] From [dbo].[SmartTrackGeoFense] Where [id]=tgv_geofenseinicio),''), 
						@GeoFin=IsNull((Select [name]      From [dbo].[SmartTrackGeoFense] Where [id]=tgv_geofensefin),''), @NombreCliente=IsNull((Select [Name] From [dbo].[Organization] Where [Id]=tgv_cuenta_cliente),''), 
						@NombreTransportista=IsNull([cue_cNombre],''), @lugarInicio=tgv_lugar_inicio, @lugarFin=tgv_lugar_fin 
						From [dbo].[m_tgviaje] 
						Left Outer Join [dbo].[DispositivoMovil] DM On [Id]=tgv_movil_transportista
						Left Outer Join [dbo].[m_cuentas] On [cue_iid]=DM.[OwnerId] 
						Where tgv_codigoexterno=@idViaje And tgv_nombre=@identificador

					Declare TmpCursor Cursor STATIC LOCAL READ_ONLY FORWARD_ONLY 
						For Select Name,StringValue From _Datos.dbo.parseJSON(@metadata) 

						Open TmpCursor
						FETCH NEXT FROM TmpCursor INTO @name,@stringValue

						WHILE @@FETCH_STATUS = 0
						Begin
							If @name != '-'
							Begin
								If @stringValue Like '/Date(%'
								Begin
									Declare @datejson varchar(100) = @stringValue
									Set @stringValue = Convert(VarChar(MAX), ( Select DATEADD(minute, DATEDIFF(minute, getutcdate(), getdate()), DATEADD(s, convert(bigint,substring(replace(replace(@datejson,'/Date(',''),')/',''),0,charindex('-',replace(replace(@datejson,'/Date(',''),')/',''))))/1000, '19700101 00:00:00:000')) ) , 20)
								End

								--Print @name + ' : ' + @stringValue
								Set @TAGVIAJES +=  @name + ' : ' + @stringValue + '<BR>' 
							End
							FETCH NEXT FROM  TmpCursor INTO @name,@stringValue
						End

					Close TmpCursor
					DEALLOCATE TmpCursor
					Set @txt = 'Fecha Inicio : '+ Convert(VarChar(MAX), @fechainicio, 20)
					--Print @txt
					Set @TAGVIAJES += @txt + '<BR>' 

					Set @txt = 'Fecha Fin : '+ Case When Year(@fechafin)=1900 Then '' Else Convert(VarChar(MAX), @fechafin, 20) End
					--Print @txt
					Set @TAGVIAJES += @txt + '<BR>' 

					Set @txt = 'Geocerca Inicio : '+ @GeoInicio
					--Print @txt
					Set @TAGVIAJES += @txt + '<BR>' 

					Set @txt = 'Geocerca Fin : '+ @GeoFin
					--Print @txt
					Set @TAGVIAJES += @txt + '<BR>' 
					
					Set @txt = 'Nombre Cliente : '+ @NombreCliente
					--Print @txt
					Set @TAGVIAJES += @txt + '<BR>' 
					
					Set @txt = 'Nombre Transportista : '+ @NombreTransportista
					--Print @txt
					Set @TAGVIAJES += @txt + '<BR>' 
					
					Set @txt = 'Lugar Inicio  : '+ @lugarInicio
					--Print @txt
					Set @TAGVIAJES += @txt + '<BR>' 
					
					Set @txt = 'Lugar Fin  : '+ @lugarFin
					--Print @txt
					Set @TAGVIAJES += @txt + '<BR>' 

					Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<TAGVIAJES>>',@TAGVIAJES) )
					Set @cPlantilla = @cTextMerge

					Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
					Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --TAGVIAJES-- | @cPlantilla : '+@cPlantilla
					RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT  
				End
			End

	End

	--Telefomo para eventos de SP o VC
	If @idRec > 0 And @cPlantilla Like '%<<TELEFONOAPP>>%'
	Begin 
		Declare @TELEFONOAPP VarChar(128) = ''
		Select Top 1 @TELEFONOAPP = Case When [rxt_nSPIP]=1 Then IsNull(SP.[Telefono],'') Else (Case When [rxt_nVCIP]=1 Then IsNull(VC.[Telefono],'') Else '' End) End
			From [dbo].[p_RXtraInfo]
		Left Outer Join  [_Datos].[dbo].[SmartPanic] SP On SP.[Imei]=[rxt_cimei]
		Left Outer Join  [_Datos].[dbo].[SmartTrack] VC ON VC.[Imei]=[rxt_cimei]
			Where rxt_iRecId = @idRec

		Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<TELEFONOAPP>>',@TELEFONOAPP) )
		Set @cPlantilla = @cTextMerge

		Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --Telefomo para eventos de SP o VC-- | @cPlantilla : '+@cPlantilla
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT  
	End

	--Servicio Tecnico
	Declare @STORDEN VarChar(10) = '-Sin Datos-'
	Declare @STINICIOVISITA VarChar(20) = ''
	Declare @STFINVISITA VarChar(20) = ''
	Declare @STTECNICO nVarChar(100) = ''
	Declare @STTIPOSERVICIO nVarChar(50) = ''
	Declare @STSERVICIO nVarChar(100) = ''

	If @idRec > 0 And @cAlarma IN ('_ST','_NS') And @cPlantilla Like '%<<ST%'
		Begin 
			Declare @iOrden [int] = 0 

			Execute [_Datos].[dbo].[SGSP_SearchNroOrdenServicio] @idRec=@idRec,@iValor=@iOrden Output

			If @iOrden>0
			Begin
				If @cAlarma = '_ST'
				Begin
					Select @STTECNICO = COALESCE(@STTECNICO + ' - ', '') + ins_cnombre
 						From [_Datos].[dbo].[SerTecVisitas] 
							Inner Join [_Datos].[dbo].[SerTecTecnicoVisitas] On stv_iVisita = svi_idKey
							Inner Join [_Tablas].[dbo].[t_instaladores] On ins_idKey = stv_iTecnico
						Where svi_iServicio = @iOrden

					Select Top 1 @STINICIOVISITA=Convert(VarChar(20), svi_tArriboAlCliente, 20),
								 @STFINVISITA=Convert(VarChar(20), svi_tSalidaDelCliente, 20),
								 @STTIPOSERVICIO=(Case When tip_ntipo = 0 Then 'Preventivo'
											  When tip_ntipo = 1 Then 'Correctivo'
											  Else 'Instalacion' End),
								 @STSERVICIO=tip_cdescripcion
 						From [_Datos].[dbo].[m_st_cabecera]
							Inner Join [_Tablas].[dbo].[t_tiposervicio] On tip_ccodigo = stc_ctipo_servicio
							Inner Join [_Datos].[dbo].[SerTecVisitas] On svi_iServicio = stc_iid
						Where stc_inumero = @iOrden
				End
				Else
				Begin
					Select Top 1 @STTIPOSERVICIO=(Case When tip_ntipo = 0 Then 'Preventivo'
											  When tip_ntipo = 1 Then 'Correctivo'
											  Else 'Instalacion' End),
								 @STSERVICIO=tip_cdescripcion
 						From [_Datos].[dbo].[m_st_cabecera]
							Inner Join [_Tablas].[dbo].[t_tiposervicio] On tip_ccodigo = stc_ctipo_servicio
						Where stc_inumero = @iOrden
				End

				Set @STORDEN = Rtrim(CAST(@iOrden As nVarChar(10)))
			End
		End

	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<STORDEN>>',@STORDEN) )
	Set @cPlantilla = @cTextMerge
	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<STINICIOVISITA>>',@STINICIOVISITA) )
	Set @cPlantilla = @cTextMerge
	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<STFINVISITA>>',@STFINVISITA) )
	Set @cPlantilla = @cTextMerge
	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<STTECNICO>>',@STTECNICO) )
	Set @cPlantilla = @cTextMerge
	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<STTIPOSERVICIO>>',@STTIPOSERVICIO) )
	Set @cPlantilla = @cTextMerge
	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'<<STSERVICIO>>',@STSERVICIO) )
	Set @cPlantilla = @cTextMerge

	Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | --Servicio Tecnico-- | @cPlantilla : '+@cPlantilla
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT  

	Set @cTextMerge = ( Select REPLACE(@cPlantilla,'[[EVENTOIMAGEN]]','') )
	Set @cPlantilla = @cTextMerge

	Set @cPlantilla = Replace(Replace(Replace(Replace(Replace(@cPlantilla COLLATE Latin1_General_BIN,'Á', 'A'),'É','E'),'Í','I'),'Ó','O'),'Ú','U')
	Set @cPlantilla = Replace(Replace(Replace(Replace(Replace(@cPlantilla COLLATE Latin1_General_BIN,'á', 'a'),'é','e'),'í','i'),'ó','o'),'ú','u')
	Set @cTextMerge = @cPlantilla

	Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | [SGSP_TextMerge] | @cTextMerge : '+@cTextMerge
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT  

	Set NoExec Off			
	END TRY
	BEGIN CATCH
		IF ERROR_NUMBER() = 2627
		BEGIN
			PRINT 'Handling PK violation...';
		END;
		ELSE IF ERROR_NUMBER() = 547
		BEGIN
			PRINT 'Handling CHECK/FK constraint violation...';
		END;
		ELSE IF ERROR_NUMBER() = 515
		BEGIN
			PRINT 'Handling NULL violation...';
		END;
		ELSE IF ERROR_NUMBER() = 245
		BEGIN
			PRINT 'Handling conversion error...';
		END;
		ELSE
		BEGIN
			PRINT 'Re-throwing error...';
		END;

		PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
		PRINT 'Error Message : ' + ERROR_MESSAGE();
		PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
		PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
		PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
		PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');

		IF (SELECT CURSOR_STATUS('global','TmpCursor')) >= -1
		 BEGIN
		  IF (SELECT CURSOR_STATUS('global','TmpCursor')) > -1
		   BEGIN
			CLOSE tmCursor
		   END
		 DEALLOCATE tmCursor
		END	
	END CATCH
END

GO
/****** Object:  StoredProcedure [dbo].[SGSP_TimerAutoProcesoEvento]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
