CREATE PROCEDURE [dbo].[SGSP_TimerAutoProcesoNY]
	@idCuenta Int = 0, 
	@AlarmaIngresada Char(3) = '',
	@tFechaHora Datetime,
	@AlarmaNY Char(3) = ''
As
--AutoProcesa NYO/NYC/NYR
--Autor : Pablo O. Canónico
--Fecha : 10/10/2017
--01-10-2019 Se activo el log en _LogDB
--29-05-2020 Se guarda en Timeline

Set NoCount ON
-----------------------------------
DECLARE @LogTable TABLE (
	LogLevel		VARCHAR(50),
	LogMessage		VARCHAR(Max),
	LogException	VARCHAR(2000),
	LogDate		DateTime DEFAULT GetDate());
-----------------------------------

BEGIN TRY
Declare @message nVarChar(Max) = '',
	    @StartDateTimeText VarChar(max) = ''

Declare  @iDebugSQL Int = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='DEBUGSQL' )

Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
Set @message = 'Start DateTime : %s | SGSP_TimerAutoProcesoNY | AutoProcesa '+@AlarmaNY+' | Id Cuenta => '+ Rtrim(Cast(@idCuenta As varchar(10))) 
RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
If @iDebugSQL = 1
	INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');

Declare @idRec Int = 0
Declare @cObservaciones nVarchar(Max)
Declare @translation nVarchar(Max)=''

--Busco si se genero NYO/NYC/NYR
Select Top 1 @idRec=rec_iid, @cObservaciones = Convert(nVarchar(MAX), rec_cObservaciones) From p_recepcion 
	Where rec_iidcuenta=@idCuenta
	And rec_calarma=@AlarmaNY
	And rec_tFechaHora<=@tFechaHora
	And rec_nEstado In(0,2)

If @idRec > 0
Begin
	Execute [_Desktop].[dbo].[LocalizationGetLocale] @Name = N'Procesado Automaticamente por evento ', @soloOutput=1, @translation = @translation OUTPUT
	Set @cObservaciones = '['+Convert(Varchar, GetDate(), 103)+' ' +Substring(Convert(Varchar, GetDate(), 114), 1, 5)+  '] [Timer] '+ Rtrim(@translation) + ' ' + @AlarmaIngresada

	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | SGSP_TimerAutoProcesoNY | Update => '+ @cObservaciones
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
	If @iDebugSQL = 1
		INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');

	Update p_recepcion
	Set rec_nEstado = 3, rec_tFechaProceso = @tFechaHora, rec_cObservaciones  = @cObservaciones
	Where rec_iid = @idRec

	Set @StartDateTimeText = Convert(VarChar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | SGSP_TimerAutoProcesoNY | Inserto TimeLine'
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
	If @iDebugSQL = 1
		INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');

	Insert Into [_Datos].[dbo].[EventosTimeLine]
				([etl_iRecID]
				,[etl_iCuenta]
				,[etl_tFechaHora]
				,[etl_cAccion]
				,[etl_cObservacion]
				,[etl_cOwner]
				,[etl_iOperador])
		Values
				(@idRec
				,@idCuenta
				,GetDate()
				,'Autoproceso'
				,Rtrim(@translation) + ' ' + @AlarmaIngresada
				,'%SISTEMA%'
				,0)
End

If @iDebugSQL = 1
	BEGIN
		BEGIN TRY
			-- Insert Logging into Table 
			INSERT INTO [_LogDB].[dbo].[Log4TSQL] ([Date], [Thread], [Level], [Logger], [Message], [Exception], [DbProcId], [DbSchema], [DbName], [DbServer],[LogModule])
				SELECT  [LogDate], @@SPID, [LogLevel], OBJECT_NAME(@@PROCID), [LogMessage], [LogException], @@PROCID, schema_name(), db_name(), @@SERVERNAME , 'Timer' FROM @LogTable
		END TRY
		BEGIN CATCH
		END CATCH;				
	END
END TRY
BEGIN CATCH
	If @iDebugSQL = 0
		Begin
			IF ERROR_NUMBER() = 2627
			BEGIN
				PRINT 'Handling PK violation...';
			END;
			ELSE IF ERROR_NUMBER() = 547
			BEGIN
				PRINT 'Handling CHECK/FK constraint violation...';
			END;
			ELSE IF ERROR_NUMBER() = 515
			BEGIN
				PRINT 'Handling NULL violation...';
			END;
			ELSE IF ERROR_NUMBER() = 245
			BEGIN
				PRINT 'Handling conversion error...';
			END;
			ELSE
			BEGIN
				PRINT 'Re-throwing error...';
			END;

			PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
			PRINT 'Error Message : ' + ERROR_MESSAGE();
			PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
			PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
			PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
			PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
		End
	Else
		Begin
			-- Create Error/Exception Message
			DECLARE @LogException	VARCHAR(2000);
			SET @LogException = (SELECT 'Error Number : ' + CAST(ERROR_NUMBER() AS NVARCHAR) + ' | Error Severity : ' + CAST(ERROR_SEVERITY() AS NVARCHAR) + ' | Error Proc : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc') + ' | Error State : ' + CAST(ERROR_STATE() AS NVARCHAR) + ' | Error Line : ' + CAST(ERROR_LINE() AS NVARCHAR) + ' | Error Message : ' + ERROR_MESSAGE());
		
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | TimerExecute | '+Rtrim(@LogException)
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			-- Rollback open transactions
			IF @@TRANCOUNT > 0
			BEGIN
			SET @LogException = @LogException + ' | TranCount : ' + CAST(@@TRANCOUNT AS NVARCHAR)
				BEGIN TRY
					INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'ERROR', 'Rolling back ' + CAST(@@TRANCOUNT AS VARCHAR) + ' open transaction(s)..';
				END TRY
				BEGIN CATCH
				END CATCH;

				ROLLBACK TRANSACTION;
			END
		
			BEGIN TRY
				INSERT INTO @LogTable (LogLevel, LogMessage, LogException) SELECT 'ERROR', '-- Exception --', @LogException;
				INSERT INTO [_LogDB].[dbo].[Log4TSQL] ([Date], [Thread], [Level], [Logger], [Message], [Exception], [DbProcId], [DbSchema], [DbName], [DbServer],[LogModule])
					SELECT  [LogDate], @@SPID, [LogLevel], OBJECT_NAME(@@PROCID), [LogMessage], [LogException], @@PROCID, schema_name(), db_name(), @@SERVERNAME , 'Timer' FROM @LogTable

			END TRY
			BEGIN CATCH
			END CATCH;

			-- Raise error to the calling instance
			RAISERROR(@LogException, 16, 1);
		End
END CATCH
GO
/****** Object:  StoredProcedure [dbo].[SGSP_TimerControlUsuario]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SGSP_TimerControlUsuario]
	@idCuenta [int] = 0,
	@iUsuario [int] = 0,
	@AlarmaGenerar [char](3) = '',
	@tFechaHoraEvento [datetime]

WITH EXECUTE AS CALLER
AS
--Controla Usuario OPN/CLO
--Autor : Pablo O. Canónico
--Fecha : 11/10/2017
--03-09-2019 Se controla nuevamente si es un codigo que Genera Alerta cuando esta dentro de horario y debe generar OPV/CLV
--01-10-2019 Se activo el log en _LogDB
Set NoCount ON
-----------------------------------
DECLARE @LogTable TABLE (
	LogLevel		VARCHAR(50),
	LogMessage		VARCHAR(Max),
	LogException	VARCHAR(2000),
	LogDate		DateTime DEFAULT GetDate());
-----------------------------------

BEGIN TRY
Declare @message nVarChar(Max) = '',
	    @StartDateTimeText VarChar(max) = ''

Declare  @iDebugSQL Int = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='DEBUGSQL' )

Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
Set @message = 'Start DateTime : %s | Controla Usuario OPN/CLO | @idCuenta => '+ Rtrim(Cast(@idCuenta As varchar(10)))+' | @iUsuario => '+ Rtrim(Cast(@iUsuario As varchar(10)))+' | @AlarmaGenerar => '+ @AlarmaGenerar+' | @tFechaHoraEvento => '+ Rtrim(Convert(VarChar, @tFechaHoraEvento,120) )
RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
If @iDebugSQL = 1
	INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');

Declare @translation nVarchar(Max)=''

Declare @rec_nestado [numeric](1, 0) = 0,
		@rec_tFechaProceso [datetime] = Null,
		@rec_idResolucion [char](3) = '',
		@rec_cObservaciones nVarchar(Max)

--Veo si AlarmaAGenerar es un codigo que Genera Alerta
Declare @nAlerta Int = 1
If @AlarmaGenerar IN('OKC','OKO')
Begin
	Set @nAlerta = (Select cod_nalerta From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@AlarmaGenerar )

	If @nAlerta = 2		--Es de NO GENERAR EVENTO
		Begin
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | Controla Usuario OPN/CLO | ('+@AlarmaGenerar+') es de tipo NO Genera Evento'
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
			If @iDebugSQL = 1
				INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');

			Set NoExec On
		End
	
	If @nAlerta = 0		--Es de NO Genera Alerta
		Set @rec_nestado = 5
End

--Busco si la cuenta esta No Habilitada
Declare @_SituacionCuenta nVarChar(100)
Select @_SituacionCuenta=(Case When est_nEstado=1 And GetDate() BetWeen est_dfechadesde And est_dfechahasta Then 'Prueba' When est_nEstado=2 Then 'No Habilitado' 
	When est_nEstado=3 Then 'Prueba x Zonas' Else 'Habilitado' End )
	From m_estado_cuenta_cab Where est_iidcuenta = @idCuenta

If @_SituacionCuenta='No Habilitado' 
Begin
	Set @rec_nestado = 7
	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | Controla Usuario OPN/CLO | Cuenta en situacion -No Habilitado- No se graba '+@AlarmaGenerar
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
	If @iDebugSQL = 1
		INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');

	Set NoExec On
End

If @_SituacionCuenta='Prueba' 
	Begin
		If ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='SETEOMODODEPRUEBA' ) = 1
			Begin		
				Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | Controla Usuario OPN/CLO | Cuenta en situacion -Prueba-'
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
				If @iDebugSQL = 1
					INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');
		
				Set @rec_nestado=6
				Set @rec_tFechaProceso= GetDate()
				Set @rec_idResolucion = (Select CAST(IsNull(par_ivalor,999) As Char(3)) As cValor FROM [_Tablas].[dbo].[t_parametros] Where par_ccodigo='MODO PRUEBA')
				Set @rec_idResolucion = Stuff('000',4-Len(@rec_idResolucion),Len(@rec_idResolucion),@rec_idResolucion)
				Execute [_Desktop].[dbo].[LocalizationGetLocale] @Name = N'Cuenta Configurada en Modo de Prueba', @soloOutput=1, @translation = @translation OUTPUT
				Set @rec_cObservaciones = '['+Convert(Varchar, GetDate(), 103)+' ' +Substring(Convert(Varchar, GetDate(), 114), 1, 5)+  '] [Timer] '+ Rtrim(@translation)
			End
	End
Else
	Begin	--Me fijo Si esta en Modo Prueba por codigos de alarma
		If Exists ( Select Top 1 est_idKey From m_estado_cuenta_item Where est_iidcuenta = @idCuenta And est_czona='_COD_' And CHARINDEX(@AlarmaGenerar, est_cData) > 0 )
		Begin
			If ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='SETEOMODODEPRUEBA' ) = 1
			Begin		
				Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | Controla Usuario OPN/CLO | Cuenta en situacion -Prueba x Codigo de Alarmas-'
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
				If @iDebugSQL = 1
					INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');

				Set @rec_nestado=6
				Set @rec_tFechaProceso= GetDate()
				Set @rec_idResolucion = (Select CAST(IsNull(par_ivalor,999) As Char(3)) As cValor FROM [_Tablas].[dbo].[t_parametros] Where par_ccodigo='MODO PRUEBA')
				Set @rec_idResolucion = Stuff('000',4-Len(@rec_idResolucion),Len(@rec_idResolucion),@rec_idResolucion)
				Execute [_Desktop].[dbo].[LocalizationGetLocale] @Name = N'Cuenta Configurada en Modo de Prueba por Codigo de Alarmas', @soloOutput=1, @translation = @translation OUTPUT
				Set @rec_cObservaciones = '['+Convert(Varchar, GetDate(), 103)+' ' +Substring(Convert(Varchar, GetDate(), 114), 1, 5)+  '] [Timer] '+ Rtrim(@translation)
			End
		End
	End

Declare @bGrabo Bit = 0  /* False */
--Busco Tipo Usuario					
Declare @nTipo Int = 0
Select @nTipo = usu_nTipo From m_usuarios 
	Where usu_iidCuenta=@idCuenta And usu_icodigo > 0 And usu_iid=@iUsuario

Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
Set @message = 'Start DateTime : %s | Controla Usuario OPN/CLO | Tipo => '+ Rtrim(Cast(@nTipo As varchar(10)))    
RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
If @iDebugSQL = 1
	INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');

If @nTipo = 1
	Begin
		Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | Controla Usuario OPN/CLO | Es Superior No se controla horarios | Id Cuenta => '+ Rtrim(Cast(@idCuenta As varchar(10)))+' | Usuario => '+ Rtrim(Cast(@iUsuario As varchar(10)))+' | Tipo => '+ Rtrim(Cast(@nTipo As varchar(10)))    
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
		If @iDebugSQL = 1
			INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');
	End
Else If @nTipo = 2
	Begin
		If @AlarmaGenerar Not IN('OPV','CLV','OKC','OKO')	--Es Normal Se controla horarios
			Begin
				Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | Controla Usuario OPN/CLO | Es Normal se controla horarios | Id Cuenta => '+ Rtrim(Cast(@idCuenta As varchar(10)))+' | Usuario => '+ Rtrim(Cast(@iUsuario As varchar(10)))+' | Tipo => '+ Rtrim(Cast(@nTipo As varchar(10)))    
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
				If @iDebugSQL = 1
					INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');

				Set	@bGrabo = 1	/* True */
			End
		Else
			Begin
				Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
				If @AlarmaGenerar IN('OKC','OKO')
					Begin
						If @AlarmaGenerar='OKC'
							Set @AlarmaGenerar = 'CLV'
						Else If @AlarmaGenerar='OKO'
							Set @AlarmaGenerar = 'OPV'

						Set @message = 'Start DateTime : %s | Controla Usuario OPN/CLO | Es Normal. Es Verificable ('+@AlarmaGenerar+'). No se controla horarios | Id Cuenta => '+ Rtrim(Cast(@idCuenta As varchar(10)))+' | Usuario => '+ Rtrim(Cast(@iUsuario As varchar(10)))+' | Tipo => '+ Rtrim(Cast(@nTipo As varchar(10)))    
					End
				Else
					Begin
						Set	@bGrabo = 1	/* True */					
						Set @message = 'Start DateTime : %s | Controla Usuario OPN/CLO | Es Normal. Es Verificable ('+@AlarmaGenerar+'). Se controla horarios | Id Cuenta => '+ Rtrim(Cast(@idCuenta As varchar(10)))+' | Usuario => '+ Rtrim(Cast(@iUsuario As varchar(10)))+' | Tipo => '+ Rtrim(Cast(@nTipo As varchar(10)))    
					End

				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
				If @iDebugSQL = 1
					INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');
			End
	End
Else If @nTipo = 3  --Es Bajo Se controla horarios
	Begin
		If @AlarmaGenerar='OKC'
			Set @AlarmaGenerar = 'CLV'
		Else If @AlarmaGenerar='OKO'
			Set @AlarmaGenerar = 'OPV'

		Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | Controla Usuario OPN/CLO | Es Bajo se controla horarios | Id Cuenta => '+ Rtrim(Cast(@idCuenta As varchar(10)))+' | Usuario => '+ Rtrim(Cast(@iUsuario As varchar(10)))+' | Tipo => '+ Rtrim(Cast(@nTipo As varchar(10)))    
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
		If @iDebugSQL = 1
			INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');		

		Set	@bGrabo = 1	/* True */
	End
Else	--NO existe. Se toma como si fuera usuario Normal	
Begin
	If @AlarmaGenerar='OKC'
		Set @AlarmaGenerar = 'CLV'
	Else If @AlarmaGenerar='OKO'
		Set @AlarmaGenerar = 'OPV'

	Declare @iCtrlUsuarioI Int = ( Select par_iValor From _Tablas.dbo.t_parametros Where par_ccodigo = 'CONTROLDEUSUARIOINEXISTENTE' )
	If @AlarmaGenerar IN('OPV','CLV') And @iCtrlUsuarioI = 0	--Si el parametro esta en 1 tiene que controlar
		Begin
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | Controla Usuario OPN/CLO | No Existe Usuario. Es Verificable ('+@AlarmaGenerar+'). No se controla horarios | Id Cuenta => '+ Rtrim(Cast(@idCuenta As varchar(10)))+' | Usuario => '+ Rtrim(Cast(@iUsuario As varchar(10)))
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
			If @iDebugSQL = 1
				INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');
		End
	Else 
		Begin
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | Controla Usuario OPN/CLO | No Existe Usuario. Se toma como si fuera usuario Normal. Se controla horarios | Id Cuenta => '+ Rtrim(Cast(@idCuenta As varchar(10)))+' | Usuario => '+ Rtrim(Cast(@iUsuario As varchar(10)))
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
			If @iDebugSQL = 1
				INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');

			Set	@bGrabo = 1	/* True */
		End
End

If @bGrabo = 1
Begin
	--Vuelvo a ver x si entro por algun codigo OK de AlarmaAGenerar es un codigo que Genera Alerta
	Set @nAlerta = (Select cod_nalerta From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@AlarmaGenerar )
	If @nAlerta = 2		--Es de NO GENERAR EVENTO
		Begin
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | Controla Usuario OPN/CLO | ('+@AlarmaGenerar+') es de tipo NO Genera Evento'
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
			If @iDebugSQL = 1
				INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');

			Set NoExec On
		End
	
	If @nAlerta = 0		--Es de NO Genera Alerta
		Set @rec_nestado = 5

	Declare @iValor Int = 0
	Declare @Fecha Datetime = DateADD(second,1,@tFechaHoraEvento)	--Es mas 1 segundo para que no pierda relacion de correlatividad
	Declare @trap table
	(
		iValor int
	)
	Insert Into @trap Execute [dbo].[SGSP_pRecepcionINS]
		@rec_iidcuenta = @idCuenta,
		@rec_calarma = @AlarmaGenerar,
		@rec_nestado  = @rec_nestado,
		@rec_cObservaciones = @rec_cObservaciones,
		@rec_nOrigen = 1,
		@rec_iUsuario = @iUsuario,
		@rec_tfechahora  = @Fecha,
		@rec_tFechaProceso = @Fecha,
		@rec_idResolucion = @rec_idResolucion,
		@iValor = @iValor OUTPUT

	--Aactualizo m_Status con ultima alarma y fecha
	UPDATE m_status Set sta_cultimaalarma = @AlarmaGenerar, sta_dfechautimaalarma = @Fecha Where sta_iidCuenta=@idCuenta
		
	--PushNotification--
	Execute [dbo].[SGSP_PushNotification] @idRec=@iValor
			
	--Envio de Mail x Evento
	Execute [dbo].[SGSP_AlarmaSMS] @idCta = @idCuenta, @cCodigoAlarma = @AlarmaGenerar, @idRec = @iValor

End

Set NoExec Off
If @iDebugSQL = 1
	BEGIN
		BEGIN TRY
			-- Insert Logging into Table 
			INSERT INTO [_LogDB].[dbo].[Log4TSQL] ([Date], [Thread], [Level], [Logger], [Message], [Exception], [DbProcId], [DbSchema], [DbName], [DbServer],[LogModule])
				SELECT  [LogDate], @@SPID, [LogLevel], OBJECT_NAME(@@PROCID), [LogMessage], [LogException], @@PROCID, schema_name(), db_name(), @@SERVERNAME , 'Timer' FROM @LogTable
		END TRY
		BEGIN CATCH
		END CATCH;				
	END
END TRY
BEGIN CATCH
	If @iDebugSQL = 0
		Begin
			IF ERROR_NUMBER() = 2627
			BEGIN
				PRINT 'Handling PK violation...';
			END;
			ELSE IF ERROR_NUMBER() = 547
			BEGIN
				PRINT 'Handling CHECK/FK constraint violation...';
			END;
			ELSE IF ERROR_NUMBER() = 515
			BEGIN
				PRINT 'Handling NULL violation...';
			END;
			ELSE IF ERROR_NUMBER() = 245
			BEGIN
				PRINT 'Handling conversion error...';
			END;
			ELSE
			BEGIN
				PRINT 'Re-throwing error...';
			END;

			PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
			PRINT 'Error Message : ' + ERROR_MESSAGE();
			PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
			PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
			PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
			PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
		End
	Else
		Begin
			-- Create Error/Exception Message
			DECLARE @LogException	VARCHAR(2000);
			SET @LogException = (SELECT 'Error Number : ' + CAST(ERROR_NUMBER() AS NVARCHAR) + ' | Error Severity : ' + CAST(ERROR_SEVERITY() AS NVARCHAR) + ' | Error Proc : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc') + ' | Error State : ' + CAST(ERROR_STATE() AS NVARCHAR) + ' | Error Line : ' + CAST(ERROR_LINE() AS NVARCHAR) + ' | Error Message : ' + ERROR_MESSAGE());
		
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | TimerExecute | '+Rtrim(@LogException)
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

			-- Rollback open transactions
			IF @@TRANCOUNT > 0
			BEGIN
			SET @LogException = @LogException + ' | TranCount : ' + CAST(@@TRANCOUNT AS NVARCHAR)
				BEGIN TRY
					INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'ERROR', 'Rolling back ' + CAST(@@TRANCOUNT AS VARCHAR) + ' open transaction(s)..';
				END TRY
				BEGIN CATCH
				END CATCH;

				ROLLBACK TRANSACTION;
			END
		
			BEGIN TRY
				INSERT INTO @LogTable (LogLevel, LogMessage, LogException) SELECT 'ERROR', '-- Exception --', @LogException;
				INSERT INTO [_LogDB].[dbo].[Log4TSQL] ([Date], [Thread], [Level], [Logger], [Message], [Exception], [DbProcId], [DbSchema], [DbName], [DbServer],[LogModule])
					SELECT  [LogDate], @@SPID, [LogLevel], OBJECT_NAME(@@PROCID), [LogMessage], [LogException], @@PROCID, schema_name(), db_name(), @@SERVERNAME , 'Timer' FROM @LogTable

			END TRY
			BEGIN CATCH
			END CATCH;

			-- Raise error to the calling instance
			RAISERROR(@LogException, 16, 1);
		End
END CATCH

GO
/****** Object:  StoredProcedure [dbo].[SGSP_TimerExecute]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO




CREATE PROCEDURE [dbo].[SGSP_TimerExecute]
WITH EXECUTE AS CALLER
AS
--Ejecucion de rutinas de control de horarios
--Autor : Pablo O. Canónico
--Fecha : 12/10/2017
--30/11/2017 Se Agrego control de SOSDemorado
--03/01/2018 Se Agrego control estados panel
--04-08-2018 Se agrego el DateFirst porque en sistemas en Language no US toma lunes como dia 1
--27-02-2019 Se agrego el DOW al where
--29-04-2019 Se agrego control de SinHorarioControlaEventos en NO con dias sin horario
--01-10-2019 Se activo el log en _LogDB
--25-03-2020 Se cambio el control para dias Feriados Full (tipo F)
--23-04-2020 Se cambio el control de CLO para rangos 
--22-07-2020 Se cambio el control de usuario bajo y _NG 
--17-09-2020 En control de OPN/CLO se agrego And [pet_cTipo] != 'P' para evitar eventos de Control de Estado de Panel
--14-12-2021 En control de Estado de Panel. Se verifica primero si ya llego el evento esperado
--12-01-2022 Se cambio el control para dias Feriados (tipo F) con horarios por cuenta
--15-03-2022 Se cambio en control CLO el <0 por >0 Datediff(second,ph.HoraDespues,pe.pet_tFechaHora) > 0 Then 'OK'
--30-06-2022 Se cambio en control CLO para cuando es TIPO='C' y el horario esta dentro de limites
--22-07-2022 En el control de SOSDemorado se agrego la busqueda de Lat/Lng de la ultima posicion recibida para guardala como posicion del evento de control generado
--01-09-2022 Se cambio en control CLO el Datediff(second,ph.HoraDespues,pe.pet_tFechaHora) por Datediff(second,pe.pet_tFechaHora,ph.HoraDespues)
--17-01-2023 Se cambio en control OPN para considerar TIPO='V'
--09-09-2024 Se cambio mensaje de push para nueva V1

Set NoCount ON

-----------------------------------
DECLARE @LogTable TABLE (
	LogLevel		VARCHAR(50),
	LogMessage		VARCHAR(Max),
	LogException	VARCHAR(2000),
	LogDate		DateTime DEFAULT GetDate());
-----------------------------------

BEGIN TRY

-- Aviso que la tarea esta funcionando
Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'TimerExecute', @Repetition = 10
--

Declare @message nVarChar(Max) = '',
	    @StartDateTimeText VarChar(max) = ''

Declare  @iDebugSQL Int = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='DEBUGSQL' )
Declare  @iExecute Int = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='TIMEREXECUTE' )
If @iExecute = 0
Begin	
	Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | TimerExecute | Configurado para NO ejecutar'
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
	If @iDebugSQL = 1
		INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');

	Set NoExec On
End

SET DATEFIRST 7
--Cuando no se utlice mas Timer CS hay que habilitar esto para saber si hay que controlar o no horarios
--Declare  @iProcesoHorarios Int = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='PROCESAHORARIOS' )
--If @iProcesoHorarios > 0
--    Begin	
--	  End

Declare @idKey Int = 0,
		@idCuenta Int = 0,
		@iUsuario Int = 0,
		@iDay Int = DATEPART(dw, GetDate()),
		@iStatus Int = 1

Declare @AlarmaIngresada Char(3) = '',
		@AlarmaGenerar Char(3) = '',
		@AutoProcesaNY Char(1) = ''

Declare @tFechaHora Datetime

-----------------------------------------------------------------------------------------------------------------------------
-----------------------------------------------------------------------------------------------------------------------------

--Control de OPN

--Cuando TIPO es OC, alarmaGenerar tiene que ser AlarmaAntes x que en AlarmaDespues esta el CLO
Declare EventosTimer CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
 With ControlHorarios As (
	Select pe.pet_idKey,pe.pet_idCuenta,pe.pet_iUsuario,pe.pet_tFechaHora,
		Antes = Case When Datediff(second,pe.pet_tFechaHora,ph.HoraAntes) < 0 Then '' Else 'X' End,
		Despues = Case When ph.[Tipo]IN ('F','V') And Convert(Char(8),ph.HoraAntes,108)='00:00:00' And Convert(Char(5),ph.HoraDespues,108)='23:59' Then 'X' Else ( Case When Datediff(second,ph.HoraDespues,pe.pet_tFechaHora) < 0 Then '' Else 'X' End) End,
		AlarmaGenerar = Case When ph.[Tipo] IN ('F','V') And Convert(Char(8),ph.HoraAntes,108)='00:00:00' And Convert(Char(5),ph.HoraDespues,108)='23:59' Then ph.AlarmaAntes Else ( Case When Datediff(second,pe.pet_tFechaHora,ph.HoraAntes) < 0 Then (Case When Datediff(second,ph.HoraDespues,pe.pet_tFechaHora) < 0 Then 'OK' Else (Case When ph.Tipo IN('OC','M','V','F') Then ph.AlarmaAntes Else ph.AlarmaDespues End ) End) Else ph.AlarmaAntes End ) End,
		--Despues = Case When ph.[Tipo]='F' And Convert(Char(8),ph.HoraAntes,108)='00:00:00' And Convert(Char(8),ph.HoraDespues,108)='23:59:00' Then 'X' Else ( Case When Datediff(second,ph.HoraDespues,pe.pet_tFechaHora) < 0 Then '' Else 'X' End) End,
		--AlarmaGenerar = Case When ph.[Tipo]='F' And Convert(Char(8),ph.HoraAntes,108)='00:00:00' And Convert(Char(8),ph.HoraDespues,108)='23:59:00' Then ph.AlarmaAntes Else ( Case When Datediff(second,pe.pet_tFechaHora,ph.HoraAntes) < 0 Then (Case When Datediff(second,ph.HoraDespues,pe.pet_tFechaHora) < 0 Then 'OK' Else (Case When ph.Tipo IN('OC','M','V','F') Then ph.AlarmaAntes Else ph.AlarmaDespues End ) End) Else ph.AlarmaAntes End ) End,
		----Despues = Case When ph.[Tipo]='F' Then 'X' Else ( Case When Datediff(second,ph.HoraDespues,pe.pet_tFechaHora) < 0 Then '' Else 'X' End) End,
		----AlarmaGenerar = Case When ph.[Tipo]='F' Then ph.AlarmaAntes Else ( Case When Datediff(second,pe.pet_tFechaHora,ph.HoraAntes) < 0 Then (Case When Datediff(second,ph.HoraDespues,pe.pet_tFechaHora) < 0 Then 'OK' Else (Case When ph.Tipo IN('OC','M','V','F') Then ph.AlarmaAntes Else ph.AlarmaDespues End ) End) Else ph.AlarmaAntes End ) End,
		------Despues = Case When Datediff(second,ph.HoraDespues,pe.pet_tFechaHora) < 0 Then '' Else 'X' End,
		------AlarmaGenerar = Case When Datediff(second,pe.pet_tFechaHora,ph.HoraAntes) < 0 Then (Case When Datediff(second,ph.HoraDespues,pe.pet_tFechaHora) < 0 Then 'OK' Else (Case When ph.Tipo IN('OC','M','V','F') Then ph.AlarmaAntes Else ph.AlarmaDespues End ) End) Else ph.AlarmaAntes End,
		ph.AutoProcesaNYO,pe.pet_cAlarma,
		ROW_NUMBER() OVER(PARTITION BY pe.pet_idCuenta Order By 
			(Case When DateDIFF(second,pe.pet_tFechaHora,ph.HoraAntes)>0 Then DateDIFF(second,pe.pet_tFechaHora,ph.HoraAntes)
				  When DateDIFF(second,ph.HoraDespues,pe.pet_tFechaHora)>0 Then DateDIFF(second,ph.HoraDespues,pe.pet_tFechaHora) 
				  When pe.pet_tfechahora Between ph.[HoraAntes] And ph.[HoraDespues] Then 0 End) Asc, pe.[pet_tFechaHora]) As rTop
	From [_Datos].[dbo].[p_EventosTimer] pe With (NOLOCK)
	Inner Join [_Datos].[dbo].[TimerHorarios] ph On ph.[idCta]=pe.[pet_idCuenta] And @iDay=ph.[DOW]
	Inner Join [_Tablas].[dbo].[t_codigos_alarma] ca On pe.[pet_cAlarma]=ca.[cod_ccodigo]
	Where ca.[cod_ntipo] = 1 And [pet_iStatus]=0 And ph.[Tipo] IN('O','OC','M','V','F') And ph.[idCta]=pe.[pet_idCuenta] And [pet_cTipo] != 'P'
	)
Select ch.pet_idKey,ch.pet_idCuenta,ch.pet_iUsuario,ch.pet_tFechaHora,ch.AlarmaGenerar,ch.AutoProcesaNYO,ch.pet_cAlarma
	From ControlHorarios ch
	Where ch.rTop = 1 And (Antes='X' Or Despues = 'X' Or AlarmaGenerar='OK')

OPEN EventosTimer
FETCH NEXT FROM EventosTimer INTO @idKey,@idCuenta,@iUsuario,@tFechaHora,@AlarmaGenerar,@AutoProcesaNY,@AlarmaIngresada
WHILE @@FETCH_STATUS = 0
BEGIN
	Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | TimerExecute | Control de OPN | IdCuenta => '+ Rtrim(Cast(@idCuenta As Varchar(10)))+' | Usuario => '+ Rtrim(Cast(@iUsuario As varchar(10)))+' | Alarma Ingresada => '+ @AlarmaIngresada+' | FechaHora Evento => '+ Rtrim(Convert(VarChar, @tFechaHora,120) )+' | Alarma a Generar => '+ @AlarmaGenerar+' | AutoProcesa NYO => '+ @AutoProcesaNY
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
	If @iDebugSQL = 1
		INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');

	--No importa si es valido o no el OPN, si tiene seteado el autoproceso hay que procesarlo
	If @AutoProcesaNY = 'S'
		Execute SGSP_TimerAutoProcesoNY @idCuenta,@AlarmaIngresada,@tFechaHora,'NYO' 

	--Si viene de SinHorarioControlaEventos en No
	If @AlarmaGenerar='_NC'
	Begin
		Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
		Set @message = 'Start DateTime : %s | TimerExecute | Control de OPN | --No tiene horario. Sin horario controla evento en NO--'
		RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
		If @iDebugSQL = 1
			INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');

		Set @iStatus = 3
	End
	Else
	Begin
		--Si el OPN esta entre Aperturas Permitidas hay que controlar Usuario por si es Tipo Bajo y Generar OPV 
		If @AlarmaGenerar IN('OK','_NG')
			Set @AlarmaGenerar = 'OKO'

		Execute SGSP_TimerControlUsuario @idCuenta,@iUsuario,@AlarmaGenerar,@tFechaHora

		Set @iStatus = 1
	End

	--Actualizo Status EventosTimer
	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | TimerExecute | Control de OPN | --Actualizo Status EventosTimer OPN-- '
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
	If @iDebugSQL = 1
		INSERT INTO @LogTable (LogLevel, LogMessage) SELECT 'DEBUG', Replace(@message,'Start DateTime : %s | ','');

	Update [_Datos].[dbo].[p_EventosTimer] WITH (UPDLOCK)
		Set [pet_iStatus]=@iStatus,
		    [pet_tStatusExec]=GetDate()
	Where [pet_idKey]=@idKey
	
	FETCH NEXT FROM EventosTimer INTO @idKey,@idCuenta,@iUsuario,@tFechaHora,@AlarmaGenerar,@AutoProcesaNY,@AlarmaIngresada
End

CLOSE EventosTimer
DEALLOCATE EventosTimer;

