Declare @nAlerta Int = (Select cod_nalerta From _Tablas.dbo.t_codigos_alarma Where cod_ccodigo=@AlarmaGenerar )

If @nAlerta = 2		--Es de NO GENERAR EVENTO
	Begin
		Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
