CREATE PROCEDURE [dbo].[SGSP_VerificoLimiteYDisponiblesSMS] @iCuenta Int As
--Verifica SMS Limite y Disponibles | Actualiza Status
--Autor :Pablo O. Canónico
--Fecha :18/03/2013

SET NOCOUNT ON
Declare @iLimiteSMS Int
Declare @iEnviadosSMS Int
Declare @iAvisoDisponibles Int 
Declare @iEnviaMail Int

Set @iAvisoDisponibles = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='SMSAVISODISPONIBLES' )
If @iAvisoDisponibles Is Null
	Set @iAvisoDisponibles = 1

Set @iEnviaMail = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='MAILSERVICE' )		
If @iEnviaMail Is Null
	Set @iEnviaMail = 0

Declare @Query nVarChar(255)
Declare @cFrom nVarChar(150)
Declare @cFromName nVarChar(100)
Declare @cTo nVarChar(150)
Declare @cSubject nVarChar(100)
Declare @cMessage nVarChar(4000)
Declare @cMessageMerge nVarChar(max)
Declare @cImagenes nVarChar(max)
Declare @cMail As nVarChar(100)
Declare @cToOriginal nVarChar(150)
Declare @nFin As int
Declare @cCuenta Char(10)
Declare @cGrabo Char(1)
Declare @cFecha Char(10)
Declare @cHora Char(10)
Declare @dDiaHoy DateTime
Set @dDiaHoy = GetDate()

Set @cFecha=(Select Convert(Char(10), @dDiaHoy,103))
Set @cHora=(Select Convert(Char(10), @dDiaHoy,108))

Set @nFin= 1
set @cFrom = ( Select par_cValor From _Tablas.dbo.t_parametros Where par_ccodigo = 'MAILSENDER')
set @cFrom = Ltrim(Rtrim(@cFrom))

Set @cFromName = ( Select par_cValor From _Tablas.dbo.t_parametros Where par_ccodigo = 'MAILSENDERNAME')
Set @cFromName = Ltrim(Rtrim(@cFromName))

set @cTo = ( Select par_cValor From _Tablas.dbo.t_parametros Where par_ccodigo = 'MAILINFORMATIVOCRA')
set @cTo = Ltrim(Rtrim(@cTo))

Declare @translation nVarChar(Max) = ''
Execute [_Desktop].[dbo].[LocalizationGetLocale] @Name = N'Alcanzo Limite de SMS Disponibles', @soloOutput=1, @translation = @translation OUTPUT
Set @cSubject = @translation 

Declare @cToSMS nVarChar(150)
Declare @iModemSMS As int
Declare @cDestinoSMS nVarChar(150)
Declare @cAsunto nVarChar(4000)
Declare @cMailRuteoSMS nVarChar(150)
Declare @nEnviaSMS numeric(1,0)
Set @cGrabo = 'S'

Declare cSms CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY FOR
	Select rep_iidcuenta,rep_iLimiteSMS,sta_iEnviadosSMS,rep_cSMSParaInforme,rep_iModemSMS,rep_cMailRuteoSMS,sta_nEnviaSMS
	From m_reportes_automaticos
		Inner Join m_status On rep_iidcuenta=sta_iidcuenta
		Where rep_iidcuenta=@iCuenta And ( rep_iLimiteSMS > 0 And rep_iLimiteSMS <> 9999 )
	
OPEN cSms
FETCH NEXT FROM cSms INTO @iCuenta,@iLimiteSMS,@iEnviadosSMS,@cToSMS,@iModemSMS,@cMailRuteoSMS,@nEnviaSMS
	WHILE @@FETCH_STATUS = 0
		Begin
			If @nEnviaSMS = 0	--Si ya controlo limite y envio mail/sms no deberia volver a hacerlo
				Begin
					If @iLimiteSMS-@iAvisoDisponibles <= @iEnviadosSMS
						Begin
							--Tengo que enviar aviso x mail a CRA
							If @cTo <> '' And @iEnviaMail > 0
							  Begin
								   Set @cMail = @cTo +';'
								   Set @cCuenta	= ( SELECT cue_clinea+'-'+cue_ncuenta FROM m_cuentas Where cue_iid=@iCuenta )	
								   Set @cMessage = 'En cuenta '+@cCuenta 

								   WHILE CHARINDEX(';',@cMail) > 0
								   BEGIN
										Set @nFin = CHARINDEX(';',@cMail)	
										Set @cTo=SUBSTRING( @cMail, 1, @nFin-1 )
			
										Set @Query = 'Select '+CHAR(39)+@cTo+CHAR(39)+' As Email'
			
										If @cGrabo = 'S' And @iEnviaMail = 1		
											EXEC _Sistema.dbo.sp_SendMail @cFrom, @cTo, @cSubject, @cMessage	

										If @cGrabo = 'S' And @iEnviaMail = 2		
										   Begin	
										    Set @cMessageMerge = ''
											EXEC SGSP_TextMerge	@iCuenta,'','','_LS',@cFecha,@cHora,0, @cMessageMerge OUTPUT, @cImagenes OUTPUT
											If @cMessageMerge Is Null
												Set @cMessageMerge = @cMessage

											EXEC _Datos.dbo.SmartMail_ProgramCreate @cFromName, @cFrom, @cSubject, @cMessageMerge, @dDiaHoy, 1, @Query, 'MAIL', @cImagenes, 802, @iCuenta
										  End

										Set @cMail = SUBSTRING( @cMail, @nFin+1, 100-@nFin )
								   END
	
								   Set @cTo = Ltrim(Rtrim(@cToOriginal))
								   Set @nEnviaSMS = 1		--Setea que envio Mail de Aviso
							  End
							--

							--Tengo que enviar aviso x SMS a la Cuenta
							If @cToSMS <> '' And @iModemSMS > 0
								Begin 
									Set @cToSMS = Ltrim(Rtrim(@cToSMS))+';'

									WHILE CHARINDEX(';',@cToSMS) > 0 And @iModemSMS > 0
									BEGIN
										Set @nFin = CHARINDEX(';',@cToSMS)	
										Set @cDestinoSMS = SUBSTRING( @cToSMS, 1, @nFin-1 )
										Set @cAsunto = @cSubject+' : '+Ltrim(@cMessage)
										If @cGrabo = 'S' And @iEnviaMail = 1	
											EXEC SGSP_SaveSMSQueue @iCuenta,@iModemSMS,@cAsunto,@cDestinoSMS

										If @cGrabo = 'S' And @iEnviaMail = 2		
											Begin	
											    Set @cMessageMerge = ''
												EXEC SGSP_TextMerge	@iCuenta,'','','_LS',@cFecha,@cHora,0, @cMessageMerge OUTPUT, @cImagenes OUTPUT
												If @cMessageMerge Is Null
													Set @cMessageMerge = @cMessage

												Set @cAsunto = @cSubject+' : '+Ltrim(@cMessageMerge)
												EXEC SGSP_SaveSMSQueue @iCuenta,@iModemSMS,@cAsunto,@cDestinoSMS
											End

										Set @cToSMS = SUBSTRING( @cToSMS, @nFin+1, 150-@nFin )
									END
									Set @nEnviaSMS = 1		--Setea que envio SMS de Aviso
								End
							--							

						End
				End
			Else
				Begin
					--Tengo que analizar si se quedo sin SMS rutee a mail si esta configurado
					If @iEnviadosSMS >= @iLimiteSMS
						Begin
							Set @nEnviaSMS = 2		--Setea que llego al limite de SMS
							If @cMailRuteoSMS <> ''
								Set @nEnviaSMS = 3		--Setea que hay mail para ruteo
				
						End 
					--							
				End			

				--Tengo que marcar la cuenta para indicar el status de envio de SMS
				If @cGrabo = 'S' And @nEnviaSMS > 0
					UPDATE [_Datos].[dbo].[m_status] SET sta_nEnviaSMS=@nEnviaSMS WHERE sta_iidcuenta=@iCuenta
					
				--

		FETCH NEXT FROM cSms INTO @iCuenta,@iLimiteSMS,@iEnviadosSMS,@cToSMS,@iModemSMS,@cMailRuteoSMS,@nEnviaSMS
		End

CLOSE cSms
DEALLOCATE cSms

GO
/****** Object:  StoredProcedure [dbo].[SGSP_VideoLinkParser]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SGSP_VideoLinkParser] @iRecID int As
--Verifica si el evento tiene asociado links de video para D-Guard
--Autor :Pablo O. Canónico
--Fecha :19/02/2015
--Se modifico para devolver links de video para poder usarlo en DSSVideoLauncher 
SET NOCOUNT ON

If (Select par_ivalor FROM _Tablas.dbo.t_parametros WHERE par_cCodigo='UTILIZAVI') = 0
	Set NoExec On


Declare @idCta   Int
Declare @cAlarma Char(3)
Declare @cZona	 Char(3)
Declare @iRXimg  Int

Select  @idCta = rec_iidcuenta, @cAlarma = rec_calarma, @cZona = rec_czona From _Datos.dbo.p_recepcion
	Where rec_iid = @iRecID

Select @iRXimg = Count(*) From _Datos.dbo.p_RXImg Where rxi_iRecId = @iRecID

If @idCta > 0
	Begin
		Declare @cData	  nVarChar(200)
		Declare @cLink	  nVarChar(200)
		declare @cLinkDSS nVarChar(2000)
		Declare @bEsDG	Bit
		--Set @bEsDG = 1  /* True */
		Set @bEsDG = 0  /* False */
		Declare @nLaunch Integer

		--Me fijo si se configuro video para la alarma
		Select @cData = cuv_clink,@cLinkDSS = cuv_cLinkDSS, @nLaunch = tvi_nLaunch From _Datos.dbo.m_cuentas_video
			Inner Join _Tablas.dbo.t_VideoID  ON cuv_iVideoID = tvi_iid
			Where CHARINDEX(@cAlarma, cuv_meventos) > 0 And cuv_iidCuenta = @idCta

		--Busco por Alarma-Zona
		Select @cLink = cvl_clink From _Datos.dbo.m_cuentas_video_links
			Where cvl_calarma = @cAlarma And cvl_czona = @cZona
					And cvl_iidCuenta  = @idCta

		Declare @cSaveImageRX nVarChar(200)
		Set @cSaveImageRX = ''
		
		If @iRXimg > 0
			Select r.*, @cLinkDSS As cuv_cLinkDSS, @nLaunch As tvi_nLaunch From _Datos.dbo.p_RXImg r Where rxi_iRecId = @iRecID
		Else
			Begin
				--Veo si es D-Guard
				If Upper(Left(@cLink,4))='DGR:'	
					Begin
						Set @cSaveImageRX = 'http://'+Rtrim(SubString(@cLink,5,195))
						Set @bEsDG = 1
					End
				Else 
					If Upper(Left(@cData,4))='DGR:'	
						Begin
							Set @cSaveImageRX = 'http://'+Rtrim(SubString(@cData,5,195))
							Set @bEsDG = 1
						End

				--Si hay info y es D-Guard inserto en RXImg
				If @cSaveImageRX <> '' And @bEsDG = 1
					Begin
						Insert Into _Datos.dbo.p_RXImg (rxi_iRecId,rxi_cImg,rxi_cCarpeta,rxi_nEstado) Values (@iRecID,Left(@cSaveImageRX,200),'[D-Guard]',1)
						Select r.*,@cLinkDSS As cvl_cLinkDSS, @nLaunch As tvi_nLaunch From _Datos.dbo.p_RXImg r Where rxi_iId = @@IDENTITY
					End	

				--Si no es DGuard tengo que traer los IMG que no entraron en RxImg
				If (Upper(Left(@cData,3))='IMG' And @bEsDG = 0)
					Begin
						Declare @cMiscPath nVarChar(100)
						Set @cMiscPath = ( Select Ltrim(par_cValor) From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='SEARCHSOFTGUARDMISCFILE' ) + '\Video\'
       
						Select Top 1 0 As rxi_iId, @iRecID As rxi_iRecId, '' As rxi_cImg, @cMiscPath+gri_ccarpeta As rxi_cCarpeta, 1 As rxi_nEstado, 'jpg' As rxi_cTipo, Null As rxi_cConfig, @cLinkDSS As cuv_cLinkDSS, @nLaunch As tvi_nLaunch 
							From p_grabacion_img Where gri_iidrecepcion = @iRecID
					End
			End 

		--Tengo que devolver el link de video que tiene configurado para poder usarlo en DSSVideoLauncher 
		If @cLink <>''	
			Set @cSaveImageRX = @cLink
		Else
			If @cData <>''
				Set @cSaveImageRX = @cData
		
		Select @cSaveImageRX As cLinkVideo, @cLinkDSS as cvl_cLinkDSS, @nLaunch As tvi_nLaunch, cue_cLinea, cue_nCuenta, rec_cContenido, rec_iid, Case When ipc_cremotehostip <> '' Then ipc_cremotehostip Else '(nada)' End As cRemoteHostIP
			  From _Datos.dbo.m_cuentas
			  Inner Join  _Datos.dbo.p_recepcion On rec_iid=@iRecID
			  Left Outer Join _Tablas.dbo.t_ip_con On ipc_nport = [rec_iPuerto]		
			Where cue_iid = @idCta 
			  And Left(@cSaveImageRX,3) In ( Select Left(tvi_cdescripcion,3) FROM _Tablas.dbo.t_VideoID Where tvi_nLaunch=1)

	End

Set NoExec Off


GO
/****** Object:  StoredProcedure [dbo].[SGSP_VtoComandos]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [dbo].[SGSP_VtoComandos]
AS
--Pasa a vencido los comandos que no se enviaron en cierto tiempo configurado en un parametro
--Autor : Pablo O. Canónico
--Fecha : 06/05/2021
SET NOCOUNT ON

BEGIN TRY
	-- Aviso que la tarea esta funcionando
	Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'VtoComandos', @Repetition = 4
	--
	SET DATEFIRST 7
	DECLARE @cSQL nVarChar(Max) = '',
		@message nVarChar(Max) = '',
		@StartDateTimeText VARCHAR(max) = ''

	Declare @iMinutos Int = ( Select par_ivalor From [_Tablas].[dbo].[t_parametros] With (NOLOCK) Where par_cCodigo='TIEMPOCOMANDOS')
	If @iMinutos Is Null Or @iMinutos < 2
		Set @iMinutos = 1440

	Set @StartDateTimeText = CONVERT(Varchar, GetDate(),120)  
	Set @message = 'Start DateTime : %s | VtoComandos | TIEMPOCOMANDOS => '+ Rtrim(Cast(@iMinutos As Varchar(10)))
	RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

	UPDATE [_Datos].[dbo].[p_comandos_ip]
		SET cmd_nEstado = 6
	WHERE cmd_nEstado = 1 AND DATEDIFF(MINUTE, cmd_tfechahora, getdate()) > @iMinutos
END TRY
BEGIN CATCH
	IF ERROR_NUMBER() = 2627
	BEGIN
		PRINT 'Handling PK violation...';
	END;
	ELSE IF ERROR_NUMBER() = 547
	BEGIN
		PRINT 'Handling CHECK/FK constraint violation...';
	END;
	ELSE IF ERROR_NUMBER() = 515
	BEGIN
		PRINT 'Handling NULL violation...';
	END;
	ELSE IF ERROR_NUMBER() = 245
	BEGIN
		PRINT 'Handling conversion error...';
	END;
	ELSE
	BEGIN
		PRINT 'Re-throwing error...';
	END;

	PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
	PRINT 'Error Message : ' + ERROR_MESSAGE();
	PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
	PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
	PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
	PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
END CATCH

GO
/****** Object:  StoredProcedure [dbo].[SmartMail_HasPendingPrograms]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SmartMail_HasPendingPrograms]	
@Filter nVarChar(2048) = ''
AS
   SET NOCOUNT ON 
   --Filters
   DECLARE @SqlFilter AS nVarChar(4000)
   SELECT @SqlFilter = dbo.GetSqlFilterForJson(@Filter, 'SmartMail_Program')
 
   --Query
   DECLARE @Sql nVarChar(MAX)                    
   SET @Sql = 'SELECT COUNT(*)
                FROM SmartMail_Program o
                WHERE o.DateStart < GETDATE()       
							AND datalength(transporttype)>0
							And transporttype IS NOT NULL
							AND datalength(body)>0
							And body IS NOT NULL                  
                 AND o.Status = ''A'' ' + @SqlFilter
                                                                                                            
   EXEC(@Sql)


GO
/****** Object:  StoredProcedure [dbo].[SmartMail_NextProgram]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SmartMail_NextProgram]	
           @Filter nVarChar(2048) = '',
            @Sort nVarChar(256) = ''           
AS
            SET NOCOUNT ON 
 
            --Sort
            DECLARE @SqlSort AS nVarChar(256)
            SELECT @SqlSort = dbo.GetSqlSortForJson(@Sort, 'Id ASC')
 
            --Filters
            DECLARE @SqlFilter AS nVarChar(4000)
            SELECT @SqlFilter = dbo.GetSqlFilterForJson(@Filter, 'SmartMail_Program')
 
            --Query
            DECLARE @Sql nVarChar(MAX)
            SET @Sql = 'SELECT TOP 1 Id, Name, [From], Body, TransportType, Query, '''' as RecurrentType, 0 as RecurrentTime, getdate() as RecurrentDateEnd 			
                        FROM SmartMail_Program
                        WHERE DateStart < GETDATE() 
							AND datalength(transporttype)>0
							And transporttype IS NOT NULL
							AND datalength(body)>0
							And body IS NOT NULL
                        AND Status = ''A'' ' + @SqlFilter + ' ORDER BY ' + @SqlSort
                                   
            --PRINT(@Sql)                                               
            EXEC(@Sql)



GO
