/****** Object:  StoredProcedure [dbo].[SmartMail_ProgramCreate]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE PROCEDURE [dbo].[SmartMail_ProgramCreate]
	@FromName [nvarchar](128),
	@FromEmail [nvarchar](128),
	@Subject [nvarchar](256),
	@Body [ntext],
	@DateStart [datetime],
	@Count [int],
	@Query [nvarchar](max),
	@TransportType [nvarchar](64) = 'MAIL',
	@Attachments [nvarchar](2048) = '',
	@Priority [int] = 0,
	@CueIid [int] = NULL
WITH EXECUTE AS CALLER
AS
SET NOCOUNT ON    
     
 --INSERT PROGRAM    
 DECLARE @ProgramId INT    
 DECLARE @From nVarChar(256)    
 SET @From = @FromName + '<'+@FromEmail+'>'    
      
 INSERT INTO _Datos.dbo.SmartMail_Program (Name, [From], Body, DateStart, Count, Status, Query, TransportType, Priority, CueIid)    
           VALUES (@Subject, @From, @Body, @DateStart, @Count, 'A', @Query, @TransportType, @Priority, @CueIid)    
 
  SET @ProgramId = @@IDENTITY               

 IF LEN(RTRIM(@Attachments)) > 0    
 BEGIN
	INSERT INTO _Datos.dbo.SmartMail_ProgramAttach (Name, ProgramId) SELECT strval, @ProgramId FROM _Datos.dbo.ParseArray(@Attachments, ',')       
END
--



GO
/****** Object:  StoredProcedure [dbo].[SmartMail_ProgramStatus]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE Procedure [dbo].[SmartMail_ProgramStatus] @Id Int, @Status VarChar(1) AS
declare @recurrent BIT
declare @FinalDate datetime
declare @startDate datetime

select @recurrent = isnull(Recurrent, 0), @startdate = datestart from smartmail_program where id = @id
set @FinalDate =  null

if @Status = 'C'
begin
	set @FinalDate =  getdate()
end

if  @Status = 'C' and  @recurrent = 1
begin
	set @status = 'A'
	set @startdate = dateadd(MINUTE, 3, getdate())

end

update
	SmartMail_Program
set
	Status = @Status,
	DateEnd = @FinalDate,
	datestart = @startdate
WHERE 
	Id = @Id


GO
