CREATE PROCEDURE [dbo].[SmartMail_Tracking_AddLink]
	@ProgramId int,
	@VersionId int,
	@Name nVarChar(512),
	@Url nVarChar(1024)
AS
	SET NOCOUNT ON

	DECLARE @LinkId INT
	SELECT @LinkId = LinkId FROM SmartMailTracking_Link WHERE ProgramId = @ProgramId AND VersionId = @VersionId AND Url = @Url

	IF @LinkId IS NULL
	BEGIN
		INSERT INTO SmartMailTracking_Link (ProgramId, VersionId, Name, Url) VALUES (@ProgramId, @VersionId, @Name, @Url)

		SELECT SCOPE_IDENTITY()		
	END

	IF @LinkId IS NOT NULL
	BEGIN
		SELECT @LinkId
	END


GO
/****** Object:  StoredProcedure [dbo].[SmartMail_Tracking_BasicReport]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SmartMail_Tracking_BasicReport]  
 @ProgramId int,  
 @VersionId int  
AS  
 SET NOCOUNT ON  
  
 --Version  
 SELECT V.ProgramId, V.VersionId, V.StartedDate, V.EndedDate, V.QtyTotal, V.QtySent   
   FROM SmartMailTracking_Version V  
  WHERE V.ProgramId = @ProgramId AND V.VersionId = @VersionId  
  
 --Emails  
 SELECT COUNT(E.EmailId) AS QtySent, SUM([Read]) AS QtyDistinctReadings, SUM(E.QtyReadings) AS QtyReadings   
   FROM SmartMailTracking_Email E    
     WHERE E.ProgramId = @ProgramId AND E.VersionId = @VersionId  
   
 --Links  
 SELECT L.Name, L.Url, COUNT(UL.LinkId) AS QtyDistinctOpenings, ISNULL(SUM(UL.QtyOpenings),0) AS QtyOpenings  
      FROM SmartMailTracking_Link L
		   LEFT JOIN SmartMailTracking_UserLink UL ON UL.LinkId = L.LinkId  
     WHERE L.ProgramId = @ProgramId AND L.VersionId = @VersionId  
  GROUP BY L.Name, L.Url   


GO
