CREATE PROCEDURE [dbo].[SP_BuscaNoRestauradas] AS
--Busca Eventos en P_Timer del dia
--Autor .Pablo O. Canónico 12-10-2006
--Se agrego campo recid para autoprocesar 20-01-2009
--Se controla fecha a futuro por restauraciones que se pasan del dia 27-07-2010
--Se agrego campo AlarmaAGenerar 04-07-2011
--Se agrego campo iIdEventoNR para poder completar tabla [EventosEnFalloRestauracion] 27-10-2016

SET NOCOUNT ON
Select tim_tfechahora,tim_iidcuenta,tim_calarma,tim_czona,tim_iid,DATEADD(MINUTE,- Cast(tim_cusuario As Numeric(3,0)),tim_tfechahora) As tim_tfechaevento,tim_irecid,tim_cAlarmaAGenerar,tim_iIdEventoNR 
From [_Datos].[dbo].[p_timer] With (NOLOCK)
Where CONVERT(char(8), tim_tfechahora,112) >= CONVERT(char(8), GetDate(),112)
   And tim_copnclo = 'R'


GO
