CREATE PROCEDURE [dbo].[SP_BuscoFormatoII] @iReceptor Int, @cFormato nVarChar(10), @iCuenta Int, @cZona  nVarChar(10), @cEvento nVarChar(10) AS
--Busca Formato para ModemIII
--Autor .Pablo O. Canónico

SET NOCOUNT ON
DECLARE @axSelect nVarChar(10)

--Busco cEvento en Formatos
Set @axSelect = (Select Top 1 for_calarma From  m_receptores_cab a With (NOLOCK)
Inner Join m_receptores_item b On b.rec_iid=a.rec_iid
Inner Join m_formatos On for_ccodigo=b.rec_cformato
Where  a.rec_iid = @iReceptor And for_cformato = @cEvento)

If  @axSelect is null
	Begin	
	    --Busco cEvento en las Zonas de la Cuenta
	    Set @axSelect = (Select Top 1 zon_codigoalarma As for_calarma From m_zonas With (NOLOCK)
			Where zon_iidcuenta=@iCuenta And zon_ccodigo=@cEvento)
	
	    If  @axSelect is null
		Begin
	            --No encontro en Zonas de la Cuenta, busca cEvento con *
		    Set @axSelect = (Select Top 1 zon_codigoalarma As for_calarma From m_zonas With (NOLOCK)
			Where zon_iidcuenta=@iCuenta And zon_ccodigo=Left(@cEvento,1)+'*')
	
		      If  @axSelect is null
		       	 Begin
			     --Busco en Zonas de la Cuenta si tiene un MAP
			     SET @axSelect = (Select Top 1 cue_iid FROM m_cuentas  With (NOLOCK)
				Inner Join m_zonas ON cue_clinea=zon_cdealer And cue_ncuenta=zon_ccuenta 
				Where zon_iidcuenta=@iCuenta And zon_ccodigo='MAP' )
	
			      If  @axSelect is null
			       	 Begin
				     --Si no tiene MAP Busco en Zonas de la Cuenta si tiene un FWD
				     SET @axSelect = (Select Top 1 cue_iid FROM m_cuentas  With (NOLOCK)
					Inner Join m_zonas ON cue_clinea=zon_cdealer And cue_ncuenta=zon_ccuenta 
					Where zon_iidcuenta=@iCuenta And zon_ccodigo='FWD' )
	
				      If  @axSelect is null
					Begin
					     --No encontro ni en Zonas ni * ni MAp ni FWD, busca cFormato en formatos del receptor que envio el evento
					     SET @axSelect = (Select Top 1 for_calarma From  m_receptores_cab a With (NOLOCK)
						Inner Join m_receptores_item b On b.rec_iid=a.rec_iid
						Inner Join m_formatos On for_ccodigo=b.rec_cformato
						Where  a.rec_iid = @iReceptor And for_cformato = @cFormato)
					End
				      Else
		    			SET @axSelect = '@F@'+@axSelect
				 End
			      Else
				  SET @axSelect = '@M@'+@axSelect
	        	 End
		End
	End	

Select @axSelect As for_cAlarma


GO
/****** Object:  StoredProcedure [dbo].[SP_BuscoIdCuenta]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SP_BuscoIdCuenta] @nPuerto Numeric(2,0), @cCuenta Character(4), @nLinea numeric(2,0) AS
--Devuelve el ID de una cuenta, usando el Puerto y el Codigo de Cuenta que leen las Dlls de los receptores
--Autor :Pablo O. Canónico 13-12-2004
--Modifica :Pablo O. Canónico 12-07-2006 sin utilizar linea
--Modifica :Pablo O. Canónico 15-04-2011 utilizando linea
SET NOCOUNT ON
DECLARE @iId Int
SET @iId = (Select Top 1 cue_iid From m_cuentas With (NOLOCK)
		Inner Join  _Tablas.Dbo.t_port_alias
			On cue_clinea=tpa_cdealer
		Inner Join  _Tablas.Dbo.t_puertos
			On pue_icodigo=tpa_ipuerto
		Inner Join _Tablas.Dbo.t_LineasXPuerto 
			On lxp_iAlias=tpa_icodigo
			Where pue_npuerto = @nPuerto
			And cue_ncuenta = @cCuenta 
			And lxp_nLinea=@nLinea
			And lxp_nEstado=1
		Order By cue_iid)

If @iId Is null
   Begin
	SET @iId = (Select Top 1 cue_iid From m_cuentas With (NOLOCK)
			Inner Join  _Tablas.Dbo.t_port_alias
				On cue_clinea=tpa_cdealer
			Inner Join  _Tablas.Dbo.t_puertos
				On pue_icodigo=tpa_ipuerto
				Where pue_npuerto = @nPuerto
				And cue_ncuenta = 'XXXX' 
			Order By cue_iid)
   End

Select @iId As cue_iid


GO
