/****** Object:  StoredProcedure [dbo].[SP_CalculaTiempoTranscurrido]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SP_CalculaTiempoTranscurrido] @iId Int AS
--Calcula el tiempo que paso desde la recepcion del evento hasta la fechahora actual
--Modificado 08-07-2009 para evitar fechas de p_recepcion mayores a GetDate()
SET NOCOUNT ON
Select Case When Year(Getdate() - rec_tFechaHora) < 1900 Then GetDate()-GetDate() Else Getdate() - rec_tFechaHora End  As Hora From _Datos.dbo.p_recepcion
Where rec_iid = @iId


GO
/****** Object:  StoredProcedure [dbo].[SP_CreoHistoria]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SP_CreoHistoria] @cCierre [char](6), @nError [int] = 0 OUTPUT AS
--Crea el historico de p_recepcion
--Autor .Pablo O. Canónico 12-07-2004
--Modifico Pablo para campos nuevos Map y Fwd 16-05-2005
--Modifico Pablo para campo nuevo MinutosEspera y ObjectID 29-08-2005
--Modifico Pablo para campo nuevo idLoc 21-03-2011
--Usar asi : SP_CreoHistoria 'AAAAMM'
--Se agregaron campos de pRecepcion_D
--Se agrego control sobre s_tablahistoricos
--TryCatch para atrapar error de creacion de tabla con users sin permisos
--2018-01-24 Se agrego el INCLUDE en el indice FechaHora
SET NOCOUNT ON
Declare @cSQL nVarChar(Max)

IF OBJECT_ID('p_recepcion'+@cCierre) Is NOT Null
   Set @nError = -5
Else
Begin
	BEGIN TRY
	  Set @nError = 0
	  Set @cSQL = 'CREATE TABLE [dbo].[p_recepcion' +  @cCierre  +  '] ( [rec_iid] [int] NOT NULL ,
		[rec_iidcuenta] [int] NOT NULL ,
		[rec_calarma] [char] (3) NOT NULL ,
		[rec_czona] [char] (3) NOT NULL ,
		[rec_iusuario] [int] NOT NULL ,
		[rec_tfechahora] [datetime] NOT NULL ,
		[rec_nestado] [numeric](1, 0) NOT NULL ,
		[rec_cContenido] [nvarchar] (50) NULL ,
		[rec_tFechaProceso] [datetime] NULL ,
		[rec_ioperador] [int] NULL ,
		[rec_cObservaciones] [ntext] NULL ,
		[rec_cTerminal] [char] (3) NULL ,
		[rec_idResolucion] [char] (3) NULL ,
		[rec_idReceptor] [int] NULL ,
		[rec_cCategorizacion] [char] (3) NULL ,
		[rec_iNYR] [int] NULL ,
		[rec_iTE] [int] NULL ,
		[rec_tFechaRecepcion] [datetime] NULL ,
		[rec_nOrigen] numeric(1, 0) NULL ,
		[rec_idMap] [int] NULL ,
		[rec_idFwd] [int] NULL ,
		[rec_iMinutosEspera] [int] NOT NULL,
		[rec_iPuerto] [int] NOT NULL,
		[rec_idLoc] [int] NULL,
		[rec_iPrioridad] [int] NULL,
		[usuario_iCodigo] [int] NULL ,
		[usuario_cNombre] [nvarchar] (30) NULL ,
		[zonas_cCodigo] [char] (10) NULL ,
		[zonas_cDescripcion] [nvarchar] (60) NULL ,
		[_Origen] [varchar](100) NULL,
		[_Puerto] [varchar](100) NULL
		) ON [PRIMARY] TEXTIMAGE_ON [PRIMARY] ' 
	  Exec (@cSQL )
	  Set @nError = @@Error
	  IF @nError = 0	
		Begin
			Declare @cTableName VarChar(17) = 'p_recepcion' +  @cCierre 
			Print @cTableName

			Set @cSQL = 'CREATE  CLUSTERED  INDEX [iid] ON [dbo].[' + @cTableName + '] ([rec_iid]) ON [PRIMARY]'
			Print @cSQL
			Exec (@cSQL )
			
			Declare @cIndxName VarChar(100) = 'NC_'+Rtrim(@cTableName)+'IdCta'
			Set @cSQL = 'CREATE NONCLUSTERED INDEX  [' + @cIndxName+']  ON [dbo].[' + @cTableName + '] ([rec_iidcuenta])'
			Print @cSQL
			Exec (@cSQL )

			Set @cIndxName = 'NC_'+Rtrim(@cTableName)+'FechaHora'
			Set @cSQL = 'CREATE NONCLUSTERED INDEX  [' + @cIndxName+']  ON [dbo].[' + @cTableName + '] ([rec_tfechahora])
				INCLUDE ([rec_iid], [rec_iidcuenta],[rec_calarma],[rec_czona],[rec_iusuario],[rec_nestado],[rec_idResolucion],[rec_cCategorizacion],[rec_idReceptor] )'
			Print @cSQL
			Exec (@cSQL )

			Set @cIndxName = 'NC_'+Rtrim(@cTableName)+'_PuertoFechaOrigen'
			Set @cSQL = 'CREATE NONCLUSTERED INDEX  [' + @cIndxName+']  ON [dbo].[' + @cTableName + '] ([rec_iPuerto], [rec_tFechaRecepcion], [rec_nOrigen]) '
			Print @cSQL
			Exec (@cSQL )

			Set @cIndxName = 'NC_'+Rtrim(@cTableName)+'_CuentaFecha'
			Set @cSQL = 'CREATE NONCLUSTERED INDEX  [' + @cIndxName+']  ON [dbo].[' + @cTableName + '] ([rec_iidcuenta], [rec_tfechahora])
					INCLUDE ([rec_iid], [rec_calarma], [rec_czona], [rec_iusuario], [rec_nestado], [rec_idResolucion], [rec_cCategorizacion], [_Origen]) '
			Print @cSQL
			Exec (@cSQL )

			Declare @cname Varchar(512), @cnombres Varchar(1024)
			Set @cNombres = ''

			Declare c_users CURSOR STATIC LOCAL READ_ONLY FORWARD_ONLY For 
				Select name From sysusers Where ( Left(Name,2) = 'SG' Or Left(Name,9) = 'SoftGuard' ) And Left(Name,9) <> 'SGSERVER\'	

			Open c_users
			Fetch Next From c_users Into @cname
			While @@FETCH_STATUS = 0
			Begin
			   Set @cNombres = @cNombres + Rtrim(@cName) + ','

			   Fetch Next From c_users Into @cname
			End
			Close c_users
			Deallocate c_users

			If Len(@cNombres) > 0
				Set @cNombres = Left(@cNombres,Len(@cNombres)-1)
		    Else
			    Set @cnombres = '[SGDesktopAccess]' --[SoftGuard],[SGCSAccess],[SGWebAccess],[SGAgentAccess],[SGDesktopAccess]'

			Set @cSQL = 'GRANT  REFERENCES ,  SELECT ,  UPDATE ,  INSERT ,  DELETE  ON  [dbo].[' +  @cTableName + '] TO ' + @cNombres
			Print @cSQL
			Exec (@cSQL )

			--Actualizo la tabla [s_tablahistoricos]
			If Not Exists ( Select Top 1 [c_periodo] From [_Sistema].[dbo].[s_tablahistoricos] Where [c_periodo] = @cTableName)
				INSERT INTO [_Sistema].[dbo].[s_tablahistoricos] ([iid_reporte],[c_periodo],[n_usado]) VALUES (0,@cTableName,0)
		End
	END TRY

	BEGIN CATCH
		PRINT 'Error Number  : ' + CAST(ERROR_NUMBER() AS VARCHAR(10));
		PRINT 'Error Message : ' + ERROR_MESSAGE();
		PRINT 'Error Severity: ' + CAST(ERROR_SEVERITY() AS VARCHAR(10));
		PRINT 'Error State   : ' + CAST(ERROR_STATE() AS VARCHAR(10));
		PRINT 'Error Line    : ' + CAST(ERROR_LINE() AS VARCHAR(10));
		PRINT 'Error Proc    : ' + ISNULL(ERROR_PROCEDURE(), 'Not within proc');
		Set @nError = -9
	END CATCH
End
Return @nError


GO
/****** Object:  StoredProcedure [dbo].[SP_CtrlComercios]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SP_CtrlComercios] @nDay Numeric(1,0), @cTipo Char(3), @DiaHoy DateTime AS 
--Selecciona el proximo limite de cierre de las cuentas en situacion habilitados que esten desactivados filtrando por tipo
--Autor .Pablo O. Canónico 02-06-2010
--01-12-2015 se agrego el DateFirst porque en sistemas en Language no US toma lunes como dia 1

SET NOCOUNT ON
SET DATEFIRST 7

SELECT hor_iidCuenta,cue_clinea,cue_ncuenta,IsNull(cue_cnombre,Space(60)) as cue_cnombre,
		CONVERT(char(8), DATEADD(minute, tol_nCierreDespues, Cast(hor_choracierre As DateTime) ),108) As HoraCierreDespues,
		CONVERT(char(8), @DiaHoy,108) As HoraActual,
		Case When hor_ndiaCierre<>@nDay Then '*' Else '' End As cTomorrow
  FROM m_horarios 
	Left Outer Join m_cuentas On hor_iidCuenta=cue_iid
	Left Outer Join m_estado_cuenta_cab On hor_iidCuenta = est_iidcuenta  
	Left Outer Join m_status On hor_iidCuenta = sta_iidcuenta  
	INNER JOIN m_horarios_tolerancia ON hor_iidCuenta=tol_iidCuenta  
	
	WHERE cue_Ctipo = @cTipo
	and est_nEstado = 0 And sta_nestado = 1
	And hor_iidCuenta>0 And hor_ndiaApertura = @nDay 
		AND NOT hor_iidCuenta IN (
			SELECT  exc_iidcuenta FROM m_horarios_excepcion
                        INNER JOIN _tablas.dbo.t_eventos_feriados ON exc_cevento=eve_ccodigo
       		                WHERE DATEPART(dw, eve_dfechadesdes)<=@nDay AND @nDay <=DATEPART(dw, eve_dfechahasta)
				  AND CONVERT(char(8), eve_dfechadesdes,112) >= CONVERT(char(8), @DiaHoy,112)
				  AND CONVERT(char(8), eve_dfechahasta,112) <= CONVERT(char(8), @DiaHoy,112)
				) And  NOT hor_iidCuenta IN (
					SELECT alt_iidCuenta FROM m_horarios_alternativos 
					LEFT OUTER JOIN m_horarios_tolerancia ON alt_iidCuenta=tol_iidCuenta
					 WHERE alt_ndiaApertura = @nDay AND alt_iidCuenta=hor_iidCuenta 
					AND Not Alt_iidCuenta IN (
						SELECT tim_iidcuenta FROM p_timer
						Where CONVERT(char(8), tim_tfechahora,112)  = CONVERT(char(8), @DiaHoy,112)
						And tim_copnclo='X' ))

UNION (
	SELECT alt_iidcuenta,cue_clinea,cue_ncuenta,IsNull(cue_cnombre,Space(60)) as cue_cnombre,
		CONVERT(char(8),DATEADD(minute, tol_nCierreDespues, Cast(alt_choracierre As DateTime) ),108) As HoraCierreDespues,
		CONVERT(char(8), @DiaHoy,108) As HoraActual,
		Case When alt_ndiaCierre<>@nDay Then '*' Else '' End As cTomorrow
  FROM m_horarios_alternativos 
	Left Outer Join m_cuentas On alt_iidCuenta=cue_iid
	Left Outer Join m_estado_cuenta_cab On alt_iidCuenta = est_iidcuenta  
	Left Outer Join m_status On alt_iidCuenta = sta_iidcuenta  

	INNER JOIN m_horarios_tolerancia ON alt_iidCuenta=tol_iidCuenta
		  WHERE  cue_Ctipo = @cTipo
			and est_nEstado = 0 And sta_nestado = 1
			And alt_iidCuenta>0  And alt_ndiaApertura = @nDay
			AND Not Alt_iidCuenta IN (
			SELECT tim_iidcuenta FROM p_timer
			Where CONVERT(char(8), tim_tfechahora,112)  = CONVERT(char(8), @DiaHoy,112)
				And tim_copnclo='X' )
			AND NOT Alt_iidCuenta IN (
			SELECT  exc_iidcuenta FROM m_horarios_excepcion 
			INNER JOIN _tablas.dbo.t_eventos_feriados ON exc_cevento=eve_ccodigo
       		                WHERE DATEPART(dw, eve_dfechadesdes)<=@nDay AND @nDay <=DATEPART(dw, eve_dfechahasta)
				  AND CONVERT(char(8), eve_dfechadesdes,112) >= CONVERT(char(8), @DiaHoy,112)
				  AND CONVERT(char(8), eve_dfechahasta,112) <= CONVERT(char(8), @DiaHoy,112)
			 			  )
	)


GO
