CREATE PROCEDURE [dbo].[SP_EventosPorTipo]  @cDesde Char(8),@cHasta Char(8)  AS 
--Selecciona los eventos de un periodo dado agrupados por tipo de evento
--Autor .Pablo O. Canónico 01-12-2005

SET NOCOUNT ON
--Opn-Clo
SELECT Count(rec_iid) As nCant, 'OC' As cTipo
	FROM p_recepcion With (NOLOCK)
	INNER JOIN _tablas.dbo.t_codigos_alarma ON rec_cAlarma= cod_cCodigo 
		And _Tablas.dbo.t_codigos_alarma.cod_ntipo IN(1,2)
	WHERE rec_nestado IN (0,1,2,3,5,6,7) 
	And ( CONVERT(char(8), rec_tfechahora,112) >= @cDesde And CONVERT(char(8), rec_tfechahora,112) <= @cHasta )
Union All
--Emergencia
SELECT Count(rec_iid) As nCant, 'EM' As cTipo
	FROM p_recepcion With (NOLOCK)
	INNER JOIN _tablas.dbo.t_codigos_alarma ON rec_cAlarma= cod_cCodigo 
		And _Tablas.dbo.t_codigos_alarma.cod_ntipo=0 
		And _Tablas.dbo.t_codigos_alarma.cod_nalerta=1
	WHERE rec_nestado IN (0,1,2,3,5,6,7)
	And ( CONVERT(char(8), rec_tfechahora,112) >= @cDesde And CONVERT(char(8), rec_tfechahora,112) <= @cHasta )
Union All
--No Emergencia
SELECT Count(rec_iid) As nCant, 'NE' As cTipo
	FROM p_recepcion With (NOLOCK)
	INNER JOIN _tablas.dbo.t_codigos_alarma ON rec_cAlarma= cod_cCodigo 
		And ( _Tablas.dbo.t_codigos_alarma.cod_ntipo IN(3,4) Or
		     (_Tablas.dbo.t_codigos_alarma.cod_ntipo=0 And _Tablas.dbo.t_codigos_alarma.cod_nalerta=0))
	WHERE rec_nestado IN (0,1,2,3,5,6,7)
	And ( CONVERT(char(8), rec_tfechahora,112) >= @cDesde And CONVERT(char(8), rec_tfechahora,112) <= @cHasta )


GO
/****** Object:  StoredProcedure [dbo].[SP_Horario]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SP_Horario] @nDay Numeric(1,0)  AS 
--Selecciona los horarios de un dia (re-escrito)
--Autor .Pablo O. Canónico 10-08-2004 / 23-11-2006 / 21-08-2007 / 11-10-2007 / 26-01-2009 / 08-08-2011 / 29-08-2014
--01-12-2015 se agrego el DateFirst porque en sistemas en Language no US toma lunes como dia 1

SET NOCOUNT ON
SET DATEFIRST 7
Declare @DiaHoy DateTime
Set @DiaHoy = GetDate()
SELECT hor_iidCuenta,
	( Case When hor_ndiaApertura = @nDay Then 
		 DATEADD(minute, -tol_nAperturaAntes, Cast(hor_choraapertura As DateTime) )
					   Else 
		 Cast('00:00' As DateTime) 
					   End	) As HoraAperturaAntes,
	( Case When hor_ndiaApertura = @nDay Then 
		( Case When tol_cAperturaAntesAlarma = Space(3) Then 'CLF' Else tol_cAperturaAntesAlarma End)
					   Else
		'___'
					   End	) As AlarmaAperturaAntes,
	( Case When hor_ndiaApertura = @nDay Then 
	        DATEADD(minute, tol_nAperturaDespues, Cast(hor_choraapertura As DateTime) ) 
					   Else
	         Cast('00:00' As DateTime) 
					   End  ) As HoraAperturaDespues,
	( Case When hor_ndiaApertura = @nDay Then 
		( Case When tol_cAperturaDespuesAlarma = Space(3) Then 'OPF' Else tol_cAperturaDespuesAlarma  End)
					   Else
		'___'
					   End	) As AlarmaAperturaDespues,
	( Case When hor_ndiaCierre = @nDay Then 
		 DATEADD(minute, -tol_nCierreAntes, Cast(hor_choracierre As DateTime) )
					   Else 
		 Cast('00:00' As DateTime) 
					   End	) As HoraCierreAntes,
	( Case When hor_ndiaCierre = @nDay Then 
		( Case When tol_cCierreAntesAlarma = Space(3) Then 'CLF' Else tol_cCierreAntesAlarma End)
					   Else
		'___'
					   End	) As AlarmaCierreAntes,
	( Case When hor_ndiaCierre = @nDay Then 
	        DATEADD(minute, tol_nCierreDespues, Cast(hor_choracierre As DateTime) )
					   Else
	         Cast('00:00' As DateTime) 
					   End  ) As HoraCierreDespues,
	( Case When hor_ndiaCierre = @nDay Then 
		( Case When tol_cCierreDespuesAlarma = Space(3) Then 'OPF' Else tol_cCierreDespuesAlarma  End)
					   Else
		'___'
					   End	) As AlarmaCierreDespues,tol_nModo,IsNull(tol_dVacacionesDesde,Getdate()-1) As dVacacionesDesde,IsNull(tol_dVacacionesHasta,Getdate()-1) As dVacacionesHasta
  FROM m_horarios 
INNER JOIN m_horarios_tolerancia ON hor_iidCuenta=tol_iidCuenta  
	WHERE  hor_iidCuenta>0 And ( hor_ndiaApertura = @nDay Or hor_ndiaCierre = @nDay )
		AND NOT hor_iidCuenta IN (
			SELECT  exc_iidcuenta FROM m_horarios_excepcion
                        INNER JOIN _tablas.dbo.t_eventos_feriados ON exc_cevento=eve_ccodigo
       		                WHERE DATEPART(dw, eve_dfechadesdes)<=@nDay AND @nDay <=DATEPART(dw, eve_dfechahasta)
				  AND CONVERT(char(8), eve_dfechadesdes,112) >= CONVERT(char(8), @DiaHoy,112)
				  AND CONVERT(char(8), eve_dfechahasta,112) <= CONVERT(char(8), @DiaHoy,112)
				) And  NOT hor_iidCuenta IN (
					SELECT alt_iidCuenta FROM m_horarios_alternativos 
					LEFT OUTER JOIN m_horarios_tolerancia ON alt_iidCuenta=tol_iidCuenta
					 WHERE alt_ndiaApertura = @nDay AND alt_iidCuenta=hor_iidCuenta 
					AND Not Alt_iidCuenta IN (
						SELECT tim_iidcuenta FROM p_timer
						Where CONVERT(char(8), tim_tfechahora,112)  = CONVERT(char(8), @DiaHoy,112)
						And tim_copnclo='X' ))
UNION (
	SELECT alt_iidcuenta,
	( Case When alt_ndiaApertura = @nDay And alt_choraapertura<>'00:00' Then 
		 DATEADD(minute, -tol_nAperturaAntes, Cast(alt_choraapertura As DateTime) )
					   Else 
		 Cast('00:00' As DateTime) 
					   End	) As HoraAperturaAntes,
	( Case When alt_ndiaApertura = @nDay Then 
		( Case When tol_cAperturaAntesAlarma = Space(3) Then 'CLF' Else tol_cAperturaAntesAlarma End)
					   Else
		'___'
					   End	) As AlarmaAperturaAntes,
	( Case When alt_ndiaApertura = @nDay And alt_choraapertura<>'00:00' Then 
	         DATEADD(minute, tol_nAperturaDespues, Cast(alt_choraapertura As DateTime) ) 
					   Else 
		 Cast('00:00' As DateTime) 
					   End	) As HoraAperturaDespues,
	( Case When alt_ndiaApertura = @nDay Then 
		( Case When tol_cAperturaDespuesAlarma = Space(3) Then 'OPF' Else tol_cAperturaDespuesAlarma  End)
					   Else
		'___'
					   End	) As AlarmaAperturaDespues,
	( Case When alt_ndiaCierre = @nDay Then 
		 DATEADD(minute, -tol_nCierreAntes, Cast(alt_choracierre As DateTime) )
					   Else 
		 Cast('23:59' As DateTime) 
					   End	) As HoraCierreAntes,
	( Case When alt_ndiaCierre = @nDay Then 
		( Case When tol_cCierreAntesAlarma = Space(3) Then 'CLF' Else tol_cCierreAntesAlarma End)
					   Else
		'___'
					   End	) As AlarmaCierreAntes,
	( Case When alt_ndiaCierre = @nDay Then 
	        DATEADD(minute, tol_nCierreDespues, Cast(alt_choracierre As DateTime) )
					   Else 
		 Cast('23:59' As DateTime) 
					   End	) As HoraCierreDespues,
	( Case When alt_ndiaCierre = @nDay Then 
		( Case When tol_cCierreDespuesAlarma = Space(3) Then 'OPF' Else tol_cCierreDespuesAlarma  End)
					   Else
		'___'
				   End	) As AlarmaCierreDespues,tol_nModo,IsNull(tol_dVacacionesDesde,Getdate()-1) As dVacacionesDesde,IsNull(tol_dVacacionesHasta,Getdate()-1) As dVacacionesHasta
  FROM m_horarios_alternativos 
	INNER JOIN m_horarios_tolerancia ON alt_iidCuenta=tol_iidCuenta
		  WHERE alt_iidCuenta>0  And ( alt_ndiaApertura = @nDay Or alt_ndiaCierre = @nDay )
			AND Not Alt_iidCuenta IN (
			SELECT tim_iidcuenta FROM p_timer
			Where CONVERT(char(8), tim_tfechahora,112)  = CONVERT(char(8), @DiaHoy,112)
				And tim_copnclo='X' )
--			AND NOT Alt_iidCuenta IN (
--			SELECT  exc_iidcuenta FROM m_horarios_excepcion 
--			INNER JOIN _tablas.dbo.t_eventos_feriados ON exc_cevento=eve_ccodigo
--       		                WHERE DATEPART(dw, eve_dfechadesdes)<=@nDay AND @nDay <=DATEPART(dw, eve_dfechahasta)
--				  AND CONVERT(char(8), eve_dfechadesdes,112) >= CONVERT(char(8), @DiaHoy,112)
--				  AND CONVERT(char(8), eve_dfechahasta,112) <= CONVERT(char(8), @DiaHoy,112)
--			 			  )
	)
Order By 1,2


GO
/****** Object:  StoredProcedure [dbo].[SP_HorarioAlternativo]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SP_HorarioAlternativo] @nDay Numeric(1,0) AS 
--Selecciona los horarios alternativos reprogramados desde monitoreo
--Autor .Pablo O. Canónico 20-02-2006 / 26-01-2009
--01-12-2015 se agrego el DateFirst porque en sistemas en Language no US toma lunes como dia 1

SET NOCOUNT ON
SET DATEFIRST 7
Declare @DiaHoy DateTime
Set @DiaHoy = GetDate()

SELECT alt_iidcuenta,
	( Case When alt_ndiaApertura = @nDay And alt_choraapertura<>'00:00' Then 
		 DATEADD(minute, -tol_nAperturaAntes, Cast(alt_choraapertura As DateTime) )
					   Else 
		 Cast('00:00' As DateTime) 
					   End	) As HoraAperturaAntes,
	( Case When alt_ndiaApertura = @nDay Then 
		( Case When tol_cAperturaAntesAlarma = Space(3) Then 'CLF' Else tol_cAperturaAntesAlarma End)
					   Else
		'___'
					   End	) As AlarmaAperturaAntes,
	( Case When alt_ndiaApertura = @nDay And alt_choraapertura<>'00:00' Then 
	         DATEADD(minute, tol_nAperturaDespues, Cast(alt_choraapertura As DateTime) ) 
					   Else 
		 Cast('00:00' As DateTime) 
					   End	) As HoraAperturaDespues,
	( Case When alt_ndiaApertura = @nDay Then 
		( Case When tol_cAperturaDespuesAlarma = Space(3) Then 'OPF' Else tol_cAperturaDespuesAlarma  End)
					   Else
		'___'
					   End	) As AlarmaAperturaDespues,
	( Case When alt_ndiaCierre = @nDay Then 
		 DATEADD(minute, -tol_nCierreAntes, Cast(alt_choracierre As DateTime) )
					   Else 
		 Cast('23:59' As DateTime) 
					   End	) As HoraCierreAntes,
	( Case When alt_ndiaCierre = @nDay Then 
		( Case When tol_cCierreAntesAlarma = Space(3) Then 'CLF' Else tol_cCierreAntesAlarma End)
					   Else
		'___'
					   End	) As AlarmaCierreAntes,
	( Case When alt_ndiaCierre = @nDay Then 
	        Cast(alt_choracierre As DateTime)
					   Else 
		Cast('23:59' As DateTime)
					   End	) As HoraCierreDespues,
-- 	( Case When alt_ndiaCierre = @nDay Then 
-- 	        DATEADD(minute, tol_nCierreDespues, Cast(alt_choracierre As DateTime) )
-- 					   Else 
-- 		 Cast('23:59' As DateTime) 
-- 					   End	) As HoraCierreDespues,
	( Case When alt_ndiaCierre = @nDay Then 
		( Case When tol_cCierreDespuesAlarma = Space(3) Then 'OPF' Else tol_cCierreDespuesAlarma  End)
					   Else
		'___'
					   End	) As AlarmaCierreDespues,
	tim_iid
  FROM m_horarios_alternativos 
	LEFT OUTER JOIN m_horarios_tolerancia ON alt_iidCuenta=tol_iidCuenta
	Inner JOIN p_timer ON alt_iidCuenta=tim_iidCuenta And tim_copnclo='X'
		  WHERE alt_ndiaapertura = @nDay AND alt_iidCuenta>0 
			AND  Alt_iidCuenta IN (
				SELECT tim_iidcuenta FROM p_timer
					Where CONVERT(char(8), tim_tfechahora,112)  = CONVERT(char(8), @DiaHoy,112)
					And tim_copnclo='X'
			 			  )
Order By 1,2


GO
