CREATE PROCEDURE [dbo].[SP_LimiteOPN]  @nDay Numeric(1,0) AS
--Busca Horarios de Limite de Apertura
--Autor .Pablo O. Canónico 27-12-2004 / 26-01-2009
--01-12-2015 se agrego el DateFirst porque en sistemas en Language no US toma lunes como dia 1

SET NOCOUNT ON
SET DATEFIRST 7
Declare @DiaHoy DateTime
Set @DiaHoy = GetDate()

SELECT hor_iidCuenta,
	( Case When hor_ndiaApertura = @nDay Then 
--	        Convert(Char(8),DATEADD(minute, tol_nAperturaDespues, Cast(hor_choraapertura As DateTime) ),14) 
--					   Else
--	        Convert(Char(8),Cast('23:59' As DateTime),14) 
	        DATEADD(minute, tol_nAperturaDespues, Cast(hor_choraapertura As DateTime) )
					   Else
	        Cast('23:59:59' As DateTime)

					   End  ) As HoraLimite,tol_nModo
  FROM m_horarios 
    INNER JOIN m_horarios_tolerancia ON hor_iidCuenta=tol_iidCuenta  
	WHERE hor_iidCuenta>0 And ( hor_ndiaApertura = @nDay Or hor_ndiaCierre = @nDay )
		AND NOT hor_iidCuenta IN (
			SELECT  exc_iidcuenta FROM m_horarios_excepcion
                        INNER JOIN _tablas.dbo.t_eventos_feriados ON exc_cevento=eve_ccodigo
			        WHERE DATEPART(dw, eve_dfechadesdes)<=@nDay AND @nDay <=DATEPART(dw, eve_dfechahasta)
				  AND CONVERT(char(8), eve_dfechadesdes,112) >= CONVERT(char(8), @DiaHoy,112)
				  AND CONVERT(char(8), eve_dfechahasta,112) <= CONVERT(char(8), @DiaHoy,112)
--       		                WHERE DAY(eve_dfechadesdes)<=@nDay AND @nDay <=DAY(eve_dfechahasta)  AND
--				MONTH(eve_dfechadesdes)<=MONTH(GETDATE()) AND MONTH(GETDATE())<=MONTH(eve_dfechahasta) 
				AND
		                DATEADD(minute,-tol_naperturaAntes,hor_choraapertura)>=CAST(eve_choradesde AS DateTime) AND 
		                DATEADD(minute,tol_naperturaDespues,hor_choraapertura)<=CAST(eve_chorahasta AS DateTime)
-- 				) And  NOT hor_iidCuenta IN (
-- 					SELECT alt_iidCuenta FROM m_horarios_alternativos 
-- 					LEFT OUTER JOIN m_horarios_tolerancia ON alt_iidCuenta=tol_iidCuenta
-- 					 WHERE alt_ndiaApertura = @nDay AND alt_iidCuenta=hor_iidCuenta )
				) 
--				And  NOT hor_choraapertura IN (
--			SELECT alt_choraapertura FROM m_horarios_alternativos 
--		 	    WHERE alt_ndiaCierre = @nDay AND alt_iidCuenta=hor_iidCuenta 
--				And alt_choraapertura=hor_choraapertura)
UNION (
	SELECT alt_iidcuenta,
	( Case When alt_ndiaApertura = @nDay Then 
	        Cast(alt_choraapertura As DateTime)
					   Else 
		Cast('23:59:59' As DateTime)
					   End	) As HoraLimite,tol_nModo
  FROM m_horarios_alternativos 
	INNER JOIN m_horarios_tolerancia ON alt_iidCuenta=tol_iidCuenta
		  WHERE alt_iidCuenta>0 And ( alt_ndiaApertura = @nDay Or alt_ndiaCierre = @nDay )
			AND  NOT Alt_iidCuenta IN (
			SELECT  exc_iidcuenta FROM m_horarios_excepcion 
			INNER JOIN _tablas.dbo.t_eventos_feriados ON exc_cevento=eve_ccodigo
			        WHERE DATEPART(dw, eve_dfechadesdes)<=@nDay AND @nDay <=DATEPART(dw, eve_dfechahasta)
				  AND CONVERT(char(8), eve_dfechadesdes,112) >= CONVERT(char(8), @DiaHoy,112)
				  AND CONVERT(char(8), eve_dfechahasta,112) <= CONVERT(char(8), @DiaHoy,112)
--       		                WHERE DAY(eve_dfechadesdes)<=@nDay AND @nDay <=DAY(eve_dfechahasta)  AND
--				MONTH(eve_dfechadesdes)<=MONTH(GETDATE()) AND MONTH(GETDATE())<=MONTH(eve_dfechahasta) 
				AND
		                DATEADD(minute,-tol_naperturaAntes,alt_choraapertura)>=CAST(eve_choradesde As DateTime) AND 
		                DATEADD(minute,tol_naperturaDespues,alt_choraapertura)<=CAST(eve_chorahasta As DateTime)	
			 			  )
	)
Order By 2,1


GO
/****** Object:  StoredProcedure [dbo].[SP_MueveAHistoria]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [dbo].[SP_MueveAHistoria] AS
--Mueve los registros de p_recepcion a Historicos
--Autor .Pablo O. Canónico 08-07-2008
--Modificado para que depure de a 1 dia y dependiendo de un parametro
--Utilza MERGE y funciona solamente con Compatibility Level en 100
--Se agrego la grabacion de s_tablahistoricos
--Se modifico la repeticion del control de TaskStatus
SET NOCOUNT ON
Declare @nMeses numeric(2)
Set @nMeses = ( Select par_ivalor From _Tablas.dbo.t_parametros With (NOLOCK) Where par_cCodigo='MESESDEPURACION' )
If @nMeses > 0
Begin
   DBCC TRACEON (1224)

   declare @dia Datetime 
   Declare @cCierre Char(6)
   Declare @cCierreDesde Char(8)
   Declare @cCierreHasta Char(19)
   Declare @cDia Char(8)
   Declare @nRows Int
   Declare @cHoraActual Char(8)
   Declare @cHorario char(9)
   Declare @iRep Int

   --1.Busco el dia y mes a depurar
   set @dia = GetDate()
   set @cDia = CONVERT(CHARACTER, @dia, 112)
   set @cCierre = Left(CONVERT(CHARACTER, DateAdd(Month,-@nMeses,@dia), 112),6)
   set @cCierreDesde = CONVERT(CHARACTER, DateAdd(Month,-@nMeses,@dia), 112)
   set @cHoraActual = CONVERT(CHARACTER, @dia, 114)
   set @cHorario = Case When @cHoraActual<='06:00:00' Then ' 06:00:00'
					 When @cHoraActual<='12:00:00' Then ' 12:00:00'
					 When @cHoraActual<='18:00:00' Then ' 18:00:00'
					 Else ' 23:59:59' End 
   set @cCierreHasta = @cCierreDesde+@cHorario	

   If @cHorario = ' 23:59:59'
		Set @iRep = 600		--60min * 10hs = 600	Porque de 20:45 que es la ultima ejecucion del dia va a las 2.45 y no se ejecuto todavia
   Else	
		Set @iRep = 360		--60min * 6hs = 360

   -- Aviso que la tarea esta funcionando
   Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'MueveAHistoria', @Repetition = @iRep
   --

   Declare @cSQL VARCHAR(Max)
   Declare @nError Int = 0,
		   @iMax Int = 0,
		   @iLoop Int = 0

   Declare @message nVarChar(Max) = '',
		   @StartDateTimeText VarChar(max) = ''

    --2.Creo los Historicos Necesarios
	IF OBJECT_ID('p_recepcion'+@cCierre) Is Null
		Execute @nError = SP_CreoHistoria @cCierre

	--2.1.Actualizo la tabla [s_tablahistoricos]
	If Not Exists ( Select Top 1 [c_periodo] From [_Sistema].[dbo].[s_tablahistoricos] Where [c_periodo] = 'p_recepcion'+@cCierre)
	  Begin
		INSERT INTO [_Sistema].[dbo].[s_tablahistoricos] ([iid_reporte],[c_periodo],[n_usado]) 
			 VALUES (0,'p_recepcion'+@cCierre,0)
	  End
	
    --3.Si se creo nuevo o ya existia es lo mismo hago MERGE
	Begin
		Set @cSQL = 'MERGE INTO [dbo].[p_recepcion' +  @cCierre  +  '] AS TGT
		USING (	 Select *, (Case When rec_nOrigen=1 Then ''%TI : Evento de Control%'' When rec_nOrigen=2 And rec_iPuerto < 100 Then ''%PG :%'' When rec_nOrigen=2 Then ''%IR :%'' When rec_nOrigen=3 Then ''%MAN : Evento Generado Manualmente%'' When rec_nOrigen=6 And rec_iPuerto < 0 Then ''%TR : Terminal Remota%'' 
			When rec_nOrigen=6 Then ''%SMS :% '' When rec_nOrigen=7 Then ''%SCH : Evento Programado%'' When rec_nOrigen=8 Then ''%JOB : Tarea Programada%'' Else ''%SG : Evento Interno%'' End ) +Space(1)+ Ltrim( (Case When rec_iPuerto<=0 Then '''' Else Cast(rec_iPuerto As Char(5)) End ) ) As _Origen, 
			--Cast(rec_iPuerto As VarChar(6)) As _Puerto
			Case When rec_cAlarma = ''_DI'' Then rec_cContenido Else Cast(rec_iPuerto As VarChar(6)) End As _Puerto
			From [dbo].[p_recepcion] With (NOLOCK)
			Where  rec_nestado > 2 And
			rec_tfechahora >= '+ CHAR(39) +  @cCierreDesde + CHAR(39) +' And rec_tfechahora <= '+ CHAR(39) + Rtrim(@cCierreHasta) + CHAR(39)+'
		) AS SRC ON TGT.rec_iid = SRC.rec_iid'

		--4.1.Solamente Inserto con Merge los registros que le corresponden 	
		Set @cSQL = @cSQL +'
		WHEN NOT MATCHED THEN 
			INSERT ([rec_iid], [rec_iidcuenta], [rec_calarma], [rec_czona], [rec_iusuario], [rec_tfechahora], [rec_nestado], [rec_cContenido], [rec_tFechaProceso], [rec_ioperador], [rec_cObservaciones], [rec_cTerminal], [rec_idResolucion], [rec_idReceptor], [rec_cCategorizacion], [rec_iNYR], [rec_iTE], [rec_tFechaRecepcion], [rec_nOrigen], [rec_idMap], [rec_idFwd], [rec_iMinutosEspera], [rec_iPuerto], [rec_idLoc], [rec_iPrioridad], [usuario_iCodigo], [usuario_cNombre], [zonas_cCodigo], [zonas_cDescripcion], [_Origen], [_Puerto] )
			VALUES(SRC.rec_iid,SRC.rec_iidcuenta,SRC.rec_calarma,SRC.rec_czona,SRC.rec_iusuario,SRC.rec_tfechahora,SRC.rec_nestado,SRC.rec_cContenido,SRC.rec_tFechaProceso,SRC.rec_ioperador,SRC.rec_cObservaciones,SRC.rec_cTerminal,SRC.rec_idResolucion,SRC.rec_idReceptor,SRC.rec_cCategorizacion,SRC.rec_iNYR,SRC.rec_iTE,SRC.rec_tFechaRecepcion,SRC.rec_nOrigen,SRC.rec_idMap,SRC.rec_idFwd,SRC.rec_iMinutosEspera,SRC.rec_iPuerto,SRC.rec_idLoc,SRC.rec_iPrioridad,SRC.rec_iusuario,'''',SRC.rec_cZona,'''',SRC._Origen,SRC._Puerto);
		'
		--Print (@cSQL) 
	    Exec (@cSQL )
   	    Select @nError = @@ERROR,@nRows = @@ROWCOUNT;

	    If @nError = 0	
	 	Begin
			IF @nRows = 0
			Begin
			 	Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
				Set @message = 'Start DateTime : %s | Warning: No rows were updated'
				RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
			End

	   		--5.Saco los registros copiados
			Select @iMax = Count(rec_iid) From [dbo].[p_recepcion]  Where rec_nestado > 2 And rec_tfechahora >= @cCierreDesde  And rec_tfechahora < @cCierreHasta
			If @iMax Between 1 And 999
				Set @iMax = 1000

		
			Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
			Set @message = 'Start DateTime : %s | --5.Sacos los registros copiados-- | Total de Registros => '+ Cast(@iMax As varchar(10))+' | Loops Necesarios Reales => '+ Cast(@iMax / 1000 As varchar(10))
			RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT
			
			Set @iMax = @iMax / 1000

			Set @iLoop = 0
			WHILE @iLoop <= @iMax And @iMax > 0
				BEGIN
					Set @iLoop = @iLoop + 1
					Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
					Set @message = 'Start DateTime : %s | Maximo 1000 | Loop => '+ Cast(@iLoop As varchar(10)) +' / '+ Cast(@iMax As varchar(10))
					RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

					Set @cSQL = 'Delete Top (1000) From [dbo].[p_recepcion]  Where rec_nestado > 2 And rec_tfechahora >= '+CHAR(39)+@cCierreDesde+CHAR(39)+ ' And rec_tfechahora < '+CHAR(39)+@cCierreHasta+CHAR(39)

					Set @StartDateTimeText = CONVERT(varchar, GetDate(),120)  
					Set @message = 'Start DateTime : %s | cSQL => '+ @cSQL
					RAISERROR( @message, 10,1,@StartDateTimeText) WITH NOWAIT

					Exec (@cSQL)

	  				IF @@ROWCOUNT = 0 BREAK;
				End;

	 	End
	End
End
Else	-- Aviso que la tarea no cumple las condiciones para funcionar
	Exec [dbo].[TaskStatus_SetLastExecutedTime] @JobName = N'MueveAHistoria', @Repetition = 360, @Date = null, @Status = 0



GO
/****** Object:  StoredProcedure [dbo].[SP_NivelSenalPorCta]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SP_NivelSenalPorCta] @idCta Int, @cDesde Char(8),@cHasta Char(8)  AS 
--Selecciona los niveles de señal/tension de eventos reales ingresados por IR entre fechas
--Autor .Pablo O. Canónico 16-10-2008
SET NOCOUNT ON
Select 1 As nTipo,AVG(nvs_nNivel) As nNivel,Day(nvs_tfechahora) As dia,Month(nvs_tfechahora) As Mes,Year(nvs_tfechahora) As Anio
   FROM [_Datos].[dbo].[p_nivelsenal]  With (NOLOCK)
	Where nvs_idCuenta = @idCta 
	And ( CONVERT(char(8), nvs_tfechahora,112) >= @cDesde And CONVERT(char(8), nvs_tfechahora,112) <= @cHasta )
	Group By Day(nvs_tfechahora),Month(nvs_tfechahora),Year(nvs_tfechahora)
Union (
Select 2 As nTipo,AVG(nvs_nTension/10) As nNivel,Day(nvs_tfechahora) As dia,Month(nvs_tfechahora) As Mes,Year(nvs_tfechahora) As Anio
   FROM [_Datos].[dbo].[p_nivelsenal]  With (NOLOCK)
	Where nvs_idCuenta = @idCta 
	And ( CONVERT(char(8), nvs_tfechahora,112) >= @cDesde And CONVERT(char(8), nvs_tfechahora,112) <= @cHasta )
	Group By Day(nvs_tfechahora),Month(nvs_tfechahora),Year(nvs_tfechahora)
)
Order By Year(nvs_tfechahora),Month(nvs_tfechahora),Day(nvs_tfechahora)


GO
/****** Object:  StoredProcedure [dbo].[SP_TraeTablaHistoricos]    Script Date: 4/21/2026 10:44:40 AM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SP_TraeTablaHistoricos] @i_idreporte Int AS
SET NOCOUNT ON
SELECT RTRIM( table_name ) AS table_name, CASE WHEN n_usado = null THEN 0 ELSE n_usado END AS l_usado, 
       @i_idreporte AS i_idreporte, CASE WHEN c_periodo = null  THEN 1 ELSE 0 END AS l_nuevo
	FROM ( SELECT table_name 
              FROM information_schema.columns 
              WHERE  table_name Like 'p_recepcion%' And table_name Not In ('p_recepcion','p_recepcion_notas','p_recepcion_proceso','p_recepcion_D')
			  	 And table_name Not Like 'p_recepcion_proceso%'
              GROUP BY table_name ) AS c_historicos 
	LEFT OUTER JOIN ( SELECT iid_reporte, c_periodo, n_usado
                           FROM _Sistema..s_tablahistoricos
                             WHERE iid_reporte = @i_idreporte ) AS c_tablahistoricos ON c_historicos.table_name = c_tablahistoricos.c_periodo
ORDER BY table_name DESC


GO
